-- Poems batch 18
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('12ee9d91-c4af-467a-90cd-ad6857e7f96f','美人宮棊','張籍','唐','唐诗','tang','','[]','紅燭臺前出翠娥，海沙鋪局巧相和。',32,'全唐诗/poet.tang.20000.json','["紅燭臺前出翠娥，海沙鋪局巧相和。", "趂行移手巡收盡，數數看誰得最多。"]'),
('53151f8d-1ea9-4c74-8681-a93760003b9c','蠻州','張籍','唐','唐诗','tang','','[]','瘴水蠻中入洞流，人家多住竹棚頭。',32,'全唐诗/poet.tang.20000.json','["瘴水蠻中入洞流，人家多住竹棚頭。", "一山海上無城郭，唯見松牌記象州。"]'),
('a149d59f-edb5-4ce1-9ace-cfe23be399f8','送元宗簡','張籍','唐','唐诗','tang','','[]','貂帽垂肩窄皂裘，雪深騎馬向西州。',32,'全唐诗/poet.tang.20000.json','["貂帽垂肩窄皂裘，雪深騎馬向西州。", "暫時相見還相送，却閉閑門依舊愁。"]'),
('c4ff8d39-cbac-431a-aaac-f12a80f1f99c','寄徐晦','張籍','唐','唐诗','tang','','[]','鄠陂魚美酒偏濃，不出琴齋見雪峰。',32,'全唐诗/poet.tang.20000.json','["鄠陂魚美酒偏濃，不出琴齋見雪峰。", "應勝昨來趨府日，簿書牀上亂重重。"]'),
('5951cc09-83ca-4e54-83dd-97bedbce2d78','寄白學士','張籍','唐','唐诗','tang','','[]','自掌天書見客稀，縱因休沐鎖雙扉。',32,'全唐诗/poet.tang.20000.json','["自掌天書見客稀，縱因休沐鎖雙扉。", "幾回扶病欲相訪，知向禁中歸未歸。"]'),
('58a7e4bd-15de-4126-a91c-de9562694ce8','喜王六同宿','張籍','唐','唐诗','tang','','[]','十八年來恨別離，唯同一宿詠新詩。',32,'全唐诗/poet.tang.20000.json','["十八年來恨別離，唯同一宿詠新詩。", "更相借問詩中語，共說如今勝舊時。"]'),
('53f67bc3-4e10-4e03-8bb7-903cfa77c55e','題玉像堂','張籍','唐','唐诗','tang','','[]','玉毫不着世間塵，輝相分明十八身。',32,'全唐诗/poet.tang.20000.json','["玉毫不着世間塵，輝相分明十八身。", "入夜無煙燈更好，堂中唯有轉經人。"]'),
('9ac10c96-2565-49a8-8d9c-c7a8e00a6bfd','與賈島閑遊','張籍','唐','唐诗','tang','','[]','水北原南草色新，雪消風暖不生塵。',32,'全唐诗/poet.tang.20000.json','["水北原南草色新，雪消風暖不生塵。", "城中車馬應無數，能解閑行有幾人。"]'),
('1708826e-98b4-46c1-b549-e7fef08b274a','哭丘長史','張籍','唐','唐诗','tang','','[]','丘公已歿故人稀，欲過街西更訪誰。',32,'全唐诗/poet.tang.20000.json','["丘公已歿故人稀，欲過街西更訪誰。", "每到子城東路上，憶君相逐入朝時。"]'),
('001fb373-42bc-4183-b801-4bd6fbd0ced2','哭孟寂','張籍','唐','唐诗','tang','','[]','曲江院裏題名處，十九人中最少年。',32,'全唐诗/poet.tang.20000.json','["曲江院裏題名處，十九人中最少年。", "今日春光君不見，杏花零落寺門前。"]'),
('37b86718-b55e-4d15-a925-35fd808661f5','患眼','張籍','唐','唐诗','tang','','[]','三年患眼今年[校]，[免]與風光便隔生。',36,'全唐诗/poet.tang.20000.json','["三年患眼今年[校]，[免]與風光便隔生。", "昨日韓家後園裏，看花猶似未分明。"]'),
('21f79e41-e677-4b23-851f-3d0ef6bd5c23','答劉競','張籍','唐','唐诗','tang','','[]','劉君久被時拋擲，老向城中作選人。',32,'全唐诗/poet.tang.20000.json','["劉君久被時拋擲，老向城中作選人。", "昨日街西相近住，每來存問老夫身。"]'),
('2b28f476-519a-4f0f-bd77-5ebc5c080eb0','贈華嚴院僧','張籍','唐','唐诗','tang','','[]','一身依止荒閑院，燭耀窗中有宿煙。',32,'全唐诗/poet.tang.20000.json','["一身依止荒閑院，燭耀窗中有宿煙。", "徧禮華嚴經裏字，不曾行到寺門前。"]'),
('dbd2b5f0-bdcd-4cf6-a824-32cdc7ed6eaf','逢故人','張籍','唐','唐诗','tang','','[]','山東一十餘年別，今日相逢在上都。',32,'全唐诗/poet.tang.20000.json','["山東一十餘年別，今日相逢在上都。", "說盡向來無限事，相看摩捋白髭鬚。"]'),
('d3df800a-ab93-4401-be88-6de07067e8d5','送蕭遠弟','張籍','唐','唐诗','tang','','[]','街北槐花傍馬垂，病身相送出門遲。',32,'全唐诗/poet.tang.20000.json','["街北槐花傍馬垂，病身相送出門遲。", "與君別後秋風夜，作得新詩說向誰。"]'),
('c7043fe9-514d-4931-9dc0-66be822cdc76','送辛少府任樂安','張籍','唐','唐诗','tang','','[]','才多不肯浪容身，老大詩章轉更新。',32,'全唐诗/poet.tang.20000.json','["才多不肯浪容身，老大詩章轉更新。", "選得天台山下住，一家全作學仙人。"]'),
('41a57e93-7560-4156-8e99-d34e36ef8ade','贈任道人','張籍','唐','唐诗','tang','','[]','長安多病無生計，藥鋪醫人亂索錢。',32,'全唐诗/poet.tang.20000.json','["長安多病無生計，藥鋪醫人亂索錢。", "欲得定知身上事，憑君爲算小行年。"]'),
('47ee7083-94cd-4830-be32-c2288e68642e','招周居士','張籍','唐','唐诗','tang','','[]','閉門秋雨濕墙莎，俗客來稀野思多。',32,'全唐诗/poet.tang.20000.json','["閉門秋雨濕墙莎，俗客來稀野思多。", "已掃書齋安藥竈，山人作意早經過。"]'),
('8be94615-01f2-4bec-a310-10374fa3b6d0','送許處士','張籍','唐','唐诗','tang','','[]','高情自與俗人疎，獨向藍溪選僻居。',32,'全唐诗/poet.tang.20000.json','["高情自與俗人疎，獨向藍溪選僻居。", "會到白雲長取醉，不能窗下讀閑書。"]'),
('dce86802-daf7-44d1-9f88-35ae33c96877','送律師歸婺州','張籍','唐','唐诗','tang','','[]','京中開講已多時，曾作壇頭證戒師。',32,'全唐诗/poet.tang.20000.json','["京中開講已多時，曾作壇頭證戒師。", "歸到雙溪橋北寺，鄉僧爭就學威儀。"]'),
('72f904c4-5ff2-419a-b3a4-b96dcc2b89cc','題楊秘書新居','張籍','唐','唐诗','tang','','[]','愛閑不向爭名地，宅在街西最靜坊。',32,'全唐诗/poet.tang.20000.json','["愛閑不向爭名地，宅在街西最靜坊。", "卷裏詩過一千首，白頭新受秘書郎。"]'),
('55839370-dff8-405f-a7fa-38486feffa91','送晊師','張籍','唐','唐诗','tang','','[]','九星臺下煎茶別，五老峰頭覓寺居。',32,'全唐诗/poet.tang.20000.json','["九星臺下煎茶別，五老峰頭覓寺居。", "作得新詩旋相寄，人來請莫達空書。"]'),
('2ee3ee4d-af63-4945-9560-930b01e3a510','送僧往金州','張籍','唐','唐诗','tang','','[]','聞道谿陰山水好，師行一一徧經過。',32,'全唐诗/poet.tang.20000.json','["聞道谿陰山水好，師行一一徧經過。", "事須覓取堪居處，若箇溪頭藥最多。"]'),
('cfc14bee-9fa0-4706-b0fc-380d3562d90b','尋徐道士','張籍','唐','唐诗','tang','','[]','尋師遠到暉天觀，竹院森森閉藥房。',32,'全唐诗/poet.tang.20000.json','["尋師遠到暉天觀，竹院森森閉藥房。", "聞入靜來經七日，仙童簷下獨焚香。"]'),
('f5224101-9e0a-4bc9-8945-5c4779ca04d2','答開州韋使君寄車前子','張籍','唐','唐诗','tang','','[]','開州午日車前子，作藥人皆道有神。',32,'全唐诗/poet.tang.20000.json','["開州午日車前子，作藥人皆道有神。", "慙愧使君憐病眼，三千餘里寄閑人。"]'),
('a3bfb43c-eae3-43dc-9864-195d236b1cfe','憶故州','張籍','唐','唐诗','tang','','[]','壘石爲山伴野夫，自收靈藥讀仙書。',32,'全唐诗/poet.tang.20000.json','["壘石爲山伴野夫，自收靈藥讀仙書。", "如今身是他州客，每見青山憶舊居。"]'),
('c8649844-a2b5-4db0-8cd9-3bacebecb233','送客遊蜀','張籍','唐','唐诗','tang','','[]','行盡青山到益州，錦城樓下二江流。',32,'全唐诗/poet.tang.20000.json','["行盡青山到益州，錦城樓下二江流。", "杜家曾向此中住，爲到浣花溪水頭。"]'),
('aebe5864-0507-4a19-b7f2-e40929e7c98c','送陸暢','張籍','唐','唐诗','tang','','[]','共踏長安街裏塵，吳州獨作未歸身。',32,'全唐诗/poet.tang.20000.json','["共踏長安街裏塵，吳州獨作未歸身。", "昔年舊宅今誰住，君過西塘與問人。"]'),
('ae0b6631-6a2b-478c-9f05-a8c1f2899e81','感春','張籍','唐','唐诗','tang','','[]','遠客悠悠任病身，謝家池上又逢春。',32,'全唐诗/poet.tang.20000.json','["遠客悠悠任病身，謝家池上又逢春。", "明年各自東西去，此地看花是別人。"]'),
('c0b1d427-649a-4860-aa54-589b206d13aa','贈李司議','張籍','唐','唐诗','tang','','[]','漢庭誰問投荒客，十載天南着白衣。',32,'全唐诗/poet.tang.20000.json','["漢庭誰問投荒客，十載天南着白衣。", "秋草茫茫惡谿路，嶺頭遙送北人稀。"]'),
('29dcc03b-5647-471d-893c-0a9cbc225dcd','別客','張籍','唐','唐诗','tang','','[]','青山歷歷水悠悠，今日相逢明日秋。',32,'全唐诗/poet.tang.20000.json','["青山歷歷水悠悠，今日相逢明日秋。", "繫馬城邊楊柳樹，爲君沽酒暫淹留。"]'),
('5fd2d72d-8fde-4406-8ed9-b8eeb91995e5','登樓寄胡家兄弟','張籍','唐','唐诗','tang','','[]','獨上西樓盡日閑，林煙演漾鳥蠻蠻。',32,'全唐诗/poet.tang.20000.json','["獨上西樓盡日閑，林煙演漾鳥蠻蠻。", "謝家兄弟重城裏，不得同看雨後山。"]'),
('3ab2c0eb-e8e5-4b84-bf00-60a49887ac0c','答劉明府','張籍','唐','唐诗','tang','','[]','身病多時又客居，滿城親舊盡相疎。',32,'全唐诗/poet.tang.20000.json','["身病多時又客居，滿城親舊盡相疎。", "可憐絳縣劉明府，猶解頻頻寄遠書。"]'),
('ecd41f12-a61f-4c5e-8cce-5289695e52d3','酬藤杖','張籍','唐','唐诗','tang','','[]','病裏出門行步遲，喜君相贈古藤枝。',32,'全唐诗/poet.tang.20000.json','["病裏出門行步遲，喜君相贈古藤枝。", "倚來自覺身生力，每向傍人說得時。"]'),
('42a7ef88-90f5-4f79-abbf-bf05bd87bc9e','法雄寺東樓','張籍','唐','唐诗','tang','','[]','汾陽舊宅今爲寺，猶有當時歌舞樓。',32,'全唐诗/poet.tang.20000.json','["汾陽舊宅今爲寺，猶有當時歌舞樓。", "四十年來車馬絕，古槐深巷暮蟬愁。"]'),
('0ec7646c-d08e-40af-8557-f9530dfacd43','寄故人','張籍','唐','唐诗','tang','','[]','靜曲閑房病客居，蟬聲滿樹槿花疎。',32,'全唐诗/poet.tang.20000.json','["靜曲閑房病客居，蟬聲滿樹槿花疎。", "故人祗在藍田縣，強半年來未得書。"]'),
('31bbcbd6-e531-470f-92ec-915fa97ce639','鄰婦哭征夫','張籍','唐','唐诗','tang','','[]','雙鬟初合便分離，萬里征夫不得隨。',32,'全唐诗/poet.tang.20000.json','["雙鬟初合便分離，萬里征夫不得隨。", "今日軍回身獨歿，去時鞍馬別人騎。"]'),
('e5388a4b-7457-4f76-826c-ffed2a8ec779','和崔駙馬聞蟬','張籍','唐','唐诗','tang','','[]','鳳凰樓下多歡樂，不覺秋風暮雨天。',32,'全唐诗/poet.tang.20000.json','["鳳凰樓下多歡樂，不覺秋風暮雨天。", "應爲昨來身暫病，蟬聲得到耳傍邊。"]'),
('badab31e-682c-4658-9a2e-cb2b13e317f0','和裴僕射看櫻桃花','張籍','唐','唐诗','tang','','[]','昨日南園新雨後，櫻桃花發舊枝柯。',32,'全唐诗/poet.tang.20000.json','["昨日南園新雨後，櫻桃花發舊枝柯。", "天明不待人同看，遶樹重重履跡多。"]'),
('0c499a93-bbd0-406b-a428-7bfe13f77626','和長安郭明府與友人縣中會飲','張籍','唐','唐诗','tang','','[]','一尊清酒兩人同，好在街西水縣中。',32,'全唐诗/poet.tang.20000.json','["一尊清酒兩人同，好在街西水縣中。", "自恨病身相去遠，此時閑坐對秋風。"]'),
('833f4a39-0f62-420f-8033-870d5e243d7e','唐昌觀看花','張籍','唐','唐诗','tang','','[]','新紅舊紫不相宜，看覺從前兩月遲。',32,'全唐诗/poet.tang.20000.json','["新紅舊紫不相宜，看覺從前兩月遲。", "更向同來詩客道，明年到此莫過時。"]'),
('8ccf17af-4e7a-46c0-826b-657b84f20989','九華觀看花','張籍','唐','唐诗','tang','','[]','街西無數閑遊處，不似九華仙觀中。',32,'全唐诗/poet.tang.20000.json','["街西無數閑遊處，不似九華仙觀中。", "花裏可憐池上景，幾重墻壁貯春風。"]'),
('fa49873e-d6a9-4a2b-87f0-b9b3fb310b20','贈姚合','張籍','唐','唐诗','tang','','[]','丹鳳城門向曉開，千官相次入朝來。',32,'全唐诗/poet.tang.20000.json','["丹鳳城門向曉開，千官相次入朝來。", "唯君獨走衝塵土，下馬橋邊報直迴。"]'),
('163ddb38-3261-4fbd-acd1-71705cb54341','同韋員外開元觀尋時道士','張籍','唐','唐诗','tang','','[]','觀裏初晴竹樹涼，閑行共到最高房。',32,'全唐诗/poet.tang.20000.json','["觀裏初晴竹樹涼，閑行共到最高房。", "昨來官罷無生計，欲就師求斷穀方。"]'),
('fe71226b-16c1-4d10-9241-ef9b61690cc5','同韓侍御南溪夜賞','張籍','唐','唐诗','tang','','[]','喜作閑人得出城，南溪兩月逐君行。',32,'全唐诗/poet.tang.20000.json','["喜作閑人得出城，南溪兩月逐君行。", "忽聞新命須歸去，一夜船中語到明。"]'),
('ad2e7334-362c-4ba1-bc63-941fff9c1ddf','使行望悟真寺','張籍','唐','唐诗','tang','','[]','採玉峰連佛寺幽，高高斜對驛門樓。',32,'全唐诗/poet.tang.20000.json','["採玉峰連佛寺幽，高高斜對驛門樓。", "無端來去騎官馬，寸步教身不得遊。"]'),
('1da2720d-861f-482d-9931-e61480f4498c','重陽日至峽道','張籍','唐','唐诗','tang','','[]','無限青山行已盡，迴看忽覺遠離家。',32,'全唐诗/poet.tang.20000.json','["無限青山行已盡，迴看忽覺遠離家。", "逢高欲飲重陽酒，山菊今朝未有花。"]'),
('bdca1529-ac5a-4830-a908-e5b1789174c3','贈主客劉郎中','張籍','唐','唐诗','tang','','[]','憶昔君登南省日，老夫猶是褐衣身。',32,'全唐诗/poet.tang.20000.json','["憶昔君登南省日，老夫猶是褐衣身。", "誰知二十餘年後，來作客曹相替人。"]'),
('2d7646fe-985e-4673-a554-61497dd86c8c','同嚴給事聞唐昌觀玉蘂近有仙過因成絕句二首 一','張籍','唐','唐诗','tang','','[]','千枝花裏玉塵飛，阿母宮中見亦稀。',32,'全唐诗/poet.tang.20000.json','["千枝花裏玉塵飛，阿母宮中見亦稀。", "應共諸仙鬬百草，獨來偷得一枝歸。"]'),
('65e884d8-cf9f-4275-ae15-f6063d2eaf63','同嚴給事聞唐昌觀玉蘂近有仙過因成絕句二首 二','張籍','唐','唐诗','tang','','[]','九色雲中紫鳳車，尋仙來到洞仙家。',32,'全唐诗/poet.tang.20000.json','["九色雲中紫鳳車，尋仙來到洞仙家。", "飛輪迴處無踪跡，唯有斑斑滿地花。"]'),
('7191c0c6-7b3a-47cb-9fe6-1ef51857319a','秋思','張籍','唐','唐诗','tang','','["\u79cb\u5929", "\u4e94\u5e74\u7ea7\u4e0a\u518c", "\u601d\u4e61", "\u5c0f\u5b66\u53e4\u8bd7"]','洛陽城裏見秋風，欲作歸書意萬重。',32,'全唐诗/poet.tang.20000.json','["洛陽城裏見秋風，欲作歸書意萬重。", "忽恐匆匆說不盡，行人臨發又開封。"]'),
('4488fc89-5956-4d50-8312-544f7126e8b4','憶遠','張籍','唐','唐诗','tang','','[]','行人猶未有歸期，萬里初程日暮時。',32,'全唐诗/poet.tang.20000.json','["行人猶未有歸期，萬里初程日暮時。", "唯愛門前雙柳樹，枝枝葉葉不相離。"]'),
('1454d2df-ace5-4fce-8b72-1a5cb201b937','玉仙館','張籍','唐','唐诗','tang','','[]','長溪新雨色如泥，野水陰雲盡向西。',32,'全唐诗/poet.tang.20000.json','["長溪新雨色如泥，野水陰雲盡向西。", "楚客天南行漸遠，山山樹裏鷓鴣啼。"]'),
('230fbb94-0120-432a-a422-117f5b69dfbc','寄府吏','張籍','唐','唐诗','tang','','[]','野外尋花共作期，今朝出郭不相隨。',32,'全唐诗/poet.tang.20000.json','["野外尋花共作期，今朝出郭不相隨。", "待君公事有閑日，此地春風應過時。"]'),
('0d7026ad-92ab-4b60-98bb-4543b8253ca0','弟蕭遠雪夜同宿','張籍','唐','唐诗','tang','','[]','數卷新遊蜀客詩，長安僻巷得相隨。',32,'全唐诗/poet.tang.20000.json','["數卷新遊蜀客詩，長安僻巷得相隨。", "草堂雪夜攜琴宿，說是青城館裏時。"]'),
('0d5cfc9c-9522-44de-9c4b-17c73394212a','涼州詞三首 一','張籍','唐','唐诗','tang','','[]','邊城暮雨雁飛低，蘆笋初生漸欲齊。',32,'全唐诗/poet.tang.20000.json','["邊城暮雨雁飛低，蘆笋初生漸欲齊。", "無數鈴聲遙過磧，應馱白練到安西。"]'),
('5743da4b-cc5b-4855-b622-30cd00c34f50','涼州詞三首 二','張籍','唐','唐诗','tang','','[]','古鎮城門白磧開，胡兵往往傍沙堆。',32,'全唐诗/poet.tang.20000.json','["古鎮城門白磧開，胡兵往往傍沙堆。", "巡邊使客行應早，欲問平安無使來。"]'),
('41b2a7ad-b60f-46aa-b9a0-42535c232763','涼州詞三首 三','張籍','唐','唐诗','tang','','["\u8fb9\u5c06", "\u6c34", "\u5199\u666f", "\u8c34\u8d23"]','鳳林關裏水東流，白草黃榆六十秋。',32,'全唐诗/poet.tang.20000.json','["鳳林關裏水東流，白草黃榆六十秋。", "邊將皆承主恩澤，無人解道取涼州。"]'),
('95afc3cc-485b-4b1d-b502-d283840537d2','宮詞 一','張籍','唐','唐诗','tang','','[]','新鷹初放兔猶肥，白日君王在內稀。',32,'全唐诗/poet.tang.20000.json','["新鷹初放兔猶肥，白日君王在內稀。", "薄暮千門臨欲鎖，紅妝飛騎向前歸。"]'),
('ac0ef485-8298-4910-92e3-45c941babf93','宮詞 二','張籍','唐','唐诗','tang','','[]','黃金捍撥紫檀槽，弦索初張調更高。',32,'全唐诗/poet.tang.20000.json','["黃金捍撥紫檀槽，弦索初張調更高。", "盡理昨來新上曲，內官簾外送櫻桃。"]'),
('40de74da-142d-4202-8d42-6538736cd361','華清宮','張籍','唐','唐诗','tang','','[]','溫泉流入漢離宮，宮樹行行浴殿空。',32,'全唐诗/poet.tang.20000.json','["溫泉流入漢離宮，宮樹行行浴殿空。", "武帝時人今欲盡，青山空閉御墻中。"]'),
('d60258ad-0f56-472e-b6f1-eae37b98766d','崔駙馬養鶴','張籍','唐','唐诗','tang','','[]','身閑無事稱高情，已有人間章句名。',32,'全唐诗/poet.tang.20000.json','["身閑無事稱高情，已有人間章句名。", "求得鶴來教翦翅，望仙臺下亦將行。"]'),
('e7818efd-615f-4df7-bd23-3cfefcba3cdc','閑遊','張籍','唐','唐诗','tang','','[]','老身不計人間事，野寺秋晴每獨過。',32,'全唐诗/poet.tang.20000.json','["老身不計人間事，野寺秋晴每獨過。", "病眼校來猶斷酒，却嫌行處菊花多。"]'),
('36f49c2a-a1fd-4807-8073-506b7e1e75c9','劉兵曹贈酒','張籍','唐','唐诗','tang','','[]','一缾顏色似甘泉，閑向新栽小竹前。',32,'全唐诗/poet.tang.20000.json','["一缾顏色似甘泉，閑向新栽小竹前。", "飲罷身中更無事，移牀獨就夕陽眠。"]'),
('4c4cde49-4616-4258-b780-f8ac5f8a8627','送梧州王使君','張籍','唐','唐诗','tang','','[]','楚江亭上秋風起，看發蒼梧太守船。',32,'全唐诗/poet.tang.20000.json','["楚江亭上秋風起，看發蒼梧太守船。", "千里同行從此別，相逢又隔幾多年。"]'),
('ce70861d-2ec3-4224-a989-c20b98b7c2c9','春日早朝','張籍','唐','唐诗','tang','','[]','曉陌春寒朝騎來，瑞雲深處見樓臺。',32,'全唐诗/poet.tang.20000.json','["曉陌春寒朝騎來，瑞雲深處見樓臺。", "夜來新雨沙堤濕，東上閤門應未開。"]'),
('037c9bcb-a457-4c3d-b359-048dda1f23bc','寄朱闞二山人','張籍','唐','唐诗','tang','','[]','爲箇朝章束此身，眼看東路去無因。',32,'全唐诗/poet.tang.20000.json','["爲箇朝章束此身，眼看東路去無因。", "歷陽舊客今應少，轉憶鄰家二老人。"]'),
('6e074a5f-78d4-4d05-a248-c872831c493e','寄李渤','張籍','唐','唐诗','tang','','[]','五度溪頭躑躅紅，嵩陽寺裏講時鐘。',32,'全唐诗/poet.tang.20000.json','["五度溪頭躑躅紅，嵩陽寺裏講時鐘。", "春山處處行應好，一月看花到幾峰。"]'),
('2f0e76c3-fa01-4082-b01c-3a1193ff7e06','尋仙','張籍','唐','唐诗','tang','','[]','溪頭一徑入青崖，處處仙居隔杏花。',32,'全唐诗/poet.tang.20000.json','["溪頭一徑入青崖，處處仙居隔杏花。", "更見峰西幽客說，雲中猶有兩三家。"]'),
('2742f3ef-4b79-44df-878f-bd61b8ff829c','同白侍郎杏園贈劉郎中','張籍','唐','唐诗','tang','','[]','一去瀟湘頭欲白，今朝始見杏花春。',32,'全唐诗/poet.tang.20000.json','["一去瀟湘頭欲白，今朝始見杏花春。", "從來遷客應無數，重到花前有幾人。"]'),
('c0cbb0bd-9129-48c9-aef6-c116139328cc','答鄱陽客藥名詩','張籍','唐','唐诗','tang','','[]','江臯歲暮相逢地，黃葉霜前半夏枝。',32,'全唐诗/poet.tang.20000.json','["江臯歲暮相逢地，黃葉霜前半夏枝。", "子夜吟詩向松桂，心中萬事喜君知。"]'),
('9c5a58a3-f22f-47e5-b9e5-02d48242cbf9','寄宋景','張籍','唐','唐诗','tang','','[]','詔發官兵取亂臣，將軍弓箭不離身。',32,'全唐诗/poet.tang.20000.json','["詔發官兵取亂臣，將軍弓箭不離身。", "今君獨在征東府，莫遣功名屬別人。"]'),
('afb264e3-d77f-4320-8a74-99504f66893a','寄王侍御','張籍','唐','唐诗','tang','','[]','愛君紫閣峰前好，新作書堂藥竈成。',32,'全唐诗/poet.tang.20000.json','["愛君紫閣峰前好，新作書堂藥竈成。", "見欲移居相近住，有田多與種黃精。"]'),
('ec0d936d-5d2c-4923-92df-40f89286341c','題渭北寺上方','張籍','唐','唐诗','tang','','[]','昔祭郊壇今謁陵，寺中高處最來登。',32,'全唐诗/poet.tang.20000.json','["昔祭郊壇今謁陵，寺中高處最來登。", "十餘年後人多別，喜見當時轉讀僧。"]'),
('555ea1b6-606e-4ff9-80f2-d1d1daf76166','閑遊','張籍','唐','唐诗','tang','','[]','終日不離塵土間，若爲能見此身閑。',32,'全唐诗/poet.tang.20000.json','["終日不離塵土間，若爲能見此身閑。", "今朝暫共遊僧語，更恨趨時別舊山。"]'),
('6e79f014-6170-4b01-b3cb-c6044a6a989a','倡女詞','張籍','唐','唐诗','tang','','[]','輕鬢叢梳闊掃眉，爲嫌風日下樓稀。',32,'全唐诗/poet.tang.20000.json','["輕鬢叢梳闊掃眉，爲嫌風日下樓稀。", "畫羅金縷難相稱，故著尋常淡薄衣。"]'),
('2a15c396-5516-4577-958b-53df6a5b5bd2','答元八遺紗帽','張籍','唐','唐诗','tang','','[]','黑紗方帽君邊得，稱對山前坐竹牀。',32,'全唐诗/poet.tang.20000.json','["黑紗方帽君邊得，稱對山前坐竹牀。", "唯恐被人偷剪樣，不曾閑戴出書堂。"]'),
('69245aca-a305-47b1-9fb5-79c1302ce84e','題僧院','張籍','唐','唐诗','tang','','[]','聞師行講青龍疏，本寺住來多少年。',32,'全唐诗/poet.tang.20000.json','["聞師行講青龍疏，本寺住來多少年。", "靜掃空房唯獨坐，千莖秋竹在簷前。"]'),
('65d0527b-5364-47a7-976b-dd87c9997d71','送元八','張籍','唐','唐诗','tang','','[]','百神齋祭相隨徧，尋竹看山亦共行。',32,'全唐诗/poet.tang.20000.json','["百神齋祭相隨徧，尋竹看山亦共行。", "明日城西送君去，舊遊重到獨題名。"]'),
('4ddfd5e0-60cd-4227-b9fe-fc44ebf1bbde','吳楚歌詞','張籍','唐','唐诗','tang','','[]','庭前春鳥啄林聲，紅夾羅襦縫未成。',32,'全唐诗/poet.tang.20000.json','["庭前春鳥啄林聲，紅夾羅襦縫未成。", "今朝社日停針線，起向朱櫻樹下行。"]'),
('a7a3efde-7272-4f8c-a71a-9ae10f8d1e35','題方睦上人月臺觀','張籍','唐','唐诗','tang','','[]','一身清淨無童子，獨坐空堂得幾年。',32,'全唐诗/poet.tang.20000.json','["一身清淨無童子，獨坐空堂得幾年。", "每夜焚香通月觀，可鄰光影最團圓。"]'),
('2ee1fe66-9b60-4913-81e0-1df1f3ea8f01','華山廟','張籍','唐','唐诗','tang','','[]','金天廟下西京道，巫女紛紛走似煙。',32,'全唐诗/poet.tang.20000.json','["金天廟下西京道，巫女紛紛走似煙。", "手把紙錢迎過客，遣求恩福到神前。"]'),
('aa48fb92-fea1-4a20-8fca-3e9559f217bf','病中酬元宗簡','張籍','唐','唐诗','tang','','[]','東風漸暖滿城春，獨占幽居養病身。',32,'全唐诗/poet.tang.20000.json','["東風漸暖滿城春，獨占幽居養病身。", "莫說櫻桃花已發，今年不作看花人。"]'),
('8f80bc0e-6754-4b32-86a7-c1bd53306e8d','寺宿齋','張籍','唐','唐诗','tang','','[]','晚到金光門外寺，寺中新竹隔簾多。',32,'全唐诗/poet.tang.20000.json','["晚到金光門外寺，寺中新竹隔簾多。", "齋官禁與僧相見，院院開門不得過。"]'),
('4ede77c0-4b3e-46d1-b196-bf7894fb10b9','贈施肩吾','張籍','唐','唐诗','tang','','[]','世間漸覺無多事，雖有空名未著身。',32,'全唐诗/poet.tang.20000.json','["世間漸覺無多事，雖有空名未著身。", "合取藥成相待喫，不須先作上天人。"]'),
('b5d817cf-5bc3-489c-a7a0-3c8579c679bd','贈王建','張籍','唐','唐诗','tang','','[]','白君去後交遊少，東野亡來篋笥貧。',32,'全唐诗/poet.tang.20000.json','["白君去後交遊少，東野亡來篋笥貧。", "賴有白頭王建在，眼前猶見詠詩人。"]'),
('b2a58a7a-bed8-4d97-9c8f-7632cd235987','逢賈島','張籍','唐','唐诗','tang','','[]','僧房逢着欵冬花，出寺行吟日已斜。',32,'全唐诗/poet.tang.20000.json','["僧房逢着欵冬花，出寺行吟日已斜。", "十二街中春雪遍，馬蹄今去入誰家。"]'),
('042adab4-fd33-403a-81fb-9facc9416757','山中酬人','張籍','唐','唐诗','tang','','[]','山中日暖春鳩鳴，逐水看花任意行。',32,'全唐诗/poet.tang.20000.json','["山中日暖春鳩鳴，逐水看花任意行。", "向晚歸來石窗下，菖蒲葉上見題名。"]'),
('02e21292-cdf8-45b7-b793-e4dc228be4fa','弱栢院僧影堂','張籍','唐','唐诗','tang','','[]','弱栢倒垂如線蔓，簷頭不見有枝柯。',32,'全唐诗/poet.tang.20000.json','["弱栢倒垂如線蔓，簷頭不見有枝柯。", "影堂香火長相續，應得人來禮拜多。"]'),
('e979ddc0-7d65-46c3-bb3a-10a65869481c','題故僧影堂','張籍','唐','唐诗','tang','','[]','香消雲鎖舊僧家，僧剎殘形半壁斜。',32,'全唐诗/poet.tang.20000.json','["香消雲鎖舊僧家，僧剎殘形半壁斜。", "日暮松煙寒漠漠，秋風吹破紙蓮花。"]'),
('dc2356f0-cb33-4b72-8cd1-6d45df9976a3','無題','張籍','唐','唐诗','tang','','[]','桃溪柳陌好經過，燈下妝成月下歌。',32,'全唐诗/poet.tang.20000.json','["桃溪柳陌好經過，燈下妝成月下歌。", "爲是襄王故宮地，至今猶有細腰多。"]'),
('437d4117-56b3-48e0-ac38-a24e4b01a0a4','山禽','張籍','唐','唐诗','tang','','[]','山禽毛如白練帶，栖我庭前栗樹枝。',32,'全唐诗/poet.tang.20000.json','["山禽毛如白練帶，栖我庭前栗樹枝。", "獮猴半夜來取栗，一雙中林向月飛。"]'),
('7b1e24a6-7cad-411b-8da6-e8e77713a608','秋山','張籍','唐','唐诗','tang','','[]','秋山無雲復無風，溪頭看月出深松。',32,'全唐诗/poet.tang.20000.json','["秋山無雲復無風，溪頭看月出深松。", "草堂不閉石牀靜，葉間墜露聲重重。"]'),
('31e6512c-2261-4dfa-9963-7c5fa2bb2f10','玉真觀','張籍','唐','唐诗','tang','','[]','臺殿曾爲貴主家，春風吹盡竹窗紗。',32,'全唐诗/poet.tang.20000.json','["臺殿曾爲貴主家，春風吹盡竹窗紗。", "院中仙女脩香火，不許閑人入看花。"]'),
('40dbacae-77ed-446d-bd71-8d917ceac572','蠻中','張籍','唐','唐诗','tang','','[]','銅柱南邊毒草春，行人幾日到金麟。',32,'全唐诗/poet.tang.20000.json','["銅柱南邊毒草春，行人幾日到金麟。", "玉鐶穿耳誰家女，自抱琵琶迎海神。"]'),
('e87c9c65-0c5b-4f40-9d65-051899546e23','贈道士','張籍','唐','唐诗','tang','','[]','茅山近別剡溪逢，玉節青旄十二重。',32,'全唐诗/poet.tang.20000.json','["茅山近別剡溪逢，玉節青旄十二重。", "自說年年上天去，羅浮最近海邊峰。"]'),
('f69298b8-1c08-4839-9f42-e38104f153ec','重平驛作','張籍','唐','唐诗','tang','','[]','茫茫菰草平如地，渺渺長堤曲似城。',32,'全唐诗/poet.tang.20000.json','["茫茫菰草平如地，渺渺長堤曲似城。", "日暮未知投宿處，逢人更問向前程。"]'),
('89d241bf-37ef-4ce6-9230-1354cb508faa','宿天竺寺寄靈隱寺僧','張籍','唐','唐诗','tang','','[]','夜向靈溪息此身，風泉竹露淨衣塵。',32,'全唐诗/poet.tang.20000.json','["夜向靈溪息此身，風泉竹露淨衣塵。", "月明石上堪同宿，那作山南山北人。"]'),
('98737665-5fb0-4215-95cf-2c90cb4fb547','酬朱慶餘','張籍','唐','唐诗','tang','','[]','越女新妝出鏡心，自知明豔更沈吟。',32,'全唐诗/poet.tang.20000.json','["越女新妝出鏡心，自知明豔更沈吟。", "齊紈未是人間貴，一曲菱歌敵萬金。"]'),
('c806e007-141f-442e-8578-8bb9833a58f4','寒食憶歸','張籍','唐','唐诗','tang','','[]','京中曹局無多事，寒食貧兒要在家。',32,'全唐诗/poet.tang.20000.json','["京中曹局無多事，寒食貧兒要在家。", "遮莫杏園勝別處，亦須歸看傍村花。"]'),
('e2ed217a-8573-490c-b436-71d4a23f99a8','寒食','張籍','唐','唐诗','tang','','[]','綠楊枝上五絲繩，枝弱春多欲不勝。',32,'全唐诗/poet.tang.20000.json','["綠楊枝上五絲繩，枝弱春多欲不勝。", "唯有一年寒食日，女郎相喚擺階𤺩。"]'),
('8f331687-0d39-43b8-b6e2-eb2cab965ff9','賦花','張籍','唐','唐诗','tang','','[]','花，花。',70,'全唐诗/poet.tang.20000.json','["花，花。", "落早，開賒。", "對酒客，興詩家。", "能迴遊騎，每駐行車。", "宛宛清風起，茸茸麗日斜。", "且願相留懽洽，惟愁虛棄光華。", "明年攀折知不遠，對此誰能更歎嗟。"]'),
('817fe88c-137c-45fc-95e3-73f6baabe907','句','張籍','唐','唐诗','tang','','[]','韓公國大賢，道德赫已聞。',48,'全唐诗/poet.tang.20000.json','["韓公國大賢，道德赫已聞。", "時出爲陽山，爾區來趨奔。", "韓官遷掾曹，子隨至荆門。", "韓入爲博士，崎嶇送歸輪。"]'),
('eaf1094e-b116-4d91-819b-df1a80e1c991','月蝕詩','盧仝','唐','唐诗','tang','','[]','新天子即位五年，歲次庚寅。',311,'全唐诗/poet.tang.20000.json','["新天子即位五年，歲次庚寅。", "斗柄插子，律調黃鐘。", "森森萬木夜殭立，寒氣贔屭頑無風。", "爛銀盤從海底出，出來照我草屋東。", "天色紺滑凝不流，冰光交貫寒朣朧。", "初疑白蓮花，浮出龍王宮。", "八月十五夜，比並不可雙。", "此時怪事發，有物吞食來。", "輪如壯士斧斫壞，桂似雪山風拉摧。", "百鍊鏡，照見膽。", "平地埋寒灰，火龍珠。", "飛出腦，却入蚌蛤胎。", "摧環破璧眼看盡，當天一搭如煤炲。", "磨蹤滅跡須臾間，便似萬古不可開。", "不料至神物，有此大狼狽。", "星如撒沙出，爭頭事光大。", "奴婢炷暗燈，揜菼如玳瑁。", "今夜吐燄長如虹，孔隙千道射戶外。", "玉川子，涕泗下。", "中庭獨自行，念此日月者。", "太陰太陽精，皇天要識物。", "日月乃化生，走天汲汲勞四體。", "與天作眼行光明，此眼不自保。", "天公行道何由行，吾見陰陽家有說。"]'),
('7fb73d6d-2a39-466f-959b-5bfb91c87fd7','哭玉碑子','盧仝','唐','唐诗','tang','','[]','山有洞左頰，拾得玉碑子。',288,'全唐诗/poet.tang.20000.json','["山有洞左頰，拾得玉碑子。", "其長一周尺，其闊一藥匕。", "顏色九秋天，稜角四面起。", "輕敲吐寒流，清悲動神鬼。", "稽首置手中，只似一片水。", "至文反無文，上帝應有以。", "予疑仙石靈，願以仙人比。", "心期香湯洗，歸送籙堂裏。", "頗奈窮相驢，行動如跛鼈。", "十里五里行，百蹶復千蹶。", "顏子不少夭，玉碑中路折。", "橫文尋龜兆，直理任瓦裂。", "劈竹不可合，破環永離別。", "向人如有情，似痛滴無血。", "勘鬬平地上，罅坼多齧缺。", "百見百傷心，不堪再提挈。", "怪哉堅貞姿，忽脃不堅固。", "矧曰人間人，安能保常度。", "敢問生物成，敗爲有真素。", "爲稟靈異氣，不得受穢汚。", "驢罪真不厚，驢生亦錯誤。", "更將前前行，復恐山神怒。", "白雲蓊閉嶺，高松吟古墓。", "置此忍其傷，驅驢下山路。"]'),
('d746a56b-a083-4549-b107-30764a8726b2','觀放魚歌','盧仝','唐','唐诗','tang','','[]','常州賢刺史，從諫議大夫除。',302,'全唐诗/poet.tang.20000.json','["常州賢刺史，從諫議大夫除。", "天地好生物，刺史性與天地俱。", "見山客，狎魚鳥。", "坐山客，北亭湖。", "命舟人，駕舫子。", "漾漾菰蒲，酒興引行處。", "正見漁人魚，刺史密會山客意。", "復念網羅嬰無辜，忽脫身上殷緋袍。", "盡買罟擭盡有無，鰻鱣鲇鱧鰌。", "涎惡最頑愚，鱒舫見豳風。", "質幹稍高流，時白噴雪鯽鯉𦛇。", "此輩肥脃爲絕尤，老鯉變化頗神異。", "三十六鱗如抹朱，水苞弘窟有蛟鼉。", "餌非龍餌唯無鱸，叢雜百千頭。", "性命懸須臾，天心應刺史。", "刺史盡活諸，一一投深泉。", "跳脫不復拘，得水競騰突。", "動作詭怪殊，或透藻而出。", "或破浪而趨，或掉尾孑孑。", "或奮鬣愉愉，或如鶯擲梭。", "或如虵銜珠，四散漸不見。", "島嶼徒縈紆，鸂鶒鴒鷗鳧。", "喜觀爭呌呼，小蝦亦相慶。", "繞岸搖其鬚，乃知貪生不獨頑癡夫。"]'),
('8a1736c7-f4b2-40ac-b7cd-e5ad31ba8794','示添丁','盧仝','唐','唐诗','tang','','[]','春風苦不仁，呼逐馬蹄行人家。',130,'全唐诗/poet.tang.20000.json','["春風苦不仁，呼逐馬蹄行人家。", "慚愧瘴氣却憐我，入我憔悴骨中爲生涯。", "數日不食強強行，何忍索我抱看滿樹花。", "不知四體正困𢞎，泥人啼哭聲呀呀。", "忽來案上翻墨汁，塗抹詩書如老鵶。", "父憐母惜摑不得，却生癡笑令人嗟。", "宿舂連曉不成米，日高始進一椀茶。", "氣力龍鍾頭欲白，憑仗添丁莫惱爺。"]'),
('8b36420a-c7bd-412f-b5ae-34b845d79afc','寄男抱孫','盧仝','唐','唐诗','tang','','[]','別來三得書，書道違離久。',288,'全唐诗/poet.tang.20000.json','["別來三得書，書道違離久。", "書處甚麤殺，且喜見汝手。", "殷十七又報，汝文頗新有。", "別來纔經年，囊盎未合斗。", "當是汝母賢，日夕加訓誘。", "尚書當畢功，禮記速須剖。", "嘍囉兒讀書，何異摧枯朽。", "尋義低作聲，便可養年壽。", "莫學村學生，麤氣強呌吼。", "下學偷功夫，新宅鋤䔧莠。", "乘涼勸奴婢，園裏耨葱韭。", "遠籬編榆棘，近眼栽桃柳。", "引水灌竹中，蒲池種蓮藕。", "撈漉蛙𢋙脚，莫遣生科斗。", "竹林吾最惜，新筍好看守。", "萬籜苞龍兒，攢迸溢林藪。", "吾眼恨不見，心腸痛如搊。", "宅錢都未還，債利日日厚。", "籜龍正稱冤，莫殺入汝口。", "丁寧囑託汝，汝活籜龍不。", "殷十七老儒，是汝父師友。", "傳讀有疑悞，輙告諮問取。", "兩手莫破拳，一吻莫飲酒。", "莫學捕鳩鴿，莫學打雞狗。"]'),
('022d23cb-86f8-444d-8d79-be5ab78ae495','自詠三首 一','盧仝','唐','唐诗','tang','','[]','爲報玉川子，知君未是賢。',48,'全唐诗/poet.tang.20000.json','["爲報玉川子，知君未是賢。", "低頭雖有地，仰面輙無天。", "骨肉清成瘦，萵蔓老覺羶。", "家書與心事，相伴過流年。"]'),
('490f56b2-c972-4c28-a4d2-0af9e7aa7b68','自詠三首 二','盧仝','唐','唐诗','tang','','[]','盧子躘踵也，賢愚總莫驚。',48,'全唐诗/poet.tang.20000.json','["盧子躘踵也，賢愚總莫驚。", "蚊蝱當家口，草石是親情。", "萬卷堆胸朽，三光撮眼明。", "翻悲廣成子，閑氣說長生。"]'),
('2d6d2bfe-caa5-421f-901e-d1d8a2b3a0d7','自詠三首 三','盧仝','唐','唐诗','tang','','[]','物外無知己，人間一癖王。',48,'全唐诗/poet.tang.20000.json','["物外無知己，人間一癖王。", "生涯身是夢，耽樂酒爲鄉。", "日月黏髭鬚，雲山鎖肺腸。", "愚公只公是，不用謾驚張。"]'),
('4b58760b-e78a-4364-abca-7d70d797939d','送王儲詹事西遊獻兵書','盧仝','唐','唐诗','tang','','[]','美酒撥醅酌，楊花飛盡時。',72,'全唐诗/poet.tang.20000.json','["美酒撥醅酌，楊花飛盡時。", "落日長安道，方寸無人知。", "篋中制勝術，氣雄屈指筭。", "半醉千殷勤，仰天一長歎。", "玉匣百鍊劒，龜文又龍吼。", "抽贈王將軍，勿使虛白首。"]'),
('99332531-4755-4c27-9e58-f8edb49a47c1','送邵兵曹歸江南','盧仝','唐','唐诗','tang','','[]','春風楊柳陌，連騎醉離觴。',48,'全唐诗/poet.tang.20000.json','["春風楊柳陌，連騎醉離觴。", "千里遠山碧，一條歸路長。", "花開愁北渚，雲去渡南湘。", "東望濛濛處，煙波是故鄉。"]'),
('52bb4abd-fd0d-4c83-8966-98c4fdbcba34','寄外兄魏澈','盧仝','唐','唐诗','tang','','[]','何處堪惆悵，情親不得親。',24,'全唐诗/poet.tang.20000.json','["何處堪惆悵，情親不得親。", "興寧樓上月，辜負酒家春。"]'),
('20f73524-3069-43f0-8dbf-bd18fd1ac51f','喜逢鄭三遊山','盧仝','唐','唐诗','tang','','[]','相逢之處花茸茸，石壁攢峰千萬重。',32,'全唐诗/poet.tang.20000.json','["相逢之處花茸茸，石壁攢峰千萬重。", "他日期君何處好，寒流石上一株松。"]'),
('2a428197-24d7-49a5-9fed-7cd545ef45af','卓女怨','盧仝','唐','唐诗','tang','','[]','妾本懷春女，春愁不自任。',48,'全唐诗/poet.tang.20000.json','["妾本懷春女，春愁不自任。", "迷魂隨鳳客，嬌思入琴心。", "託援交情重，當壚酌意深。", "誰家有夫壻，作賦得黃金。"]'),
('16677134-de54-4cf8-84bc-4322f7aa47c0','守歲二首 一','盧仝','唐','唐诗','tang','','[]','去年留不住，年來也任他。',24,'全唐诗/poet.tang.20000.json','["去年留不住，年來也任他。", "當壚一榼酒，爭奈兩年何。"]'),
('5e5b0860-39b1-46ee-aa71-d772bd24bbc5','守歲二首 二','盧仝','唐','唐诗','tang','','[]','老來經節臘，樂事甚悠悠。',24,'全唐诗/poet.tang.20000.json','["老來經節臘，樂事甚悠悠。", "不及兒童日，都盧不解愁。"]'),
('848eba6c-b222-4d42-92c5-c40f4d9fc35d','新月','盧仝','唐','唐诗','tang','','[]','仙宮雲箔卷，露出玉簾鉤。',24,'全唐诗/poet.tang.20000.json','["仙宮雲箔卷，露出玉簾鉤。", "清光無所贈，相憶鳳皇樓。"]'),
('8251441b-49cc-4e10-a2b7-04f29a180df3','解悶','盧仝','唐','唐诗','tang','','[]','人生都幾日，一半是離憂。',24,'全唐诗/poet.tang.20000.json','["人生都幾日，一半是離憂。", "但有尊中物，從他萬事休。"]'),
('fcd6c448-bd3c-43dd-bdde-066f63af4013','楊子津','盧仝','唐','唐诗','tang','','[]','風卷魚龍暗楚關，白波沈却海門山。',32,'全唐诗/poet.tang.20000.json','["風卷魚龍暗楚關，白波沈却海門山。", "鵬騰鼇倒且快性，地坼天開總是閑。"]'),
('920bb4e9-69cb-4226-a45c-04ba744e19c3','人日立春','盧仝','唐','唐诗','tang','','[]','春度春歸無限春，今朝方始覺成人。',32,'全唐诗/poet.tang.20000.json','["春度春歸無限春，今朝方始覺成人。", "從今尅己應猶及，顏與梅花俱自新。"]'),
('4f414cae-e8ad-4929-b0db-72336a855944','送尉遲羽之歸宣州','盧仝','唐','唐诗','tang','','[]','君歸呼，君歸興不孤。',26,'全唐诗/poet.tang.20000.json','["君歸呼，君歸興不孤。", "謝朓澄江今夜月，也應憶著此山夫。"]'),
('0b675645-500d-44b9-a70d-0bee63b0f7aa','悲新年','盧仝','唐','唐诗','tang','','[]','新年何事最堪悲，病客遙聽百舌兒。',32,'全唐诗/poet.tang.20000.json','["新年何事最堪悲，病客遙聽百舌兒。", "太歲只遊桃李徑，春風肯管歲寒枝。"]'),
('d46a47e0-dacf-4ae3-ae54-69db477abb28','憶酒寄劉侍郎','盧仝','唐','唐诗','tang','','[]','愛酒如偷蜜，憎醒似見刀。',24,'全唐诗/poet.tang.20000.json','["愛酒如偷蜜，憎醒似見刀。", "君爲麯糵主，酒醴莫辭勞。"]'),
('8b3dfcbb-be3e-4168-8e5f-19ce1e5fac80','白鷺鷥','盧仝','唐','唐诗','tang','','[]','刻成片玉白鷺鷥，欲捉纖鱗心自急。',32,'全唐诗/poet.tang.20000.json','["刻成片玉白鷺鷥，欲捉纖鱗心自急。", "翹足沙頭不得時，傍人不知謂閑立。"]'),
('03f8a03b-c23c-49bc-8ee1-50de17d40c23','風中琴','盧仝','唐','唐诗','tang','','[]','五音六律十三徽，龍吟鶴響思庖羲。',32,'全唐诗/poet.tang.20000.json','["五音六律十三徽，龍吟鶴響思庖羲。", "一彈流水一彈月，水月風生松樹枝。"]'),
('f548c1e1-4ec6-450e-8a5e-bf7f91fa1248','感秋別怨','盧仝','唐','唐诗','tang','','[]','霜秋自斷魂，楚調怨離分。',48,'全唐诗/poet.tang.20000.json','["霜秋自斷魂，楚調怨離分。", "魄散瑤臺月，心隨巫峽雲。", "蛾眉誰共畫，鳳曲不同聞。", "莫似湘妃淚，斑斑點翠裙。"]'),
('174ab978-0f84-4865-957e-80d9f1a346d7','新蟬','盧仝','唐','唐诗','tang','','[]','泉溜潛幽咽，琴鳴乍往還。',24,'全唐诗/poet.tang.20000.json','["泉溜潛幽咽，琴鳴乍往還。", "長風翦不斷，還在樹枝間。"]'),
('755f9536-506a-47a2-a6bf-f83de74da4e8','題褚遂良孫庭竹','盧仝','唐','唐诗','tang','','[]','負霜停雪舊根枝，龍笙鳳管君莫截。',32,'全唐诗/poet.tang.20000.json','["負霜停雪舊根枝，龍笙鳳管君莫截。", "春風一番琴上來，搖碎金尊碧天月。"]'),
('e121d784-e855-4bc0-b69f-342c12d3e93d','訪含曦上人','盧仝','唐','唐诗','tang','','[]','三入寺，曦未來。',24,'全唐诗/poet.tang.20000.json','["三入寺，曦未來。", "轆轤無人井百尺，渴心歸去生塵埃。"]'),
('070f7ff7-71cb-4969-b3b5-d138eaaddfed','客淮南病','盧仝','唐','唐诗','tang','','[]','揚州蒸毒似燂湯，客病清枯鬢欲霜。',32,'全唐诗/poet.tang.20000.json','["揚州蒸毒似燂湯，客病清枯鬢欲霜。", "且喜閉門無俗物，四肢安穩一張牀。"]'),
('0a2ac536-d749-4430-b92c-aa82369da683','村醉','盧仝','唐','唐诗','tang','','[]','昨夜村飲歸，健倒三四五。',24,'全唐诗/poet.tang.20000.json','["昨夜村飲歸，健倒三四五。", "摩挲青莓苔，莫嗔驚著汝。"]'),
('da7785f1-3aaa-4274-a55a-da81028024df','村醉','盧仝','唐','唐诗','tang','','[]','村醉黄昏歸，健倒三四五。',24,'全唐诗/poet.tang.20000.json','["村醉黄昏歸，健倒三四五。", "摩娑莓苔背，嗔我驚爾不。"]'),
('59e3f594-bbfb-4574-ab2e-69b415d8468c','蕭宅二三子贈答詩二十首 客贈石','盧仝','唐','唐诗','tang','','[]','竹下青莎中，細長三四片。',24,'全唐诗/poet.tang.20000.json','["竹下青莎中，細長三四片。", "主人雖不歸，長見主人面。"]'),
('1d3be722-0840-4501-a2f8-d9c13878355d','蕭宅二三子贈答詩二十首 石讓竹','盧仝','唐','唐诗','tang','','[]','自顧撥不轉，何敢當主人。',24,'全唐诗/poet.tang.20000.json','["自顧撥不轉，何敢當主人。", "竹弟有清風，可以娛嘉賓。"]'),
('a1199d7f-9101-4e0e-9498-072a9bdee1d2','蕭宅二三子贈答詩二十首 竹荅客','盧仝','唐','唐诗','tang','','[]','竹弟謝石兄，清風非所任。',24,'全唐诗/poet.tang.20000.json','["竹弟謝石兄，清風非所任。", "隨分有蕭瑟，實無堅重心。"]'),
('7bb357ff-c3f3-43bb-ba83-43ac708f5a44','蕭宅二三子贈答詩二十首 石請客','盧仝','唐','唐诗','tang','','[]','竹弟雖讓客，不敢當客恩。',24,'全唐诗/poet.tang.20000.json','["竹弟雖讓客，不敢當客恩。", "自慙埋沒久，滿面蒼苔痕。"]'),
('c1177d8e-a46f-48f9-b280-bc2b6179f59e','蕭宅二三子贈答詩二十首 客荅石','盧仝','唐','唐诗','tang','','[]','遍索天地間，彼此最癡癖。',24,'全唐诗/poet.tang.20000.json','["遍索天地間，彼此最癡癖。", "主人幸未來，與君爲莫逆。"]'),
('769a722c-3e1e-4b9a-adee-e6592eaa96c7','蕭宅二三子贈答詩二十首 石荅竹','盧仝','唐','唐诗','tang','','[]','石報孤竹君，此客甚高調。',114,'全唐诗/poet.tang.20000.json','["石報孤竹君，此客甚高調。", "共我相共癡，不怕主人天下笑。", "我非蛺蝶兒，我非桃李枝。", "不要兒女撲，不要春風吹。", "苔蘚印我面，雨露皴我皮。", "此故不嫌我，突兀蒙相知。", "此客即西歸，我心徒依依。", "我欲隨客去，累重不解飛。", "知弟虛心亦待客，此客何以共報之。"]'),
('8e8e6eed-cb19-49b2-979a-ec1d3a0e3729','蕭宅二三子贈答詩二十首 竹請客','盧仝','唐','唐诗','tang','','["\u6cf0\u5c71"]','我本泰山阿，避地到南國。',48,'全唐诗/poet.tang.20000.json','["我本泰山阿，避地到南國。", "主人欲移家，我亦要歸北。", "上客幸先歸，願託歸飛翼。", "唯將翛翛風，累路報恩德。"]'),
('a2ad5a4a-4de4-4f9e-85d3-7147996b9b11','蕭宅二三子贈答詩二十首 客謝竹','盧仝','唐','唐诗','tang','','[]','揚州駮雜地，不辨龍𧈼蜴。',48,'全唐诗/poet.tang.20000.json','["揚州駮雜地，不辨龍𧈼蜴。", "客身正乾枯，行處無膏澤。", "太山道不遠，相庇實無力。", "君若隨我行，必有煎茶厄。"]'),
('ebe156b5-edc2-4eb7-8537-c6c694e1c02b','蕭宅二三子贈答詩二十首 石請客','盧仝','唐','唐诗','tang','','[]','啓母是諸母，三十六峰是諸父。',62,'全唐诗/poet.tang.20000.json','["啓母是諸母，三十六峰是諸父。", "知君家近父母家，小人安得不懷土。", "憐君與我金石交，君歸可得共載否。", "小人無以報君恩，使君池亭風月古。"]'),
('1fecc3a7-92f6-42d1-9dca-1a82a0f1cee4','蕭宅二三子贈答詩二十首 客謝石','盧仝','唐','唐诗','tang','','[]','我有水竹莊，甚近嵩之巔。',48,'全唐诗/poet.tang.20000.json','["我有水竹莊，甚近嵩之巔。", "是君歸休處，可以終天年。", "雖有提攜勞，不憂糧食錢。", "但恐主人心，疑我相釣竿。"]'),
('5a26f6d1-4f79-4ee4-ae75-7c4d32ffd227','蕭宅二三子贈答詩二十首 石再請客','盧仝','唐','唐诗','tang','','[]','主人若知我，應喜我結得君。',51,'全唐诗/poet.tang.20000.json','["主人若知我，應喜我結得君。", "主人不知我，我住何求于主人。", "我在天地間，自是一片物。", "可得杠壓我，使我頭不出。"]'),
('f905ae5b-7950-494f-88b4-44b5d4041f2c','蕭宅二三子贈答詩二十首 客許石','盧仝','唐','唐诗','tang','','[]','石公說道理，句句出凡格。',48,'全唐诗/poet.tang.20000.json','["石公說道理，句句出凡格。", "相知貴知心，豈恨主爲客。", "過須歸去來，旦晚上無厄。", "主人誠賢人，多應不相責。"]'),
('705f9582-c56d-4641-80a7-e1c8638d9649','蕭宅二三子贈答詩二十首 井請客','盧仝','唐','唐诗','tang','','[]','我生天地間，頗是往還數。',48,'全唐诗/poet.tang.20000.json','["我生天地間，頗是往還數。", "已効炊爨勞，我亦不願住。", "君有造化力，在君一降顧。", "我願拔黃泉，輕舉隨君去。"]'),
('2f1d3111-022a-4153-9476-1a1356ca575e','蕭宅二三子贈答詩二十首 客謝井','盧仝','唐','唐诗','tang','','[]','改邑不改井，此是井卦辭。',48,'全唐诗/poet.tang.20000.json','["改邑不改井，此是井卦辭。", "井公莫怪驚，說我成憨癡。", "我縱有神力，爭敢將公歸。", "揚州惡百姓，疑我卷地皮。"]'),
('6a8d087c-afdb-4acd-9ef0-e670f627b0b7','蕭宅二三子贈答詩二十首 馬蘭請客','盧仝','唐','唐诗','tang','','[]','蘭蘭是小草，不怕郎君駡。',24,'全唐诗/poet.tang.20000.json','["蘭蘭是小草，不怕郎君駡。", "願得隨君行，暫到嵩山下。"]'),
('e610c414-386a-433d-98d3-f8ac508574ec','蕭宅二三子贈答詩二十首 客請馬蘭','盧仝','唐','唐诗','tang','','[]','嵩山未必憐蘭蘭，蘭蘭已受郎君恩。',32,'全唐诗/poet.tang.20000.json','["嵩山未必憐蘭蘭，蘭蘭已受郎君恩。", "不須刷帚跳蹤走，只擬蘭浪出其門。"]'),
('d010bccc-64dd-44be-ad5c-6821e9fab47c','蕭宅二三子贈答詩二十首 蛺蝶請客','盧仝','唐','唐诗','tang','','[]','粉末爲四體，春風爲生涯。',24,'全唐诗/poet.tang.20000.json','["粉末爲四體，春風爲生涯。", "願得紛飛去，與君爲眼花。"]'),
('5092fe9b-fd4c-4145-99e9-281d5a979652','蕭宅二三子贈答詩二十首 客荅蛺蝶','盧仝','唐','唐诗','tang','','[]','君是輕薄子，莫窺君子腸。',24,'全唐诗/poet.tang.20000.json','["君是輕薄子，莫窺君子腸。", "且須看雀兒，雀兒銜爾將。"]'),
('d32dbdef-e399-4e2c-a322-bafa0404e934','蕭宅二三子贈答詩二十首 蝦𢋙請客','盧仝','唐','唐诗','tang','','[]','凡有水竹處，我曹長先行。',28,'全唐诗/poet.tang.20000.json','["凡有水竹處，我曹長先行。", "願君借我一勺水，與君晝夜歌德聲。"]'),
('4093bcad-73b0-44dc-90f7-8b2d48364c11','蕭宅二三子贈答詩二十首 客請蝦𢋙','盧仝','唐','唐诗','tang','','[]','蝦𢋙𢋙，叩頭莫語人聞聲，揚州蝦蜆忽得便。',36,'全唐诗/poet.tang.20000.json','["蝦𢋙𢋙，叩頭莫語人聞聲，揚州蝦蜆忽得便。", "腥臊臭穢逐我行，我身化作青泥坑。"]'),
('b80d6611-a75f-46ca-a380-6d5af8fc7713','龜銘','盧仝','唐','唐诗','tang','','[]','龜，汝靈於人，不靈於身。',39,'全唐诗/poet.tang.20000.json','["龜，汝靈於人，不靈於身。", "致網於津，吾靈於身。", "不靈於人，致走於塵。", "龜，吾與汝鄰。"]'),
('e46fd2d2-c301-4a2d-b2dc-d711002dc368','梳銘','盧仝','唐','唐诗','tang','','[]','有髮兮朝朝思理，有身兮胡不如是。',16,'全唐诗/poet.tang.20000.json','["有髮兮朝朝思理，有身兮胡不如是。"]'),
('dc34b08a-2f2f-4e84-83e7-5ec4bf590d97','小婦吟','盧仝','唐','唐诗','tang','','[]','小婦欲入門，隈門勻紅妝。',122,'全唐诗/poet.tang.20000.json','["小婦欲入門，隈門勻紅妝。", "大婦出門迎，正頓羅衣裳。", "門邊兩相見，笑樂不可當。", "夫子於傍聊斷腸，小婦哆㖷上高堂。", "開玉匣，取琴張。", "陳金罍，酌滿觴。", "顧言兩相樂，永與同心事我郎。", "夫子於傍剩欲狂，珠簾風度百花香。", "翠帳雲屏白玉牀，啼鳥休啼花莫笑，女英新喜得娥皇。"]'),
('2fc2889f-6a5b-4219-bac2-26d55463ade5','月下寄徐希仁','盧仝','唐','唐诗','tang','','[]','夜半沙上行，月瑩天心明。',48,'全唐诗/poet.tang.20000.json','["夜半沙上行，月瑩天心明。", "沙月浩無際，此中離思生。", "上天何寥廓，下地何崢嶸。", "吾道豈已矣，爲君傾兕觥。"]'),
('fc21d4e2-2331-4059-b838-60c1576202d1','贈徐希仁石硯別','盧仝','唐','唐诗','tang','','[]','靈山一片不靈石，手斲成器心所惜。',80,'全唐诗/poet.tang.20000.json','["靈山一片不靈石，手斲成器心所惜。", "鳳鳥不至池不成，蛟龍乾蟠水空滴。", "青松火鍊翠煙凝，寒竹風搖遠天碧。", "今日贈君離別心，此中至淺造化深。", "用之可以過珪璧，棄置還爲一片石。"]'),
('25009c82-a1b6-47cb-9a8c-56050539f556','有所思','盧仝','唐','唐诗','tang','','["\u7231\u60c5"]','當時我醉美人家，美人顏色嬌如花。',152,'全唐诗/poet.tang.20000.json','["當時我醉美人家，美人顏色嬌如花。", "今日美人棄我去，青樓珠箔天之涯。", "天涯娟娟姮娥月，三五二八盈又缺。", "翠眉蟬鬢生別離，一望不見心斷絕。", "心斷絕，幾千里。", "夢中醉臥巫山雲，覺來淚滴湘江水。", "湘江兩岸花木深，美人不見愁人心。", "含愁更奏綠綺琴，調高弦絕無知音。", "美人兮美人，不知爲暮雨兮爲朝雲。", "相思一夜梅花發，忽到窗前疑是君。"]'),
('6ceeebbc-4292-4d5a-ac04-4f224e649636','樓上女兒曲','盧仝','唐','唐诗','tang','','[]','誰家女兒樓上頭，指揮婢子挂簾鉤。',150,'全唐诗/poet.tang.20000.json','["誰家女兒樓上頭，指揮婢子挂簾鉤。", "林花撩亂心之愁，卷却羅袖彈箜篌。", "箜篌歷亂五六弦，羅袖掩面啼向天。", "相思弦斷情不斷，落花紛紛心欲穿。", "心欲穿，憑欄干。", "相憶柳條綠，相思錦帳寒。", "直緣感君恩愛一迴顧，使我雙淚長珊珊。", "我有嬌靨待君笑，我有嬌蛾待君掃。", "鶯花爛熳君不來，及至君來花已老。", "心腸寸斷誰得知，玉堦冪歷生青草。"]'),
('3c683683-1221-476c-be6e-0e7a0e34c25e','秋夢行','盧仝','唐','唐诗','tang','','[]','客行一夜秋風起，客夢南遊渡湘水。',184,'全唐诗/poet.tang.20000.json','["客行一夜秋風起，客夢南遊渡湘水。", "湘水泠泠徹底清，二妃怨處無限情。", "娥皇不語啓嬌靨，女英目成轉心愜。", "長眉入鬢何連娟，肌膚白玉秀且鮮。", "裴回共詠東方日，沈吟再理南風弦。", "聲斷續，思綿綿，中含幽意兩不宣。", "殷勤纖手驚破夢，中宵寂寞心悽然。", "心悽然，腸亦絕。", "寐不寐兮玉枕寒，夜深夜兮霜似雪。", "鏡中不見雙翠眉，臺前空挂纖纖月。", "纖纖月，盈復缺，娟娟似眉意難訣。", "願此眉兮如此月，千里萬里光不滅。"]'),
('81f82a1d-d40f-407d-8a33-ae6d458c0e3e','自君之出矣','盧仝','唐','唐诗','tang','','[]','自君之出矣，壁上蜘蛛織。',96,'全唐诗/poet.tang.20000.json','["自君之出矣，壁上蜘蛛織。", "近取見妾心，夜夜無休息。", "妾有雙玉環，寄君表相憶。", "環是妾之心，玉是君之德。", "馳情增悴容，蓄思損精力。", "玉簟寒悽悽，延想心惻惻。", "風含霜月明，水泛碧天色。", "此水有盡時，此情無終極。"]'),
('6f33754e-1fb7-4140-8654-d729e9254a10','走筆謝孟諫議寄新茶','盧仝','唐','唐诗','tang','','[]','日高丈五睡正濃，軍將打門驚周公。',303,'全唐诗/poet.tang.20000.json','["日高丈五睡正濃，軍將打門驚周公。", "口云諫議送書信，白絹斜封三道印。", "開緘宛見諫議面，手閱月團三百片。", "聞道新年入山裏，蟄蟲驚動春風起。", "天子須嘗陽羨茶，百草不敢先開花。", "仁風暗結珠琲瓃，先春抽出黃金芽。", "摘鮮焙芳旋封裹，至精至好且不奢。", "至尊之餘合王公，何事便到山人家。", "柴門反關無俗客，紗帽籠頭自煎喫。", "碧雲引風吹不斷，白花浮光凝椀面。", "一椀喉吻潤，兩椀破孤悶。", "三椀搜枯腸，唯有文字五千卷。", "四椀發輕汗，平生不平事。", "盡向毛孔散，五椀肌骨清。", "六椀通仙靈，七椀喫不得也。", "唯覺兩腋習習清風生，蓬萊山，在何處？", "玉川子，乘此清風欲歸去。", "山上羣仙司下土，地位清高隔風雨。", "安得知百萬億蒼生命，墮在巔崖受辛苦。", "便爲諫議問蒼生，到頭還得蘇息否。"]'),
('6fac0cea-b4ee-419b-9802-786d508141f9','冬行三首 一','盧仝','唐','唐诗','tang','','[]','蟲豸臘月皆在蟄，吾獨何乃勞其形。',94,'全唐诗/poet.tang.20000.json','["蟲豸臘月皆在蟄，吾獨何乃勞其形。", "小大無由知天命，但怪守道不得寧。", "老母妻子一揮手，涕下便作千里行。", "自顧不及遭霜葉，旦夕保得同飄零。", "達生何足云，偶然苦樂經其身。", "古來堯孔與桀跖，善惡何補如今人。"]'),
('1afe4765-24bf-4454-9663-7d3f5fdbcefd','冬行三首 二','盧仝','唐','唐诗','tang','','[]','長年愛伊洛，決計卜長久。',252,'全唐诗/poet.tang.20000.json','["長年愛伊洛，決計卜長久。", "賒買里仁宅，水竹且小有。", "賣宅將還資，舊業苦不厚。", "債家徵利心，餓虎血染口。", "臘風刀刻肌，遂向東南走。", "賢哉韓員外，勸我莫強取。", "憑風謝長者，敢不愧心苟。", "賃載得估舟，估雜非吾偶。", "壯色排榻席，別座夸羊酒。", "落日無精光，啞暝被掣肘。", "漕石生齒牙，洗灘亂相掫。", "奔澌嚼篙杖，夾岸雪龍吼。", "可憐聖明朝，還爲喪家狗。", "通運隔南溟，債利拄北斗。", "揚州屋舍賤，還債堪了不。", "此宅貯書籍，地濕憂蠹朽。", "賈僎舊相識，十年與營守。", "貧交多變態，僎得君子不。", "利命子罕言，我誠孔門醜。", "且貴終焉圖，死免慙狐首。", "何當歸帝鄉，白雲永相友。"]'),
('56148045-3c5d-4d26-ac33-0fab19d30e23','冬行三首 三','盧仝','唐','唐诗','tang','','[]','不敢唾汴水，汴水入東海。',168,'全唐诗/poet.tang.20000.json','["不敢唾汴水，汴水入東海。", "汚泥龍王宮，恐獲不敬罪。", "不敢蹋汴堤，汴堤連秦宮。", "蹋盡天子土，饋餫無由通。", "此言雖太闊，且是臣心腸。", "野風結陰兵，千里鳴刀槍。", "海月護羇魄，到曉點孤光。", "上不事天子，下不識侯王。", "夜半睡獨覺，爽氣盈心堂。", "顏子甚年少，孔聖同行藏。", "我年過顏子，敢道不自強。", "船人雖奴兵，亦有意智長。", "問我何所得，樂色填清揚。", "我報果有爲，孔經在衣裳。"]'),
('3ab323d7-8bea-45ff-8bc0-5a018dbb7707','常州孟諫議座上聞韓員外職方貶國子博士有感五首 一','盧仝','唐','唐诗','tang','','[]','忽見除書到，韓君又學官。',48,'全唐诗/poet.tang.20000.json','["忽見除書到，韓君又學官。", "死生縱有命，人事始知難。", "烈火先燒玉，庭蕪不養蘭。", "山夫與刺史，相對兩巑岏。"]'),
('5f6cb8bf-c3fd-410b-abe2-01174beb3dbb','常州孟諫議座上聞韓員外職方貶國子博士有感五首 二','盧仝','唐','唐诗','tang','','[]','干祿無便佞，宜知黜此身。',48,'全唐诗/poet.tang.20000.json','["干祿無便佞，宜知黜此身。", "員郎猶小小，國學大頻頻。", "孤宦心肝直，天王苦死嗔。", "朝廷無諫議，誰是雪韓人。"]'),
('b44d6bf6-f460-4736-bca8-39ac88e509d4','常州孟諫議座上聞韓員外職方貶國子博士有感五首 三','盧仝','唐','唐诗','tang','','[]','何事遭朝貶，知何被不容。',48,'全唐诗/poet.tang.20000.json','["何事遭朝貶，知何被不容。", "不如思所自，只欲涕無從。", "爵服何曾好，荷衣已慣縫。", "朝官莫相識，歸去老巖松。"]'),
('daf43c26-4521-4b77-841b-27df85b36a01','常州孟諫議座上聞韓員外職方貶國子博士有感五首 四','盧仝','唐','唐诗','tang','','[]','力小垂垂上，天高又不登。',48,'全唐诗/poet.tang.20000.json','["力小垂垂上，天高又不登。", "致身唯一己，獲罪則顏朋。", "祿位埋坑穽，康莊壘劒稜。", "公卿共惜取，莫遣玉山崩。"]'),
('29f67424-a9c8-4065-895b-d0ab93422b9a','常州孟諫議座上聞韓員外職方貶國子博士有感五首 五','盧仝','唐','唐诗','tang','','[]','誰憐野田子，海內一韓侯。',48,'全唐诗/poet.tang.20000.json','["誰憐野田子，海內一韓侯。", "左道官雖樂，剛腸得健無。", "功名生地獄，禮教死天囚。", "莫言耕種好，須避蒺藜秋。"]'),
('5ee0b9cd-d5c0-4ae2-99cd-84f862aaa02b','夏夜聞蚯蚓吟','盧仝','唐','唐诗','tang','','[]','夏夜雨欲作，傍砌蚯蚓吟。',72,'全唐诗/poet.tang.20000.json','["夏夜雨欲作，傍砌蚯蚓吟。", "念爾無筋骨，也應天地心。", "汝無親朋累，汝無名利侵。", "孤韻似有說，哀怨何其深。", "泛泛輕薄子，旦夕還謳吟。", "肝膽異汝輩，熱血徒相侵。"]'),
('f658ef82-ee49-4fc2-b63f-81fe26a6bc06','揚州送伯齡過江','盧仝','唐','唐诗','tang','','[]','伯齡不厭山，山不養伯齡。',96,'全唐诗/poet.tang.20000.json','["伯齡不厭山，山不養伯齡。", "松顛有樵墮，石上無禾生。", "不忍六尺軀，遂作東南行。", "諸侯盡食肉，壯氣吞八紘。", "不唧溜鈍漢，何由通姓名。", "夷齊餓死日，武王稱聖明。", "節義士枉死，何異鴻毛輕。", "努力事干謁，我心終不平。"]'),
('7c71c254-efaf-47d0-bee9-057f1136e0b7','憶金鵝山沈山人二首 一','盧仝','唐','唐诗','tang','','[]','君家山頭松樹風，適來入我竹林裏。',130,'全唐诗/poet.tang.20000.json','["君家山頭松樹風，適來入我竹林裏。", "一片新茶破鼻香，請君速來助我喜。", "莫合九轉大還丹，莫讀三十六部大洞經。", "閑來共我說真意，齒下領取真長生。", "不須服藥求神仙，神仙意智或偶然。", "自古聖賢放入土，淮南雞犬驅上天。", "白日上昇應不惡，藥成且輙一丸藥。", "暫時上天少問天，蛇頭蝎尾誰安著。"]'),
('9a51666c-2ed6-4b2e-97f8-dfbc457fd9ec','憶金鵝山沈山人二首 二','盧仝','唐','唐诗','tang','','[]','君愛鍊藥藥欲成，我愛鍊骨骨已清。',137,'全唐诗/poet.tang.20000.json','["君愛鍊藥藥欲成，我愛鍊骨骨已清。", "試自比校得仙者，也應合得天上行。", "天門九重高崔嵬，清空鑿出黃金堆。", "夜叉守門晝不啓，夜半醮祭夜半開。", "夜叉喜歡動關鎖，鎖聲㩧地生風雷。", "地上禽獸重血食，性命血化飛黃埃。", "太上道君蓮花臺，九門隔闊安在哉？", "嗚呼！沈君大藥成，兼須巧會鬼物情，無求長生喪厥生。"]'),
('4b0d49ff-7769-43a0-b6e4-976cd4faa115','寄蕭二十三慶中','盧仝','唐','唐诗','tang','','[]','蕭乎蕭乎，憶蕭者嵩山之盧。',105,'全唐诗/poet.tang.20000.json','["蕭乎蕭乎，憶蕭者嵩山之盧。", "盧揚州，蕭歙州。", "相思過春花，鬢毛生麥秋。", "千災萬怪天南道，猩猩鸚鵡皆人言。", "山魈吹火蟲入椀，鴆鳥咒詛鮫吐涎。", "就中南瘴欺北客，憑君數磨犀角喫。", "我憶君心千百間，千百間君何時還，使我夜夜勞魂魄。"]'),
('8a24a9f0-a89c-4b78-910f-ee4d8e51ea31','贈金鵝山人沈師魯','盧仝','唐','唐诗','tang','','[]','金鵝山中客，來到揚州市。',214,'全唐诗/poet.tang.20000.json','["金鵝山中客，來到揚州市。", "買藥牀頭一破顏，撇然便有上天意。", "日月高挂玄關深，金膏切淬肌骨異。", "人皆食穀與五味，獨食太和陰陽氣。", "浩浩流珠走百關，綿綿若存有深致。", "種玉不耕山外非內粹，鑿儒關決文泉彰。", "風雅因君不復墜，光不外照刃不磨。", "迴避人間惡富貴，三日四日五六日。", "盤礴化元搜萬類，晝飲興酣陶天和。", "夜話造微□精魅，示我插血不死方。", "賞我風格不肥膩，肉眼不識天上書。", "小儒安敢窺奧祕，崑崙路隔西北天。", "三山後浮不著地，君到頭來憶我時，金簡爲吾鐫一字。"]'),
('085d992c-6234-4aa5-98bf-0aa2189f3353','歎昨日三首 一','盧仝','唐','唐诗','tang','','[]','昨日之日不可追，今日之日須臾期。',64,'全唐诗/poet.tang.20000.json','["昨日之日不可追，今日之日須臾期。", "如此如此復如此，壯心死盡生鬢絲。", "秋風落葉客腸斷，不辦斗酒開愁眉。", "賢名聖行甚辛苦，周公孔子徒自欺。"]'),
('d5179515-796e-467d-b744-3ab3494f1238','歎昨日三首 二','盧仝','唐','唐诗','tang','','[]','天下薄夫苦耽酒，玉川先生也耽酒。',64,'全唐诗/poet.tang.20000.json','["天下薄夫苦耽酒，玉川先生也耽酒。", "薄夫有錢恣張樂，先生無錢養恬漠。", "有錢無錢俱可憐，百年驟過如流川。", "平生心事消散盡，天上白日悠悠懸。"]'),
('27e447ee-3210-40f1-8e5a-299cda7ccc9b','歎昨日三首 三','盧仝','唐','唐诗','tang','','[]','上帝板板主何物，日車劫劫西向沒。',64,'全唐诗/poet.tang.20000.json','["上帝板板主何物，日車劫劫西向沒。", "自古賢聖無奈何，道行不得皆白骨。", "白骨土化鬼入泉，生人莫負平生年。", "何時出得禁酒國，滿甕釀酒曝背眠。"]'),
('5b79b11a-be68-48be-ad32-9920a6b12b77','月蝕詩','盧仝','唐','唐诗','tang','','[]','東海出明月，清明照毫髮。',120,'全唐诗/poet.tang.20000.json','["東海出明月，清明照毫髮。", "朱弦初罷彈，金兔正奇絕。", "三五與二八，此時光滿時。", "頗奈蝦𢋙兒，吞我芳桂枝。", "我愛明鏡潔，爾乃痕翳之。", "爾且無六翮，焉得升天涯。", "方寸有白刃，無由揚清輝。", "如何萬里光，遭爾小物欺。", "却吐天漢中，良久素魄微。", "日月尚如此，人情良可知。"]'),
('34abb2d3-a044-4ea5-aa2e-232ac5dd93aa','直鉤吟','盧仝','唐','唐诗','tang','','[]','初歲學釣魚，自謂魚易得。',40,'全唐诗/poet.tang.20000.json','["初歲學釣魚，自謂魚易得。", "三十持釣竿，一魚釣不得。", "人鉤曲，我鉤直，哀哉我鉤又無食。"]'),
('49d493f7-226a-4782-a0aa-cbe9b0ea4671','與馬異結交詩','盧仝','唐','唐诗','tang','','[]','天地日月如等閑，盧仝四十無往還。',395,'全唐诗/poet.tang.20000.json','["天地日月如等閑，盧仝四十無往還。", "唯有一片心脾骨，巉巖崒硉兀鬱律。", "刀劒爲峰㟧，平地放著高如崑崙山。", "天不容，地不受，日月不敢偷照耀。", "神農畫八卦，鑿破天心胸。", "女媧本是伏羲婦，恐天怒。", "擣鍊五色石，引日月之針，五星之縷把天補。", "補了三日不肯歸壻家，走向日中放老鵶。", "月裏栽桂養蝦𢋙，天公發怒化龍蛇。", "此龍此蛇得死病，神農合藥救死命。", "天怪神農黨龍蛇，罰神農爲牛頭。", "令載元氣車，不知藥中有毒藥。", "藥殺元氣天不覺，爾來天地不神聖。", "日月之光無正定，不知元氣元不死。", "忽聞空中喚馬異，馬異若不是祥瑞。", "空中敢道不容易，昨日仝不仝，異自異，是謂大仝而小異。", "今日仝自仝，異不異，是謂仝不往兮異不至。", "直當中兮動天地，白玉璞裏斵出相思心。", "黃金鑛裏鑄出相思淚，忽聞空中崩崖倒谷聲。", "絕勝明珠千萬斛，買得西施南威一雙婢。", "此婢嬌饒惱殺人，凝脂爲膚翡翠裙。", "唯解畫眉朱點脣，自從獲得君。", "敲金摐玉凌浮雲，却返顧。", "一雙婢子何足云，平生結交若少人。"]'),
('a0605938-ef92-4d3e-b031-e8cb113851ac','感古四首 一','盧仝','唐','唐诗','tang','','[]','天生聖明君，必資忠賢臣。',168,'全唐诗/poet.tang.20000.json','["天生聖明君，必資忠賢臣。", "舜禹竭股肱，共佐堯爲君。", "四載成地理，七政齊天文。", "階下蓂莢生，琴上南風薰。", "輪轉夏殷周，時復猶一人。", "秦漢事讒巧，魏晉忘機鈞。", "猜忌相翦滅，爾來迷恩親。", "以愚保其身，不覺身沈淪。", "以智理其國，遂爲國之賊。", "苟圖容一身，萬事良可惻。", "可憐萬乘君，聰明受沈惑。", "忠良伏草莽，無因施羽翼。", "日月異又蝕，天地晦如墨。", "既亢而後求，異哉龍之德。"]'),
('f7cbf2e2-135e-4220-931b-aa406aff8545','感古四首 二','盧仝','唐','唐诗','tang','','[]','人生何所貴，所貴有終始。',228,'全唐诗/poet.tang.20000.json','["人生何所貴，所貴有終始。", "昨日盈尺璧，今朝盡瑕棄。", "蒼蠅點垂棘，巧舌成錦綺。", "箕子爲之奴，比干諫而死。", "仲尼魯司寇，出走爲羣婢。", "假如屈原醒，其奈一國醉。", "一國醉號呶，一人行清高。", "便欲激頹波，此事真徒勞。", "上山逢猛虎，入海逢巨鼇。", "王者苟不死，腰下魚鱗刀。", "東海波連天，三度成桑田。", "高岸高於屋，斯須變溪谷。", "天地猶尚然，人情難久全。", "夜半白刃讐，旦來金石堅。", "蕭綬既解坼，陳印亦棄捐。", "竭節遇刀割，輸忠遭禍纏。", "不予衾之眠，信予衾之穿。", "鏡明不自照，膏潤徒自煎。", "抱劍長太息，淚墮秋風前。"]'),
('5482de02-7c4d-4eee-9c39-550fa181d847','感古四首 三','盧仝','唐','唐诗','tang','','[]','古來不患寡，所患患不均。',168,'全唐诗/poet.tang.20000.json','["古來不患寡，所患患不均。", "單醪投長河，三軍盡沈淪。", "今人異古人，結託唯親賓。", "毀坼維鵲巢，不行鳲鳩仁。", "鄙恡不識分，有心占陽春。", "鸞鶴日已疎，燕雀日已親。", "小物無大志，安測棲松筠。", "恩眷多棄故，物情尚逐新。", "瓦礫暫拂拭，光掩連城珍。", "脣吻恣談鑠，黃金同灰塵。", "蘇秦北遊趙，張祿西入秦。", "既變嫂叔節，仍擯華陽君。", "萬世金石交，一餉如浮雲。", "骨肉且不顧，何況長羈貧。"]'),
('5c8a4fd5-ec11-47b9-9fa9-f593c78f1dd6','感古四首 四','盧仝','唐','唐诗','tang','','[]','君莫以富貴，輕忽他年少。',174,'全唐诗/poet.tang.20000.json','["君莫以富貴，輕忽他年少。", "聽我暫話會稽朱太守，正受凍餓時。", "索得人家貴傲婦，讀書書史未潤身。", "負薪辛苦胝生肘，謂言琴與瑟。", "糟糠結長久，不分殺人羽翮成。", "臨臨沖天婦嫌醜，□□□□□□□。", "其奈一朝太守振羽儀，鄉關晝行衣錦衣。", "哀哉舊婦何眉目，新壻隨行向天哭。", "寸心金石徒爾爲，杯水庭沙空自覆。", "乃知愚婦人，妬忌陰毒心。", "唯救眼底事，不思日月深。", "等閑取羞死，豈如甘布衾。"]'),
('f008105c-31b5-4425-a657-0190d8ccb568','雜興','盧仝','唐','唐诗','tang','','[]','意志未成百不解，見人富貴亦心愛。',160,'全唐诗/poet.tang.20000.json','["意志未成百不解，見人富貴亦心愛。", "等閑對酒呼三達，屠羊殺牛皆自在。", "放心爲樂笙歌攢，壯氣激作風霜寒。", "廚中玉饌盈金盤，方丈厭見嫌不餐。", "飛鷹躍馬實快性，脣腐齒爛空巑岏。", "豈期福極翻成禍，禍成身誅家亦破。", "昨朝惆悵不如君，今日悲君不如我。", "否泰交加無定主，嬾學風雲戢翎羽。", "綠酒清琴好養生，出將入相無心取。", "三五圖書舊揣摩，五千道德新䂓矩。"]'),
('6e9c969b-01de-455e-9897-95790e017031','酬徐公以新文見招','盧仝','唐','唐诗','tang','','[]','昨夜霜月明，果有清音生。',24,'全唐诗/poet.tang.20000.json','["昨夜霜月明，果有清音生。", "便欲走相和，愁聞寒玉聲。"]'),
('4a33c0ea-0d03-4d50-83c1-ca030bbd4628','門箴','盧仝','唐','唐诗','tang','','[]','貪殘奸酗，狡佞訐愎。',76,'全唐诗/poet.tang.20000.json','["貪殘奸酗，狡佞訐愎。", "身之八殺，背惠，恃己。", "狎不肖，妬賢能。", "命之四孽，有是有此予敢辭。", "無是無此予之師，一日不見予心思。", "思其人，懼其人。", "其交其難，敢告于門。"]'),
('a7a08144-c10f-44ef-8558-7064cc123c68','孟夫子生生亭賦','盧仝','唐','唐诗','tang','','[]','玉川子沿孟冬之寒流兮，輟櫂上登生生亭。',164,'全唐诗/poet.tang.20000.json','["玉川子沿孟冬之寒流兮，輟櫂上登生生亭。", "夫子何之兮，面逐雲沒兮南行。", "百川注海而心不寫兮，落日千里凝寒精。", "予日衰期人生之世斯已矣，爰爲今日猶猶岐路之心生。", "悲夫！南國風濤，魚龍畜伏。", "予小子戇朴，必不能濟夫子欲。", "嗟自慙承夫子而不失予兮，傳古道甚分明。", "予且廣孤目遐賷于天壤兮，庶得外盡萬物變化之幽情。", "然後慙愧而來歸兮，大息吾躬于夫子之亭。"]'),
('1a55ca5a-de6c-4286-90a0-e57ed2adfeec','走筆追王內丘','盧仝','唐','唐诗','tang','','[]','自識夫子面，便獲夫子心。',127,'全唐诗/poet.tang.20000.json','["自識夫子面，便獲夫子心。", "夫子一啓顏，義重千黃金。", "平原孟嘗骨已土，始有夫子堪知音。", "忽然夫子不語，帶蓆帽，騎驢去。", "余對醁醽不能斟，君且來，余之瞻望心悠哉。", "零雨其濛愁不散，閑花寂寂斑堦苔。", "不如對此景，含笑傾金罍。", "莫問四肢暢，暫取眉頭開。", "弦琴待夫子，夫子來不來。"]'),
('f07f68a9-44c3-46d2-ba95-d54b51080a77','思君吟寄□□生','盧仝','唐','唐诗','tang','','[]','我思君兮河之壖，我爲河中之泉，君爲河中之青天。',102,'全唐诗/poet.tang.20000.json','["我思君兮河之壖，我爲河中之泉，君爲河中之青天。", "天青青，泉泠泠。", "泉含青天天隔泉，我思君兮心亦然。", "心亦然，此心復在天之側。", "我心爲風兮淅淅，君身爲雲兮羃羃。", "此風引此雲兮雲不來，此風此雲兮何悠哉，與我身心雙裴回。"]'),
('7adf7cb1-c2fc-48b8-b0da-afc846ccfbda','將歸山招冰僧','盧仝','唐','唐诗','tang','','[]','買得一片田，濟源花洞前。',122,'全唐诗/poet.tang.20000.json','["買得一片田，濟源花洞前。", "千里石壁坼，一條流泌泉。", "青松盤樛枝，森森上插青冥天。", "枝上有□猨，宿處近鶴巢。", "清唳孤吟聲相交，月輪下射空洞響，絲篁成韻風蕭蕭。", "我心塵外心，愛此塵外物。", "欲結塵外交，苦無塵外骨。", "泌泉有冰公，心靜見真佛。", "可結塵外交，占此松與月。"]'),
('c8cf8714-e532-4480-b383-40518617e24c','詶願公雪中見寄','盧仝','唐','唐诗','tang','','[]','積雪三十日，車馬路不通。',72,'全唐诗/poet.tang.20000.json','["積雪三十日，車馬路不通。", "貧病交親絕，想憶唯願公。", "春鳩報春歸，苦寒生暗風。", "簷乳墮懸玉，日脚浮輕紅。", "梅柳意却活，園圃冰始融。", "更候四體好，方可到寺中。"]'),
('edd3c229-3ebe-407a-bdb4-c68a740456b2','苦雪寄退之','盧仝','唐','唐诗','tang','','[]','天王二月行時令，白銀作雪漫天涯。',242,'全唐诗/poet.tang.20000.json','["天王二月行時令，白銀作雪漫天涯。", "山人門前徧受賜，平地一尺白玉沙。", "雲頹月壞桂英下，鶴毛風剪亂參差。", "山人屋中[凍]欲死，千樹萬樹飛春花。", "菜頭出土膠入地，山莊取粟埋却車。", "冷絮刀生削峭骨，冷虀斧破慰老牙。", "病妻煙眼淚滴滴，飢嬰哭乳聲呶呶。", "市頭博米不用物，酒店買酒不肯賒。", "聞道西風弄劒戟，長堦殺人如亂麻。", "天眼高開欺草芽，我死未肯興歎嗟。", "但恨口中無酒氣，劉伶見我相揄揶。", "清風攪腸筋力絕，白灰壓屋梁柱斜。", "聖明有道□命漢，可得再見朝日耶。", "柴門沒脛晝不埽，黃昏遶樹棲寒鴉。", "唯有河南韓縣令，時時醉飽過貧家。"]'),
('a9b43b1b-2edd-4129-9f05-4eea40538815','寄贈含曦上人','盧仝','唐','唐诗','tang','','[]','楞伽大師兄，誇曦識道理。',288,'全唐诗/poet.tang.20000.json','["楞伽大師兄，誇曦識道理。", "破鏁推玄關，高辯果難揣。", "論語老莊易，搜索通神鬼。", "起信中百門，敲骨得佛髓。", "此外雜經律，泛讀一萬紙。", "高殿排名僧，執卷坐纍纍。", "化物自一心，三教齊發起。", "隨鐘嚼宮商，滿口文字美。", "商賈女郎輩，不曾道生死。", "縱遇彊禮拜，雅語不露齒。", "劈破天地來，節義可屈指。", "季展即此僧，孤立無依倚。", "近來愛作詩，新奇頗煩委。", "忽忽造古格，削盡俗綺靡。", "假如慵裹頭，但勤讀書史。", "切磋併工夫，休遠不可比。", "憐僧無遠□，信佛殊未已。", "貌古饒風情，清論興亹亹。", "訪余十數度，相去三五里。", "見時心亦喜，不見心亦喜。", "見時談謔樂，四座盡角嘴。", "不見養天和，無人聒人耳。", "昨朝披雪來，面色赤韡韡。", "封竈養黃金，許割方寸匕。"]'),
('5d159bac-5591-4cea-b4be-a8189dcd002e','聽蕭君姬人彈琴','盧仝','唐','唐诗','tang','','[]','彈琴人似膝上琴，聽琴人似匣中弦。',224,'全唐诗/poet.tang.20000.json','["彈琴人似膝上琴，聽琴人似匣中弦。", "二物各一處，音韻何由傳。", "無風質氣兩相感，萬般悲意方纏綿。", "初時天山之外飛白雪，漸漸萬丈澗地生流泉。", "風梅花落輕揚揚，十指乾淨聲涓涓。", "昭君可惜嫁單于，沙場不遠只眼前。", "蔡琰薄命沒胡虜，烏梟啾唧啼胡天。", "關山險隔一萬里，顏色錯漠生風煙。", "形魄散逐五音盡，雙蛾結草空嬋娟。", "中腹苦恨杳不極，新心愁絕難復傳。", "金尊湛湛夜沈沈，餘音疊發清聯綿。", "主人醉盈有得色，座客向隅增內然。", "孔子怪責顏回瑟，野夫何事蕭君筵。", "拂衣屢命請中廢，月照書窗歸獨眠。"]'),
('dd604a5e-6500-41f4-91cb-37957d8d961f','蜻蜓歌','盧仝','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河中流日影斜，水天一色無津涯。',170,'全唐诗/poet.tang.20000.json','["黃河中流日影斜，水天一色無津涯。", "處處驚波噴流飛雪花，篙工檝師力且武。", "進寸退尺莫能度，吾甚懼。", "念汝小蟲子，造化借羽翼。", "隨風戲中流，翩然有餘力。", "吾不如汝無他，無羽翼。", "吾若有羽翼，則上叩天關。", "爲聖君請賢臣，布惠化于人間。", "然後東飛浴東溟，吸日精。", "撼若木之英，紛而零。", "使地上學仙之子，得而食之皆長生。", "不學汝無端小蟲子，葉葉水上無一事，忽遭風雨水中死。"]'),
('fe37afc9-aa87-4bd6-963c-18680677f581','出山作','盧仝','唐','唐诗','tang','','[]','出山忘掩山門路，釣竿插在枯桑樹。',48,'全唐诗/poet.tang.20000.json','["出山忘掩山門路，釣竿插在枯桑樹。", "當時只有鳥窺窬，更亦無人得知處。", "家僮若失釣魚竿，定是猨猴把將去。"]'),
('35ba3b04-173b-479d-a01f-d90e9f988722','寄崔柳州','盧仝','唐','唐诗','tang','','[]','使者立取書，疊紙生百憂。',72,'全唐诗/poet.tang.20000.json','["使者立取書，疊紙生百憂。", "使君若不信，他時看白頭。", "三百六十州，尅情惟柳州。", "柳州蠻天末，鄙夫嵩之幽。", "花落隴水頭，各自東西流。", "凜凜長相逐，爲謝池上鷗。"]'),
('d11d433d-29f4-47e8-99a3-91bb21b3f50b','贈稚禪師','盧仝','唐','唐诗','tang','','[]','春風滿禪院，師獨坐南軒。',48,'全唐诗/poet.tang.20000.json','["春風滿禪院，師獨坐南軒。", "萬化見中盡，始覺靜性尊。", "我來契平生，目擊道自存。", "與師不動遊，遊此無迹門。"]'),
('8fefc1f8-1294-4635-a7c8-31354af6cace','送好約法師歸江南','盧仝','唐','唐诗','tang','','[]','杯度度一身，法度度萬民。',28,'全唐诗/poet.tang.20000.json','["杯度度一身，法度度萬民。", "爲報江南三二日，這回應見雪中人。"]'),
('9c200cc4-403f-415b-a379-d1f52f4b1e3c','蕭二十三赴歙州婚期二首 一','盧仝','唐','唐诗','tang','','[]','淮上客情殊冷落，蠻方春早客何如。',32,'全唐诗/poet.tang.20000.json','["淮上客情殊冷落，蠻方春早客何如。", "相思莫道無來使，迴雁峯前好寄書。"]'),
('4c0cf5ac-21e0-44fe-9a34-b3d4f1912d5a','蕭二十三赴歙州婚期二首 二','盧仝','唐','唐诗','tang','','[]','南方山水生時興，教有新詩得寄余。',32,'全唐诗/poet.tang.20000.json','["南方山水生時興，教有新詩得寄余。", "路帶長安迢遰急，多應不逐使君書。"]'),
('1d1553c3-e3fc-4073-9512-1e6b16f06046','掩關銘','盧仝','唐','唐诗','tang','','[]','蛇毒毒有形，藥毒毒有名。',48,'全唐诗/poet.tang.20000.json','["蛇毒毒有形，藥毒毒有名。", "人毒毒在心，對面如弟兄。", "美言不可聽，深於千丈坑。", "不如掩關坐，幽鳥時一聲。"]'),
('80fc47d5-a784-443d-ac9c-b4d17845d161','逢病軍人','盧仝','唐','唐诗','tang','','["\u519b\u4eba", "\u6218\u4e89", "\u4f24\u6000"]','行多有病住無糧，萬里還鄉未到鄉。',32,'全唐诗/poet.tang.20000.json','["行多有病住無糧，萬里還鄉未到鄉。", "蓬鬢哀吟古城下，不堪秋氣入金瘡。"]'),
('f23edbec-77aa-4290-9908-8f2cedccdc15','山中','盧仝','唐','唐诗','tang','','[]','飢拾松花渴飲泉，偶從山後到山前。',32,'全唐诗/poet.tang.20000.json','["飢拾松花渴飲泉，偶從山後到山前。", "陽坡軟草厚如織，困與鹿麛相伴眠。"]'),
('dc767cf6-5731-4a4c-9cf9-7df7e0a9b31e','除夜 一','盧仝','唐','唐诗','tang','','[]','衰殘歸未遂，寂寞此宵情。',48,'全唐诗/poet.tang.20000.json','["衰殘歸未遂，寂寞此宵情。", "舊國餘千里，新年隔數更。", "寒猶近北峭，風漸向東生。", "惟見長安陌，晨鐘度火城。"]'),
('55dc5769-3159-4269-b65f-081c50d3664c','除夜 二','盧仝','唐','唐诗','tang','','[]','殷勤惜此夜，此夜在逡巡。',48,'全唐诗/poet.tang.20000.json','["殷勤惜此夜，此夜在逡巡。", "燭盡年還別，雞鳴老更新。", "儺聲方去病，酒色已迎春。", "明日持杯處，誰爲最後人。"]'),
('af691759-fafe-4b65-893b-e37af39cbf6a','李憑箜篌引','李賀','唐','唐诗','tang','','[]','吳絲蜀桐張高秋，空白凝雲頹不流。',112,'全唐诗/poet.tang.20000.json','["吳絲蜀桐張高秋，空白凝雲頹不流。", "江娥啼竹素女愁，李憑中國彈箜篌。", "崑山玉碎鳳皇呌，芙蓉泣露香蘭笑。", "十二門前融冷光，二十三絲動紫皇。", "女媧鍊石補天處，石破天驚逗秋雨。", "夢入坤山教神嫗，老魚跳波瘦蛟舞。", "吳質不眠倚桂樹，露脚斜飛溼寒兔。"]'),
('60f418f1-447d-4916-b885-1cbab41f3bb8','殘絲曲','李賀','唐','唐诗','tang','','[]','垂楊葉老鶯哺兒，殘絲欲斷黃蜂歸。',64,'全唐诗/poet.tang.20000.json','["垂楊葉老鶯哺兒，殘絲欲斷黃蜂歸。", "綠鬢年少金釵客，縹粉壺中沈琥珀。", "花臺欲暮春辭去，落花起作迴風舞。", "榆莢相催不知數，沈郎青錢夾城路。"]'),
('eb9c11f4-96b8-4445-9ca8-7a6f7c87da21','還自會稽歌','李賀','唐','唐诗','tang','','[]','野粉椒壁黃，溼螢滿梁殿。',48,'全唐诗/poet.tang.20000.json','["野粉椒壁黃，溼螢滿梁殿。", "臺城應教人，秋衾夢銅輦。", "吳霜點歸鬢，身與塘蒲晚。", "脈脈辭金魚，羈臣守迍賤。"]'),
('28565010-46b8-4425-a301-c7127f25b0cd','出城寄權璩楊敬之','李賀','唐','唐诗','tang','','["\u6625\u5929", "\u6292\u60c5", "\u65e0\u5948", "\u5fc3\u60c5", "\u58ee\u5fd7\u672a\u916c"]','草暖雲昏萬里春，宮花拂面送行人。',32,'全唐诗/poet.tang.20000.json','["草暖雲昏萬里春，宮花拂面送行人。", "自言漢劒當飛去，何事還車載病身。"]'),
('114321a4-5ada-4be8-8bae-1e6fb19d4e6f','示弟','李賀','唐','唐诗','tang','','[]','別弟三年後，還家一日餘。',48,'全唐诗/poet.tang.20000.json','["別弟三年後，還家一日餘。", "醁醽今夕酒，緗帙去時書。", "病骨猶能在，人間底事無。", "何須問牛馬，拋擲任梟盧。"]'),
('67cdba49-3ca4-4a9c-a2c2-ba0e179c93f4','竹','李賀','唐','唐诗','tang','','[]','入水文光動，抽空綠影春。',48,'全唐诗/poet.tang.20000.json','["入水文光動，抽空綠影春。", "露華生筍逕，苔色拂霜根。", "織可承香汗，裁堪釣錦鱗。", "三梁曾入用，一節奉王孫。"]'),
('06007eea-c3e4-4a76-86c1-c2917fdff50f','同沈駙馬賦得御溝水','李賀','唐','唐诗','tang','','[]','入苑白泱泱，宮入正靨黃。',48,'全唐诗/poet.tang.20000.json','["入苑白泱泱，宮入正靨黃。", "遶堤龍骨冷，拂岸鴨頭香。", "別館驚殘夢，停杯泛小觴。", "幸因流浪處，暫得見何郎。"]'),
('1bec046f-3d2a-4202-8402-29a7f60269ee','始爲奉禮憶昌谷山居','李賀','唐','唐诗','tang','','[]','掃斷馬蹄痕，衙迴自閉門。',72,'全唐诗/poet.tang.20000.json','["掃斷馬蹄痕，衙迴自閉門。", "長鎗江米熟，小樹棗花春。", "向壁懸如意，當簾閱角巾。", "犬書曾去洛，鶴病悔遊秦。", "土甑封茶葉，山盃鎖竹根。", "不知船上月，誰櫂滿溪雲。"]'),
('833084ff-f269-4288-ad2b-6a62817f4c49','七夕','李賀','唐','唐诗','tang','','["\u601d\u5ff5", "\u4e03\u5915\u60c5\u4eba\u8282", "\u4e03\u5915\u8282"]','別浦今朝暗，羅帷午夜愁。',48,'全唐诗/poet.tang.20000.json','["別浦今朝暗，羅帷午夜愁。", "鵲辭穿線月，花入曝衣樓。", "天上分金鏡，人間望玉鉤。", "錢塘蘇小小，更值一年秋。"]'),
('e7251348-a89b-45a4-aa43-ac2156854063','過華清宮','李賀','唐','唐诗','tang','','[]','春月夜啼鴉，宮簾隔御花。',48,'全唐诗/poet.tang.20000.json','["春月夜啼鴉，宮簾隔御花。", "雲生朱絡暗，石斷紫錢斜。", "玉椀盛殘露，銀燈點舊紗。", "蜀王無近信，泉上有芹芽。"]'),
('851cd22f-1855-4daf-8578-dc0d3170570a','送沈亞之歌','李賀','唐','唐诗','tang','','["\u9001\u522b", "\u5bbd\u6170"]','吳興才人怨春風，桃花滿陌千里紅。',128,'全唐诗/poet.tang.20000.json','["吳興才人怨春風，桃花滿陌千里紅。", "紫絲竹斷騘馬小，家住錢塘東復東。", "白藤交穿織書笈，短策齊裁如梵夾。", "雄光寶礦獻春卿，煙底驀波乘一葉。", "春卿拾材白日下，擲置黃金解龍馬。", "攜笈歸江重入門，勞勞誰是憐君者。", "吾聞壯夫重心骨，古人三走無摧捽。", "請君待旦事長鞭，他日還轅及秋律。"]'),
('0e4aa75a-c9d0-42d6-b470-3c933525d99d','詠懷二首 一','李賀','唐','唐诗','tang','','["\u6cf0\u5c71"]','長卿懷茂陵，綠草垂石井。',48,'全唐诗/poet.tang.20000.json','["長卿懷茂陵，綠草垂石井。", "彈琴看文君，春風吹鬢影。", "梁王與武帝，棄之如斷梗。", "惟留一簡書，金泥泰山頂。"]'),
('08f4c7c2-b546-4c58-ab26-d07d53c83330','詠懷二首 二','李賀','唐','唐诗','tang','','[]','日夕著書罷，驚霜落素絲。',48,'全唐诗/poet.tang.20000.json','["日夕著書罷，驚霜落素絲。", "鏡中聊自笑，詎是南山期。", "頭上無幅巾，苦蘗已染衣。", "不見清溪魚，飲水得自宜。"]'),
('285d8546-7dc9-41ef-97ce-fbe35e8bb9c0','追和柳惲','李賀','唐','唐诗','tang','','[]','汀洲白蘋草，柳惲乘馬歸。',48,'全唐诗/poet.tang.20000.json','["汀洲白蘋草，柳惲乘馬歸。", "江頭樝樹香，岸上蝴蝶飛。", "酒盃箬葉露，玉軫蜀桐虛。", "朱樓通水陌，沙暖一雙魚。"]'),
('14bb787d-e384-4568-a9b7-d6dd6a447125','春坊正字劒子歌','李賀','唐','唐诗','tang','','[]','先輩匣中三尺水，曾入吳潭斬龍子。',96,'全唐诗/poet.tang.20000.json','["先輩匣中三尺水，曾入吳潭斬龍子。", "隙月斜明刮露寒，練帶平鋪吹不起。", "蛟胎皮老蒺藜刺，鸊鵜淬花白鷴尾。", "直是荆軻一片心，莫教照見春坊字。", "挼絲團金懸䍡𦌉，神光欲截藍田玉。", "提出西方白帝驚，嗷嗷鬼母秋郊哭。"]'),
('8f873896-d13b-474f-a111-3c36beb1455c','貴公子夜闌曲','李賀','唐','唐诗','tang','','[]','褭褭沈水煙，烏啼夜闌景。',24,'全唐诗/poet.tang.20000.json','["褭褭沈水煙，烏啼夜闌景。", "曲沼芙蓉波，腰圍白玉冷。"]'),
('5ec77a99-b8d7-4845-b03e-47704d8f4fd9','雁門太守行','李賀','唐','唐诗','tang','','["\u6218\u4e89", "\u521d\u4e2d\u53e4\u8bd7", "\u4e50\u5e9c", "\u4e5d\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)", "\u8fb9\u585e", "\u62df\u53e4"]','黑雲壓城城欲摧，甲光向日金鱗開。',64,'全唐诗/poet.tang.20000.json','["黑雲壓城城欲摧，甲光向日金鱗開。", "角聲滿天秋色裏，塞上燕脂凝夜紫。", "半卷紅旗臨易水，霜重鼓寒聲不起。", "報君黃金臺上意，提攜玉龍爲君死。"]'),
('62f91b86-6227-4527-bb0b-21cd0bb40c68','大堤曲','李賀','唐','唐诗','tang','','["\u7231\u60c5", "\u5973\u5b50"]','妾家住橫塘，紅紗滿桂香。',80,'全唐诗/poet.tang.20000.json','["妾家住橫塘，紅紗滿桂香。", "青雲教綰頭上髻，明月與作耳邊璫。", "蓮風起，江畔春。", "大堤上，留北人。", "郎食鯉魚尾，妾食猩猩脣。", "莫指襄陽道，綠浦歸帆少。", "今日菖蒲花，明朝楓樹老。"]'),
('cdb9ef73-95e2-4c70-8ab7-3512bdd7899a','蜀國弦','李賀','唐','唐诗','tang','','["\u79bb\u522b", "\u6292\u60c5", "\u5c71\u6c34", "\u5199\u666f"]','楓香晚花靜，錦水南山影。',48,'全唐诗/poet.tang.20000.json','["楓香晚花靜，錦水南山影。", "驚石墜猨哀，竹雲愁半嶺。", "涼月生秋浦，玉沙粼粼光。", "誰家紅淚客，不忍過瞿塘。"]'),
('5123af54-01dd-4aa8-aa3d-0f4147076fb3','蘇小小墓','李賀','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u9b3c", "\u5199\u666f"]','幽蘭露，如啼眼。',60,'全唐诗/poet.tang.20000.json','["幽蘭露，如啼眼。", "無物結同心，煙花不堪剪。", "草如茵，松如蓋。", "風爲裳，水爲珮。", "油壁車，夕相待。", "冷翠燭，勞光彩。", "西陵下，風吹雨。"]'),
('812cff97-e2ca-447b-abf6-76617a8f77f8','夢天','李賀','唐','唐诗','tang','','["\u68a6\u6e38", "\u6708\u5bab", "\u60f3\u8c61", "\u54f2\u7406"]','老兔寒蟾泣天色，雲樓半開壁斜白。',64,'全唐诗/poet.tang.20000.json','["老兔寒蟾泣天色，雲樓半開壁斜白。", "玉輪軋露溼團光，鸞珮相逢桂香陌。", "黃塵清水三山下，更變千年如走馬。", "遙望齊州九點煙，一泓海水杯中瀉。"]'),
('d47b5ddf-b6b3-4cab-b622-9638c75f9d05','唐兒歌','李賀','唐','唐诗','tang','','[]','頭玉磽磽眉刷翠，杜郎生得真男子。',80,'全唐诗/poet.tang.20000.json','["頭玉磽磽眉刷翠，杜郎生得真男子。", "骨重神寒天廟器，一雙瞳人剪秋水。", "竹馬梢梢搖綠尾，銀鸞睒光踏半臂。", "東家嬌娘求對值，濃笑畫空作唐字。", "眼大心雄知所以，莫忘作歌人姓李。"]'),
('d3342f18-e2fa-4cf0-9cb7-22dac3b27996','綠章封事','李賀','唐','唐诗','tang','','[]','青霓扣額呼宮神，鴻龍玉狗開天門。',96,'全唐诗/poet.tang.20000.json','["青霓扣額呼宮神，鴻龍玉狗開天門。", "石榴花發滿溪津，溪女洗花染白雲。", "綠章封事諮元父，六街馬蹄浩無主。", "虛空風氣不清泠，短衣小冠作塵土。", "金家香衖千輪鳴，楊雄秋室無俗聲。", "願攜漢戟招書鬼，休令恨骨填蒿里。"]'),
('914d9fc8-19ec-440a-bc48-3cef9caa8768','河南府試十二月樂詞 正月','李賀','唐','唐诗','tang','','[]','上樓迎春新春歸，暗黃著柳宮漏遲。',64,'全唐诗/poet.tang.20000.json','["上樓迎春新春歸，暗黃著柳宮漏遲。", "薄薄淡靄弄野姿，寒綠幽風生短絲。", "錦牀曉臥玉肌冷，露臉未開對朝暝。", "官街柳帶不堪折，早晚菖蒲勝綰結。"]'),
('125b75c6-8e96-40ba-88b9-7ee641cf8f09','河南府試十二月樂詞 二月','李賀','唐','唐诗','tang','','[]','二月飲酒採桑津，宜男草生蘭笑人。',72,'全唐诗/poet.tang.20000.json','["二月飲酒採桑津，宜男草生蘭笑人。", "蒲如交劒風如薰，勞勞胡燕怨酣春。", "薇帳逗煙生綠塵，金翹峨髻愁暮雲。", "沓颯起舞真珠裙，津頭送別唱流水，酒客背寒南山死。"]'),
('4a4cca6a-fe64-4cb3-86af-e9768374ed35','河南府試十二月樂詞 三月','李賀','唐','唐诗','tang','','[]','東方風來滿眼春，花城柳暗愁殺人。',80,'全唐诗/poet.tang.20000.json','["東方風來滿眼春，花城柳暗愁殺人。", "複宮深殿竹風起，新翠舞衿淨如水。", "光風轉蕙百餘里，暖霧驅雲撲天地。", "軍裝宮妓掃蛾淺，搖搖錦旗夾城暖。", "曲水漂香去不歸，梨花落盡成秋苑。"]'),
('b2679bd1-a495-4b9b-9388-cdebc0fae71b','河南府試十二月樂詞 四月','李賀','唐','唐诗','tang','','[]','曉涼暮涼樹如蓋，千山濃綠生雲外。',56,'全唐诗/poet.tang.20000.json','["曉涼暮涼樹如蓋，千山濃綠生雲外。", "依微香雨青氛氳，膩葉蟠花照曲門。", "金塘閑水搖碧漪，老景沈重無驚飛，墮紅殘萼暗參差。"]'),
('c0b70e60-687b-4300-a82f-5ef31807f377','河南府試十二月樂詞 五月','李賀','唐','唐诗','tang','','[]','雕玉押簾額，輕縠籠虛門。',48,'全唐诗/poet.tang.20000.json','["雕玉押簾額，輕縠籠虛門。", "井汲鉛華水，扇織鴛鴦紋。", "迴雪舞涼殿，甘露洗空綠。", "羅袖從徊翔，香汗沾寶粟。"]'),
('94a3e3ca-a454-4c8d-a7ac-db2972824153','河南府試十二月樂詞 六月','李賀','唐','唐诗','tang','','[]','裁生羅，伐湘竹。',40,'全唐诗/poet.tang.20000.json','["裁生羅，伐湘竹。", "帔拂疎霜簟秋玉，炎炎紅鏡東方開。", "暈如車輪上裴回，啾啾赤帝騎龍來。"]'),
('bd9c6e48-67cc-4572-ac94-c84fa2fe2102','河南府試十二月樂詞 七月','李賀','唐','唐诗','tang','','[]','星依雲渚冷，露滴盤中圓。',60,'全唐诗/poet.tang.20000.json','["星依雲渚冷，露滴盤中圓。", "好花生木末，衰蕙愁空園。", "夜天如玉砌，池葉極青錢。", "僅厭舞衫薄，稍知花簟寒。", "曉風何拂拂，北斗光闌干。"]'),
('449f1e98-a05e-49b7-9889-9ec3b83028f5','河南府試十二月樂詞 八月','李賀','唐','唐诗','tang','','[]','孀妾怨夜長，獨客夢歸家。',48,'全唐诗/poet.tang.20000.json','["孀妾怨夜長，獨客夢歸家。", "傍簷蟲緝絲，向壁燈垂花。", "簾外月光吐，簾內樹影斜。", "悠悠飛露姿，點綴池中荷。"]'),
('490c93ea-fe03-429a-bb4a-7449b67b010d','河南府試十二月樂詞 九月','李賀','唐','唐诗','tang','','[]','離宮散螢天似水，竹黃池冷芙蓉死。',65,'全唐诗/poet.tang.20000.json','["離宮散螢天似水，竹黃池冷芙蓉死。", "月綴金鋪光脈脈，涼苑虛庭空澹白。", "露花飛飛風草草，翠錦斕斑滿層道。", "雞人罷唱曉瓏璁𤧚，鴉啼金井下疎桐。"]'),
('466d4a0b-4f78-42b8-bb58-f82dfd417011','河南府試十二月樂詞 十月','李賀','唐','唐诗','tang','','[]','玉壺銀箭稍難傾，釭花夜笑凝幽明。',56,'全唐诗/poet.tang.20000.json','["玉壺銀箭稍難傾，釭花夜笑凝幽明。", "碎霜斜舞上羅幕，燭龍兩行照飛閣。", "珠帷怨臥不成眠，金鳳刺衣著體寒，長眉對月鬬彎環。"]'),
('f36afa21-659d-4c53-951f-95b112fb00d9','河南府試十二月樂詞 十一月','李賀','唐','唐诗','tang','','[]','宮城團迴凜嚴光，白天碎碎墮瓊芳。',32,'全唐诗/poet.tang.20000.json','["宮城團迴凜嚴光，白天碎碎墮瓊芳。", "撾鍾高飲千日酒，却天凝寒作君壽。"]'),
('e261fc91-5868-45d2-af14-8c55afdecfc8','河南府試十二月樂詞 十二月','李賀','唐','唐诗','tang','','[]','日脚淡光紅灑灑，薄霜不銷桂枝下。',32,'全唐诗/poet.tang.20000.json','["日脚淡光紅灑灑，薄霜不銷桂枝下。", "依稀和氣排冬嚴，已就長日辭長夜。"]'),
('851219e8-5993-4d52-868a-8dfe431c0ddb','河南府試十二月樂詞 閏月','李賀','唐','唐诗','tang','','[]','帝重光，年重時。',40,'全唐诗/poet.tang.20000.json','["帝重光，年重時。", "七十二候迴環推，天官玉琯灰剩飛。", "今歲何長來歲遲，王母移桃獻天子。"]'),
('681fe831-2fb0-4bae-bb2a-41d499309c7a','天上謠','李賀','唐','唐诗','tang','','[]','天河夜轉漂迴星，銀浦流雲學水聲。',96,'全唐诗/poet.tang.20000.json','["天河夜轉漂迴星，銀浦流雲學水聲。", "玉宮桂樹花未落，仙妾採香垂珮纓。", "秦妃卷簾北窗曉，窗前植桐青鳳小。", "王子吹笙鵞管長，呼龍耕煙種瑤草。", "粉霞紅綬藕絲裙，青洲步拾蘭苕春。", "東指羲和能走馬，海塵新生石山下。"]'),
('41a7ff30-5f3a-44dd-bdf9-217b0772d04e','浩歌','李賀','唐','唐诗','tang','','["\u6625\u5929", "\u6292\u6000", "\u5199\u666f"]','南風吹山作平地，帝遣天吳移海水。',128,'全唐诗/poet.tang.20000.json','["南風吹山作平地，帝遣天吳移海水。", "王母桃花千遍紅，彭祖巫咸幾回死。", "青毛驄馬參差錢，嬌春楊柳含細煙。", "箏人勸我金屈巵，神血未凝身問誰。", "不須浪飲丁都護，世上英雄本無主。", "買絲繡作平原君，有酒惟澆趙州土。", "漏催水咽玉蟾蜍，衛娘髮薄不勝梳。", "看見秋眉換新綠，二十男兒那刺促。"]'),
('58301f45-20a8-4430-9da2-73aa936311b0','秋來','李賀','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u9b3c", "\u60b2\u79cb"]','桐風驚心壯士苦，衰燈絡緯啼寒素。',64,'全唐诗/poet.tang.20000.json','["桐風驚心壯士苦，衰燈絡緯啼寒素。", "誰看青簡一編書，不遣花蟲粉空蠹。", "思牽今夜腸應直，雨冷香魂弔書客。", "秋墳鬼唱鮑家詩，恨血千年土中碧。"]'),
('68f64cf6-fb41-4aeb-9649-612828fa994f','帝子歌','李賀','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭明月一千里，涼風雁啼天在水。',64,'全唐诗/poet.tang.20000.json','["洞庭明月一千里，涼風雁啼天在水。", "九節菖蒲石上死，湘神彈琴迎帝子。", "山頭老桂吹古香，雌龍怨吟寒水光。", "沙浦走魚白石郎，閑取真珠擲龍堂。"]'),
('20940092-30e7-45fb-b74d-866aa0f9368d','秦王飲酒','李賀','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u5199\u4eba", "\u8bbd\u55bb", "\u5199\u4eba\u8bd7"]','秦王騎虎遊八極，劒光照空天自碧。',120,'全唐诗/poet.tang.20000.json','["秦王騎虎遊八極，劒光照空天自碧。", "羲和敲日玻璃聲，劫灰飛盡古今平。", "龍頭瀉酒邀酒星，金槽琵琶夜棖棖。", "洞庭雨脚來吹笙，酒酣喝月使倒行。", "銀雲櫛櫛瑤殿明，宮門掌事報一更。", "花樓玉鳳聲嬌獰，海綃紅文香淺清。", "黃鵞跌舞千年觥，仙人燭樹蠟煙輕，清琴醉眼淚泓泓。"]'),
('4ce0824b-965f-482e-bf01-ce11bb71519a','洛姝真珠','李賀','唐','唐诗','tang','','[]','真珠小娘下清廓，洛苑香風飛綽綽。',128,'全唐诗/poet.tang.20000.json','["真珠小娘下清廓，洛苑香風飛綽綽。", "寒鬢斜釵玉燕光，高樓唱月敲懸璫。", "蘭風桂露灑幽翠，紅弦褭雲咽深思。", "花袍白馬不歸來，濃蛾疊柳香脣醉。", "金鵞屏風蜀山夢，鸞裾鳳帶行煙重。", "八驄籠晃臉差移，日絲繁散曛羅洞。", "市南曲陌無秋涼，楚腰衛鬢四時芳。", "玉喉窱窱排空光，牽雲曳雪留陸郎。"]'),
('7bd22cdb-d78e-4bd5-af73-b08be1974bbe','李夫人歌','李賀','唐','唐诗','tang','','[]','紫皇宮殿重重開，夫人飛入瓊瑤臺。',80,'全唐诗/poet.tang.20000.json','["紫皇宮殿重重開，夫人飛入瓊瑤臺。", "綠香繡帳何時歇，青雲無光宮水咽。", "翩聯桂花墜秋月，孤鸞驚啼商絲發。", "紅壁闌珊懸珮璫，歌臺小妓遙相望。", "玉蟾滴水雞人唱，露華蘭葉參差光。"]'),
('9b8850ed-6675-484b-90da-32b3125eff83','走馬引','李賀','唐','唐诗','tang','','[]','我有辭鄉劒，玉鋒堪截雲。',48,'全唐诗/poet.tang.20000.json','["我有辭鄉劒，玉鋒堪截雲。", "襄陽走馬客，意氣自生春。", "朝嫌劒花淨，暮嫌劒光冷。", "能持劒向人，不解持照身。"]'),
('a61b7143-b9e1-4f90-8377-a0b43ba22469','湘妃','李賀','唐','唐诗','tang','','[]','筠竹千年老不死，長伴秦娥蓋湘水。',64,'全唐诗/poet.tang.20000.json','["筠竹千年老不死，長伴秦娥蓋湘水。", "蠻娘吟弄滿寒空，九山靜綠淚花紅。", "離鸞別鳳煙梧中，巫雲蜀雨遙相通。", "幽愁秋氣上青楓，涼夜波間吟古龍。"]'),
('6766c804-9532-42e3-b85d-d0d4d8bccecf','南園十三首 一','李賀','唐','唐诗','tang','','[]','花枝草蔓眼中開，小白長紅越女腮。',32,'全唐诗/poet.tang.20000.json','["花枝草蔓眼中開，小白長紅越女腮。", "可憐日暮嫣香落，嫁與春風不用媒。"]'),
('f7be70b4-9936-4c6b-85fc-0424a0585aaa','南園十三首 二','李賀','唐','唐诗','tang','','[]','宮北田塍曉氣酣，黃桑飲露窣宮簾。',32,'全唐诗/poet.tang.20000.json','["宮北田塍曉氣酣，黃桑飲露窣宮簾。", "長腰健婦偷攀折，將餧吳王八蠒蠶。"]'),
('21e0b774-e999-4b7a-9e1d-25160d5398c8','南園十三首 三','李賀','唐','唐诗','tang','','[]','竹裏繰絲挑網車，青蟬獨噪日光斜。',32,'全唐诗/poet.tang.20000.json','["竹裏繰絲挑網車，青蟬獨噪日光斜。", "桃膠迎夏香琥珀，自課越傭能種瓜。"]'),
('daa7ff23-495a-4b06-ac17-e74485a5a79a','南園十三首 四','李賀','唐','唐诗','tang','','[]','三十未有二十餘，白日長飢小甲蔬。',32,'全唐诗/poet.tang.20000.json','["三十未有二十餘，白日長飢小甲蔬。", "橋頭長老相哀念，因遺戎韜一卷書。"]'),
('b810b1ca-557d-4589-bebb-766e3bec858d','南園十三首 五','李賀','唐','唐诗','tang','','["\u7231\u56fd", "\u52b1\u5fd7", "\u5e26\u6709\u5730\u540d", "\u5730\u540d"]','男兒何不帶吳鉤，收取關山五十州。',32,'全唐诗/poet.tang.20000.json','["男兒何不帶吳鉤，收取關山五十州。", "請君暫上凌煙閣，若箇書生萬戶侯。"]'),
('22f75e20-7e62-4c0e-93ca-f71ebba61fa6','南園十三首 六','李賀','唐','唐诗','tang','','[]','尋章摘句老雕蟲，曉月當簾挂玉弓。',32,'全唐诗/poet.tang.20000.json','["尋章摘句老雕蟲，曉月當簾挂玉弓。", "不見年年遼海上，文章何處哭秋風。"]'),
('62b591eb-db79-4031-a251-393685fe82ff','南園十三首 七','李賀','唐','唐诗','tang','','[]','長卿牢落悲空舍，曼倩詼諧取自容。',32,'全唐诗/poet.tang.20000.json','["長卿牢落悲空舍，曼倩詼諧取自容。", "見買若耶溪水劒，明朝歸去事猨公。"]'),
('60fb1559-a65f-4dab-97ed-ac5e568e5c77','南園十三首 八','李賀','唐','唐诗','tang','','[]','春水初生乳燕飛，黃蜂小尾撲花歸。',32,'全唐诗/poet.tang.20000.json','["春水初生乳燕飛，黃蜂小尾撲花歸。", "窗含遠色通書幌，魚擁香鉤近石磯。"]'),
('d1ec4bb4-6f3b-4f1b-accf-a861c00c088d','南園十三首 九','李賀','唐','唐诗','tang','','[]','泉沙耎臥鴛鴦暖，曲岸迴篙舴艋遲。',32,'全唐诗/poet.tang.20000.json','["泉沙耎臥鴛鴦暖，曲岸迴篙舴艋遲。", "瀉酒木欄椒葉蓋，病容扶起種菱絲。"]'),
('19bb5bca-4b8e-48f2-a343-664238cc8f92','南園十三首 十','李賀','唐','唐诗','tang','','[]','邊讓今朝憶蔡邕，無心裁曲臥春風。',32,'全唐诗/poet.tang.20000.json','["邊讓今朝憶蔡邕，無心裁曲臥春風。", "舍南有竹堪書字，老去溪頭作釣翁。"]'),
('32f9d2a4-562b-41b6-8908-54ddeae48f90','南園十三首 十一','李賀','唐','唐诗','tang','','[]','長巒谷口倚嵇家，白晝千峰老翠華。',32,'全唐诗/poet.tang.20000.json','["長巒谷口倚嵇家，白晝千峰老翠華。", "自履藤鞋收石蜜，手牽苔絮長蒓花。"]'),
('ea8a85f0-c040-4d22-a1a5-ac73d071c92d','南園十三首 十二','李賀','唐','唐诗','tang','','[]','松溪黑水新龍卵，桂洞生硝舊馬牙。',32,'全唐诗/poet.tang.20000.json','["松溪黑水新龍卵，桂洞生硝舊馬牙。", "誰遣虞卿裁道帔，輕綃一匹染朝霞。"]'),
('d3a57a70-7001-44b7-9027-ba29a150c8bb','南園十三首 十三','李賀','唐','唐诗','tang','','[]','小樹開朝逕，長茸溼夜煙。',48,'全唐诗/poet.tang.20000.json','["小樹開朝逕，長茸溼夜煙。", "柳花驚雪浦，麥雨漲溪田。", "古剎疎鐘度，遙嵐破月懸。", "沙頭敲石火，燒竹照漁船。"]'),
('56f01a7d-2d53-4191-b6e4-7cc94fa76515','金銅仙人辭漢歌','李賀','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6000\u53e4", "\u79bb\u522b", "\u611f\u4f24"]','茂陵劉郎秋風客，夜聞馬嘶曉無跡。',96,'全唐诗/poet.tang.20000.json','["茂陵劉郎秋風客，夜聞馬嘶曉無跡。", "畫欄桂樹懸秋香，三十六宮土花碧。", "魏官牽車指千里，東關酸風射眸子。", "空將漢月出宮門，憶君清淚如鉛水。", "衰蘭送客咸陽道，天若有情天亦老。", "攜盤獨出月荒涼，渭城已遠波聲小。"]'),
('82db064c-c110-44e1-a74f-c0bc0caa831a','古悠悠行','李賀','唐','唐诗','tang','','[]','白景歸西山，碧華上迢迢。',48,'全唐诗/poet.tang.20000.json','["白景歸西山，碧華上迢迢。", "今古何處盡，千歲隨風飄。", "海沙變成石，魚沫吹秦橋。", "空光遠流浪，銅柱從年消。"]'),
('05af0540-9332-454f-ad42-e94a93a45df4','黃頭郎','李賀','唐','唐诗','tang','','["\u6000\u4eba", "\u5199\u4eba", "\u5987\u5973", "\u5199\u4eba\u8bd7"]','黃頭郎，撈攏去不歸。',70,'全唐诗/poet.tang.20000.json','["黃頭郎，撈攏去不歸。", "南浦芙蓉影，愁紅獨自垂。", "水弄湘娥珮，竹啼山露月。", "玉瑟調青門，石雲溼黃葛。", "沙上蘼蕪花，秋風已先發。", "好持掃羅薦，香出鴛鴦熱。"]'),
('3ad494dc-1f51-4918-bb12-f85f371d5cc6','馬詩二十三首 一','李賀','唐','唐诗','tang','','["\u9a6c", "\u6292\u6000", "\u5199\u9a6c", "\u6000\u624d\u4e0d\u9047"]','龍脊貼連錢，銀蹄白踏煙。',24,'全唐诗/poet.tang.20000.json','["龍脊貼連錢，銀蹄白踏煙。", "無人織錦韂，誰爲鑄金鞭。"]'),
('ad120d2f-ce6b-47ef-915e-737b8cb5ccca','馬詩二十三首 二','李賀','唐','唐诗','tang','','["\u9a6c", "\u5199\u9a6c", "\u8d5e\u7f8e", "\u54c1\u683c"]','臘月草根甜，天街雪似鹽。',24,'全唐诗/poet.tang.20000.json','["臘月草根甜，天街雪似鹽。", "未知口硬軟，先擬蒺藜銜。"]'),
('2f8c7c7f-a625-4201-a873-a4d653d64a27','馬詩二十三首 三','李賀','唐','唐诗','tang','','["\u9a6c", "\u5199\u9a6c", "\u6124\u6168", "\u6000\u624d\u4e0d\u9047"]','忽憶周天子，驅車上玉山。',24,'全唐诗/poet.tang.20000.json','["忽憶周天子，驅車上玉山。", "鳴騶辭鳳苑，赤驥最承恩。"]'),
('b0bca75a-a429-449f-abf5-9e1e0c8cc483','馬詩二十三首 四','李賀','唐','唐诗','tang','','["\u9a6c", "\u6292\u6000", "\u5199\u9a6c", "\u6000\u624d\u4e0d\u9047"]','此馬非凡馬，房星本是星。',24,'全唐诗/poet.tang.20000.json','["此馬非凡馬，房星本是星。", "向前敲瘦骨，猶自帶銅聲。"]'),
('b1ccc932-7dd7-429c-9868-948a1f91e4f1','馬詩二十三首 五','李賀','唐','唐诗','tang','','["\u6218\u4e89", "\u5199\u9a6c", "\u5199\u666f", "\u8fb9\u585e", "\u548f\u7269\u8bd7", "\u516d\u5e74\u7ea7\u4e0a\u518c"]','大漠山如雪，燕山月似鉤。',24,'全唐诗/poet.tang.20000.json','["大漠山如雪，燕山月似鉤。", "何當金絡腦，快走踏清秋。"]'),
('9e8e4fea-14d1-41d0-a777-ddaf67da6146','馬詩二十三首 六','李賀','唐','唐诗','tang','','[]','飢臥骨查牙，粗毛刺破花。',24,'全唐诗/poet.tang.20000.json','["飢臥骨查牙，粗毛刺破花。", "鬣焦朱色落，髮斷鋸長麻。"]'),
('38b65cdf-a0e4-4590-ada7-2b2538293225','馬詩二十三首 七','李賀','唐','唐诗','tang','','[]','西母酒將闌，東王飯已乾。',24,'全唐诗/poet.tang.20000.json','["西母酒將闌，東王飯已乾。", "君王若燕去，誰爲拽車轅。"]'),
('2516db4e-350d-4d95-83b9-ed69ee9687a3','馬詩二十三首 八','李賀','唐','唐诗','tang','','["\u9a6c", "\u5199\u9a6c", "\u6124\u6168", "\u6000\u624d\u4e0d\u9047"]','赤兔無人用，當須呂布騎。',24,'全唐诗/poet.tang.20000.json','["赤兔無人用，當須呂布騎。", "吾聞果下馬，羇策任蠻兒。"]'),
('b2f6a1de-496c-41bf-9454-f06b9e31cd7c','馬詩二十三首 九','李賀','唐','唐诗','tang','','["\u9a6c", "\u5199\u9a6c", "\u6124\u6168", "\u6000\u624d\u4e0d\u9047"]','飂叔去怱怱，如今不豢龍。',24,'全唐诗/poet.tang.20000.json','["飂叔去怱怱，如今不豢龍。", "夜來霜壓棧，駿骨折西風。"]'),
('f3ced668-1a31-4bfb-a688-4a21b6d20301','馬詩二十三首 十','李賀','唐','唐诗','tang','','[]','摧榜渡烏江，神騅泣向風。',12,'全唐诗/poet.tang.20000.json','["摧榜渡烏江，神騅泣向風。"]'),
('68830ff6-060c-4f73-95fc-202d6e1ce252','馬詩二十三首 十一','李賀','唐','唐诗','tang','','[]','內馬賜宮人，銀韉刺騏驎。',24,'全唐诗/poet.tang.20000.json','["內馬賜宮人，銀韉刺騏驎。", "午時鹽坂上，蹭蹬溘風塵。"]'),
('e3daa457-1d07-4caa-bf36-8b3c379a7333','馬詩二十三首 十二','李賀','唐','唐诗','tang','','[]','批竹初攢耳，桃花未上身。',24,'全唐诗/poet.tang.20000.json','["批竹初攢耳，桃花未上身。", "他時須攪陣，牽去借將軍。"]'),
('8ecb39f4-671a-4916-ac2d-095e3ad44e8f','馬詩二十三首 十三','李賀','唐','唐诗','tang','','[]','寶玦誰家子，長聞俠骨香。',24,'全唐诗/poet.tang.20000.json','["寶玦誰家子，長聞俠骨香。", "堆金買駿骨，將送楚襄王。"]'),
('cd42be7e-4ad9-4998-87a3-48dbbd9e6be8','馬詩二十三首 十四','李賀','唐','唐诗','tang','','[]','香襆赭羅新，盤龍蹙鐙鱗。',24,'全唐诗/poet.tang.20000.json','["香襆赭羅新，盤龍蹙鐙鱗。", "迴看南陌上，誰道不逢春。"]'),
('321a9b5e-291a-47ae-bce9-c8d80d8018fa','馬詩二十三首 十五','李賀','唐','唐诗','tang','','[]','不從桓公獵，何能伏虎威。',24,'全唐诗/poet.tang.20000.json','["不從桓公獵，何能伏虎威。", "一朝溝隴出，看取拂雲飛。"]'),
('9544e82e-2666-4419-aed1-8b941648f6e6','馬詩二十三首 十六','李賀','唐','唐诗','tang','','[]','唐劍斬隋公，拳毛屬太宗。',24,'全唐诗/poet.tang.20000.json','["唐劍斬隋公，拳毛屬太宗。", "莫嫌金甲重，且去捉𩘶風。"]'),
('1847269f-3877-4dd5-826e-8c912f111efe','馬詩二十三首 十七','李賀','唐','唐诗','tang','','[]','白鐵剉青禾，碪間落細莎。',24,'全唐诗/poet.tang.20000.json','["白鐵剉青禾，碪間落細莎。", "世人憐小頸，金埒畏長牙。"]'),
('cb5a4269-c06a-4c8a-bb03-a65a24b5baeb','馬詩二十三首 十八','李賀','唐','唐诗','tang','','["\u9a6c", "\u5199\u9a6c", "\u6124\u6168", "\u6000\u624d\u4e0d\u9047"]','伯樂向前看，旋毛在腹間。',24,'全唐诗/poet.tang.20000.json','["伯樂向前看，旋毛在腹間。", "祗今掊白草，何日驀青山。"]'),
('d28d4e75-7433-4044-a078-82547323d997','馬詩二十三首 十九','李賀','唐','唐诗','tang','','[]','蕭寺馱經馬，元從竺國來。',24,'全唐诗/poet.tang.20000.json','["蕭寺馱經馬，元從竺國來。", "空知有善相，不解走章臺。"]'),
('d7062712-dbd0-414b-a528-36496930d3e1','馬詩二十三首 二十','李賀','唐','唐诗','tang','','[]','重圍如燕尾，寶劍似魚腸。',24,'全唐诗/poet.tang.20000.json','["重圍如燕尾，寶劍似魚腸。", "欲求千里脚，先采眼中光。"]'),
('b5becd0c-e3f6-432a-ae2b-a17683098860','馬詩二十三首 二十一','李賀','唐','唐诗','tang','','[]','暫繫騰黃馬，仙人上綵樓。',24,'全唐诗/poet.tang.20000.json','["暫繫騰黃馬，仙人上綵樓。", "須鞭玉勒吏，何事謫高州。"]'),
('e08d02a9-041f-4864-a26c-6e6f5a612d5a','馬詩二十三首 二十二','李賀','唐','唐诗','tang','','[]','汗血到王家，隨鸞撼玉珂。',24,'全唐诗/poet.tang.20000.json','["汗血到王家，隨鸞撼玉珂。", "少君騎海上，人見是青騾。"]'),
('2fe1085b-c5a4-4dd5-a9e0-286066b0d923','馬詩二十三首 二十三','李賀','唐','唐诗','tang','','["\u5bd3\u4eba", "\u9a6c", "\u501f\u53e4\u8bbd\u4eca", "\u5199\u9a6c"]','武帝愛神仙，燒金得紫煙。',24,'全唐诗/poet.tang.20000.json','["武帝愛神仙，燒金得紫煙。", "廐中皆肉馬，不解上青天。"]'),
('7344a621-9c5b-435b-ab03-5bce85d24ce2','申胡子觱篥歌','李賀','唐','唐诗','tang','','[]','顏熱感君酒，含嚼蘆中聲。',96,'全唐诗/poet.tang.20000.json','["顏熱感君酒，含嚼蘆中聲。", "花娘篸綏妥，休睡芙蓉屏。", "誰截太平管，列點排空星。", "直貫開花風，天上驅雲行。", "今夕歲華落，令人惜平生。", "心事如波濤，中坐時時驚。", "朔客騎白馬，劍弝懸蘭纓。", "俊健如生猱，肯拾蓬中螢。"]'),
('c8ca253f-7981-4bcc-a6dc-b7444401d39f','老夫採玉歌','李賀','唐','唐诗','tang','','[]','採玉採玉須水碧，琢作步搖徒好色。',96,'全唐诗/poet.tang.20000.json','["採玉採玉須水碧，琢作步搖徒好色。", "老夫飢寒龍爲愁，藍溪水氣無清白。", "夜雨岡頭食蓁子，杜鵑口血老夫淚。", "藍溪之水厭生人，身死千年恨溪水。", "斜山柏風雨如嘯，泉脚挂繩青褭褭。", "村寒白屋念嬌嬰，古臺石磴懸腸草。"]'),
('bfdbb451-5c25-4b22-9e1f-a6632ec76ded','傷心行','李賀','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u5199\u666f"]','咽咽學楚吟，病骨傷幽素。',48,'全唐诗/poet.tang.20000.json','["咽咽學楚吟，病骨傷幽素。", "秋姿白髮生，木葉啼風雨。", "燈青蘭膏歇，落照飛蛾舞。", "古壁生凝塵，羇魂夢中語。"]'),
('0aaa9d12-9f44-4cb4-8aac-a78a92553844','湖中曲','李賀','唐','唐诗','tang','','[]','長眉越沙採蘭若，桂葉水葓春漠漠。',64,'全唐诗/poet.tang.20000.json','["長眉越沙採蘭若，桂葉水葓春漠漠。", "橫船醉眠白晝閑，渡口梅風歌扇薄。", "燕釵玉股照青渠，越王嬌郎小字書。", "蜀紙封巾報雲鬢，晚漏壺中水淋盡。"]'),
('da48aa4d-256d-4e2f-a2aa-983f13a9c601','黃家洞','李賀','唐','唐诗','tang','','["\u53d9\u4e8b", "\u6218\u4e89", "\u751f\u6d3b"]','雀步蹙沙聲促促，四尺角弓青石鏃。',80,'全唐诗/poet.tang.20000.json','["雀步蹙沙聲促促，四尺角弓青石鏃。", "黑幡三點銅鼓鳴，高作猨啼搖箭箙。", "綵巾纏踍幅半斜，溪頭簇隊暎葛花。", "山潭晚霧吟白鼉，竹蛇飛蠹射金沙。", "閑驅竹馬緩歸家，官軍自殺容州槎。"]'),
('f1afe006-f5d7-46a5-8c31-d77b80134155','屏風曲','李賀','唐','唐诗','tang','','[]','蝶棲石竹銀交關，水凝綠鴨瑠璃錢。',64,'全唐诗/poet.tang.20000.json','["蝶棲石竹銀交關，水凝綠鴨瑠璃錢。", "團迴六曲抱膏蘭，將鬟鏡上擲金蟬。", "沈香火暖茱萸煙，酒觥綰帶新承懽。", "月風吹露屏外寒，城上烏啼楚女眠。"]'),
('1d44c69a-e64a-44d4-9576-9ea3bf805533','南山田中行','李賀','唐','唐诗','tang','','["\u79cb\u5929", "\u5199\u666f"]','秋野明，秋風白，塘水漻漻蟲嘖嘖。',64,'全唐诗/poet.tang.20000.json','["秋野明，秋風白，塘水漻漻蟲嘖嘖。", "雲根苔蘚山上石，冷紅泣露嬌啼色。", "荒畦九月稻叉牙，蟄螢低飛隴逕斜。", "石脈水流泉滴沙，鬼燈如漆點松花。"]'),
('1e5b7ea7-dbf3-4be0-820b-afa48ba1d10d','貴主征行樂','李賀','唐','唐诗','tang','','[]','奚騎黃銅連鎖甲，羅旗香幹金畫葉。',64,'全唐诗/poet.tang.20000.json','["奚騎黃銅連鎖甲，羅旗香幹金畫葉。", "中軍留醉河陽城，嬌嘶紫燕踏花行。", "春營騎將如紅玉，走馬捎鞭上空綠。", "女垣素月角吚吚，牙帳未開分錦衣。"]'),
('317e061a-3b17-440f-8152-3fed3c0521e2','酒罷張大徹索贈詩','李賀','唐','唐诗','tang','','[]','長鬣張郎三十八，天遣裁詩花作骨。',96,'全唐诗/poet.tang.20000.json','["長鬣張郎三十八，天遣裁詩花作骨。", "往還誰是龍頭人，公主遣秉魚須笏。", "太行青草上白衫，匣中章奏密如蠶。", "金門石閣知卿有，豸角雞香早晚含。", "隴西長吉摧頹客，酒闌感覺中區窄。", "葛衣斷碎趙城秋，吟詩一夜東方白。"]'),
('d48cdb59-2492-497b-a8c3-11a3930448bb','羅浮山父與葛篇','李賀','唐','唐诗','tang','','[]','依依宜織江雨空，雨中六月蘭臺風。',64,'全唐诗/poet.tang.20000.json','["依依宜織江雨空，雨中六月蘭臺風。", "博羅老仙時出洞，千歲石牀啼鬼工。", "蛇毒濃凝洞堂溼，江魚不食銜沙立。", "欲剪箱中一尺天，吳娥莫道吳刀澀。"]'),
('acf90853-d3e3-4d49-8495-5052d5f550ba','仁和里雜敘皇甫湜','李賀','唐','唐诗','tang','','["\u6292\u60c5", "\u611f\u6fc0", "\u611f\u6168"]','大人乞馬癯乃寒，宗人貸宅荒厥垣。',160,'全唐诗/poet.tang.20000.json','["大人乞馬癯乃寒，宗人貸宅荒厥垣。", "橫庭鼠徑空土澀，出籬大棗垂朱殘。", "安定美人截黃綬，脫落纓裾瞑朝酒。", "還家白筆未上頭，使我清聲落人後。", "枉辱稱知犯君眼，排引纔陞強絙斷。", "洛風送馬入長關，闔扇未開逢猰犬。", "那知堅都相草草，客枕幽單看春老。", "歸來骨薄面無膏，疫氣衝頭鬢莖少。", "欲雕小說干天官，宗孫不調爲誰憐。", "明朝下元復西道，崆峒敘別長如天。"]'),
('e0e70d45-6b58-4da7-a310-20eba5f99759','宮娃歌','李賀','唐','唐诗','tang','','["\u906d\u9047", "\u5199\u4eba", "\u5b64\u5bc2", "\u540c\u60c5", "\u5199\u4eba\u8bd7"]','蠟光高懸照紗空，花房夜擣紅守宮。',96,'全唐诗/poet.tang.20000.json','["蠟光高懸照紗空，花房夜擣紅守宮。", "象口吹香毾㲪暖，七星挂城聞漏板。", "寒入罘罳殿影昏，彩鸞簾額著霜痕。", "啼蛄弔月鉤欄下，屈膝銅鋪鎖阿甄。", "夢入家門上沙渚，天河落處長洲路。", "願君光明如太陽，放妾騎魚撇波去。"]'),
('b424ec07-c22f-4298-afc7-67867346083e','堂堂','李賀','唐','唐诗','tang','','[]','堂堂復堂堂，紅脫梅灰香。',60,'全唐诗/poet.tang.20000.json','["堂堂復堂堂，紅脫梅灰香。", "十年粉蠹生畫梁，飢蟲不食推碎黃。", "蕙花已老桃葉長，禁院懸簾隔御光。", "華清源中礜石湯，裴回白鳳隨君王。"]'),
('51fc09e9-17cd-49ff-934e-cd19b4f46522','勉愛行二首送小季之廬山 一','李賀','唐','唐诗','tang','','["\u5e90\u5c71"]','洛郊無俎豆，弊廐慙老馬。',48,'全唐诗/poet.tang.20000.json','["洛郊無俎豆，弊廐慙老馬。", "小雁過鑪峰，影落楚水下。", "長船倚雲泊，石鏡秋涼夜。", "豈解有鄉情，弄月聊嗚啞。"]'),
('b724197b-7e08-48dc-ae31-73b45d05f7ba','勉愛行二首送小季之廬山 二','李賀','唐','唐诗','tang','','["\u5e90\u5c71", "\u79bb\u522b", "\u4e0d\u820d", "\u6101\u7eea"]','別柳當馬頭，官槐如兔目。',120,'全唐诗/poet.tang.20000.json','["別柳當馬頭，官槐如兔目。", "欲將千里別，持我易斗粟。", "南雲北雲空脈斷，靈臺經絡懸春綫。", "青軒樹轉月滿牀，下國飢兒夢中見。", "維爾之昆二十餘，年來持鏡頗有鬚。", "辭家三載今如此，索米王門一事無。", "荒溝古水光如刀，庭南拱柳生蠐螬。", "江干幼客真可念，郊原晚吹悲號號。"]'),
('a72113fb-a98f-45a8-8ba3-187f3f48f7aa','致酒行','李賀','唐','唐诗','tang','','[]','零落棲遲一杯酒，主人奉觴客長壽。',98,'全唐诗/poet.tang.20000.json','["零落棲遲一杯酒，主人奉觴客長壽。", "主父西遊困不歸，家人折斷門前柳。", "吾聞馬周昔作新豐客，天荒地老無人識。", "空將牋上兩行書，直犯龍顏請恩澤。", "我有迷魂招不得，雄雞一聲天下白。", "少年心事當拏雲，誰念幽寒坐嗚呃。"]'),
('acb07724-e918-43a3-aa7e-468a38763397','長歌續短歌','李賀','唐','唐诗','tang','','["\u6292\u60c5", "\u4ed5\u9014", "\u6124\u61d1"]','長歌破衣襟，短歌斷白髮。',84,'全唐诗/poet.tang.20000.json','["長歌破衣襟，短歌斷白髮。", "秦王不可見，旦夕成內熱。", "渴飲壺中酒，飢拔隴頭粟。", "淒淒四月闌，千里一時綠。", "夜峰何離離，明月落石底。", "裴回沿石尋，照出高峰外。", "不得與之遊，歌成鬢先改。"]'),
('16957082-263a-4df2-8c19-2089529655ec','公莫舞歌','李賀','唐','唐诗','tang','','[]','方花古礎排九楹，刺豹淋血盛銀甖。',128,'全唐诗/poet.tang.20000.json','["方花古礎排九楹，刺豹淋血盛銀甖。", "華筵鼓吹無桐竹，長刀直立割鳴箏。", "橫楣麤錦生紅緯，日炙錦嫣王未醉。", "腰下三看寶玦光，項莊掉箾欄前起。", "材官小臣公莫舞，座上真人赤龍子。", "芒碭雲端抱天迴，咸陽王氣清如水。", "鐵樞鐵楗重束關，大旗五丈撞雙鐶。", "漢王今日頒秦印，絕臏刳腸臣不論。"]'),
('a9a139ef-ff30-4fc2-9842-d7a9b3574324','昌谷北園新笋四首 一','李賀','唐','唐诗','tang','','[]','籜落長竿削玉開，君看母笋是龍材。',32,'全唐诗/poet.tang.20000.json','["籜落長竿削玉開，君看母笋是龍材。", "更容一夜抽千尺，別却池園數寸泥。"]'),
('07b8b26f-a5e9-4c40-b74c-eaf253688e9f','昌谷北園新笋四首 二','李賀','唐','唐诗','tang','','[]','斫取青光寫楚辭，膩香春粉黑離離。',32,'全唐诗/poet.tang.20000.json','["斫取青光寫楚辭，膩香春粉黑離離。", "無情有恨何人見，露壓煙啼千萬枝。"]'),
('c684b750-6e49-4153-8303-905684c0f6fb','昌谷北園新笋四首 三','李賀','唐','唐诗','tang','','[]','家泉石眼兩三莖，曉看陰根紫脈生。',32,'全唐诗/poet.tang.20000.json','["家泉石眼兩三莖，曉看陰根紫脈生。", "今年水曲春沙上，笛管新篁拔玉青。"]'),
('a1a49d92-891b-44bf-9e83-d2ea5f7ed85f','昌谷北園新笋四首 四','李賀','唐','唐诗','tang','','[]','古竹老梢惹碧雲，茂陵歸臥歎清貧。',32,'全唐诗/poet.tang.20000.json','["古竹老梢惹碧雲，茂陵歸臥歎清貧。", "風吹千畝迎雨嘯，鳥重一枝入酒尊。"]'),
('d39fe071-dea2-470e-b2b7-b48b12d4304c','惱公','李賀','唐','唐诗','tang','','[]','宋玉愁空斷，嬌饒粉自紅。',288,'全唐诗/poet.tang.20000.json','["宋玉愁空斷，嬌饒粉自紅。", "歌聲春草露，門掩杏花叢。", "注口櫻桃小，添眉桂葉濃。", "曉奩妝秀靨，夜帳減香筒。", "鈿鏡飛孤鵲，江圖畫水葓。", "陂陀梳碧鳳，腰褭帶金蟲。", "杜若含清露，河蒲聚紫茸。", "月分蛾黛破，花合靨朱融。", "髮重疑盤霧，腰輕乍倚風。", "密書題荳蔲，隱語笑芙蓉。", "莫鎖茱萸匣，休開翡翠籠。", "弄珠驚漢燕，燒蜜引胡蜂。", "醉纈拋紅網，單羅挂綠蒙。", "數錢教姹女，買藥問巴賨。", "勻臉安斜雁，移燈想夢熊。", "腸攢非束竹，胘急是張弓。", "晚樹迷新蝶，殘蜺憶斷虹。", "古時填渤澥，今日鑿崆峒。", "繡沓褰長幔，羅裙結短封。", "心搖如舞鶴，骨出似飛龍。", "井檻淋清漆，門鋪綴白銅。", "隈花開兔徑，向壁印狐蹤。", "玳瑁釘簾薄，琉璃疊扇烘。", "象牀緣素柏，瑤席卷香葱。"]'),
('560856e3-9708-4efd-9cfe-8a9c5c0fd096','感諷五首 一','李賀','唐','唐诗','tang','','[]','合浦無明珠，龍洲無木奴。',120,'全唐诗/poet.tang.20000.json','["合浦無明珠，龍洲無木奴。", "足知造化力，不給使君須。", "越婦未織作，吳蠶始蠕蠕。", "縣官騎馬來，獰色虬紫鬚。", "懷中一方板，板上數行書。", "不因使君怒，焉得詣爾廬。", "越婦拜縣官，桑牙今尚小。", "會待春日晏，絲車方擲掉。", "越婦通言語，小姑具黃粱。", "縣官踏飡去，簿吏復登堂。"]'),
('4210ab0f-985d-4ca2-bc11-037cee0d3d73','感諷五首 二','李賀','唐','唐诗','tang','','[]','奇俊無少年，日車何躃躃。',72,'全唐诗/poet.tang.20000.json','["奇俊無少年，日車何躃躃。", "我待紆雙綬，遺我星星髮。", "都門賈生墓，青蠅久斷絕。", "寒食搖揚天，憤景長肅殺。", "皇漢十二帝，唯帝稱睿哲。", "一夕信豎兒，文明永淪歇。"]'),
('44dfe6bb-4c4b-4b21-88ef-4d5699f05068','感諷五首 三','李賀','唐','唐诗','tang','','[]','南山何其悲，鬼雨灑空草。',60,'全唐诗/poet.tang.20000.json','["南山何其悲，鬼雨灑空草。", "長安夜半秋，風前幾人老。", "低迷黃昏徑，褭褭青櫟道。", "月午樹無影，一山唯白曉。", "漆炬迎新人，幽壙螢擾擾。"]'),
('272efd22-2590-4180-ab3e-245d04c0ade5','感諷五首 四','李賀','唐','唐诗','tang','','[]','星盡四方高，萬物知天曙。',48,'全唐诗/poet.tang.20000.json','["星盡四方高，萬物知天曙。", "己生須己養，荷擔出門去。", "君平久不反，康伯循國路。", "曉思何譊譊，闤闠千人語。"]'),
('14142f5f-c6e2-44f4-ac0f-9ba1c1db12ac','感諷五首 五','李賀','唐','唐诗','tang','','[]','石根秋水明，石畔秋草瘦。',72,'全唐诗/poet.tang.20000.json','["石根秋水明，石畔秋草瘦。", "侵衣野竹香，蟄蟄垂葉厚。", "岑中月歸來，蟾光挂空秀。", "桂露對仙娥，星星下雲逗。", "淒涼梔子落，山璺泣清漏。", "下有張仲蔚，披書案將朽。"]'),
('350ee905-ef68-43ab-9fd0-8e670cd02bff','三月過行宮','李賀','唐','唐诗','tang','','["\u906d\u9047", "\u5199\u4eba", "\u6292\u6000", "\u5199\u666f", "\u5199\u4eba\u8bd7"]','渠水紅繁擁御牆，風嬌小葉學娥妝。',32,'全唐诗/poet.tang.20000.json','["渠水紅繁擁御牆，風嬌小葉學娥妝。", "垂簾幾度青春老，堪鎖千年白日長。"]'),
('ccaab9e5-fc07-4957-8394-bded82237057','追和何謝銅雀妓','李賀','唐','唐诗','tang','','[]','佳人一壺酒，秋容滿千里。',48,'全唐诗/poet.tang.20000.json','["佳人一壺酒，秋容滿千里。", "石馬臥新煙，憂來何所似。", "歌聲且潛弄，陵樹風自起。", "長裾壓高臺，淚眼看花机。"]'),
('9374b699-91e7-4c44-a4ba-d6612fa297fb','送秦光祿北征','李賀','唐','唐诗','tang','','[]','北虜膠堪折，秋沙亂曉鼙。',264,'全唐诗/poet.tang.20000.json','["北虜膠堪折，秋沙亂曉鼙。", "髯胡頻犯塞，驕氣似橫霓。", "灞水樓船渡，營門細柳開。", "將軍馳白馬，豪彥騁雄材。", "箭射欃槍落，旗懸日月低。", "榆稀山易見，甲重馬頻嘶。", "天遠星光沒，沙平草葉齊。", "風吹雲路火，雪汙玉關泥。", "屢斷呼韓頸，曾然董卓臍。", "太常猶舊寵，光祿是新隮。", "寶玦麒麟起，銀壺狒狖啼。", "桃花連馬發，綵絮撲鞍來。", "呵臂懸金斗，當脣注玉罍。", "清蘇和碎蟻，紫膩卷浮杯。", "虎鞹先蒙馬，魚腸且斷犀。", "䟃𧽼西旅狗，蹙額北方奚。", "守帳然香暮，看鷹永夜棲。", "黃龍就別鏡，青塚念陽臺。", "周處長橋役，侯調短弄哀。", "錢塘階鳳羽，正室擘鸞釵。", "內子攀琪樹，羌兒奏落梅。", "今朝擎劒去，何日刺蛟迴。"]'),
('b0f600ea-90fe-49ef-8c68-fbc1fa2c3be8','酬荅二首 一','李賀','唐','唐诗','tang','','[]','金魚公子夾衫長，密裝腰鞓割玉方。',32,'全唐诗/poet.tang.20000.json','["金魚公子夾衫長，密裝腰鞓割玉方。", "行處春風隨馬尾，柳花偏打內家香。"]'),
('453b1561-a1c1-4667-995f-4445c2039b97','酬荅二首 二','李賀','唐','唐诗','tang','','[]','雍州二月梅池春，御水鵁鶄暖白蘋。',32,'全唐诗/poet.tang.20000.json','["雍州二月梅池春，御水鵁鶄暖白蘋。", "試問酒旗歌板地，今朝誰是抝花人。"]'),
('d0457707-c9f1-4af6-aaa9-87ad58c36e79','畫角東城','李賀','唐','唐诗','tang','','[]','河轉曙蕭蕭，鴉飛睥睨高。',48,'全唐诗/poet.tang.20000.json','["河轉曙蕭蕭，鴉飛睥睨高。", "帆長摽越甸，壁冷挂吳刀。", "淡菜生寒日，鮞魚潠白濤。", "水花霑抹額，旗鼓夜迎潮。"]'),
('46c575b1-ebe5-40d7-a165-2e12af5bf58f','謝秀才有妾縞練改從於人秀才留之不得[後]生感憶座人製詩嘲謝賀復繼四首 一','李賀','唐','唐诗','tang','','[]','誰知泥憶雲，望斷梨花春。',48,'全唐诗/poet.tang.20000.json','["誰知泥憶雲，望斷梨花春。", "荷絲製機練，竹葉剪花裙。", "月明啼阿姊，燈暗會良人。", "也識君夫壻，金魚挂在身。"]'),
('46b6fa89-674a-4fc1-9f16-661d6bb7955b','謝秀才有妾縞練改從於人秀才留之不得[後]生感憶座人製詩嘲謝賀復繼四首 二','李賀','唐','唐诗','tang','','[]','銅鏡立青鸞，燕脂拂紫綿。',48,'全唐诗/poet.tang.20000.json','["銅鏡立青鸞，燕脂拂紫綿。", "腮花弄暗粉，眼尾淚侵寒。", "碧玉破不復，瑤琴重撥弦。", "今日非昔日，何人敢正看。"]'),
('a7ae8fa9-d895-41fc-ad7e-d4c851facc2a','謝秀才有妾縞練改從於人秀才留之不得[後]生感憶座人製詩嘲謝賀復繼四首 三','李賀','唐','唐诗','tang','','[]','洞房思不禁，蜂子作花心。',48,'全唐诗/poet.tang.20000.json','["洞房思不禁，蜂子作花心。", "灰暖殘香炷，髮冷青蟲簪。", "夜遙燈焰短，睡熟小屏深。", "好作鴛鴦夢，南城罷擣碪。"]'),
('1595f955-a610-478e-80f7-2d23500b9a6a','謝秀才有妾縞練改從於人秀才留之不得[後]生感憶座人製詩嘲謝賀復繼四首 四','李賀','唐','唐诗','tang','','[]','尋常輕宋玉，今日嫁文鴦。',48,'全唐诗/poet.tang.20000.json','["尋常輕宋玉，今日嫁文鴦。", "戟幹橫龍簴，刀環倚桂窗。", "邀人裁半袖，端坐據胡牀。", "淚溼紅輪重，棲烏上井梁。"]'),
('90178bb0-a9eb-49a8-9e95-90406ba8e6ee','昌谷讀書示巴童','李賀','唐','唐诗','tang','','[]','蟲響燈光薄，宵寒藥氣濃。',24,'全唐诗/poet.tang.20000.json','["蟲響燈光薄，宵寒藥氣濃。", "君憐垂翅客，辛苦尚相從。"]'),
('8aee0b0a-cc97-4674-9249-8c4994f3fa28','巴童荅','李賀','唐','唐诗','tang','','[]','巨鼻宜山褐，龐眉入苦吟。',24,'全唐诗/poet.tang.20000.json','["巨鼻宜山褐，龐眉入苦吟。", "非君唱樂府，誰識怨秋深。"]'),
('ddc4142a-003e-4f0a-a1c8-8957a8095ec1','代崔家送客','李賀','唐','唐诗','tang','','[]','行蓋柳煙下，馬蹄白翩翩。',24,'全唐诗/poet.tang.20000.json','["行蓋柳煙下，馬蹄白翩翩。", "恐隨行處盡，何忍重揚鞭。"]'),
('24d03596-113c-446f-a02d-9eb6fd89e372','出城','李賀','唐','唐诗','tang','','[]','雪下桂花稀，啼烏被彈歸。',48,'全唐诗/poet.tang.20000.json','["雪下桂花稀，啼烏被彈歸。", "關水乘驢影，秦風帽帶垂。", "入鄉試萬里，無印自堪悲。", "卿卿忍相問，鏡中雙淚姿。"]'),
('aa55e6e0-786a-459f-9e8f-5d7d95b99d74','莫種樹','李賀','唐','唐诗','tang','','[]','園中莫種樹，種樹四時愁。',24,'全唐诗/poet.tang.20000.json','["園中莫種樹，種樹四時愁。", "獨睡南牀月，今秋似去秋。"]'),
('b0059347-876b-42c8-b167-f5087c5c7f34','將發','李賀','唐','唐诗','tang','','[]','東牀卷席罷，[濩]落將行去。',26,'全唐诗/poet.tang.20000.json','["東牀卷席罷，[濩]落將行去。", "秋白遙遙空，日滿門前路。"]'),
('704657df-b57f-4d75-bea8-5d1e84c521f6','追賦畫江潭苑四首 一','李賀','唐','唐诗','tang','','[]','吳苑曉蒼蒼，宮衣水濺黃。',48,'全唐诗/poet.tang.20000.json','["吳苑曉蒼蒼，宮衣水濺黃。", "小鬟紅粉薄，騎馬珮珠長。", "路指臺城迥，羅薰袴褶香。", "行雲霑翠輦，今日似襄王。"]'),
('b2df42a4-a3a4-4405-844c-de1bf5f05cb3','追賦畫江潭苑四首 二','李賀','唐','唐诗','tang','','[]','寶袜菊衣單，蕉花密露寒。',48,'全唐诗/poet.tang.20000.json','["寶袜菊衣單，蕉花密露寒。", "水光蘭澤葉，帶重剪刀錢。", "角暖盤弓易，靴長上馬難。", "淚痕霑寢帳，勻粉照金鞍。"]'),
('7cb76c4b-f352-4602-b624-e1f1e882810f','追賦畫江潭苑四首 三','李賀','唐','唐诗','tang','','[]','剪翅小鷹斜，[縚]根玉鏇花。',50,'全唐诗/poet.tang.20000.json','["剪翅小鷹斜，[縚]根玉鏇花。", "鞦垂妝鈿粟，箭箙釘文牙。", "●●啼深竹，鵁鶄老溼沙。", "宮官燒蠟火，飛燼汚鉛華。"]'),
('18e0260b-9aeb-41f5-863d-1a536df7375c','追賦畫江潭苑四首 四','李賀','唐','唐诗','tang','','[]','十騎簇芙蓉，宮衣小隊紅。',48,'全唐诗/poet.tang.20000.json','["十騎簇芙蓉，宮衣小隊紅。", "練香熏宋鵲，尋箭踏盧龍。", "旗溼金鈴重，霜乾玉鐙空。", "今朝畫眉早，不待景陽鐘。"]'),
('f2fda5c5-2793-4d74-95ab-740b1b76cdfb','潞州張大宅病酒遇江使寄上十四兄','李賀','唐','唐诗','tang','','[]','秋至昭關後，當知趙國寒。',144,'全唐诗/poet.tang.20000.json','["秋至昭關後，當知趙國寒。", "繫書隨短羽，寫恨破長箋。", "病客眠清曉，疎桐墜綠鮮。", "城鴉啼粉堞，軍吹壓蘆煙。", "岸幘褰沙幌，枯塘臥折蓮。", "木窗銀跡畫，石磴水痕錢。", "旅酒侵愁肺，離歌繞懦弦。", "詩封兩條淚，露折一枝蘭。", "莎老沙雞泣，松乾瓦獸殘。", "覺騎燕地馬，夢載楚溪船。", "椒桂傾長席，鱸魴斫玳筵。", "豈能忘舊路，江島滯佳年。"]'),
('55b00fa6-b2d9-48a4-8fdb-54306ce1f937','難忘曲','李賀','唐','唐诗','tang','','[]','夾道開洞門，弱楊低畫戟。',48,'全唐诗/poet.tang.20000.json','["夾道開洞門，弱楊低畫戟。", "簾影竹華起，簫聲吹日色。", "蜂語繞妝鏡，拂蛾學春碧。", "亂繫丁香梢，滿欄花向夕。"]'),
('c107ed9d-e05d-41bd-9e9e-4745173f8255','賈公閭貴壻曲','李賀','唐','唐诗','tang','','[]','朝衣不須長，分花對袍縫。',72,'全唐诗/poet.tang.20000.json','["朝衣不須長，分花對袍縫。", "嚶嚶白馬來，滿腦黃金重。", "今朝香氣苦，珊瑚澀難枕。", "且要弄風人，暖蒲沙上飲。", "燕語踏簾鉤，日虹屏中碧。", "潘令在河陽，無人死芳色。"]'),
('180e8166-9278-4e03-b344-4f37efabb16a','夜飲朝眠曲','李賀','唐','唐诗','tang','','[]','觴酣出座東方高，腰橫半解星勞勞。',64,'全唐诗/poet.tang.20000.json','["觴酣出座東方高，腰橫半解星勞勞。", "柳苑鴉啼公主醉，薄露壓花蕙園氣。", "玉轉溼絲牽曉水，熟粉生香琅玕紫。", "夜飲朝眠斷無事，楚羅之幃臥皇子。"]'),
('7192c1f4-0028-485d-b0fe-ff7b307cd1be','王濬墓下作','李賀','唐','唐诗','tang','','[]','人間無阿童，猶唱水中龍。',72,'全唐诗/poet.tang.20000.json','["人間無阿童，猶唱水中龍。", "白草侵煙死，秋梨遶地紅。", "古書平黑石，袖劒斷青銅。", "耕勢魚鱗起，墳科馬鬣封。", "菊花垂溼露，棘徑臥乾蓬。", "松柏愁香澀，南原幾夜風。"]'),
('c4750ff6-aa6c-4c46-810d-cf6e80019450','客遊','李賀','唐','唐诗','tang','','[]','悲滿千里心，日暖南山石。',48,'全唐诗/poet.tang.20000.json','["悲滿千里心，日暖南山石。", "不謁承明廬，老作平原客。", "四時別家廟，三年去鄉國。", "旅歌屢彈鋏，歸問時裂帛。"]'),
('840a294d-06b8-45a1-9751-fa3e97c881ee','崇義里滯雨','李賀','唐','唐诗','tang','','["\u5199\u96e8", "\u79cb\u5929", "\u6292\u6000", "\u96e8", "\u6000\u624d\u4e0d\u9047", "\u6124\u61d1"]','落莫誰家子，來感長安秋。',72,'全唐诗/poet.tang.20000.json','["落莫誰家子，來感長安秋。", "壯年抱羈恨，夢泣生白頭。", "瘦馬秣敗草，雨沫飄寒溝。", "南宮古簾暗，溼景傳籤籌。", "家山遠千里，雲脚天東頭。", "憂眠枕劒匣，客帳夢封侯。"]'),
('e4b44d96-5663-4738-b0e1-e2acff426643','馮小憐','李賀','唐','唐诗','tang','','[]','灣頭見小憐，請上琵琶弦。',48,'全唐诗/poet.tang.20000.json','["灣頭見小憐，請上琵琶弦。", "破得春風恨，今朝直幾錢。", "裙垂竹葉帶，鬢溼杏花煙。", "玉冷紅絲重，齊宮妾駕鞭。"]'),
('f8c28456-0138-477b-bcee-9fda818734e1','贈陳商','李賀','唐','唐诗','tang','','["\u6292\u60c5", "\u58ee\u5fd7\u672a\u916c", "\u6124\u61d1"]','長安有男兒，二十心已朽。',204,'全唐诗/poet.tang.20000.json','["長安有男兒，二十心已朽。", "楞伽堆案前，楚辭繫肘後。", "人生有窮拙，日暮聊飲酒。", "秪今道已塞，何必須白首。", "淒淒陳述聖，披褐鉏俎豆。", "學爲堯舜文，時人責衰偶。", "柴門車轍凍，日下榆影瘦。", "黃昏訪我來，苦節青陽皺。", "太華五千仞，劈地抽森秀。", "旁古無寸尋，一上戛牛斗。", "公卿縱不憐，寧能鎖吾口。", "李生師太華，大坐看白晝。", "逢霜作樸𣙙，得氣爲春柳。", "禮節乃相去，顦顇如芻狗。", "風雪直齋壇，墨組貫銅綬。", "臣妾氣態間，唯欲承箕帚。", "天眼何時開，古劒庸一吼。"]'),
('595fe873-891d-44c3-9eb6-06431778e788','釣魚詩','李賀','唐','唐诗','tang','','[]','秋水釣紅渠，仙人待素書。',74,'全唐诗/poet.tang.20000.json','["秋水釣紅渠，仙人待素書。", "菱絲縈獨繭，蒲米蟄雙魚。", "斜竹垂清沼，長綸貫碧虛。", "餌懸春[蜥蜴]，鉤墜小蟾蜍。", "詹子情無限，龍陽恨有餘。", "爲看煙浦上，楚女淚霑裾。"]'),
('795f68f3-7560-456d-98f6-34779af12e7f','奉和二兄罷使遣馬歸延州','李賀','唐','唐诗','tang','','[]','空留三尺劒，不用一丸泥。',72,'全唐诗/poet.tang.20000.json','["空留三尺劒，不用一丸泥。", "馬向沙場去，人歸故國來。", "笛愁翻隴水，酒喜瀝春灰。", "錦帶休驚雁，羅衣尚鬬雞。", "還吳已渺渺，入郢莫淒淒。", "自是桃李樹，何畏不成蹊。"]'),
('8a8188ef-4df5-44d7-8663-5810b6715b84','荅贈','李賀','唐','唐诗','tang','','[]','本是張公子，曾名萼綠華。',48,'全唐诗/poet.tang.20000.json','["本是張公子，曾名萼綠華。", "沈香熏小像，楊柳伴啼鴉。", "露重金泥冷，盃闌玉樹斜。", "琴堂沽酒客，新買後園花。"]'),
('0b99e7df-1750-406e-8bc2-2db21439bff1','題趙生壁','李賀','唐','唐诗','tang','','[]','大婦然竹根，中婦舂玉屑。',48,'全唐诗/poet.tang.20000.json','["大婦然竹根，中婦舂玉屑。", "冬暖拾松枝，日煙坐蒙滅。", "木蘚青桐老，石井水聲發。", "曝背臥東亭，桃花滿肌骨。"]'),
('adec055f-ac09-4e9d-8326-fc651fd2b789','感春','李賀','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u6292\u60c5", "\u6101\u95f7"]','日暖自蕭條，花悲北郭騷。',48,'全唐诗/poet.tang.20000.json','["日暖自蕭條，花悲北郭騷。", "榆穿萊子眼，柳斷舞兒腰。", "上幕迎神燕，飛絲送百勞。", "胡琴今日恨，急語向檀槽。"]'),
('ea601ea7-e4e4-4df9-9028-9f427b4fcf67','仙人','李賀','唐','唐诗','tang','','[]','彈琴石壁上，翻翻一仙人。',48,'全唐诗/poet.tang.20000.json','["彈琴石壁上，翻翻一仙人。", "手持白鸞尾，夜掃南山雲。", "鹿飲寒澗下，魚歸清海濱。", "當時漢武帝，書報桃花春。"]'),
('e040a8b4-2c34-4a49-b071-61ea1608b511','河陽歌','李賀','唐','唐诗','tang','','[]','染羅衣，秋藍難著色。',96,'全唐诗/poet.tang.20000.json','["染羅衣，秋藍難著色。", "不是無心人，爲作臺邛客。", "花燒中潬城，顏郎身已老。", "惜許兩少年，抽心似春草。", "今日見銀牌，今夜鳴玉讌。", "牛頭高一尺，隔坐應相見。", "月從東方來，酒從東方轉。", "觥船飫口紅，[蜜]炬千枝爛。"]'),
('77164c1c-7e9d-4adb-ab34-40e9ee518149','花遊曲','李賀','唐','唐诗','tang','','[]','春柳南陌態，冷花寒露姿。',48,'全唐诗/poet.tang.20000.json','["春柳南陌態，冷花寒露姿。", "今朝醉城外，拂鏡濃掃眉。", "煙溼愁車重，紅油覆畫衣。", "舞裙香不暖，酒色上來遲。"]'),
('449ee08c-9e9a-4b41-bd3b-e1278738e8a6','春晝','李賀','唐','唐诗','tang','','[]','朱城報春更漏轉，光風催蘭吹小殿。',86,'全唐诗/poet.tang.20000.json','["朱城報春更漏轉，光風催蘭吹小殿。", "草細堪梳，柳長如線。", "卷衣秦帝，掃粉趙燕。", "日含畫幕，蜂上羅薦。", "平陽花塢，河陽花縣。", "越婦搘機，吳蠶作繭。", "菱汀繫帶，荷塘倚扇。", "江南有情，塞北無恨。"]'),
('3b51fcb2-7c45-4bc8-b433-cb309041d811','安樂宮','李賀','唐','唐诗','tang','','[]','深井桐烏起，尚復牽情水。',60,'全唐诗/poet.tang.20000.json','["深井桐烏起，尚復牽情水。", "未盥邵陵瓜，缾中弄長翠。", "新成安樂宮，宮如鳳皇翅。", "歌迴蠟板鳴，左悺提壺使。", "綠蘩悲水曲，茱萸別秋子。"]'),
('97f0e647-3011-4b70-9741-2fbdbff85fdd','胡蝶飛','李賀','唐','唐诗','tang','','[]','楊花撲帳春雲熱，龜甲屏風醉眼纈。',32,'全唐诗/poet.tang.20000.json','["楊花撲帳春雲熱，龜甲屏風醉眼纈。", "東家胡蝶西家飛，白騎少年今日歸。"]'),
('b0a06901-b758-4f7c-858a-31cd2039db1f','梁公子','李賀','唐','唐诗','tang','','[]','風彩出蕭家，本是菖蒲花。',48,'全唐诗/poet.tang.20000.json','["風彩出蕭家，本是菖蒲花。", "南塘連子熟，洗馬走江沙。", "御牋銀沫冷，長簟鳳窠斜。", "種柳營中暗，題書賜館娃。"]'),
('18063111-e1b2-4859-8a15-9b72efc39279','牡丹種曲','李賀','唐','唐诗','tang','','[]','蓮枝未長秦蘅老，走馬馱金斸春草。',96,'全唐诗/poet.tang.20000.json','["蓮枝未長秦蘅老，走馬馱金斸春草。", "水灌香泥却月盆，一夜綠房迎白曉。", "美人醉語園中煙，晚華已散蝶又闌。", "梁王老去羅衣在，拂袖風吹蜀國弦。", "歸霞帔拖蜀帳昏，嫣紅落粉罷承恩。", "檀郎謝女眠何處，樓臺月明燕夜語。"]'),
('2b791d3a-fd4f-404a-be8a-28299bcd819d','後園鑿井歌','李賀','唐','唐诗','tang','','["\u592b\u59bb", "\u7231\u60c5", "\u751f\u6d3b"]','井上轆轤牀上轉，水聲繁，弦聲淺。',46,'全唐诗/poet.tang.20000.json','["井上轆轤牀上轉，水聲繁，弦聲淺。", "情若何，荀奉倩。", "城頭日，長向城頭住。", "一日作千年，不須流下去。"]'),
('368be09e-2866-4ac2-8341-95a8f728c4a0','開愁歌','李賀','唐','唐诗','tang','','["\u79cb\u5929", "\u6292\u6000", "\u996e\u9152"]','秋風吹地百草乾，華容碧影生晚寒。',96,'全唐诗/poet.tang.20000.json','["秋風吹地百草乾，華容碧影生晚寒。", "我當二十不得意，一心愁謝如枯蘭。", "衣如飛鶉馬如狗，臨岐擊劍生銅吼。", "旗亭下馬解秋衣，請貰宜陽一壺酒。", "壺中喚天雲不開，白晝萬里閑淒迷。", "主人勸我養心骨，莫受俗物相填𧱉。"]'),
('55f41995-ba87-48ef-ba9b-aa927c567099','秦宮詩','李賀','唐','唐诗','tang','','["\u9ec4\u6cb3"]','越羅衫袂迎春風，玉刻麒麟腰帶紅。',160,'全唐诗/poet.tang.20000.json','["越羅衫袂迎春風，玉刻麒麟腰帶紅。", "樓頭曲宴仙人語，帳底吹笙香霧濃。", "人間酒暖春茫茫，花枝入簾白日長。", "飛窗複道傳籌飲，十夜銅盤膩燭黃。", "禿衿小袖調鸚鵡，紫繡麻䪗踏哮虎。", "斫桂燒金待曉筵，白鹿青蘇夜半煮。", "桐英永巷騎新馬，內屋深屏生色畫。", "開門爛用水衡錢，卷起黃河向身瀉。", "皇天厄運猶曾裂，秦宮一生花底活。", "鸞篦奪得不還人，醉睡氍毺滿堂月。"]'),
('5c36237e-3433-4874-ad41-a22860fa2a8a','古鄴城童子謠效王粲刺曹操','李賀','唐','唐诗','tang','','[]','鄴城中，暮塵起。',64,'全唐诗/poet.tang.20000.json','["鄴城中，暮塵起。", "將黑丸，斫文吏。", "棘爲鞭，虎爲馬。", "團團走，鄴城下。", "切玉劍，射日弓。", "獻何人，奉相公。", "扶轂來，關右兒。", "香掃塗，相公歸。"]'),
('dadedde0-d4fd-44e4-8805-586ed3717ef7','楊生青花紫石硯歌','李賀','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269", "\u8d5e\u7f8e", "\u781a\u77f3"]','端州石工巧如神，踏天磨刀割紫雲。',80,'全唐诗/poet.tang.20000.json','["端州石工巧如神，踏天磨刀割紫雲。", "傭刓抱水含滿脣，暗灑萇弘冷血痕。", "紗帷晝暖墨花春，輕漚漂沫松麝薰。", "乾膩薄重立脚勻，數寸光秋無日昏。", "圓毫促點聲靜新，孔硯寬頑何足云。"]'),
('6f19f606-b838-41ec-8e9c-c0863bb0bec6','房中思','李賀','唐','唐诗','tang','','[]','新桂如蛾眉，秋風吹小綠。',48,'全唐诗/poet.tang.20000.json','["新桂如蛾眉，秋風吹小綠。", "行輪出門去，玉鑾聲斷續。", "月軒下風露，曉庭自幽澀。", "誰能事貞素，臥聽莎雞泣。"]'),
('9f1b8b1c-d6f4-4117-91e5-e012a5c39f8d','石城曉','李賀','唐','唐诗','tang','','[]','月落大隄上，女垣棲烏起。',80,'全唐诗/poet.tang.20000.json','["月落大隄上，女垣棲烏起。", "細露溼團紅，寒香解夜醉。", "女牛渡天河，柳煙滿城曲。", "上客留斷纓，殘蛾鬬雙綠。", "春帳依微蟬翼羅，橫茵突金隱體花。", "帳前輕絮鶴毛起，欲說春心無所似。"]'),
('934bd927-617f-46d2-bed6-985abfc99921','苦晝短','李賀','唐','唐诗','tang','','[]','飛光飛光，勸爾一杯酒。',138,'全唐诗/poet.tang.20000.json','["飛光飛光，勸爾一杯酒。", "吾不識青天高，黃地厚。", "唯見月寒日暖，來煎人壽。", "食熊則肥，食蛙則瘦。", "神君何在，太一安有。", "天東有若木，下置銜燭龍。", "吾將斬龍足，嚼龍肉。", "使之朝不得迴，夜不得伏。", "自然老者不死，少者不哭。", "何爲服黃金，吞白玉。", "誰似任公子，雲中騎碧驢。", "劉徹茂陵多滯骨，嬴政梓棺費鮑魚。"]'),
('246674af-83a0-456a-acf5-bb8aeeffba75','章和二年中','李賀','唐','唐诗','tang','','[]','雲蕭索，田風拂拂，麥芒如篲黍如粟。',97,'全唐诗/poet.tang.20000.json','["雲蕭索，田風拂拂，麥芒如篲黍如粟。", "關中父老百領襦，關東吏人乏詬租。", "健犢春耕土膏黑，菖蒲叢叢沿水脈。", "殷勤爲我下田租，百錢攜償絲桐客。", "遊春漫光塢花白，野林散香神降席。", "拜神得壽獻天子，七星貫斷姮娥死。"]'),
('118ccb2f-fd27-4e22-9c10-4e449f3f0a0a','春歸昌谷','李賀','唐','唐诗','tang','','[]','束髮方讀書，謀身苦不早。',288,'全唐诗/poet.tang.20000.json','["束髮方讀書，謀身苦不早。", "終軍未乘傳，顏子鬢先老。", "天網信崇大，矯士常慅慅。", "逸目駢甘華，羈心如荼蓼。", "旱雲二三月，岑岫相顛倒。", "誰揭頳玉盤，東方發紅照。", "春熱張鶴蓋，兔目官槐小。", "思焦面如病，嘗膽腸似絞。", "京國心爛漫，夜夢歸家少。", "發軔東門外，天地皆浩浩。", "青樹驪山頭，花風滿秦道。", "宮臺光錯落，裝盡偏峰嶠。", "細綠及團紅，當路雜啼笑。", "香風下高廣，鞍馬正華耀。", "獨乘雞棲車，自覺少風調。", "心曲語形影，祗身焉足樂。", "豈能脫負檐，刻鶴曾無兆。", "幽幽太華側，老柏如建纛。", "龍皮相排戛，翠羽更蕩掉。", "驅趨委憔悴，眺覽強容貌。", "花蔓閡行輈，縠煙暝深徼。", "少健無所就，入門愧家老。", "聽講依大樹，觀書臨曲沼。", "知非出柙虎，甘作藏霧豹。"]'),
('f8c55c63-c2c0-4b1a-8368-93ea24fed046','昌谷詩','李賀','唐','唐诗','tang','','[]','昌谷五月稻，細青滿平水。',288,'全唐诗/poet.tang.20000.json','["昌谷五月稻，細青滿平水。", "遙巒相壓疊，頹綠愁墮地。", "光潔無秋思，涼曠吹浮媚。", "竹香滿淒寂，粉節塗生翠。", "草髮垂恨鬢，光露泣幽淚。", "層圍爛洞曲，芳徑老紅醉。", "攢蟲鎪古柳，蟬子鳴高邃。", "大帶委黃葛，紫蒲交狹涘。", "石錢差復藉，厚葉皆蟠膩。", "汰沙好平白，立馬印青字。", "晚鱗自遨遊，瘦鵠暝單跱。", "嘹嘹溼蛄聲，咽源驚濺起。", "紆緩玉真路，神娥蕙花裏。", "苔絮縈澗礫，山實垂頳紫。", "小柏儼重扇，肥松突丹髓。", "鳴流走響韻，壠秋拖光穟。", "鶯唱閔女歌，瀑懸楚練帔。", "風露滿笑眼，駢巖雜舒墜。", "亂條迸石嶺，細頸喧島毖。", "日脚埽昏翳，新雲啓華閟。", "謐謐厭夏光，商風道清氣。", "高眠服玉容，燒桂祀天几。", "霧衣夜披拂，眠壇夢真粹。", "待駕棲鸞老，故宮椒壁圮。"]'),
('504d52fe-70fd-4dc2-8bf3-8faff1fa5ec4','銅駝悲','李賀','唐','唐诗','tang','','["\u60b2\u4f24", "\u6292\u60c5", "\u6101\u82e6"]','落魄三月罷，尋花去東家。',72,'全唐诗/poet.tang.20000.json','["落魄三月罷，尋花去東家。", "誰作送春曲，洛岸悲銅駝。", "橋南多馬客，北山饒古人。", "客飲盃中酒，駝悲千萬春。", "生世莫徒勞，風吹盤上燭。", "厭見桃株笑，銅駝夜來哭。"]'),
('285ac776-5a32-4366-af69-92136732c1b5','自昌谷到洛後門','李賀','唐','唐诗','tang','','[]','九月大野白，蒼芩竦秋門。',156,'全唐诗/poet.tang.20000.json','["九月大野白，蒼芩竦秋門。", "寒涼十月末，露霰濛曉昏。", "澹色結晝天，心事填空雲。", "道上千里風，野竹蛇涎痕。", "石澗涷波聲，雞叫清寒晨。", "強行到東舍，解馬投舊鄰。", "東家名廖者，鄉曲傳姓辛。", "杖頭非飲酒，吾請造其人。", "始欲南去楚，又將西適秦。", "襄王與武帝，各自留青春。", "聞道蘭臺上，宋玉無歸魂。", "緗縹兩行字，蟄蟲蠹秋芸。", "爲探秦臺意，豈命余負薪。"]'),
('7cde13a8-f1cf-4ac8-b723-5faaf5b0029d','七月一日曉入太行山','李賀','唐','唐诗','tang','','[]','一夕遶山秋，香露溘蒙菉。',48,'全唐诗/poet.tang.20000.json','["一夕遶山秋，香露溘蒙菉。", "新橋倚雲阪，候蟲嘶露樸。", "洛南今已遠，越衾誰爲熟。", "石氣何淒淒，老莎如短鏃。"]'),
('45e71353-3040-4da8-9f07-daf449d6c4a3','秋涼詩寄正字十二兄','李賀','唐','唐诗','tang','','[]','閉門感秋風，幽姿任契闊。',120,'全唐诗/poet.tang.20000.json','["閉門感秋風，幽姿任契闊。", "大野生素空，天地曠肅殺。", "露光泣殘蕙，蟲響連夜發。", "房寒寸輝薄，迎風絳紗折。", "披書古芸馥，恨唱華容歇。", "百日不相知，花光變涼節。", "弟兄誰念慮，牋翰既通達。", "青袍度白馬，草簡奏東闕。", "夢中相聚笑，覺見半牀月。", "長思劇尋環，亂憂抵覃葛。"]'),
('de51f6f7-eb38-4119-b448-66dc337e4dfa','艾如張','李賀','唐','唐诗','tang','','[]','錦襜褕，繡襠襦。',80,'全唐诗/poet.tang.20000.json','["錦襜褕，繡襠襦。", "強飲啄，哺爾雛。", "隴東臥穟滿風雨，莫信籠媒隴西去。", "齊人織網如素空，張在野田平碧中。", "網絲漠漠無形影，誤爾觸之傷首紅。", "艾葉綠花誰剪刻，中藏禍機不可測。"]'),
('b8c5f866-877e-4690-b5d3-f6b55bbd27a1','上雲樂','李賀','唐','唐诗','tang','','[]','飛香走紅滿天春，花龍盤盤上紫雲。',64,'全唐诗/poet.tang.20000.json','["飛香走紅滿天春，花龍盤盤上紫雲。", "三千宮女列金屋，五十弦瑟海上聞。", "天江碎碎銀沙路，嬴女機中斷煙素。", "斷煙素，縫衣縷，八月一日君前舞。"]'),
('dd685601-7976-4c6c-8fd0-169ae4163487','摩多樓子','李賀','唐','唐诗','tang','','[]','玉塞去金人，二萬四千里。',72,'全唐诗/poet.tang.20000.json','["玉塞去金人，二萬四千里。", "風吹沙作雲，一時渡遼水。", "天白水如練，甲絲雙串斷。", "行行莫苦辛，城月猶殘半。", "曉氣朔煙上，趢趗胡馬蹄。", "行人臨水別，隔隴長東西。"]'),
('0422e408-0484-40d0-b826-da8e2c947490','猛虎行','李賀','唐','唐诗','tang','','["\u6cf0\u5c71"]','長戈莫舂，長弩莫抨。',80,'全唐诗/poet.tang.20000.json','["長戈莫舂，長弩莫抨。", "乳孫哺子，教得生獰。", "舉頭爲城，掉尾爲旌。", "東海黃公，愁見夜行。", "道逢騶虞，牛哀不平。", "何用尺刀，壁上雷鳴。", "泰山之下，婦人哭聲。", "官家有程，吏不敢聽。"]'),
('d0e7182f-cc73-4de5-b3c2-d891d0034686','日出行','李賀','唐','唐诗','tang','','["\u9ec4\u6cb3"]','白日下崑崙，發光如舒絲。',81,'全唐诗/poet.tang.20000.json','["白日下崑崙，發光如舒絲。", "徒照葵藿心，不照遊子悲。", "折折黃河曲，日從中央轉。", "暘谷耳曾聞，若木眼不見。", "奈爾鑠石，胡爲銷人，羿彎弓屬矢那不中。", "足令久不得奔，詎教晨光夕昏。"]'),
('8f6bd03f-8b60-487c-8448-570a10a581a5','苦篁調嘯引','李賀','唐','唐诗','tang','','[]','請說軒轅在時事，伶倫採竹二十四。',90,'全唐诗/poet.tang.20000.json','["請說軒轅在時事，伶倫採竹二十四。", "伶倫採之自崑丘，軒轅詔遣中分作十二。", "伶倫以之正音律，軒轅以之調元氣。", "當時黃帝上天時，二十三管咸相隨。", "唯留一管人間吹，無德不能得此管，此管沈埋虞舜祠。"]'),
('9815b2df-26e7-4efc-ab90-c4efbe1deffc','拂舞歌辭','李賀','唐','唐诗','tang','','[]','吳娥聲絕天，空雲閑裴回。',112,'全唐诗/poet.tang.20000.json','["吳娥聲絕天，空雲閑裴回。", "門外滿車馬，亦須生綠苔。", "尊有烏程酒，勸君千萬壽。", "全勝漢武錦樓上，曉望晴寒飲花露。", "東方日不破，天光無老時。", "丹成作蛇乘白霧，千年重化玉井土。", "從蛇作土一千載，吳堤綠草年年在。", "背有八卦稱神仙，邪鱗頑甲滑腥涎。"]'),
('d3e70d45-82d5-44a7-a20e-cbb2c762d857','夜坐吟','李賀','唐','唐诗','tang','','[]','踏踏馬蹄誰見過，眼看北斗直天河。',72,'全唐诗/poet.tang.20000.json','["踏踏馬蹄誰見過，眼看北斗直天河。", "西風羅幕生翠波，鉛華笑妾顰青蛾。", "爲君起唱長相思，簾外嚴霜皆倒飛。", "明星爛爛東方陲，紅霞梢出東南涯，陸郎去矣乘班騅。"]'),
('301681cd-441c-4a5c-967e-fbf82511de3a','箜篌引','李賀','唐','唐诗','tang','','[]','公乎公乎，提壺將焉如。',100,'全唐诗/poet.tang.20000.json','["公乎公乎，提壺將焉如。", "屈平沈湘不足慕，徐衍入海誠爲愚。", "公乎公乎，牀有菅席盤有魚。", "北里有賢兄，東隣有小姑。", "隴畝油油黍與葫，瓦甒濁醪蟻浮浮。", "黍可食，醪可飲，公乎公乎其奈居。", "被髮奔流竟何如，賢兄小姑哭嗚嗚。"]'),
('05184315-6703-4e60-b85a-57b887c2b7c0','巫山高','李賀','唐','唐诗','tang','','["\u5199\u5c71", "\u5199\u666f", "\u63cf\u5199\u5c71"]','碧叢叢，高插天，大江翻瀾神曳煙。',64,'全唐诗/poet.tang.20000.json','["碧叢叢，高插天，大江翻瀾神曳煙。", "楚魂尋夢風颸然，曉風飛雨生苔錢。", "瑤姬一去一千年，丁香筇竹啼老猨。", "古祠近月蟾桂寒，椒花墜紅溼雲間。"]'),
('52abee2b-32dd-4f8d-922e-a7b6cb28c181','平城下','李賀','唐','唐诗','tang','','[]','飢寒平城下，夜夜守明月。',96,'全唐诗/poet.tang.20000.json','["飢寒平城下，夜夜守明月。", "別劒無玉花，海風斷鬢髮。", "塞長連白空，遙見漢旗紅。", "青帳吹短笛，煙霧溼晝龍。", "日晚在城上，依稀望城下。", "風吹枯蓬起，城中嘶瘦馬。", "借問築城吏，去關幾千里。", "惟愁裹屍歸，不惜倒戈死。"]'),
('1c2c37c6-de2a-400a-9de6-ca2b6473e38e','江南弄','李賀','唐','唐诗','tang','','[]','江中綠霧起涼波，天上疊巘紅嵯峨。',64,'全唐诗/poet.tang.20000.json','["江中綠霧起涼波，天上疊巘紅嵯峨。", "水風浦雲生老竹，渚暝蒲帆如一幅。", "鱸魚千頭酒百斛，酒中倒臥南山綠。", "吳歈越吟未終曲，江上團團帖寒玉。"]'),
('5ec67bba-ece4-49ff-81b0-455d662a0be2','榮華樂','李賀','唐','唐诗','tang','','[]','鳶肩公子二十餘，齒編貝，脣激朱。',359,'全唐诗/poet.tang.20000.json','["鳶肩公子二十餘，齒編貝，脣激朱。", "氣如虹霓，飲如建瓴。", "走馬夜歸呌嚴更，徑穿複道遊椒房。", "龍裘金玦雜花光，玉堂調笑金樓子。", "臺下戲學邯鄲倡，口吟舌話稱女郎。", "錦祛繡面漢帝旁，得明珠十斛。", "白璧一雙，新詔垂金曳紫光煌煌。", "馬如飛，人如水。", "九卿六官皆望履，將迴日月先反掌。", "欲作江河唯畫地，峨峨虎冠上切雲。", "竦劒晨趨凌紫氛，繡段千尋貽皂隸。", "黃金百鎰貺家臣，十二門前張大宅。", "晴春煙起連天碧，金鋪綴日雜紅光。", "銅龍齧環似爭力，瑤姬凝醉臥芳席。", "海素籠窗空下隔，丹穴取鳳充行庖。", "貜貜如拳那足食，金蟾呀呀蘭燭香。", "軍裝武妓聲琅璫，誰知花雨夜來過。", "但見池臺春草長，嘈嘈弦吹匝天開。", "洪厓簫聲遶天來，天長一矢貫雙虎。", "雲弝絕騁聒旱雷，亂袖交竿管兒舞。", "吳音綠鳥學言語，能教刻石平紫金。", "解送刻毛寄新兔，三皇皇后七貴人。", "五十校尉二將軍，當時飛去逐彩雲，化作今日京華春。"]'),
('ebcafead-15e8-433f-8127-f29e78237222','相勸酒','李賀','唐','唐诗','tang','','[]','羲和騁六轡，晝夕不曾閑。',168,'全唐诗/poet.tang.20000.json','["羲和騁六轡，晝夕不曾閑。", "彈烏崦嵫竹，抶馬蟠桃鞭。", "蓐收既斷翠柳，青帝又造紅蘭。", "堯舜至今萬萬歲，數子將爲傾蓋間。", "青錢白璧買無端，丈夫快意方爲歡。", "臛蠵臛熊何足云，會須鍾飲北海，箕踞南山。", "歌淫淫，管愔愔，橫波好送雕題金。", "人生得意且如此，何用強知元化心。", "相勸酒，終無輟，伏願陛下鴻名終不歇。", "子孫綿如石上葛，來長安，車駢駢。", "中有梁冀舊宅，石崇故園。"]'),
('e0dbf3a4-19cd-4279-9613-4de2cc5d4734','瑤華樂','李賀','唐','唐诗','tang','','[]','穆天子，走龍媒，八轡冬瓏逐天迴。',142,'全唐诗/poet.tang.20000.json','["穆天子，走龍媒，八轡冬瓏逐天迴。", "五精掃地凝雲開，高門左右日月環。", "四方錯鏤稜層殷，舞霞垂尾長盤珊。", "江澄海淨神母顏，施紅點翠照虞泉。", "曳雲拖玉下崑山，列斾如松，張蓋如輪。", "金風殿秋，清明發春。", "八鑾十乘，矗如雲屯。", "瓊鍾瑤席甘露文，玄霜絳雪何足云，薰梅染柳將贈君。", "鉛華之水洗君骨，與君相對作真質。"]'),
('32638651-d574-455c-a0d2-07d2b0956018','北中寒','李賀','唐','唐诗','tang','','["\u9ec4\u6cb3"]','一方黑照三方紫，黃河冰合魚龍死。',64,'全唐诗/poet.tang.20000.json','["一方黑照三方紫，黃河冰合魚龍死。", "三尺木皮斷文理，百石強車上河水。", "霜花草上大如錢，揮刀不入迷濛天。", "爭瀯海水飛凌喧，山瀑無聲玉虹懸。"]'),
('ff19d74e-bc9a-48e9-9f9b-ab9722df50a9','梁臺古愁','李賀','唐','唐诗','tang','','[]','梁王臺沼空中立，天河之水夜飛入。',96,'全唐诗/poet.tang.20000.json','["梁王臺沼空中立，天河之水夜飛入。", "臺前鬬玉作蛟龍，綠粉掃天愁露溼。", "撞鐘飲酒行射天，金虎蹙裘噴血斑。", "朝朝暮暮愁海翻，長繩繫日樂當年。", "芙蓉凝紅得秋色，蘭臉別春啼脈脈。", "蘆洲客雁報春來，寥落野篁秋漫白。"]'),
('0db2e58b-f499-4672-a2b2-340734b67051','公無出門','李賀','唐','唐诗','tang','','[]','天迷迷，地密密。',140,'全唐诗/poet.tang.20000.json','["天迷迷，地密密。", "熊虺食人魂，雪霜斷人骨。", "嗾犬狺狺相索索，舐掌偏宜佩蘭客。", "帝遣乘軒災自息，玉星點劒黃金軛。", "我雖跨馬不得還，歷陽湖波大如山。", "毒虬相視振金環，狻猊猰貐吐嚵涎。", "鮑焦一世披草眠，顏回廿九鬢毛斑。", "顏回非血衰，鮑焦不違天。", "天畏遭銜齧，所以致之然。", "分明猶懼公不信，公看呵壁書問天。"]'),
('0d28db5a-f66d-45e8-abbc-babe8dde823c','神弦別曲','李賀','唐','唐诗','tang','','[]','巫山小女隔雲別，春風松花山上發。',64,'全唐诗/poet.tang.20000.json','["巫山小女隔雲別，春風松花山上發。", "綠蓋獨穿香徑歸，白馬花竿前孑孑。", "蜀江風澹水如羅，墮蘭誰泛相經過。", "南山桂樹爲君死，雲衫淺汚紅脂花。"]'),
('54fb0ffc-a287-41a6-b415-ebf47436548a','綠水詞','李賀','唐','唐诗','tang','','["\u7231\u60c5", "\u56de\u5fc6", "\u5973\u5b50", "\u76f8\u601d"]','今宵好風月，阿侯在何處。',48,'全唐诗/poet.tang.20000.json','["今宵好風月，阿侯在何處。", "爲有傾人色，翻成足愁苦。", "東湖採蓮葉，南湖拔蒲根。", "未持寄小姑，且持感愁魂。"]'),
('7e6f07aa-32c4-4ef6-8804-38d843053c54','沙路曲','李賀','唐','唐诗','tang','','[]','柳臉半眠丞相樹，珮馬釘鈴踏沙路。',80,'全唐诗/poet.tang.20000.json','["柳臉半眠丞相樹，珮馬釘鈴踏沙路。", "斷燼遺香褭翠煙，燭騎啼烏上天去。", "帝家玉龍開九關，帝前動笏移南山。", "獨垂重印押千官，金窠篆字紅屈盤。", "沙路歸來聞好語，旱火不光天下雨。"]'),
('d08f89e8-887d-4dca-99b3-1ed4f2378876','上之回','李賀','唐','唐诗','tang','','[]','上之回，大旗喜。',48,'全唐诗/poet.tang.20000.json','["上之回，大旗喜。", "懸紅雲，撻鳳尾。", "劒匣破，舞蛟龍。", "蚩尤死，鼓逢逢。", "天高慶雷齊墜地，地無驚煙海千里。"]'),
('f4e6f5ab-ad75-4489-87f9-ffedbcc67926','高軒過','李賀','唐','唐诗','tang','','["\u53d9\u4e8b", "\u5199\u4eba", "\u8bbf\u53cb", "\u8d5e\u9882", "\u5199\u4eba\u8bd7"]','華裾織翠青如葱，金環壓轡搖玲瓏。',108,'全唐诗/poet.tang.20000.json','["華裾織翠青如葱，金環壓轡搖玲瓏。", "馬蹄隱耳聲隆隆，入門下馬氣如虹。", "云是東京才子，文章鉅公。", "二十八宿羅心胸，九精照耀貫當中。", "殿前作賦聲摩空，筆補造化天無功。", "龐眉書客感秋蓬，誰知死草生華風。", "我今垂翅附冥鴻，他日不羞蛇作龍。"]'),
('cd990bbb-82e3-458b-b958-f2783a07dd3a','貝宮夫人','李賀','唐','唐诗','tang','','[]','丁丁海女弄金環，雀釵翹揭雙翅關。',64,'全唐诗/poet.tang.20000.json','["丁丁海女弄金環，雀釵翹揭雙翅關。", "六宮不語一生閑，高懸銀牓照青山。", "長眉凝綠幾千年，清涼堪老鏡中鸞。", "秋肌稍覺玉衣寒，空光帖妥水如天。"]'),
('c152a1b7-60aa-48c8-ac8c-7b2a9ddc6c24','蘭香神女廟','李賀','唐','唐诗','tang','','[]','古春年年在，閑綠搖暖雲。',180,'全唐诗/poet.tang.20000.json','["古春年年在，閑綠搖暖雲。", "松香飛晚華，柳渚含日昏。", "沙砌落紅滿，石泉生水芹。", "幽篁畫新粉，蛾綠橫曉門。", "弱蕙不勝露，山秀愁空春。", "舞珮剪鸞翼，帳帶塗輕銀。", "蘭桂吹濃香，菱藕長莘莘。", "看雨逢瑤姬，乘船值江君。", "吹簫飲酒醉，結綬金絲裙。", "走天呵白鹿，遊水鞭錦鱗。", "密髮虛鬟飛，膩頰凝花勻。", "團鬢分蛛巢，穠眉籠小脣。", "弄蝶和輕妍，風光怯腰身。", "深幃金鴨冷，奩鏡幽鳳塵。", "踏霧乘風歸，撼玉山上聞。"]'),
('fd5fc9fd-285d-4464-8168-f245709cbe1a','送韋仁實兄弟入關','李賀','唐','唐诗','tang','','["\u601d\u5ff5", "\u53cb\u4eba", "\u9001\u522b"]','送客飲別酒，千觴無赭顏。',108,'全唐诗/poet.tang.20000.json','["送客飲別酒，千觴無赭顏。", "何物最傷心，馬首鳴金鐶。", "野色浩無主，秋明空曠間。", "坐來壯膽破，斷目不能看。", "行槐引西道，青梢長攢攢。", "韋郎好兄弟，疊玉生文翰。", "我在山上舍，一畝蒿磽田。", "夜雨呌租吏，春聲暗交關。", "誰解念勞勞，蒼突唯南山。"]'),
('c8711b9e-4367-419b-8a7d-83e4f8ee8a98','洛陽城外別皇甫湜','李賀','唐','唐诗','tang','','[]','洛陽吹別風，龍門起斷煙。',48,'全唐诗/poet.tang.20000.json','["洛陽吹別風，龍門起斷煙。", "冬樹束生澀，晚紫凝華天。", "單身野霜上，疲馬飛蓬間。", "凭軒一雙淚，奉墜綠衣前。"]'),
('3ab98ee1-0c01-45cb-966e-981b5b301c8b','溪晚涼','李賀','唐','唐诗','tang','','[]','白狐向月號山風，秋寒掃雲留碧空。',64,'全唐诗/poet.tang.21000.json','["白狐向月號山風，秋寒掃雲留碧空。", "玉煙青溼白如幢，銀灣曉轉流天東。", "溪汀眠鷺夢征鴻，輕漣不語細游溶。", "層岫迴岑複疊龍，苦篁對客吟歌筒。"]'),
('bb653660-c834-4f30-a5c7-504e99f08354','官不來題皇甫湜先輩廳','李賀','唐','唐诗','tang','','[]','官不來，官庭秋，老桐錯幹青龍愁。',40,'全唐诗/poet.tang.21000.json','["官不來，官庭秋，老桐錯幹青龍愁。", "書司曹佐走如牛，疊聲問佐官來不。", "官不來，門幽幽。"]'),
('dd1c0560-c28a-4d9e-b303-5756dc060554','長平箭頭歌','李賀','唐','唐诗','tang','','[]','漆灰骨末丹水沙，淒淒古血生銅花。',128,'全唐诗/poet.tang.21000.json','["漆灰骨末丹水沙，淒淒古血生銅花。", "白翎金簳雨中盡，直餘三脊殘狼牙。", "我尋平原乘兩馬，驛東石田蒿塢下。", "風長日短星蕭蕭，黑旗雲溼懸空夜。", "左魂右魄啼肌瘦，酪瓶倒盡將羊炙。", "蟲棲雁病蘆筍紅，迴風送客吹陰火。", "訪古汍瀾收斷鏃，折鋒赤璺曾刲肉。", "南陌東城馬上兒，勸我將金換簝竹。"]'),
('9168257a-0124-48ed-a906-9ba00f446ac8','江樓曲','李賀','唐','唐诗','tang','','[]','樓前流水江陵道，鯉魚風起芙蓉老。',96,'全唐诗/poet.tang.21000.json','["樓前流水江陵道，鯉魚風起芙蓉老。", "曉釵催鬢語南風，抽帆歸來一日功。", "鼉吟浦口飛梅雨，竿頭酒旗換青苧。", "蕭騷浪白雲差池，黃粉油衫寄郎主。", "新槽酒聲苦無力，南湖一頃菱花白。", "眼前便有千里愁，小玉開屏見山色。"]'),
('49d31b27-344a-4ae2-b8cb-be347f790f3a','塞下曲','李賀','唐','唐诗','tang','','["\u4e50\u5e9c", "\u8fb9\u585e"]','胡角引北風，薊門白於水。',72,'全唐诗/poet.tang.21000.json','["胡角引北風，薊門白於水。", "天含青海道，城頭月千里。", "露下旗濛濛，寒金鳴夜刻。", "蕃甲鏁蛇鱗，馬嘶青塚白。", "秋靜見旄頭，沙遠席羈愁。", "帳北天應盡，河聲出塞流。"]'),
('7a178fb4-16b1-4b9b-a552-c7ed198caa87','染絲上春機','李賀','唐','唐诗','tang','','[]','玉罌泣水桐花井，蒨絲沈水如雲影。',64,'全唐诗/poet.tang.21000.json','["玉罌泣水桐花井，蒨絲沈水如雲影。", "美人嬾態燕脂愁，春梭拋擲鳴高樓。", "綵線結茸背複疊，白袷玉郎寄桃葉。", "爲君挑鸞作腰綬，願君處處宜春酒。"]'),
('fe1d099d-0184-461a-9460-ee06e660584c','五粒小松歌','李賀','唐','唐诗','tang','','[]','蛇子蛇孫鱗蜿蜿，新香幾粒洪厓飯。',64,'全唐诗/poet.tang.21000.json','["蛇子蛇孫鱗蜿蜿，新香幾粒洪厓飯。", "綠波浸葉滿濃光，細束龍髯鉸刀剪。", "主人壁上鋪州圖，主人堂前多俗儒。", "月明白露秋淚滴，石筍溪雲肯寄書。"]'),
('c5542580-eb5f-4d8a-beb9-7d1353e9bb73','塘上行','李賀','唐','唐诗','tang','','[]','藕花涼露溼，花缺藕根澀。',24,'全唐诗/poet.tang.21000.json','["藕花涼露溼，花缺藕根澀。", "飛下雌鴛鴦，塘水聲溘溘。"]'),
('324b12b1-4e01-4037-bd08-4f6616e4ba53','呂將軍歌','李賀','唐','唐诗','tang','','[]','呂將軍，騎赤兔。',152,'全唐诗/poet.tang.21000.json','["呂將軍，騎赤兔。", "獨攜大膽出秦門，金粟堆邊哭陵樹。", "北方逆氣汙青天，劒龍夜呌將軍閑。", "將軍振袖揮劒鍔，玉闕朱城有門閣。", "榼榼銀龜搖白馬，傅粉女郎火旗下。", "恆山鐵騎請金槍，遙聞箙中花箭香。", "西郊寒蓬葉如刺，皇天新栽養神驥。", "廐中高桁排蹇蹄，飽食青芻飲白水。", "圓蒼低迷蓋張地，九州人事皆如此。", "赤山秀鋌禦時英，綠眼將軍會天意。"]'),
('a10a0601-e9b9-4e5e-9553-ab625ef13ddc','休洗紅','李賀','唐','唐诗','tang','','[]','休洗紅，洗多紅色淺。',34,'全唐诗/poet.tang.21000.json','["休洗紅，洗多紅色淺。", "卿卿騁少年，昨日殷橋見。", "封侯早歸來，莫作弦上箭。"]'),
('21b336af-06d1-4ec7-8492-ba001b89b96c','神弦曲','李賀','唐','唐诗','tang','','[]','西山日沒東山昏，旋風吹馬馬踏雲。',80,'全唐诗/poet.tang.21000.json','["西山日沒東山昏，旋風吹馬馬踏雲。", "畫弦素管聲淺繁，花裙綷䌨步秋塵。", "桂葉刷風桂墜子，青狸哭血寒狐死。", "古壁彩虬金帖尾，雨工騎入秋潭水。", "百年老鴞成木魅，笑聲碧火巢中起。"]'),
('ee31b315-58e8-4a6f-86eb-542e2405bae0','野歌','李賀','唐','唐诗','tang','','[]','鵶翎羽箭山桑弓，仰天射落銜蘆鴻。',64,'全唐诗/poet.tang.21000.json','["鵶翎羽箭山桑弓，仰天射落銜蘆鴻。", "麻衣黑肥衝北風，帶酒日晚歌田中。", "男兒屈窮心不窮，枯榮不等嗔天公。", "寒風又變爲春柳，條條看即煙濛濛。"]'),
('80b0850d-cb82-47c3-91a5-6f3a93cb403f','神弦','李賀','唐','唐诗','tang','','[]','女巫澆酒雲滿空，玉爐炭火香鼕鼕。',96,'全唐诗/poet.tang.21000.json','["女巫澆酒雲滿空，玉爐炭火香鼕鼕。", "海神山鬼來座中，紙錢窸窣鳴𩘶風。", "相思木帖金舞鸞，攢蛾一啑重一彈。", "呼星召鬼歆杯盤，山魅食時人森寒。", "終南日色低平灣，神兮長在有無間。", "神嗔神喜師更顏，送神萬騎還青山。"]'),
('ff880442-2fe3-4e95-a762-ee8e9b1c026d','將進酒','李賀','唐','唐诗','tang','','["\u5bb4\u996e", "\u4eba\u751f", "\u9f13\u5439\u66f2\u8f9e", "\u4e50\u5e9c", "\u8bbd\u55bb"]','琉璃鍾，琥珀濃，小槽酒滴真珠紅。',81,'全唐诗/poet.tang.21000.json','["琉璃鍾，琥珀濃，小槽酒滴真珠紅。", "烹龍炮鳳玉脂泣，羅屏繡幕圍香風。", "吹龍笛，擊鼉鼓，皓齒歌，細腰舞。", "況是青春日將暮，桃花亂落如紅雨。", "勸君終日酩酊醉，酒不到劉伶墳上土。"]'),
('a75e413d-42ce-4ab5-8bad-8ec13b514a7a','美人梳頭歌','李賀','唐','唐诗','tang','','[]','西施曉夢綃帳寒，香鬟墮髻半沈檀。',128,'全唐诗/poet.tang.21000.json','["西施曉夢綃帳寒，香鬟墮髻半沈檀。", "轆轤咿啞轉鳴玉，驚起芙蓉睡新足。", "雙鸞開鏡秋水光，解鬟臨鏡立象牀。", "一編香絲雲撒地，玉釵落處無聲膩。", "纖手却盤老鵶色，翠滑寶釵簪不得。", "春風爛熳惱嬌慵，十八鬟多無氣力。", "妝成𩭏鬌敧不斜，雲裾數步踏雁沙。", "背人不語向何處，下堦自折櫻桃花。"]'),
('535efe6f-d7cc-4b2d-b6ca-3514fd6a3044','月漉漉篇','李賀','唐','唐诗','tang','','[]','月漉漉，波煙玉。',68,'全唐诗/poet.tang.21000.json','["月漉漉，波煙玉。", "莎青桂花繁，芙蓉別江木。", "粉態裌羅寒，雁羽鋪煙溼。", "誰能看石帆，乘船鏡中入。", "秋白鮮紅死，水香蓮子齊。", "挽菱隔歌袖，綠刺罥銀泥。"]'),
('cc44e8dd-356a-430e-96e6-945192f3fb85','京城','李賀','唐','唐诗','tang','','[]','驅馬出門意，牢落長安心。',24,'全唐诗/poet.tang.21000.json','["驅馬出門意，牢落長安心。", "兩事誰向道，自作秋風吟。"]'),
('1c2b1699-d06e-4aaa-ae74-3e5caa7654cc','官街鼓','李賀','唐','唐诗','tang','','[]','曉聲隆隆催轉日，暮聲隆隆呼月出。',80,'全唐诗/poet.tang.21000.json','["曉聲隆隆催轉日，暮聲隆隆呼月出。", "漢城黃柳暎新簾，柏陵飛燕埋香骨。", "磓發千年日長白，孝武秦王聽不得。", "從君翠髮蘆花色，獨共南山守中國。", "幾迴天上葬神仙，漏聲相將無斷緣。"]'),
('adc8f8c2-9cb5-4ee9-bf45-45d8f8011cc2','許公子鄭姬歌','李賀','唐','唐诗','tang','','[]','許史世家外親貴，宮錦千端買沈醉。',192,'全唐诗/poet.tang.21000.json','["許史世家外親貴，宮錦千端買沈醉。", "銅駝酒熟烘明膠，古堤大柳煙中翠。", "桂開客花名鄭袖，入洛聞香鼎門口。", "先將芍藥獻妝臺，後解黃金大如斗。", "莫愁簾中許合歡，清弦五十爲君彈。", "彈聲咽春弄君骨，骨興牽人馬上鞍。", "兩馬八蹄踏蘭苑，情如合竹誰能見。", "夜光玉枕栖鳳皇，袷羅當門刺純綫。", "長翻蜀紙卷明君，轉角含商破碧雲。", "自從小靨來東道，曲裏長眉少見人。", "相如塚上生秋柏，三秦誰是言情客。", "蛾鬟醉眼拜諸宗，爲謁皇孫請曹植。"]'),
('ba9e4f53-6289-4f5c-a810-dbddc67fb100','新夏歌','李賀','唐','唐诗','tang','','[]','曉木千籠真蠟綵，落蕊枯香數分在。',80,'全唐诗/poet.tang.21000.json','["曉木千籠真蠟綵，落蕊枯香數分在。", "陰枝秀牙卷縹茸，長風迴氣扶葱蘢。", "野家麥畦上新壠，長畛裴回桑柘重。", "刺香滿地菖蒲草，雨梁燕語悲身老。", "三月搖揚入河道，天濃地濃柳梳掃。"]'),
('2354f955-cf18-4f45-b55f-2ebe0a7329e3','題歸夢','李賀','唐','唐诗','tang','','[]','長安風雨夜，書客夢昌谷。',48,'全唐诗/poet.tang.21000.json','["長安風雨夜，書客夢昌谷。", "怡怡中堂笑，小弟栽澗菉。", "家門厚重意，望我飽飢腹。", "勞勞一寸心，燈花照魚目。"]'),
('281fefbc-fb0a-4e20-80dc-726c2a682427','經沙苑','李賀','唐','唐诗','tang','','[]','野水泛長瀾，宮牙開小蒨。',48,'全唐诗/poet.tang.21000.json','["野水泛長瀾，宮牙開小蒨。", "無人柳自春，草渚鴛鴦暖。", "晴嘶臥沙馬，老去悲啼展。", "今春還不歸，塞嚶折翅雁。"]'),
('7917ea14-d308-483a-af68-396ff5c08995','出城別張又新酬李漢','李賀','唐','唐诗','tang','','[]','李子別上國，南山崆峒春。',288,'全唐诗/poet.tang.21000.json','["李子別上國，南山崆峒春。", "不聞今夕鼓，差慰煎情人。", "趙壹賦命薄，馬卿家業貧。", "鄉書何所報，紫蕨生石雲。", "長安玉桂國，戟帶披侯門。", "慘陰地自光，寶馬踏曉昏。", "臘春戲草苑，玉輓鳴𨏈轔。", "綠網縋金鈴，霞卷清池漘。", "開貫瀉蚨母，買冰防夏蠅。", "時宜裂大袂，劒客車盤茵。", "小人如死灰，心切生秋榛。", "皇圖跨四海，百姓拖長紳。", "光明靄不發，腰龜徒甃銀。", "吾將譟禮樂，聲調摩清新。", "欲使十千歲，帝道如飛神。", "華實自蒼老，流采長傾湓。", "沒沒暗齰舌，涕血不敢論。", "今將下東道，祭酒而別秦。", "六郡無勦兒，長刀誰拭塵。", "地理陽無正，快馬逐服轅。", "二子美年少，調道講清渾。", "譏笑斷冬夜，家庭疎篠穿。", "曙風起四方，秋月當東懸。", "賦詩面投擲，悲哉不遇人。"]'),
('39e3a49f-20cd-4347-a982-bee45e0b422c','南園','李賀','唐','唐诗','tang','','[]','方領蕙帶折角巾，杜若已老蘭苕春。',64,'全唐诗/poet.tang.21000.json','["方領蕙帶折角巾，杜若已老蘭苕春。", "南山削秀藍玉合，小雨歸去飛涼雲。", "熟杏暖香梨葉老，草梢竹柵鎖池痕。", "鄭公鄉老開酒尊，坐汎楚奏吟招魂。"]'),
('773e3420-7888-4c61-b026-fad74cf8a313','假龍吟歌','李賀','唐','唐诗','tang','','[]','石軋銅杯，吟詠枯瘁。',94,'全唐诗/poet.tang.21000.json','["石軋銅杯，吟詠枯瘁。", "蒼鷹擺血，白鳳下肺。", "桂子自落，雲弄車蓋。", "木死沙崩惡谿島，阿母得仙今不老。", "窞中跳汰截清涎，隈壖臥水埋金爪。", "崖蹬蒼苔弔石髮，江君掩帳篔簹折。", "蓮花去國一千年，雨後聞腥猶帶鐵。"]'),
('a5b887a4-c160-4f64-add7-4fedcb3043ab','感諷六首 一','李賀','唐','唐诗','tang','','[]','人間春蕩蕩，帳暖香揚揚。',72,'全唐诗/poet.tang.21000.json','["人間春蕩蕩，帳暖香揚揚。", "飛光染幽紅，誇嬌來洞房。", "舞席泥金蛇，桐竹羅花牀。", "眼逐春瞑醉，粉隨淚色黃。", "王子下馬來，曲沼鳴鴛鴦。", "焉知腸車轉，一夕巡九方。"]'),
('f83ee031-9f9f-493f-961e-7f16a7483b7a','感諷六首 二','李賀','唐','唐诗','tang','','[]','苦風吹朔寒，沙驚秦木折。',48,'全唐诗/poet.tang.21000.json','["苦風吹朔寒，沙驚秦木折。", "舞影逐空天，畫鼓餘清節。", "蜀書秋信斷，黑水朝波咽。", "嬌魂從回風，死處懸鄉月。"]'),
('d281fee1-0565-42c7-a16f-73cc97d6fd32','感諷六首 三','李賀','唐','唐诗','tang','','[]','雜雜胡馬塵，森森邊士戟。',72,'全唐诗/poet.tang.21000.json','["雜雜胡馬塵，森森邊士戟。", "天教胡馬戰，曉雲皆血色。", "婦人攜漢卒，箭箙囊巾幗。", "不慙金印重，踉蹡腰鞬力。", "恂恂鄉門老，昨夜試鋒鏑。", "走馬遣書勳，誰能分粉墨。"]'),
('062be68d-ab40-4f92-a653-0b4444650205','感諷六首 四','李賀','唐','唐诗','tang','','[]','青門放彈去，馬色連空郊。',72,'全唐诗/poet.tang.21000.json','["青門放彈去，馬色連空郊。", "何年帝家物，玉裝鞍上搖。", "去去走犬歸，來來坐烹羔。", "千金不了饌，狢肉稱盤臊。", "試問誰家子，乃老能佩刀。", "西山白蓋下，賢儁寒蕭蕭。"]'),
('cb82e8ad-edd0-482a-96b3-8e8b2ecb5ead','感諷六首 五','李賀','唐','唐诗','tang','','[]','曉菊泫寒露，似悲團扇風。',48,'全唐诗/poet.tang.21000.json','["曉菊泫寒露，似悲團扇風。", "秋涼經漢殿，班子泣衰紅。", "本無辭輦意，豈見入空宮。", "腰衱珮珠斷，灰蝶生陰松。"]'),
('d53c6d4b-cb61-49aa-a6ec-cbd8946a8bbc','感諷六首 六','李賀','唐','唐诗','tang','','[]','蝶飛紅粉臺，柳掃吹笙道。',84,'全唐诗/poet.tang.21000.json','["蝶飛紅粉臺，柳掃吹笙道。", "十日懸戶庭，九秋無衰草。", "調歌送風轉，杯池白魚小。", "水宴截香腴，菱科映青罩。", "䒠蒙梨花滿，春昏弄長嘯。", "唯愁苦花落，不悟世衰到。", "撫舊唯銷魂，南山坐悲峭。"]'),
('0e3272d3-dfbf-4e6b-86c2-22cb5ae6b4a7','莫愁曲','李賀','唐','唐诗','tang','','[]','草生龍坡下，鵶噪城堞頭。',96,'全唐诗/poet.tang.21000.json','["草生龍坡下，鵶噪城堞頭。", "何人此城裏，城角栽石榴。", "青絲繫五馬，黃金絡雙牛。", "白魚駕蓮船，夜作十里遊。", "歸來無人識，暗上沈香樓。", "羅牀倚瑤瑟，殘月傾簾鉤。", "今日槿花落，明朝桐樹秋。", "莫負平生意，何名何莫愁。"]'),
('2159bbc3-f147-4442-82ee-16ee250587a9','夜來樂','李賀','唐','唐诗','tang','','[]','紅羅複帳金流蘇，華燈九枝懸鯉魚。',126,'全唐诗/poet.tang.21000.json','["紅羅複帳金流蘇，華燈九枝懸鯉魚。", "麗人暎月開銅鋪，春水滴酒猩猩沽。", "重一篋，香十株，赤金瓜子兼雜麩。", "五絲封青鳧，阿侯此笑千萬餘。", "南軒漢轉簾影疎，桐林啞啞挾子烏。", "劒崖鞭節青石珠，白騧吹湍凝霜鬚。", "漏長送珮承明廬，倡樓嵯峨明月孤。", "新客下馬故客去，綠蟬秀黛重拂梳。"]'),
('e51b5b5b-fca3-41dc-955a-bca2eb6a3f06','嘲雪','李賀','唐','唐诗','tang','','[]','昨日發葱嶺，今朝下蘭渚。',48,'全唐诗/poet.tang.21000.json','["昨日發葱嶺，今朝下蘭渚。", "喜從千里來，亂笑含春語。", "龍沙溼漢旗，鳳扇迎秦素。", "久別遼城鶴，毛衣已應故。"]'),
('b07c75ea-7eec-4c11-890a-5dc4513ebdb9','春懷引','李賀','唐','唐诗','tang','','[]','芳蹊密影成花洞，柳結濃煙花帶重。',64,'全唐诗/poet.tang.21000.json','["芳蹊密影成花洞，柳結濃煙花帶重。", "蟾蜍碾玉挂明弓，捍撥裝金打仙鳳。", "寶枕垂雲選春夢，鈿合碧寒龍腦凍。", "阿侯繫錦覓周郎，憑仗東風好相送。"]'),
('e725e0c8-c1df-4ed4-ba45-0cf3cd64b40b','白虎行','李賀','唐','唐诗','tang','','[]','火烏日暗崩騰雲，秦皇虎視蒼生羣。',176,'全唐诗/poet.tang.21000.json','["火烏日暗崩騰雲，秦皇虎視蒼生羣。", "燒書滅國無暇日，鑄劒佩玦惟將軍。", "玉壇設醮思沖天，一世二世當萬年。", "燒丹未得不死藥，拏舟海上尋神仙。", "鯨魚張鬣海波沸，耕人半作征人鬼。", "雄豪氣猛如燄煙，無人爲決天河水。", "誰最苦兮誰最苦，報人義士深相許。", "漸離擊筑荆卿歌，荆卿把酒燕丹語。", "劒如霜兮膽如鐵，出燕城兮望秦月。", "天授秦封祚未移，衮龍衣點荆卿血。", "朱旗卓地白虎死，漢皇知是真天子。"]'),
('ec96e2f8-e52b-4a5e-813f-94c1c78d5270','有所思','李賀','唐','唐诗','tang','','[]','去年陌上歌離曲，今日君書遠遊蜀。',172,'全唐诗/poet.tang.21000.json','["去年陌上歌離曲，今日君書遠遊蜀。", "簾外花開二月風，臺前淚滴千行竹。", "琴心與妾腸，此夜斷還續。", "想君白馬懸雕弓，世間何處無春風。", "君心未肯鎮如石，妾顏不久如花紅。", "夜殘高碧橫長河，河上無梁空白波。", "西風未起悲龍梭，年年織素攢雙蛾。", "江山迢遰無休絕，淚眼看燈乍明滅。", "自從孤館深鎖窗，桂花幾度圓還缺。", "鵶鵶向曉鳴森木，風過池塘響叢玉。", "白日蕭條夢不成，橋南更問仙人卜。"]'),
('83cbc920-6d79-4458-ac38-df147d8e33f6','啁少年','李賀','唐','唐诗','tang','','[]','青騘馬肥金鞍光，龍腦入縷羅衫香。',176,'全唐诗/poet.tang.21000.json','["青騘馬肥金鞍光，龍腦入縷羅衫香。", "美人狹坐飛瓊觴，貧人喚云天上郎。", "別起高樓臨碧篠，絲曳紅鱗出深沼。", "有時半醉百花前，背把金丸落飛鳥。", "自說生來未爲客，一身美妾過三百。", "豈知斸地種苗家，官稅頻催勿人織。", "長得積玉誇豪毅，每揖閑人多意氣。", "生來不讀半行書，只把黃金買身貴。", "少年安得長少年，海波尚變爲桑田。", "榮枯遞傳急如箭，天公不肯於公偏。", "莫道韶華鎮長在，髮白面皺專相待。"]'),
('bfd5cd4a-43aa-40c9-ad9b-a1865081dfcf','高平縣東私路','李賀','唐','唐诗','tang','','[]','侵侵槲葉香，木花滯寒雨。',48,'全唐诗/poet.tang.21000.json','["侵侵槲葉香，木花滯寒雨。", "今夕山上秋，永謝無人處。", "石磎遠荒澀，棠實懸辛苦。", "古者定幽尋，呼君作私路。"]'),
('0b18bfad-a576-4eda-b6cc-04e8c86a5ccb','神仙曲','李賀','唐','唐诗','tang','','[]','碧峰海面藏靈書，上帝揀作神仙居。',80,'全唐诗/poet.tang.21000.json','["碧峰海面藏靈書，上帝揀作神仙居。", "清明笑語聞空虛，鬬乘巨浪騎鯨魚。", "春羅書字邀王母，共讌紅樓最深處。", "鶴羽衝風過海遲，不如却使青龍去。", "猶疑王母不相許，垂露娃鬟更傳語。"]'),
('38b8a259-112d-41a1-802d-b092799eea5f','龍夜吟','李賀','唐','唐诗','tang','','[]','鬈髮胡兒眼睛綠，高樓夜靜吹橫竹。',112,'全唐诗/poet.tang.21000.json','["鬈髮胡兒眼睛綠，高樓夜靜吹橫竹。", "一聲似向天上來，月下美人望鄉哭。", "直排七點星藏指，暗合清風調宮徵。", "蜀道秋深雲滿林，湘江半夜龍驚起。", "玉堂美人邊塞情，碧窗皓月愁中聽。", "寒碪能擣百尺練，粉淚凝珠滴紅線。", "胡兒莫作隴頭吟，隔窗暗結愁人心。"]'),
('3c8eaafa-5117-4c0a-beba-c08ea1739273','崑崙使者','李賀','唐','唐诗','tang','','["\u5199\u4eba", "\u6000\u53e4", "\u5199\u4eba\u8bd7"]','崑崙使者無消息，茂陵煙樹生愁色。',64,'全唐诗/poet.tang.21000.json','["崑崙使者無消息，茂陵煙樹生愁色。", "金盤玉露自淋漓，元氣茫茫收不得。", "麒麟背上石文裂，虬龍鱗下紅枝折。", "何處偏傷萬國心，中天夜久高明月。"]'),
('18cb0076-2c50-47b6-a3c0-9cf51a30b701','漢唐姬飲酒歌','李賀','唐','唐诗','tang','','[]','御服沾霜露，天衢長蓁棘。',168,'全唐诗/poet.tang.21000.json','["御服沾霜露，天衢長蓁棘。", "金隱秋塵姿，無人爲帶飾。", "玉堂歌聲寢，芳林煙樹隔。", "雲陽臺上歌，鬼哭復何益。", "鐵劒常光光，至兇威屢逼。", "彊梟噬母心，犇厲索人魄。", "相看兩相泣，淚下如波激。", "寧用清酒爲，欲作黃泉客。", "不說玉山頹，且無飲中色。", "勉從天帝訴，天上寡沈厄。", "無處張穗帷，如何望松柏。", "妾身晝團團，君魂夜寂寂。", "蛾眉自覺長，頸粉誰憐白。", "矜持昭陽意，不肯看南陌。"]'),
('03eec718-71e4-463f-a2f4-b1a65cda8271','聽穎師琴歌','李賀','唐','唐诗','tang','','[]','別浦雲歸桂花渚，蜀國弦中雙鳳語。',128,'全唐诗/poet.tang.21000.json','["別浦雲歸桂花渚，蜀國弦中雙鳳語。", "芙蓉葉落秋鸞離，越王夜起遊天姥。", "暗珮清臣敲水玉，渡海蛾眉牽白鹿。", "誰看挾劒赴長橋，誰看浸髮題春竹。", "竺僧前立當吾門，梵宮真相眉稜尊。", "古琴大軫長八尺，嶧陽老樹非桐孫。", "涼館聞弦驚病客，藥囊暫別龍鬚席。", "請歌直請卿相歌，奉禮官卑復何益。"]'),
('090c4ddd-409b-4518-b504-db28af790d03','謠俗','李賀','唐','唐诗','tang','','[]','上林胡蝶小，試伴漢家君。',48,'全唐诗/poet.tang.21000.json','["上林胡蝶小，試伴漢家君。", "飛向南城去，誤落石榴裙。", "脈脈花滿樹，翾翾燕遶雲。", "出門不識路，羞問陌頭人。"]'),
('85e1e940-c5c5-4a9d-bda5-56514b77f862','靜女春曙曲','李賀','唐','唐诗','tang','','[]','嫩葉憐芳抱新蕊，泣露枝枝滴夭淚。',64,'全唐诗/poet.tang.21000.json','["嫩葉憐芳抱新蕊，泣露枝枝滴夭淚。", "粉窗香咽頹曉雲，錦堆花密藏春睡。", "戀屏孔雀搖金尾，鶯舌分明呼婢子。", "冰洞寒龍半匣水，一隻商鸞逐煙起。"]'),
('e2b5ac48-6bb1-4334-a16c-df4735d0b339','少年樂','李賀','唐','唐诗','tang','','[]','芳草落花如錦地，二十長遊醉鄉裏。',64,'全唐诗/poet.tang.21000.json','["芳草落花如錦地，二十長遊醉鄉裏。", "紅纓不動白馬驕，垂柳金絲香拂水。", "吳娥未笑花不開，綠鬢聳墮蘭雲起。", "陸郎倚醉牽羅袂，奪得寶釵金翡翠。"]'),
('d0694187-a3f6-45b6-891d-559eec2f8846','句','李賀','唐','唐诗','tang','','[]','不見山巔樹，摧杌下爲薪。',48,'全唐诗/poet.tang.21000.json','["不見山巔樹，摧杌下爲薪。", "日覩井中泥，上出作埃塵。", "情知一丘趣，不謝千里印。", "倚劍登高臺，悠悠送春目。"]'),
('15b64bb3-bf4c-4fb0-a085-6e77003ee595','冰柱','劉叉','唐','唐诗','tang','','[]','師干久不息，農爲兵兮民重嗟。',337,'全唐诗/poet.tang.21000.json','["師干久不息，農爲兵兮民重嗟。", "騷然縣宇，土崩水潰。", "畹中無熟穀，壠上無桑麻。", "王春判序，百卉茁甲含葩。", "有客避兵奔遊僻，跋履險阨至三巴。", "貂裘蒙茸已敝縷，鬢髮蓬舥。", "雀驚鼠伏，寧遑安處。", "獨臥旅舍無好夢，更堪走風沙。", "天人一夜剪瑛琭，詰旦都成六出花。", "南畝未盈尺，纖片亂舞空紛拏。", "旋落旋逐朝暾化，簷間冰柱若削出交加。", "或低或昂，小大瑩潔。", "隨勢無等差，始疑玉龍下界來人世。", "齊向茅簷布爪牙，又疑漢高帝。", "西方未斬虵，人不識，誰爲當風杖莫邪。", "鏗鏜冰有韻，的皪玉無瑕。", "不爲四時雨，徒於道路成泥柤。", "不爲九江浪，徒爲汩沒天之涯。", "不爲雙井水，滿甌泛泛烹春茶。", "不爲中山漿，清新馥鼻盈百車。", "不爲池與沼，養魚種芰成霪䨟。", "不爲醴泉與甘露，使名異瑞世俗誇。", "特稟朝澈氣，潔然自許靡間其邇遐。", "森然氣結一千里，滴瀝聲沈十萬家。"]'),
('d2476df2-cdf0-4858-ac5c-4701e1448249','雪車','劉叉','唐','唐诗','tang','','[]','臘令凝綈三十日，繽紛密雪一復一。',326,'全唐诗/poet.tang.21000.json','["臘令凝綈三十日，繽紛密雪一復一。", "孰云潤澤在枯荄，闤闠餓民涷欲死。", "死中猶被豺狼食，官車初還城壘未完備。", "人家千里無煙火，雞犬何太怨。", "天不卹吾甿，如何連夜瑤花亂。", "皎潔既同君子節，沾濡多著小人面。", "寒鏁侯門見客稀，色迷塞路行商斷。", "小小細細如塵間，輕輕緩緩成樸簌。", "官家不知民餒寒，盡驅牛車盈道載屑玉。", "載載欲何之，祕藏深宮以禦炎酷。", "徒能自衛九重間，豈信車轍血，點點盡是農夫哭。", "刀兵殘喪後，滿野誰爲載白骨。", "遠戍久乏糧，太倉誰爲運紅粟。", "戎夫尚逆命，扁箱鹿角誰爲敵。", "士夫困征討，買花載酒誰爲適。", "天子端然少旁求，股肱耳目皆姦慝。", "依違用事佞上方，猶驅餓民運造化防暑阨。", "吾聞躬耕南畝舜之聖，爲民吞蝗唐之德。", "未聞𭐁孽苦蒼生，相羣相黨上下爲蟊賊。", "廟堂食祿不自慙，我爲斯民歎息還歎息。"]'),
('7d3175cc-c64d-43f3-b4ad-71520347a41b','修養','劉叉','唐','唐诗','tang','','[]','損神終日談虛空，不必歸命于胎中。',136,'全唐诗/poet.tang.21000.json','["損神終日談虛空，不必歸命于胎中。", "我神不西亦不東，煙收雲散何濛濛。", "嘗令體如微微風，綿綿不斷道自沖。", "世人逢一不逢一，一回存想一回出。", "只知一切望一切，不覺一日損一日。", "勸君修真復識真，世上道人多忤人。", "披圖醮錄益亂神，此法那能堅此身。", "心田自有靈地珍，惜哉自有不自親，明真汩沒隨埃塵。"]'),
('5c2c7e1c-d794-41d1-9881-b5f10f3091b0','勿執古寄韓潮州','劉叉','唐','唐诗','tang','','[]','古人皆執古，不辭[凍]餓悲。',122,'全唐诗/poet.tang.21000.json','["古人皆執古，不辭[凍]餓悲。", "今人亦執古，自取行坐危。", "老菊凌霜葩，獰松抱雪姿。", "武王亦至明，寧哀首陽飢。", "仲尼豈非聖，但爲互鄉嗤。", "寸心生萬路，今古棼若絲。", "逐逐行不盡，茫茫休者誰。", "來恨不可遏，去悔何足追。", "玉石共笑唾，駑驥相奔馳。", "請君勿執古，執古徒自隳。"]'),
('079d8703-4f09-470f-befa-99a4ac7b8064','荅孟東野','劉叉','唐','唐诗','tang','','[]','酸寒孟夫子，苦愛老叉詩。',96,'全唐诗/poet.tang.21000.json','["酸寒孟夫子，苦愛老叉詩。", "生澀有百篇，謂是瓊瑤辭。", "百篇非所長，憂來豁窮悲。", "唯有剛腸鐵，百鍊不柔虧。", "退之何可駡，東野何可欺。", "文王已云沒，誰顧好爵縻。", "生死守一丘，寧計飽與飢。", "萬事付杯酒，從人笑狂癡。"]'),
('4c8b0e2e-4661-4642-a715-00d396d90cbd','自古無長生勸姚合酒','劉叉','唐','唐诗','tang','','[]','奉子一杯酒，爲子照顏色。',96,'全唐诗/poet.tang.21000.json','["奉子一杯酒，爲子照顏色。", "但願腮上紅，莫管頦下白。", "自古無長生，生者何戚戚。", "登山勿厭高，四望都無極。", "丘隴逐日多，天地爲我窄。", "祗見李耳書，對之空脈脈。", "何曾見天上，著得劉安宅。", "若問長生人，昭昭孔丘籍。"]'),
('7f234b77-2534-4c6b-b520-f0777a31f3d1','獨飲','劉叉','唐','唐诗','tang','','[]','盡欲調太羹，自古無好手。',24,'全唐诗/poet.tang.21000.json','["盡欲調太羹，自古無好手。", "所以山中人，兀兀但飲酒。"]'),
('606b2f00-9ff0-4a2d-b063-af31f8ea1b5f','作詩','劉叉','唐','唐诗','tang','','[]','作詩無知音，作不如不作。',48,'全唐诗/poet.tang.21000.json','["作詩無知音，作不如不作。", "未逢賡載人，此道終寂寞。", "有虞今已歿，來者誰爲託。", "朗詠豁心胸，筆與淚俱落。"]'),
('b40d5d7a-e7ab-4119-b8ca-3c6ebbe9f557','天津橋','劉叉','唐','唐诗','tang','','[]','洛陽宮闕照天地，四面山川無毒氣。',32,'全唐诗/poet.tang.21000.json','["洛陽宮闕照天地，四面山川無毒氣。", "誰令漢祖都秦關，從此姦雄轉相熾。"]'),
('1ce98907-9e83-4f28-8bb3-2362ae4e8e79','嘲荆卿','劉叉','唐','唐诗','tang','','[]','白虹千里氣，血頸一劒義。',24,'全唐诗/poet.tang.21000.json','["白虹千里氣，血頸一劒義。", "報恩不到頭，徒作輕生士。"]'),
('85af0312-9510-454d-afe8-b82853cba420','代牛言','劉叉','唐','唐诗','tang','','[]','渴飲潁水流，餓喘吳門月。',24,'全唐诗/poet.tang.21000.json','["渴飲潁水流，餓喘吳門月。", "黃金如可種，我力終不竭。"]'),
('d996038d-4df8-41f4-8af6-162acb4f27b2','莫問卜','劉叉','唐','唐诗','tang','','[]','莫問卜，人生吉凶皆自速。',28,'全唐诗/poet.tang.21000.json','["莫問卜，人生吉凶皆自速。", "伏羲文王若無死，今人不爲古人哭。"]'),
('cf5eecaf-79f1-484c-93e2-8e28fb3c0816','觀八駿圖','劉叉','唐','唐诗','tang','','[]','穆王八駿走不歇，海外去尋長日月。',32,'全唐诗/poet.tang.21000.json','["穆王八駿走不歇，海外去尋長日月。", "五雲望斷阿母宮，歸來落得新白髮。"]'),
('050e1015-1d53-45c5-b538-623ee654739e','經戰地','劉叉','唐','唐诗','tang','','[]','殺氣不上天，陰風吹雨血。',36,'全唐诗/poet.tang.21000.json','["殺氣不上天，陰風吹雨血。", "冤魂不入地，髑髏哭沙月。", "人命固有常，此地何夭折。"]'),
('6be87407-badb-43ad-818f-ae1cc5912e5d','野哭','劉叉','唐','唐诗','tang','','[]','棘針生獰義路閑，野泉相弔聲潺潺。',32,'全唐诗/poet.tang.21000.json','["棘針生獰義路閑，野泉相弔聲潺潺。", "哀哉異教溺頹俗，淳源一去何時還。"]'),
('49b1dcf3-10cf-418c-b0ea-0ad13c57c113','古怨','劉叉','唐','唐诗','tang','','[]','君莫嫌醜婦，醜婦死守貞。',48,'全唐诗/poet.tang.21000.json','["君莫嫌醜婦，醜婦死守貞。", "山頭一怪石，長作望夫名。", "鳥有並翼飛，獸有比肩行。", "丈夫不立義，豈如鳥獸情。"]'),
('96236616-17cf-4ad6-ae80-f61082920c1c','烈士詠','劉叉','唐','唐诗','tang','','[]','烈士或愛金，愛金不爲貧。',36,'全唐诗/poet.tang.21000.json','["烈士或愛金，愛金不爲貧。", "義死天亦許，利生鬼亦嗔。", "胡爲輕薄兒，使酒殺平人。"]'),
('677e4fd6-dc66-4cb1-836a-ec7acc9efbfd','狂夫','劉叉','唐','唐诗','tang','','[]','大妻唱舜歌，小妻鼓湘瑟。',36,'全唐诗/poet.tang.21000.json','["大妻唱舜歌，小妻鼓湘瑟。", "狂夫遊冶歸，端坐仍作色。", "不讀關雎篇，安知后妃德。"]'),
('366a64be-3fe0-40ae-a68f-7d4b7cc07d8c','餓詠','劉叉','唐','唐诗','tang','','[]','文王久不出，賢士如土賤。',24,'全唐诗/poet.tang.21000.json','["文王久不出，賢士如土賤。", "妻孥從餓死，敢愛黃金篆。"]'),
('e053f9c5-6d2d-49e8-ae48-0a088e092a90','自問','劉叉','唐','唐诗','tang','','[]','自問彭城子，何人授汝顛。',48,'全唐诗/poet.tang.21000.json','["自問彭城子，何人授汝顛。", "酒腸寬似海，詩膽大於天。", "斷劒徒勞匣，枯琴無復弦。", "相逢不多合，賴是向林泉。"]'),
('a3f3d740-0b8d-40ba-ac34-e31f181a780a','入蜀','劉叉','唐','唐诗','tang','','[]','望空問真宰，此路爲誰開。',48,'全唐诗/poet.tang.21000.json','["望空問真宰，此路爲誰開。", "峽色侵天去，江聲滾地來。", "孔明深有意，鍾會亦何才。", "信此非人事，悲歌付一杯。"]'),
('b4330b62-6af0-4f81-81b7-6987aae2d27c','塞上逢盧仝','劉叉','唐','唐诗','tang','','[]','直到桑乾北，逢君夜不眠。',50,'全唐诗/poet.tang.21000.json','["直到桑乾北，逢君夜不眠。", "上樓腰脚健，懷土眼睛穿。", "斗柄寒垂地，河流[凍]徹天。", "羈魂泣相向，何事有詩篇。"]'),
('4a4cf7b5-bbe2-4d5a-b477-84e8f83f766f','偶書','劉叉','唐','唐诗','tang','','[]','日出扶桑一丈高，人間萬事細如毛。',32,'全唐诗/poet.tang.21000.json','["日出扶桑一丈高，人間萬事細如毛。", "野夫怒見不平處，磨損胸中萬古刀。"]'),
('257f4489-b3b3-4d7f-b58d-4cae8b7b7b48','愛碣山石','劉叉','唐','唐诗','tang','','[]','碣石何青青，挽我雙眼睛。',24,'全唐诗/poet.tang.21000.json','["碣石何青青，挽我雙眼睛。", "愛爾多古峭，不到人間行。"]'),
('f4c335d0-4a26-4d20-9e5d-2e9af410fc26','與孟東野','劉叉','唐','唐诗','tang','','[]','寒衣草木皮，飢飯葵藿根。',24,'全唐诗/poet.tang.21000.json','["寒衣草木皮，飢飯葵藿根。", "不爲孟夫子，豈識市井門。"]'),
('039c28a3-da91-4375-8060-e61bbc52ad40','姚秀才愛予小劒因贈','劉叉','唐','唐诗','tang','','[]','一條古時水，向我手心流。',24,'全唐诗/poet.tang.21000.json','["一條古時水，向我手心流。", "臨行瀉贈君，勿薄細碎讐。"]'),
('a14f435a-c28e-46f8-8ccc-4b5e1760a3d0','老恨','劉叉','唐','唐诗','tang','','[]','雪打杉松殘，補書書不完。',24,'全唐诗/poet.tang.21000.json','["雪打杉松殘，補書書不完。", "嬾學渭上翁，辛苦把釣竿。"]'),
('0a29dfca-8f3f-421d-a0da-2cc6fc67ef12','思歸樂','元稹','唐','唐诗','tang','','[]','山中思歸樂，盡作思歸鳴。',288,'全唐诗/poet.tang.21000.json','["山中思歸樂，盡作思歸鳴。", "爾是此山鳥，安得失鄉名。", "應緣此山路，自古離人征。", "陰愁感和氣，俾爾從此生。", "我雖失鄉去，我無失鄉情。", "慘舒在方寸，寵辱將何驚。", "浮生居大塊，尋丈可寄形。", "身安即形樂，豈獨樂咸京。", "命者道之本，死者天之平。", "安問遠與近，何言殤與彭。", "君看趙工部，八十支體輕。", "交州二十載，一到長安城。", "長安不須臾，復作交州行。", "交州又累歲，移鎮廣與荆。", "歸朝新天子，濟濟爲上卿。", "肌膚無瘴色，飲食康且寧。", "長安一晝夜，死者如霣星。", "喪車四門出，何關炎瘴縈。", "況我三十二，百年未半程。", "江陵道塗近，楚俗雲水清。", "遐想玉泉寺，久聞峴山亭。", "此去盡綿歷，豈無心賞幷。", "紅餐日充腹，碧澗朝析酲。", "開門待賓客，寄書安弟兄。"]'),
('b4ebe174-7a53-4aee-aa19-4eddbee497eb','春鳩','元稹','唐','唐诗','tang','','[]','春鳩與百舌，音響詎同年。',48,'全唐诗/poet.tang.21000.json','["春鳩與百舌，音響詎同年。", "如何一時語，俱得春風憐。", "猶知化工意，當春不生蟬。", "免教爭呌噪，沸渭桃花前。"]'),
('9607c64e-762e-4d27-a30f-353287826d55','春蟬','元稹','唐','唐诗','tang','','[]','我自東歸日，厭苦春鳩聲。',96,'全唐诗/poet.tang.21000.json','["我自東歸日，厭苦春鳩聲。", "作詩憐化工，不遣春蟬生。", "及來商山道，山深氣不平。", "春秋兩相似，蟲豸百種鳴。", "風松不成韻，蜩螗沸如羹。", "豈無朝陽鳳，羞與微物爭。", "安得天上雨，奔渾河海傾。", "蕩滌反時氣，然後好晴明。"]'),
('393238aa-5671-4a79-ba77-4ee2f61b4ecd','兔絲','元稹','唐','唐诗','tang','','[]','人生莫依倚，依倚事不成。',120,'全唐诗/poet.tang.21000.json','["人生莫依倚，依倚事不成。", "君看兔絲蔓，依倚榛與荆。", "荆榛易蒙密，百鳥撩亂鳴。", "下有狐兔穴，奔走亦縱橫。", "樵童斫將去，柔蔓與之幷。", "翳薈生可恥，束縛死無名。", "桂樹月中出，珊瑚石上生。", "俊鶻度海食，應龍升天行。", "靈物本特達，不復相纏縈。", "纏縈竟何者，荆棘與飛莖。"]'),
('b38d0371-cb80-445a-b403-dd45f14735c0','古社','元稹','唐','唐诗','tang','','[]','古社基阯在，人散社不神。',156,'全唐诗/poet.tang.21000.json','["古社基阯在，人散社不神。", "惟有空心樹，妖狐藏魅人。", "狐惑意顛倒，臊腥不復聞。", "丘墳變城郭，花草仍荆榛。", "良田千萬頃，占作天荒田。", "主人議芟斫，怪見不敢前。", "那言空山燒，夜隨風馬奔。", "飛聲鼓鼙震，高燄旗幟飜。", "逡巡荆棘盡，狐兔無子孫。", "狐死魅人滅，煙消壇墠存。", "繞壇舊田地，給授有等倫。", "農收邨落盛，社樹新團圓。", "社公千萬歲，永保邨中民。"]'),
('06235d6c-7a5b-4c35-beb0-d39a618f3ac9','松樹','元稹','唐','唐诗','tang','','[]','華山高幢幢，上有高高松。',120,'全唐诗/poet.tang.21000.json','["華山高幢幢，上有高高松。", "株株遙各各，葉葉相重重。", "槐樹夾道植，枝葉俱冥蒙。", "既無貞直榦，復有罥挂蟲。", "何不種松樹，使之搖清風。", "秦時已曾種，顦顇種不供。", "可憐孤松意，不與槐樹同。", "閑在高山頂，樛盤虯與龍。", "屈爲大廈棟，庇蔭侯與公。", "不肯作行伍，俱在塵土中。"]'),
('5c950fba-cec7-4ba4-88c5-1dc0c53d6fc3','芳樹','元稹','唐','唐诗','tang','','[]','芳樹已寥落，孤英尤可嘉。',96,'全唐诗/poet.tang.21000.json','["芳樹已寥落，孤英尤可嘉。", "可憐團團葉，蓋覆深深花。", "遊蜂競鑽刺，鬬雀亦紛拏。", "天生細碎物，不愛好華光。", "非無殲殄法，念爾有生涯。", "春雷一聲發，驚燕亦驚蛇。", "清池養神蔡，已復長蝦蟇。", "雨露貴平施，吾其春草芽。"]'),
('a8a399d1-a4cb-465e-8fb9-94b6c70f95f0','桐花','元稹','唐','唐诗','tang','','[]','朧月上山館，紫桐垂好陰。',288,'全唐诗/poet.tang.21000.json','["朧月上山館，紫桐垂好陰。", "可惜暗澹色，無人知此心。", "舜沒蒼梧野，鳳歸丹穴岑。", "遺落在人世，光華那復深。", "年年怨春意，不競桃杏林。", "唯占清明後，牡丹還復侵。", "況此空館閉，云誰恣幽尋。", "徒煩鳥噪集，不語山嶔岑。", "滿院青苔地，一樹蓮花簪。", "自開還自落，暗芳終暗沈。", "爾生不得所，我願裁爲琴。", "安置君王側，調和元首音。", "安問宮徵角，先辨雅鄭淫。", "宮弦春以君，君若春日臨。", "商弦廉以臣，臣作旱天霖。", "人安角聲暢，人困鬬不任。", "羽以類萬物，祆物神不歆。", "徵以節百事，奉事罔不欽。", "五者苟不亂，天命乃可忱。", "君若問孝理，彈作梁山吟。", "君若事宗廟，拊以和球琳。", "君若不好諫，願獻觸疏箴。", "君若不罷獵，請聽荒于禽。", "君若侈臺殿，雍門可霑襟。"]'),
('2a9478ae-d31f-4585-b661-148d0ed6a26e','雉媒','元稹','唐','唐诗','tang','','[]','雙雉在野時，可憐同嗜欲。',240,'全唐诗/poet.tang.21000.json','["雙雉在野時，可憐同嗜欲。", "毛衣前後成，一種文章足。", "一雉獨先飛，衝開芳草綠。", "網羅幽草中，暗被潛羈束。", "剪刀摧六翮，絲線縫雙目。", "啖養能幾時，依然已馴熟。", "都無舊性靈，返與他心腹。", "置在芳草中，翻令誘同族。", "前時相失者，思君意彌篤。", "朝朝舊處飛，往往巢邊哭。", "今朝樹上啼，哀音斷還續。", "遠見爾文章，知君草中伏。", "和鳴忽相召，鼓翅遙相矚。", "畏我未肯來，又啄翳前粟。", "歛翮遠投君，飛馳勢奔蹙。", "罥挂在君前，向君聲促促。", "信君決無疑，不道君相覆。", "自恨飛太高，疎羅偶然觸。", "看看架上鷹，擬食無罪肉。", "君意定何如，依舊雕籠宿。"]'),
('b435b155-568b-402a-bf90-fcff2881aabd','箭鏃','元稹','唐','唐诗','tang','','[]','箭鏃本求利，淬礪良甚難。',168,'全唐诗/poet.tang.21000.json','["箭鏃本求利，淬礪良甚難。", "礪將何所用，礪以射凶殘。", "不礪射不入，不射人不安。", "爲盜即當射，寧問私與官。", "夜射官中盜，中之血闌干。", "帶箭君前訴，君王悄不歡。", "頃曾爲盜者，百箭中心攢。", "競將兒女淚，滴瀝助辛酸。", "君王責良帥，此禍誰爲端。", "帥言發硎罪，不使刃稍刓。", "君王不忍殺，逐之如迸丸。", "仍令後來箭，盡可頭團團。", "發硎去雖遠，礪鏃心不闌。", "會射蛟螭盡，舟行無惡瀾。"]'),
('c3b191f6-3b5b-42bc-bb0e-dc0421c9df0e','賽神','元稹','唐','唐诗','tang','','[]','邨落事妖神，林木大如邨。',288,'全唐诗/poet.tang.21000.json','["邨落事妖神，林木大如邨。", "事來三十載，巫覡傳子孫。", "邨中四時祭，殺盡雞與豚。", "主人不堪命，積燎曾欲燔。", "旋風天地轉，急雨江河翻。", "採薪持斧者，棄斧縱橫奔。", "山深多掩暎，僅免鯨鯢吞。", "主人集鄰里，各各持酒罇。", "廟中再三拜，願得禾稼存。", "去年大巫死，小覡又妖言。", "邑中神明宰，有意效西門。", "焚除計未決，伺者迭乘軒。", "廟深荆棘厚，但見狐兔蹲。", "巫言小神變，可驗牛馬蕃。", "邑吏齊進說，幸勿禍鄉原。", "踰年計不定，縣聽良亦煩。", "涉夏祭時至，因令修四垣。", "憂虞神憤恨，玉帛意彌敦。", "我來神廟下，簫鼓正喧喧。", "因言遣妖術，滅絕由本根。", "主人中罷舞，許我重疊論。", "蜉蝣生溼處，鴟鴞集黃昏。", "主人邪心起，氣燄日夜繁。", "狐貍得蹊徑，潛穴主人園。"]'),
('08155b8d-f4f2-486d-8d3d-b7260482feb1','大觜烏','元稹','唐','唐诗','tang','','[]','陽烏有二類，觜白者名慈。',288,'全唐诗/poet.tang.21000.json','["陽烏有二類，觜白者名慈。", "求食哺慈母，因以此名之。", "飲啄頗廉儉，音響亦柔雌。", "百巢同一樹，棲宿不復疑。", "得食先反哺，一身常苦羸。", "緣知五常性，飜被衆禽欺。", "其一觜大者，攫搏性貪癡。", "有力強如鶻，有爪利如錐。", "音響甚㕭嗗，潛通妖怪詞。", "受日餘光庇，終天無死期。", "翺翔富人屋，棲息屋前枝。", "巫言此烏至，財產日豐宜。", "主人一心惑，誘引不知疲。", "轉見烏來集，自言家轉孳。", "白鶴門外養，花鷹架上維。", "專聽烏喜怒，信受若神龜。", "舉家同此意，彈射不復施。", "往往清池側，却令鵷鷺隨。", "羣烏飽粱肉，毛羽色澤滋。", "遠近恣所往，貪殘無不爲。", "巢禽攫雛卵，廐馬啄瘡痍。", "滲瀝脂膏盡，鳳皇那得知。", "主人一朝病，爭向屋檐窺。", "呦鷕呼羣鵩，翩翻集怪鴟。"]'),
('048200b9-d1cb-4c99-bd0d-69066c944e24','分水嶺','元稹','唐','唐诗','tang','','[]','崔嵬分水嶺，高下與雲平。',216,'全唐诗/poet.tang.21000.json','["崔嵬分水嶺，高下與雲平。", "上有分流水，東西隨勢傾。", "朝同一源出，暮隔千里情。", "風雨各自異，波瀾相背驚。", "勢高競奔注，勢曲已回縈。", "偶值當途石，蹙縮又縱橫。", "有時遭孔穴，變作嗚咽聲。", "褊淺無所用，奔波奚所營。", "團團井中水，不復東西征。", "上應美人意，中涵孤月明。", "旋風西面起，井深波不生。", "堅冰一時合，井深凍不成。", "終年汲引絕，不耗復不盈。", "五月金石鑠，既寒亦既清。", "易時不易性，改邑不改名。", "定如拱北極，瑩若燒玉英。", "君門客如水，日夜隨勢行。", "君看守心者，井水爲君盟。"]'),
('34cc279f-d8a2-42b0-9549-522d116b8897','四皓廟','元稹','唐','唐诗','tang','','[]','巢由昔避世，堯舜不得臣。',288,'全唐诗/poet.tang.21000.json','["巢由昔避世，堯舜不得臣。", "伊呂雖急病，湯武乃可君。", "四賢胡爲者，千載名氛氳。", "顯晦有遺迹，前後疑不倫。", "秦政虐天下，黷武窮生民。", "諸侯戰必死，壯士眉亦嚬。", "張良韓孺子，椎碎屬車輪。", "遂令英雄意，日夜思報秦。", "先生相將去，不復嬰世塵。", "雲卷在孤岫，龍潛爲小鱗。", "秦王轉無道，諫者鼎鑊親。", "茅焦脫衣諫，先生無一言。", "趙高殺二世，先生如不聞。", "劉項取天下，先生游白雲。", "海內八年戰，先生全一身。", "漢業日已定，先生名亦振。", "不得爲濟世，宜哉爲隱淪。", "如何一朝起，屈作儲貳賓。", "安存孝惠帝，摧顇戚夫人。", "舍大以謀細，虯盤而蠖伸。", "惠帝竟不嗣，呂氏禍有因。", "雖懷安劉志，未若周與陳。", "皆落子房術，先生道何屯。", "出處貴明白，故吾今有云。"]'),
('2cab97ee-60f4-4700-a7c6-8df13d928a21','青雲驛','元稹','唐','唐诗','tang','','[]','岧嶢青雲嶺，下有千仞谿。',288,'全唐诗/poet.tang.21000.json','["岧嶢青雲嶺，下有千仞谿。", "裴回不可上，人倦馬亦嘶。", "願登青雲路，若望丹霞梯。", "謂言青雲驛，繡戶芙蓉閨。", "謂言青雲騎，玉勒黃金蹄。", "謂言青雲具，瑚璉雜象犀。", "謂言青雲吏，的的顏如珪。", "懷此青雲望，安能復久稽。", "攀援信不易，風雨正淒淒。", "已怪杜鵑鳥，先來山下啼。", "纔及青雲驛，忽遇蓬蒿妻。", "延我開蓽戶，鑿竇宛如圭。", "逡巡吏來謁，頭白顏色黧。", "饋食頻叫噪，假器仍乞醯。", "嚮時延我者，共捨藿與藜。", "乘我牂牁馬，蒙茸大如羝。", "悔爲青雲意，此意良噬臍。", "昔游蜀門下，有驛名青泥。", "聞名意慘愴，若墜牢與狴。", "雲泥異所稱，人物一以齊。", "復聞閶闔上，下視日月低。", "銀城蘂珠殿，玉版金字題。", "大帝直南北，羣仙侍東西。", "龍虎儼隊仗，雷霆轟鼓鼙。"]'),
('fabc073e-fb05-46e9-92c1-398d7c47c759','陽城驛','元稹','唐','唐诗','tang','','[]','商有陽城驛，名同陽道州。',288,'全唐诗/poet.tang.21000.json','["商有陽城驛，名同陽道州。", "陽公沒已久，感我淚交流。", "昔公孝父母，行與曾閔儔。", "既孤善兄弟，兄弟和且柔。", "一夕不相見，若懷三歲憂。", "遂誓不婚娶，沒齒同衾裯。", "妹夫死他縣，遺骨無人收。", "公令季弟往，公與仲弟留。", "相別竟不得，三人同遠遊。", "共負他鄉骨，歸來藏故丘。", "棲遲居夏邑，邑人無苟媮。", "里中競長短，來問劣與優。", "官刑一朝恥，公短終身羞。", "公亦不遺布，人自不盜牛。", "問公何能爾，忠信先自修。", "發言當道理，不顧黨與讐。", "聲香漸翕習，冠蓋若雲浮。", "少者從公學，老者從公遊。", "往來相告報，縣尹與公侯。", "名落公卿口，湧如波薦舟。", "天子得聞之，書下再三求。", "書中願一見，不異旱地虯。", "何以持爲聘，束帛藉琳球。", "何以持爲御，駟馬駕安輈。"]'),
('a59c6ba2-5861-4180-a422-9adbd40dc892','苦雨','元稹','唐','唐诗','tang','','[]','江瘴氣候惡，庭空田地蕪。',288,'全唐诗/poet.tang.21000.json','["江瘴氣候惡，庭空田地蕪。", "煩昏一日內，陰暗三四殊。", "巢燕汚牀席，蒼蠅點肌膚。", "不足生詬怒，但苦寡歡娛。", "夜來稍清晏，放體階前呼。", "未飽風月思，已爲蚊蚋圖。", "我受簪組身，我生天地爐。", "炎蒸安敢勌，蟲豸何時無。", "凌晨坐堂廡，努力泥中趨。", "官家事不了，尤悔亦可虞。", "門外竹橋折，馬驚不敢踰。", "回頭命僮御，向我色踟躕。", "自顧方濩落，安能相詰誅。", "隱忍心憤恨，翻爲聲喣愉。", "逡巡崔嵬日，杲曜東南隅。", "已復雲蔽翳，不使及泥塗。", "良農盡蒲葦，厚地積潢汚。", "三光不得照，萬物何由蘇。", "安得飛廉車，磔裂雲將軀。", "又提精陽劒，蛟螭支節屠。", "陰沴皆電埽，幽妖亦雷驅。", "煌煌啓閶闔，軋軋掉乾樞。", "東西生日月，晝夜如轉珠。", "百川朝巨海，六龍蹋亨衢。"]'),
('9b7e07cd-3289-4873-ab4f-3e582641ddd7','種竹','元稹','唐','唐诗','tang','','[]','昔公憐我直，比之秋竹竿。',120,'全唐诗/poet.tang.21000.json','["昔公憐我直，比之秋竹竿。", "秋來苦相憶，種竹廳前看。", "失地顏色改，傷根枝葉殘。", "清風猶淅淅，高節空團團。", "鳴蟬聒暮景，跳蛙集幽闌。", "塵土復晝夜，梢雲良獨難。", "丹丘信云遠，安得臨仙壇。", "瘴江冬草綠，何人驚歲寒。", "可憐亭亭榦，一一青琅玕。", "孤鳳竟不至，坐傷時節闌。"]'),
('2fbada56-daea-4a1d-86de-04d8687d70d9','和樂天贈樊著作','元稹','唐','唐诗','tang','','[]','君爲著作詩，志激詞且溫。',288,'全唐诗/poet.tang.21000.json','["君爲著作詩，志激詞且溫。", "璨然光揚者，皆以義烈聞。", "千慮竟一失，冰玉不斷痕。", "謬予頑不肖，列在數子間。", "因君譏史氏，我亦能具陳。", "羲黃眇云遠，載籍無遺文。", "煌煌二帝道，鋪設在典墳。", "堯心惟舜會，因著爲話言。", "臯夔益稷禹，粗得無間然。", "緬然千載後，後聖曰孔宣。", "迥知皇王意，綴書爲百篇。", "是時游夏輩，不敢措舌端。", "信哉作遺訓，職在聖與賢。", "如何至近古，史氏爲閑官。", "但令識字者，竊弄刀筆權。", "由心書曲直，不使當世觀。", "貽之千萬代，疑言相竝傳。", "人人異所見，各各私所偏。", "以是曰褒貶，不如都無焉。", "況乃丈夫志，用捨貴當年。", "顧予有微尚，願以出處論。", "出非利吾已，其出貴道全。", "全道豈虛設，道全當及人。", "全則富與壽，虧則饑與寒。"]'),
('7dc28e2e-578e-47bd-8ca9-c648ab400c82','和樂天感鶴','元稹','唐','唐诗','tang','','[]','我有所愛鶴，毛羽霜雪妍。',120,'全唐诗/poet.tang.21000.json','["我有所愛鶴，毛羽霜雪妍。", "秋霄一滴露，聲聞林外天。", "自隨衛侯去，遂入大夫軒。", "雲貌久已隔，玉音無復傳。", "吟君感鶴操，不覺心惕然。", "無乃予所愛，誤爲微物遷。", "因茲諭直質，未免柔細牽。", "君看孤松樹，左右蘿蔦纏。", "既可習爲飽，亦可薰爲荃。", "期君常善救，勿令終棄捐。"]'),
('29f6c161-100e-4023-90c0-26a5739b7e53','諭寶二首 一','元稹','唐','唐诗','tang','','["\u6cf0\u5c71"]','沈玉在弱泥，泥弱玉易沈。',72,'全唐诗/poet.tang.21000.json','["沈玉在弱泥，泥弱玉易沈。", "扶桑寒日薄，不照萬丈心。", "安得潛淵虯，拔壑超鄧林。", "泥封泰山阯，水散旱天霖。", "洗此泥下玉，照耀臺殿深。", "刻爲傳國寶，神器人不侵。"]'),
('3f8b47ed-b2ac-4b77-8af3-2b131e20a8cf','諭寶二首 二','元稹','唐','唐诗','tang','','[]','冰置白玉壺，始見清皎潔。',288,'全唐诗/poet.tang.21000.json','["冰置白玉壺，始見清皎潔。", "珠穿殷紅縷，始見明洞徹。", "鏌鋣無人淬，兩刃幽壤鐵。", "秦鏡無人拭，一片埋霧月。", "驥跼環堵中，骨附筋入節。", "虯蟠尺澤內，魚貫蛙同穴。", "艅艎無巨海，浮浮矜瀎潏。", "棟梁無廣廈，顛倒臥霜雪。", "大鵬無長空，舉翮受羈絏。", "豫樟無厚地，危柢真卼臲。", "圭璧無卞和，甘與頑石列。", "舜禹無陶堯，名隨腐草滅。", "神功伏神物，神物神乃別。", "神人不世出，所以神功絕。", "神物豈徒然，用之乃施設。", "禹功九州理，舜德天下悅。", "璧充傳國璽，圭用祈太折。", "千尋豫樟榦，九萬大鵬歇。", "棟梁庇生民，艅艎濟來哲。", "虯騰旱天雨，驥騁流電掣。", "鏡懸姦膽露，劒拂妖蛇裂。", "珠玉照乘光，冰瑩環坐熱。", "此物比在泥，斯言爲誰發。", "於今盡凡耳，不爲君不說。"]'),
('52ba3893-9000-4079-9996-b50f4c7bf415','說劒','元稹','唐','唐诗','tang','','[]','吾友有寶劒，密之如密友。',288,'全唐诗/poet.tang.21000.json','["吾友有寶劒，密之如密友。", "我實膠漆交，中堂共杯酒。", "酒酣肝膽露，恨不眼前剖。", "高唱荆卿歌，亂擊相如缶。", "更擊復更唱，更酌亦更壽。", "白虹坐上飛，青蛇匣中吼。", "我聞音響異，疑是干將偶。", "爲君再拜言，神物可見不。", "君言我所重，我自爲君取。", "迎篋已焚香，近鞘先澤手。", "徐抽寸寸刃，漸屈彎彎肘。", "殺殺霜在鋒，團團月臨紐。", "逡巡潛虯躍，鬱律驚左右。", "霆電滿室光，蛟龍繞身走。", "我爲捧之泣，此劒別來久。", "鑄時近山破，藏在松桂朽。", "幽匣獄底埋，神人水心守。", "本是稽泥淬，果非雷煥有。", "我欲評劒功，願君良聽受。", "劒可剸犀兕，劒可切瓊玖。", "劒決天外雲，劒衝日中斗。", "劒隳妖蛇腹，劒拂佞臣首。", "太古初斷鼇，武王親擊紂。", "燕丹卷地圖，陳平綰花綬。"]'),
('d383b134-10df-471c-9c0b-09230cb4d342','書異','元稹','唐','唐诗','tang','','[]','孟冬初寒月，渚澤蒲尚青。',192,'全唐诗/poet.tang.21000.json','["孟冬初寒月，渚澤蒲尚青。", "飄蕭北風起，皓雪紛滿庭。", "行過冬至後，凍閉萬物零。", "奔渾馳暴雨，驟鼓轟雷霆。", "傳云不終日，通宵曾莫停。", "瘴雲愁拂地，急霤疑注缾。", "洶湧潢潦濁，噴薄鯨鯢腥。", "跳趫井蛙喜，突兀水怪形。", "飛蚋奔不死，修蛇蟄再醒。", "應龍非時出，無乃歲不寧。", "吾聞陰陽戶，啓閉各有扃。", "後時無肅殺，廢職乃玄冥。", "座配五天帝，薦用百品珍。", "權爲祝融奪，神其焉得靈。", "春秋雷電異，則必書諸經。", "仲冬雷雨苦，願省蒙蔽刑。"]'),
('1404cdcc-cc01-430c-8aed-f0897c9f4d66','和樂天折劒頭','元稹','唐','唐诗','tang','','[]','聞君得折劒，一片雄心起。',60,'全唐诗/poet.tang.21000.json','["聞君得折劒，一片雄心起。", "詎意鐵蛟龍，潛在延津水。", "風雲會一合，呼吸期萬里。", "雷震山嶽碎，電斬鯨鯢死。", "莫但寶劒頭，劒頭非此比。"]'),
('df1958fe-3b06-4860-9050-66a413ebf53f','松鶴','元稹','唐','唐诗','tang','','[]','渚宮本坳下，佛廟有臺閣。',144,'全唐诗/poet.tang.21000.json','["渚宮本坳下，佛廟有臺閣。", "臺下三四松，低昂勢前却。", "是時晴景麗，松梢殘雪薄。", "日色相玲瓏，纖雲暎羅幕。", "逡巡九霄外，似振風中鐸。", "漸見尺帛光，孤飛唳空鶴。", "裴回耀霜雪，顧慕下寥廓。", "蹋動樛盤枝，龍蛇互跳躍。", "俯瞰九江水，旁瞻萬里壑。", "無心眄烏鳶，有字悲城郭。", "清角已沈絕，虞韶亦冥寞。", "鶱翻勿重留，幸及鈞天作。"]'),
('aceae76b-ffff-4b6f-8c08-6572a7b2bdf8','競渡','元稹','唐','唐诗','tang','','["\u9ec4\u6cb3"]','吾觀競舟子，因測大競源。',288,'全唐诗/poet.tang.21000.json','["吾觀競舟子，因測大競源。", "天地昔將競，蓬勃晝夜昏。", "龍蛇相嗔薄，海岱俱崩奔。", "羣動皆攪撓，化作流渾渾。", "數極鬬心息，太和蒸混元。", "一氣忽爲二，矗然畫乾坤。", "日月復照耀，春秋遞寒溫。", "八荒坦以曠，萬物羅以繁。", "聖人中間立，理世了不煩。", "延綿復幾歲，逮及羲與軒。", "炎皇熾如炭，蚩尤扇其燔。", "有熊競心起，驅獸出林樊。", "一戰波委燄，再戰火燎原。", "戰訖天下定，號之爲軒轅。", "自是豈無競，瑣細不復言。", "其次有龍競，競渡龍之門。", "龍門浚如瀉，淙射不可援。", "赤鱗化時至，唐突鰭鬣掀。", "乘風瞥然去，萬里黃河飜。", "接瞬電烻出，微吟霹靂喧。", "傍瞻曠宇宙，俯瞰卑崑崙。", "庶類咸在下，九霄行易捫。", "倏辭蛙黽穴，遽排天帝閽。", "迴悲曝鰓者，未免鯨鯢吞。"]'),
('67027072-45f2-443a-b8b2-b82cbfd0558d','寺院新竹','元稹','唐','唐诗','tang','','[]','寶地琉璃坼，紫苞琅玕踴。',168,'全唐诗/poet.tang.21000.json','["寶地琉璃坼，紫苞琅玕踴。", "亭亭巧於削，一一大如拱。", "冰碧林外寒，峯巒眼前聳。", "槎枒矛戟合，屹仡龍蛇動。", "煙泛翠光流，歲餘霜彩重。", "風朝竽籟過，雨夜鬼神恐。", "佳色有鮮妍，修莖無擁腫。", "節高迷玉鏃，籜綴疑花捧。", "詎必太山根，本自仙壇種。", "誰令植幽壤，復此依閑冗。", "居然霄漢姿，坐受藩籬壅。", "噪集勌鴟烏，炎昏繁蠛蠓。", "未遭伶倫聽，非安子猶寵。", "威鳳來有時，虛心豈無奉。"]'),
('c0604487-cc43-4761-9d62-013e84c9f087','詶別致用','元稹','唐','唐诗','tang','','[]','風行自委順，雲合非有期。',216,'全唐诗/poet.tang.21000.json','["風行自委順，雲合非有期。", "神哉心相見，無眹安得離。", "我有懇憤志，三十無人知。", "修身不言命，謀道不擇時。", "達則濟億兆，窮亦濟毫氂。", "濟人無大小，誓不空濟私。", "研幾未淳熟，與世忽參差。", "意氣一爲累，猜仍良已隨。", "昨來竄荆蠻，分與平生隳。", "那言返爲遇，獲見心所奇。", "一見肺肝盡，坦然無滯疑。", "感念交契定，淚流如斷縻。", "此交定生死，非爲論盛衰。", "此契宗會極，非爲同路岐。", "君今虎在柙，我亦鷹就羈。", "馴養保性命，安能奮殊姿。", "玉色深不變，井水撓不移。", "相看各年少，未敢深自悲。"]'),
('193fbd8d-cb2c-41d3-b3f2-7756d0fdcef9','竹部','元稹','唐','唐诗','tang','','[]','竹部竹山近，歲伐竹山竹。',144,'全唐诗/poet.tang.21000.json','["竹部竹山近，歲伐竹山竹。", "伐竹歲亦深，深林隔深谷。", "朝朝冰雪行，夜夜豺狼宿。", "科首霜斷蓬，枯形燒餘木。", "一束十餘莖，千錢百餘束。", "得錢盈千百，得粟盈斗斛。", "歸來不買食，父子分半菽。", "持此欲何爲，官家歲輸促。", "我來荆門掾，寓食公堂肉。", "豈惟遍妻孥，亦以及僮僕。", "分爾有限資，飽我無端腹。", "愧爾不復言，爾生何太蹙。"]'),
('d97c36a4-f388-4f8a-bd90-85c9131f8766','賽神','元稹','唐','唐诗','tang','','[]','楚俗不事事，巫風事妖神。',216,'全唐诗/poet.tang.21000.json','["楚俗不事事，巫風事妖神。", "事妖結妖社，不問疎與親。", "年年十月暮，珠稻欲垂新。", "家家不歛穫，賽妖無富貧。", "殺牛貰官酒，椎鼓集頑民。", "喧闐里閭隘，兇酗日夜頻。", "歲暮雪霜至，稻珠隨隴湮。", "吏來官稅迫，求質倍稱緡。", "貧者日消鑠，富亦無倉囷。", "不謂事神苦，自言誠不真。", "岳陽賢刺史，念此爲俗屯。", "未可一朝去，俾之爲等倫。", "粗許存習俗，不得呼黨人。", "但許一日澤，不得月與旬。", "吾聞國僑理，三年名乃振。", "巫風燎原久，未必憐徙薪。", "我來歌此事，非獨歌政仁。", "此事四鄰有，亦欲聞四鄰。"]'),
('855b9365-2123-4728-8eed-13888fc717ab','競舟','元稹','唐','唐诗','tang','','["\u957f\u6c5f"]','楚俗不愛力，費力爲競舟。',240,'全唐诗/poet.tang.21000.json','["楚俗不愛力，費力爲競舟。", "買舟俟一競，競歛貧者賕。", "年年四五月，蠒實麥小秋。", "積水堰堤壞，拔秧蒲稗稠。", "此時集丁壯，習競南畝頭。", "朝飲邨社酒，暮椎鄰舍牛。", "祭船如祭祖，習競如習讐。", "連延數十日，作業不復憂。", "君侯饌良吉，會客陳膳羞。", "畫鷁四來合，大競長江流。", "建標明取舍，勝負死生求。", "一時讙呼罷，三月農事休。", "岳陽賢刺史，念此爲俗疣。", "習俗難盡去，聊用去其尤。", "百船不留一，一競不滯留。", "自爲里中戲，我亦不寓遊。", "吾聞管仲教，沐樹懲墮遊。", "節此淫競俗，得爲良政不。", "我來歌此事，非獨歌此州。", "此事數州有，亦欲聞數州。"]'),
('909d8dde-fbcd-4dff-a1c5-db20860f1635','茅舍','元稹','唐','唐诗','tang','','[]','楚俗不理居，居人盡茅舍。',288,'全唐诗/poet.tang.21000.json','["楚俗不理居，居人盡茅舍。", "茅苫竹梁棟，茅疎竹仍罅。", "邊緣隄岸斜，詰屈檐楹亞。", "籬落不蔽肩，街衢不容駕。", "南風五月盛，時雨不來下。", "竹蠹茅亦乾，迎風自焚灺。", "防虞集鄰里，巡警勞晝夜。", "遺燼一星然，連延禍相嫁。", "號呼鄰穀帛，奔走伐桑柘。", "舊架已新焚，新茅又初架。", "前日洪州牧，念此常嗟訝。", "牧民未及久，郡邑紛如化。", "峻邸儼相望，飛甍遠相跨。", "旗亭紅粉泥，佛廟青鴛瓦。", "斯事纔未終，斯人久云謝。", "有客自洪來，洪民至今藉。", "惜其心太亟，作役無容暇。", "臺觀亦已多，工徒稍冤咤。", "我欲他郡長，三時務耕稼。", "農收次邑居，先室後臺榭。", "啓閉既及期，公私亦相借。", "度材無強略，庀役有定價。", "不使及僭差，粗得禦寒夏。", "火至殊陳鄭，人安極嵩華。"]'),
('755c64d7-d314-457d-a628-c906470a71ae','後湖','元稹','唐','唐诗','tang','','[]','荆有泥濘水，在荆之邑郛。',288,'全唐诗/poet.tang.21000.json','["荆有泥濘水，在荆之邑郛。", "郛前水在後，謂之爲後湖。", "環湖十餘里，歲積潢與汚。", "臭腐魚鼇死，不植菰與蒲。", "鄭公理三載，其理用喣愉。", "歲稔民四至，隘廛亦隘衢。", "公乃署其地，爲民先矢謨。", "人人儻自爲，我亦不庀徒。", "下里得聞之，各各相俞俞。", "提攜翁及孫，捧戴婦與姑。", "壯者負礫石，老亦捽茅蒭。", "斤磨片片雪，椎隱連連珠。", "朝餐布庭落，夜宿完戶樞。", "鄰里近相告，親戚遠相呼。", "鬻者自爲鬻，酤者自爲酤。", "雞犬豐中市，人民岐下都。", "百年廢滯所，一旦奧浩區。", "我實司水土，得爲官事無。", "人言賤事貴，貴直不貴諛。", "此實公所小，安用歌袴襦。", "答云潭及廣，以至鄂與吳。", "萬里盡澤國，居人皆墊濡。", "富者不容蓋，貧者不庇軀。", "得不歌此事，以我爲楷模。"]'),
('bd9a064c-3229-4e8d-870c-9ddbccad9c50','八駿圖詩','元稹','唐','唐诗','tang','','[]','穆滿志空闊，將行九州野。',120,'全唐诗/poet.tang.21000.json','["穆滿志空闊，將行九州野。", "神馭四來歸，天與八駿馬。", "龍種無凡性，龍行無暫捨。", "朝辭扶桑底，暮宿崑崙下。", "鼻息吼春雷，蹄聲裂寒瓦。", "尾掉滄波黑，汗染白雲赭。", "華輈本修密，翠蓋尚妍冶。", "御者腕不移，乘者寐不假。", "車無輪扁斵，轡無王良把。", "雖有萬駿來，誰是敢騎者。"]'),
('6fd0c84b-5f2e-4973-afb7-5deef60546be','畫松','元稹','唐','唐诗','tang','','[]','張璪畫古松，往往得神骨。',72,'全唐诗/poet.tang.21000.json','["張璪畫古松，往往得神骨。", "翠帚掃春風，枯龍戛寒月。", "流傳畫師輩，奇態盡埋沒。", "纖枝無蕭灑，頑榦空突兀。", "乃悟埃塵心，難狀煙霄質。", "我去淅陽山，深山看真物。"]'),
('aaf435b6-7c18-4c02-b8ca-1a2c7b738c15','遣興十首 一','元稹','唐','唐诗','tang','','[]','始見棃花房，坐對棃花白。',48,'全唐诗/poet.tang.21000.json','["始見棃花房，坐對棃花白。", "行看棃葉青，已復棃葉赤。", "嚴霜九月半，危蔕幾時客。", "況有高高原，秋風四來迫。"]'),
('75e6e7b3-dda9-4f2a-91a7-9a2976ec97ce','遣興十首 二','元稹','唐','唐诗','tang','','[]','莫厭夏日長，莫愁冬日短。',48,'全唐诗/poet.tang.21000.json','["莫厭夏日長，莫愁冬日短。", "欲識短復長，君看寒又暖。", "城中百萬家，冤哀雜絲管。", "草沒奉誠園，軒車昔曾滿。"]'),
('1ee554fc-28dd-423b-a821-57d98415b601','遣興十首 三','元稹','唐','唐诗','tang','','[]','孤竹迸荒園，誤與蓬麻列。',48,'全唐诗/poet.tang.21000.json','["孤竹迸荒園，誤與蓬麻列。", "久擁蕭蕭風，空長高高節。", "嚴霜蕩羣穢，蓬斷麻亦折。", "獨立轉亭亭，心期鳳皇別。"]'),
('bd266d86-07dc-40f5-9434-b62b1d96d70a','遣興十首 四','元稹','唐','唐诗','tang','','[]','豔豔翦紅英，團團削翠莖。',48,'全唐诗/poet.tang.21000.json','["豔豔翦紅英，團團削翠莖。", "託根在褊淺，因依泥滓生。", "中有合歡蘂，池枯難遽呈。", "涼宵露華重，低徊當月明。"]'),
('4e16a0af-bbba-400c-b2f9-0242307b8afe','遣興十首 五','元稹','唐','唐诗','tang','','[]','晚荷猶展卷，早蟬遽蕭嘹。',48,'全唐诗/poet.tang.21000.json','["晚荷猶展卷，早蟬遽蕭嘹。", "露葉行已重，況乃江風搖。", "炎夏火再伏，清商暗回飆。", "寄言抱志士，日月東西跳。"]'),
('a81d7f9e-49be-4cbf-83ba-a4b64617e5a9','遣興十首 六','元稹','唐','唐诗','tang','','[]','買馬買鋸牙，買犢買破車。',48,'全唐诗/poet.tang.21000.json','["買馬買鋸牙，買犢買破車。", "養禽當養鶻，種樹先種花。", "人生負俊健，天意與光華。", "莫學蚯蚓輩，食泥近土涯。"]'),
('0cab9190-6971-47af-8208-c109b241231f','遣興十首 七','元稹','唐','唐诗','tang','','[]','愛直莫愛夸，愛疾莫愛斜。',48,'全唐诗/poet.tang.21000.json','["愛直莫愛夸，愛疾莫愛斜。", "愛謨莫愛詐，愛施莫愛奢。", "擇才不求備，任物不過涯。", "用人如用己，理國如理家。"]'),
('39c0ce48-29cc-4ea4-ba3e-d31aa9a75e60','遣興十首 八','元稹','唐','唐诗','tang','','[]','㸌㸌刀刃光，彎彎弓面張。',48,'全唐诗/poet.tang.21000.json','["㸌㸌刀刃光，彎彎弓面張。", "入水斬犀兕，上山椎虎狼。", "里中無老少，喚作癲兒郎。", "一日風雲會，橫行歸故鄉。"]'),
('e82ab5b9-7ad5-40ad-ab93-c4a7f2347b0b','遣興十首 九','元稹','唐','唐诗','tang','','[]','團團規內星，未必明如月。',48,'全唐诗/poet.tang.21000.json','["團團規內星，未必明如月。", "託迹近北辰，周天無淪沒。", "老人在南極，地遠光不發。", "見則壽聖明，願照高高闕。"]'),
('2edd5889-0cf6-40f9-8f25-4495d45076fa','遣興十首 十','元稹','唐','唐诗','tang','','[]','河清諒嘉瑞，吾帝真聖人。',48,'全唐诗/poet.tang.21000.json','["河清諒嘉瑞，吾帝真聖人。", "時哉不我夢，此時爲廢民。", "光陰本跳躑，功業勞苦辛。", "一到江陵郡，三年成去塵。"]'),
('0a2a2ea7-19ad-4913-b71c-9636923b14d9','野節鞭','元稹','唐','唐诗','tang','','[]','神鞭鞭宇宙，玉鞭鞭騏驥。',288,'全唐诗/poet.tang.21000.json','["神鞭鞭宇宙，玉鞭鞭騏驥。", "緊綛野節鞭，本用鞭贔屭。", "使君鞭甚長，使君馬亦利。", "司馬竝馬行，司馬馬顦顇。", "短鞭不可施，疾步無由致。", "使君駐馬言，願以長鞭遺。", "此遺不尋常，此鞭不容易。", "金堅無繳繞，玉滑無塵膩。", "青蛇坼生石，不刺山阿地。", "烏龜旋眼斑，不染江頭淚。", "長看雷雨痕，未忍駑駘試。", "持用換所持，無令等閑棄。", "答云君何奇，贈我君所貴。", "我用亦不凡，終身保明義。", "誓以鞭姦頑，不以鞭蹇躓。", "指撝狡兔蹤，決撻怪龍睡。", "惜令寸寸折，節節不虛墜。", "因作換鞭詩，詩成謂同志。", "而我得聞之，笑君年少意。", "安用換長鞭，鞭長亦奚爲。", "我有鞭尺餘，泥拋風雨漬。", "不擬閑贈行，唯將爛誇醉。", "春來信馬頭，款緩花前轡。", "願我遲似攣，饒君疾如翅。"]'),
('bc2dc6a8-32e6-482a-ad51-309c52882337','旱災自咎貽七縣宰','元稹','唐','唐诗','tang','','[]','吾聞上帝心，降命明且仁。',288,'全唐诗/poet.tang.21000.json','["吾聞上帝心，降命明且仁。", "臣稹苟有罪，胡不災我身。", "胡爲旱一州，禍此千萬人。", "一旱猶可忍，其旱亦已頻。", "臘雪不滿地，膏雨不降春。", "惻惻詔書下，半減麥與緡。", "半租豈不薄，尚竭力與筋。", "竭力不敢憚，慚戴天子恩。", "纍纍婦拜姑，吶吶翁語孫。", "禾黍日夜長，足得盈我囷。", "還填折粟稅，酬償貰麥鄰。", "苟無公私責，飲水不爲貧。", "歡言未盈口，旱氣已再振。", "六月天不雨，秋孟亦既旬。", "區區昧陋積，禱祝非不勤。", "日馳衰白顏，再拜泥甲鱗。", "歸來重思忖，願告諸邑君。", "以彼天道遠，豈如人事親。", "團團囹圄中，無乃冤不申。", "擾擾食廩內，無乃姦有因。", "軋軋輸送車，無乃使不倫。", "遙遙負擔卒，無乃役不均。", "今年無大麥，計與珠玉濱。", "邨胥與里吏，無乃求取繁。"]'),
('4403a9ef-46d6-4167-a6f8-5110a82548de','蟲豸詩  一','元稹','唐','唐诗','tang','','[]','巴蛇千種毒，其最鼻褰蛇。',48,'全唐诗/poet.tang.21000.json','["巴蛇千種毒，其最鼻褰蛇。", "掉舌翻紅燄，盤身蹙白花。", "噴人豎毛髮，飲浪沸泥沙。", "欲學叔敖瘞，其如多似麻。"]'),
('2bb4e894-312f-4685-8215-9a91b4857fba','蟲豸詩  二','元稹','唐','唐诗','tang','','[]','越嶺南濱海，武都西隱戎。',48,'全唐诗/poet.tang.21000.json','["越嶺南濱海，武都西隱戎。", "雄黃假名石，鷣鳥遠難籠。", "詎有隳腸計，應無破腦功。", "巴山晝昏黑，妖霧毒濛濛。"]'),
('0f76a9c6-8aa6-4ba6-8e93-28f7e7feaa24','蟲豸詩  三','元稹','唐','唐诗','tang','','[]','漢帝斬蛇劒，晉時燒上天。',48,'全唐诗/poet.tang.21000.json','["漢帝斬蛇劒，晉時燒上天。", "自茲繁巨蟒，往往壽千年。", "白晝遮長道，青溪蒸毒煙。", "戰龍蒼海外，平地血浮船。"]'),
('f3eb6890-789c-467d-b5e7-9892520ca718','蟲豸詩  一','元稹','唐','唐诗','tang','','[]','巴蛇蟠窟穴，穴下有巢蜂。',48,'全唐诗/poet.tang.21000.json','["巴蛇蟠窟穴，穴下有巢蜂。", "近樹禽垂翅，依原獸絕蹤。", "微遭斷手足，厚毒破心胸。", "昔甚招魂句，那知眼自逢。"]'),
('e0a27bf8-573b-4d89-b177-98de3a00b452','蟲豸詩  二','元稹','唐','唐诗','tang','','[]','梨笑清都月，蜂游紫殿春。',48,'全唐诗/poet.tang.21000.json','["梨笑清都月，蜂游紫殿春。", "構脾分部伍，嚼蕊奉君親。", "翅羽頗同類，心神固異倫。", "安知人世裏，下有噬人人。"]'),
('9692918c-8a0b-4091-8c2b-4c997717b993','蟲豸詩  三','元稹','唐','唐诗','tang','','[]','蘭蕙本同畹，蜂蛇亦雜居。',48,'全唐诗/poet.tang.21000.json','["蘭蕙本同畹，蜂蛇亦雜居。", "害心俱毒螫，妖燄兩吹噓。", "雷蟄吞噬止，枯焚巢穴除。", "可憐相濟惡，勿謂禍無餘。"]'),
('3f5f4c9c-9cba-45ab-a378-b9eaaea6e9a4','蟲豸詩  一','元稹','唐','唐诗','tang','','[]','蜘蛛天下足，巴蜀就中多。',48,'全唐诗/poet.tang.21000.json','["蜘蛛天下足，巴蜀就中多。", "縫隙容長踦，虛空織橫羅。", "縈纏傷竹柏，吞噬及蟲蛾。", "爲送佳人喜，珠櫳無奈何。"]'),
('128bab67-8594-48a5-ba06-60aa72426fd4','蟲豸詩  二','元稹','唐','唐诗','tang','','[]','網密將求食，絲斜誤著人。',48,'全唐诗/poet.tang.21000.json','["網密將求食，絲斜誤著人。", "因依方紀緒，挂罥遂容身。", "截道蟬冠礙，漫天玉露頻。", "兒童憐小巧，漸欲及車輪。"]'),
('5eb23364-cf92-4fad-9b8e-d0c74f5f8726','蟲豸詩  三','元稹','唐','唐诗','tang','','[]','稚子憐圓網，佳人祝喜絲。',48,'全唐诗/poet.tang.21000.json','["稚子憐圓網，佳人祝喜絲。", "那知緣暗隙，忽被囓柔肌。", "毒腠攻猶易，焚心療恐遲。", "看看長祅緒，和扁欲漣洏。"]'),
('411395f3-d3f0-4b64-b7ec-e2341f7701c8','蟲豸詩  一','元稹','唐','唐诗','tang','','[]','蟻子生無處，偏因溼處生。',48,'全唐诗/poet.tang.21000.json','["蟻子生無處，偏因溼處生。", "陰霪煩擾攘，拾粒苦譻𧭈。", "牀上主人病，耳中虛藏鳴。", "雷霆翻不省，聞汝作牛聲。"]'),
('872884eb-a61d-4884-94dd-69dc32620d22','蟲豸詩  二','元稹','唐','唐诗','tang','','[]','時術功雖細，年深禍亦成。',48,'全唐诗/poet.tang.21000.json','["時術功雖細，年深禍亦成。", "攻穿漏江海，噆食困蛟鯨。", "敢憚榱𣡵蠹，深藏柱石傾。", "寄言持重者，微物莫全輕。"]'),
('e3fe932c-027b-4689-9289-d4445b39c9be','蟲豸詩  三','元稹','唐','唐诗','tang','','[]','攘攘終朝見，悠悠卒歲疑。',48,'全唐诗/poet.tang.21000.json','["攘攘終朝見，悠悠卒歲疑。", "詎能分牝牡，焉得有蝝蚳。", "徙市竟何意，生涯都幾時。", "巢由或逢我，應似我相期。"]'),
('2c76ab9d-896e-4d57-937f-91695a9aa894','蟲豸詩  一','元稹','唐','唐诗','tang','','[]','蟆子微於蚋，朝繁夜則無。',48,'全唐诗/poet.tang.21000.json','["蟆子微於蚋，朝繁夜則無。", "毫端生羽翼，針喙噆肌膚。", "暗毒應難免，羸形日漸枯。", "將身遠相就，不敢恨非辜。"]'),
('eceec461-19df-41bb-9979-fc6f2d6ab4e3','蟲豸詩  二','元稹','唐','唐诗','tang','','[]','晦景權藏毒，明時敢噬人。',48,'全唐诗/poet.tang.21000.json','["晦景權藏毒，明時敢噬人。", "不勞生詬怒，祗足助酸辛。", "隼眥看無物，蛇軀庇有鱗。", "天方芻狗我，甘與爾相親。"]'),
('74a566d6-89d1-4036-a849-abe633e5bf14','蟲豸詩  三','元稹','唐','唐诗','tang','','[]','有口深堪異，趨時詎可量。',48,'全唐诗/poet.tang.21000.json','["有口深堪異，趨時詎可量。", "誰令通鼻息，何故辨馨香。", "沈水來滄海，崇蘭泛露光。", "那能枉焚爇，爾衆我微茫。"]'),
('d0102e91-8d1f-43c3-8116-88098ac902ce','蟲豸詩  一','元稹','唐','唐诗','tang','','[]','可歎浮塵子，纖埃喻此微。',48,'全唐诗/poet.tang.21000.json','["可歎浮塵子，纖埃喻此微。", "寧諭隔紗幌，幷解透綿衣。", "有毒能成痏，無聲不見飛。", "病來雙眼暗，何計辨雰霏。"]'),
('e5e7e7f3-7d24-4968-9bf6-e9fd2d02bbeb','蟲豸詩  二','元稹','唐','唐诗','tang','','[]','乍可巢蚊睫，胡爲附蟒鱗。',48,'全唐诗/poet.tang.21000.json','["乍可巢蚊睫，胡爲附蟒鱗。", "已微於蠢蠢，仍害及仁人。", "動植皆分命，毫芒亦是身。", "哀哉此幽物，生死敵浮塵。"]'),
('f2c4140a-ed9f-4d7f-a3b2-2da6d6bc3fe1','蟲豸詩  三','元稹','唐','唐诗','tang','','[]','但覺皮膚憯，安知瑣細來。',48,'全唐诗/poet.tang.21000.json','["但覺皮膚憯，安知瑣細來。", "因風吹薄霧，向日誤輕埃。", "暗囓堪銷骨，潛飛有禍胎。", "然無防備處，留待雪霜摧。"]'),
('40637f56-967f-417a-89ad-4f372182b82c','蟲豸詩  一','元稹','唐','唐诗','tang','','[]','陰深山有瘴，溼墊草多蝱。',48,'全唐诗/poet.tang.21000.json','["陰深山有瘴，溼墊草多蝱。", "衆噬錐刀毒，羣飛風雨聲。", "汗粘瘡痏痛，日曝苦辛行。", "飽爾蛆殘腹，安知天地情。"]'),
('94f99da0-5d2c-4175-a138-4ad16e360342','蟲豸詩  二','元稹','唐','唐诗','tang','','[]','千山溪沸石，六月火燒雲。',48,'全唐诗/poet.tang.21000.json','["千山溪沸石，六月火燒雲。", "自顧生無類，那堪毒有羣。", "搏牛皮若截，噬馬血成文。", "蹄角尚如此，肌膚安可云。"]'),
('de1c8d47-55b7-4072-b878-93cd07a02b5f','蟲豸詩  三','元稹','唐','唐诗','tang','','[]','辛螫終非久，炎涼本遞興。',48,'全唐诗/poet.tang.21000.json','["辛螫終非久，炎涼本遞興。", "秋風自天落，夏蘖與霜澄。", "一鏡開潭面，千鋒露石稜。", "氣平蟲豸死，雲路好攀登。"]'),
('ba754cfa-4feb-43f8-9bcb-24deaabd5487','楚歌十首 一','元稹','唐','唐诗','tang','','[]','楚人千萬戶，生死繫時君。',48,'全唐诗/poet.tang.21000.json','["楚人千萬戶，生死繫時君。", "當璧便爲嗣，賢愚安可分。", "干戈長浩浩，篡亂亦紛紛。", "縱有明在下，區區何足云。"]'),
('966f4f4f-388a-41fd-9ae0-bb13f11b8bfd','楚歌十首 二','元稹','唐','唐诗','tang','','[]','陶虞事已遠，尼父獨將明。',48,'全唐诗/poet.tang.21000.json','["陶虞事已遠，尼父獨將明。", "潛穴龍無位，幽林蘭自生。", "楚王謀授邑，此意復中傾。", "未別子西語，縱來何所成。"]'),
('7c148921-adcf-446f-b195-73b2a6fb7f7d','楚歌十首 三','元稹','唐','唐诗','tang','','[]','平王漸昏惑，無極轉承恩。',48,'全唐诗/poet.tang.21000.json','["平王漸昏惑，無極轉承恩。", "子建猶相貳，伍奢安得存。", "生居宮雉閟，死葬寢園尊。", "豈料奔吳士，鞭屍郢市門。"]'),
('ffd2582f-032b-469c-8197-86a6b3fcab91','楚歌十首 四','元稹','唐','唐诗','tang','','[]','懼盈因鄧曼，罷獵爲樊姬。',48,'全唐诗/poet.tang.21000.json','["懼盈因鄧曼，罷獵爲樊姬。", "盛德留金石，清風鑒薄帷。", "襄王忽妖夢，宋玉復淫辭。", "萬事捐宮館，空山雲雨期。"]'),
('afc3a802-7480-4a0e-88fe-b013e9cff7da','楚歌十首 五','元稹','唐','唐诗','tang','','[]','宜僚南市住，未省食人恩。',48,'全唐诗/poet.tang.21000.json','["宜僚南市住，未省食人恩。", "臨難忽相感，解紛寧用言。", "何如晉夷甫，坐占紫微垣。", "看著五胡亂，清談空自尊。"]'),
('b8ed0cae-28f1-4bbc-b9a8-0e48ac31c24f','楚歌十首 六','元稹','唐','唐诗','tang','','[]','誰恃王深寵，誰爲楚上卿。',48,'全唐诗/poet.tang.21000.json','["誰恃王深寵，誰爲楚上卿。", "包胥心獨許，連夜哭秦兵。", "千乘徒虛爾，一夫安可輕。", "殷勤聘名士，莫但倚方城。"]'),
('701da57e-3257-4289-998b-a3042ad5fb14','楚歌十首 七','元稹','唐','唐诗','tang','','[]','梁業雄圖盡，遺孫世運消。',48,'全唐诗/poet.tang.21000.json','["梁業雄圖盡，遺孫世運消。", "宣明徒有號，江漢不相朝。", "碑碣高臨路，松枝半作樵。", "唯餘開聖寺，猶學武皇妖。"]'),
('a70a992c-6ca6-4a79-9997-2197a204c5bb','楚歌十首 八','元稹','唐','唐诗','tang','','[]','江陵南北道，長有遠人來。',36,'全唐诗/poet.tang.21000.json','["江陵南北道，長有遠人來。", "死別登舟去，生心上馬迴。", "榮枯誠異日，今古盡同灰。"]'),
('bfe907e2-c892-4893-b463-3cb229cddb89','楚歌十首 九','元稹','唐','唐诗','tang','','[]','三峽連天水，奔波萬里來。',48,'全唐诗/poet.tang.21000.json','["三峽連天水，奔波萬里來。", "風濤各自急，前後苦相推。", "倒入黃牛漩，驚衝灩澦堆。", "古今流不盡，流去不曾迴。"]'),
('c2f9fd22-4d4e-4614-97e8-b5f0186584a9','楚歌十首 十','元稹','唐','唐诗','tang','','[]','八荒同日月，萬古共山川。',48,'全唐诗/poet.tang.21000.json','["八荒同日月，萬古共山川。", "生死既由命，興衰還付天。", "棲棲王粲賦，憤憤屈平篇。", "各自埋幽恨，江流終宛然。"]'),
('ef397857-d135-46ca-8580-dd9ab65d2db3','襄陽道','元稹','唐','唐诗','tang','','[]','羊公名漸遠，唯有峴山碑。',48,'全唐诗/poet.tang.21000.json','["羊公名漸遠，唯有峴山碑。", "近日稱難繼，曹王任馬彝。", "椒蘭俱下世，城郭到今時。", "漢水清如玉，流來本爲誰。"]'),
('6b4aa2bb-9d0c-41c6-9a2f-bd7dac0df7ac','賦得魚登龍門','元稹','唐','唐诗','tang','','[]','魚貫終何益，龍門在苦登。',72,'全唐诗/poet.tang.21000.json','["魚貫終何益，龍門在苦登。", "有成當作雨，無用恥爲鵬。", "激浪誠難泝，雄心亦自憑。", "風雲潛會合，鬐鬣忽騰凌。", "泥滓辭河濁，煙霄見海澄。", "迴瞻順流輩，誰敢望同升。"]'),
('fffe87cc-4990-4051-9cae-9cc53afef0bd','貞元曆','元稹','唐','唐诗','tang','','[]','象魏纔頒曆，龍鑣已御天。',48,'全唐诗/poet.tang.21000.json','["象魏纔頒曆，龍鑣已御天。", "猶看後元曆，新署永貞年。", "半歲光陰在，三朝禮數遷。", "無因書簡冊，空得詠詩篇。"]'),
('3f5114cf-d59a-4a34-9e1f-f3828deb038b','塞馬','元稹','唐','唐诗','tang','','[]','塞馬倦江渚，今朝神彩生。',48,'全唐诗/poet.tang.21000.json','["塞馬倦江渚，今朝神彩生。", "曉風寒獵獵，乍得草頭行。", "夷狄寢烽候，關河無戰聲。", "何由當陣面，從爾四蹄輕。"]'),
('17c6b57f-2574-4491-965f-83127fd81a37','鹿角鎮','元稹','唐','唐诗','tang','','[]','去年湖水滿，此地覆行舟。',48,'全唐诗/poet.tang.21000.json','["去年湖水滿，此地覆行舟。", "萬怪吹高浪，千人死亂流。", "誰能問帝子，何事寵陽侯。", "漸恐鯨鯢大，波濤及九州。"]'),
('adf8f5e2-bfd7-4fd8-bcae-b47488ff6b7f','感事三首 一','元稹','唐','唐诗','tang','','[]','爲國謀羊舌，從來不爲身。',24,'全唐诗/poet.tang.21000.json','["爲國謀羊舌，從來不爲身。", "此心長自保，終不學張陳。"]'),
('2a019e34-9574-468a-906d-903071a4bac8','感事三首 二','元稹','唐','唐诗','tang','','[]','自笑心何劣，區區辨所冤。',24,'全唐诗/poet.tang.21000.json','["自笑心何劣，區區辨所冤。", "伯仁雖到死，終不向人言。"]'),
('bd8007f6-1d78-4c54-a1ea-ac85294c212a','感事三首 三','元稹','唐','唐诗','tang','','[]','富貴年皆長，風塵舊轉稀。',24,'全唐诗/poet.tang.21000.json','["富貴年皆長，風塵舊轉稀。", "白頭方見絕，遙爲一霑衣。"]'),
('55251641-dd16-4501-baf4-886c0d3599ad','題翰林東閤前小松','元稹','唐','唐诗','tang','','[]','簷礙修鱗亞，霜侵簇翠黃。',24,'全唐诗/poet.tang.21000.json','["簷礙修鱗亞，霜侵簇翠黃。", "唯餘入琴韻，終待舜弦張。"]'),
('c969ec8f-af68-484d-9131-ddd7ad918280','清都夜境','元稹','唐','唐诗','tang','','[]','夜久連觀靜，斜月何晶熒。',120,'全唐诗/poet.tang.21000.json','["夜久連觀靜，斜月何晶熒。", "寥天如碧玉，歷歷綴華星。", "樓榭自陰暎，雲牖深冥冥。", "纖埃悄不起，玉砌寒光清。", "棲鶴露微影，枯松多怪形。", "南廂儼容衛，音響如可聆。", "啓聖發空洞，朝真趨廣庭。", "閑開蘂珠殿，暗閱金字經。", "屏氣動方息，凝神心自靈。", "悠悠車馬上，浩思安得寧。"]'),
('36ead4f2-ce71-4c04-9dae-84f0cf10c5ab','春晚寄楊十二兼呈趙八','元稹','唐','唐诗','tang','','[]','蒙蒙竹樹深，簾牖多清陰。',108,'全唐诗/poet.tang.21000.json','["蒙蒙竹樹深，簾牖多清陰。", "避日坐林影，餘花委芳襟。", "傾尊就殘酌，舒卷續微吟。", "空際颺高蝶，風中聆素琴。", "廣庭備幽趣，復對商山岑。", "獨此愛時景，曠懷雲外心。", "遷鸎戀嘉木，求友多好音。", "自無琅玕實，安得蓮花簪。", "寄之二君子，希見雙南金。"]'),
('c55e6652-beb5-4064-9463-04e26fa7f0fc','與楊十二李三早入永壽寺看牡丹','元稹','唐','唐诗','tang','','[]','曉入白蓮宮，琉璃花界淨。',96,'全唐诗/poet.tang.21000.json','["曉入白蓮宮，琉璃花界淨。", "開敷多喻草，凌亂被幽徑。", "壓砌錦地鋪，當霞日輪暎。", "蝶舞香暫飄，蠭牽蕊難正。", "籠處彩雲合，露湛紅珠瑩。", "結葉影自交，搖風光不定。", "繁華有時節，安得保全盛。", "色見盡浮榮，希君了真性。"]'),
('d342a15b-2a35-4f8f-8ec1-45df42fb4d55','春餘遣興','元稹','唐','唐诗','tang','','[]','春去日漸遲，庭空草偏長。',144,'全唐诗/poet.tang.21000.json','["春去日漸遲，庭空草偏長。", "餘英間初實，雪絮縈蛛網。", "好鳥多息陰，新篁已成響。", "簾開斜照入，樹褭游絲上。", "絕跡念物閑，良時契心賞。", "單衣頗新綽，虛室復清敞。", "置酒奉親賓，樹萱自怡養。", "笑倚連枝花，恭扶瑞藤杖。", "步屧恣優游，望山多氣象。", "雲葉遙卷舒，風裾動蕭爽。", "簪纓固煩雜，江海徒浩蕩。", "野馬籠赤霄，無由負羈鞅。"]'),
('fbea6fa2-9164-4aa2-b3a2-4a33a8ead96a','憶雲之','元稹','唐','唐诗','tang','','[]','爲魚實愛泉，食辛寧避蓼。',168,'全唐诗/poet.tang.21000.json','["爲魚實愛泉，食辛寧避蓼。", "人生既相合，不復論窕窕。", "滄海良有窮，白日非長皎。", "何事一人心，各在四方表。", "泛若逐水萍，居爲附松蔦。", "流浪隨所之，縈紆牽所繞。", "百齡頗跼促，況復迷壽夭。", "芟髮君已衰，冠歲予非小。", "娛樂不及時，暮年壯心少。", "感此幽念綿，遂爲長悄悄。", "中庭草木春，歷亂遞相擾。", "奇樹花冥冥，竹竿鳳褭褭。", "幽芳被蘭徑，安得寄天杪。", "萬里瀟湘魂，夜夜南枝鳥。"]'),
('17ae0e25-c004-42a1-b9d2-cb854cd10c0e','別李三','元稹','唐','唐诗','tang','','[]','階蓂附瑤砌，藂蘭偶芳藿。',96,'全唐诗/poet.tang.21000.json','["階蓂附瑤砌，藂蘭偶芳藿。", "高位良有依，幽姿亦相託。", "鮑叔知我貧，烹葵不爲薄。", "半面契始終，千金比然諾。", "人生繫時命，安得無苦樂。", "但感遊子顏，又值餘英落。", "蒼蒼秦樹雲，去去緱山鶴。", "日暮分手歸，楊花滿城郭。"]'),
('ed8cefd7-9acb-43dd-880b-0b2c9659da99','秋夕遠懷','元稹','唐','唐诗','tang','','[]','旦夕天氣爽，風飄葉漸輕。',48,'全唐诗/poet.tang.21000.json','["旦夕天氣爽，風飄葉漸輕。", "星繁河漢白，露逼衾枕清。", "丹鳥月中滅，莎雞牀下鳴。", "悠悠此懷抱，況復多遠情。"]'),
('28fd18f1-a0b6-4aef-9ac3-4de9a7839572','東西道','元稹','唐','唐诗','tang','','[]','天皇開四極，便有東西道。',48,'全唐诗/poet.tang.21000.json','["天皇開四極，便有東西道。", "萬古閱行人，行人幾人老。", "顧我倦行者，息陰何不早？", "少壯塵事多，那言壯年好。"]'),
('864823bd-36a5-4ffb-afb0-08debd6583f3','分流水','元稹','唐','唐诗','tang','','[]','古時愁別淚，滴作分流水。',48,'全唐诗/poet.tang.21000.json','["古時愁別淚，滴作分流水。", "日夜東西流，分流幾千里。", "通塞兩不見，波瀾各自起。", "與君相背飛，去去心如此。"]'),
('7e2ef4b2-a580-4a91-a465-2a89be25d5af','西還','元稹','唐','唐诗','tang','','[]','悠悠洛陽夢，鬱鬱灞陵樹。',24,'全唐诗/poet.tang.21000.json','["悠悠洛陽夢，鬱鬱灞陵樹。", "落日正西歸，逢君又東去。"]'),
('90d24d06-910e-476e-8819-47f127e03360','含風夕','元稹','唐','唐诗','tang','','[]','炎昏勌煩久，逮此含風夕。',240,'全唐诗/poet.tang.21000.json','["炎昏勌煩久，逮此含風夕。", "夏服稍輕清，秋堂已岑寂。", "載欣涼宇曠，復念佳辰擲。", "絡緯驚歲功，顧我何成績。", "青熒微月鉤，幽暉洞陰魄。", "水鏡涵玉輪，若見淵泉璧。", "參差簾牖重，次第籠虛白。", "樹影滿空牀，螢光綴深壁。", "悵望牽牛星，復爲經年隔。", "露網褭風珠，輕河泛遙碧。", "詎無深秋夜，感此乍流易。", "亦有遲暮年，壯年良自惜。", "循環切中腸，感念追往昔。", "接瞬無停陰，何言問陳積。", "馨香推蕙蘭，堅貞諭松柏。", "生物固有涯，安能比金石。", "況茲百齡內，擾擾紛衆役。", "日月東西馳，飛車無留跡。", "來者良未窮，去矣定奚適。", "委順在物爲，營營復何益。"]'),
('2261d409-1d3d-4286-979e-2dcae212eea5','秋堂夕','元稹','唐','唐诗','tang','','[]','炎涼正迴互，金火鬱相乘。',216,'全唐诗/poet.tang.21000.json','["炎涼正迴互，金火鬱相乘。", "雲雷時交構，川澤方蒸騰。", "清風一朝勝，白露忽已凝。", "草木凡氣盡，始見天地澄。", "況此秋堂夕，幽懷曠無朋。", "蕭條簾外雨，倏閃案前燈。", "書卷滿牀席，蠨蛸懸復升。", "啼兒屢啞咽，勌僮時寢興。", "泛覺昏夜目，詠謠暢煩膺。", "況吟獲麟章，欲罷久不能。", "堯舜事已遠，丘道安可勝。", "蜉蝣不信鶴，蜩鷃肯窺鵬。", "當年且不偶，沒世何必稱。", "胡爲揭聞見，褒貶貽愛憎。", "焉用汩其泥，豈在清如冰。", "非白又非黑，誰能點青蠅。", "處世苟無悶，佯狂道非弘。", "無言被人覺，予亦笑孫登。"]'),
('3dce476e-3c4b-4e29-b7df-e6cf83a3f07b','酬樂天','元稹','唐','唐诗','tang','','[]','放鶴在深水，置魚在高枝。',144,'全唐诗/poet.tang.21000.json','["放鶴在深水，置魚在高枝。", "升沈或異勢，同謂非所宜。", "君爲邑中吏，皎皎鸞鳳姿。", "顧我何爲者，翻侍白玉墀。", "昔作芸香侶，三載不暫離。", "逮茲忽相失，旦夕夢魂思。", "崔嵬驪山頂，宮樹遙參差。", "祗得兩相望，不得長相隨。", "多君歲寒意，裁作秋興詩。", "上言風塵苦，下言時節移。", "官家事拘束，安得攜手期。", "願爲雲與雨，會合天之垂。"]'),
('16b7b30e-0f7c-4915-bd40-2aef2e3884cc','楊子華畫三首 一','元稹','唐','唐诗','tang','','[]','楊畫遠於展，何言今在茲。',48,'全唐诗/poet.tang.21000.json','["楊畫遠於展，何言今在茲。", "依然古妝服，但感時節移。", "念君一朝意，遺我千載思。", "子亦幾時客，安能長苦悲。"]'),
('7fe720b1-bd93-400f-b107-178710f0ea75','楊子華畫三首 二','元稹','唐','唐诗','tang','','[]','皓腕卷紅袖，錦韝臂蒼鶚。',72,'全唐诗/poet.tang.21000.json','["皓腕卷紅袖，錦韝臂蒼鶚。", "故人斷弦心，稚齒從禽樂。", "當年惜貴遊，遺形寄丹雘。", "骨象或依稀，鉛華已寥落。", "似對古人民，無復昔城郭。", "子亦觀病身，色空俱寂寞。"]'),
('d6916f5c-a432-4e91-81ae-9f9f69a49e24','楊子華畫三首 三','元稹','唐','唐诗','tang','','[]','顛倒世人心，紛紛乏公是。',48,'全唐诗/poet.tang.21000.json','["顛倒世人心，紛紛乏公是。", "真賞畫不成，畫賞真相似。", "丹青各所尚，工拙何足恃。", "求此妄中精，嗟哉子華子。"]'),
('05f04e27-0036-455d-a517-eff31de0f327','西州院','元稹','唐','唐诗','tang','','[]','自入西州院，唯見東川城。',144,'全唐诗/poet.tang.21000.json','["自入西州院，唯見東川城。", "今夜城頭月，非暗又非明。", "文案牀席滿，卷舒贓罪名。", "慘悽且煩勌，棄之階下行。", "悵望天廻轉，動搖萬里情。", "參辰次第出，牛女顛倒傾。", "況此風中柳，枝條千萬莖。", "到來籬下筍，亦已長短生。", "感愴正多緒，鵶鵶相喚驚。", "牆上杜鵑鳥，又作思歸鳴。", "以彼撩亂思，吟爲幽怨聲。", "吟罷終不寢，鼕鼕復鐺鐺。"]'),
('d4ccc5e8-7c44-4d38-8605-774e54b5f1eb','臺中鞫獄憶開元觀舊事呈損之兼贈周兄四十韻','元稹','唐','唐诗','tang','','[]','憶在開元館，食柏練玉顏。',288,'全唐诗/poet.tang.21000.json','["憶在開元館，食柏練玉顏。", "疎慵日高臥，自謂輕人寰。", "李生隔牆住，隔牆如隔山。", "怪我久不識，先來問驕頑。", "十過乃一往，遂成相往還。", "以我文章卷，文章甚斒斕。", "因言辛庾輩，亦願放羸孱。", "既廻數子顧，展轉相連攀。", "驅令選科目，若在闠與闤。", "學隨塵土墜，漫數公卿關。", "唯恐壞情性，安能懼謗訕。", "還招辛庾李，靜處杯巡環。", "進取果由命，不由趨險艱。", "穿楊二三子，弓矢次第彎。", "推我亦上道，再聯朝士班。", "二月除御史，三月使巴蠻。", "蠻民詀諵訴，齧指明痛癏。", "憐蠻不解語，爲發昏帥姦。", "歸來五六月，旱色天地殷。", "分司別兄弟，各各淚潸潸。", "哀哉劇部職，唯數贓罪鍰。", "死款依稀取，鬬辭方便刪。", "道心常自愧，柔髮難久黫。", "折支望車乘，支痛誰置患。"]'),
('75cfad90-de67-4955-98ca-5ec0eb0fa62f','韋氏館與周隱客杜歸和泛舟','元稹','唐','唐诗','tang','','[]','天色低澹澹，池光漫油油。',96,'全唐诗/poet.tang.21000.json','["天色低澹澹，池光漫油油。", "輕舟閑繳繞，不遠池上樓。", "時物欣外獎，真元隨內修。", "神恬津藏滿，氣委支節柔。", "衆處豈自異，曠懷誰我儔。", "風車籠野馬，八荒安足遊。", "開顏陸渾杜，握手靈都周。", "持君寶珠贈，頂戴頭上頭。"]'),
('4e6ab262-f5b3-4c3e-ba7f-d43780e8fa44','劉氏館集隱客歸和子元及之子蒙晦之','元稹','唐','唐诗','tang','','[]','溼墊緣竹徑，寥落護岸冰。',48,'全唐诗/poet.tang.21000.json','["溼墊緣竹徑，寥落護岸冰。", "偶然沽市酒，不越四五升。", "詩客愛時景，道人話升騰。", "笑言各有趣，悠哉古孫登。"]'),
('1082f931-41c9-4f50-973b-82fdb64ab869','寄隱客','元稹','唐','唐诗','tang','','[]','我年三十二，鬢有八九絲。',144,'全唐诗/poet.tang.21000.json','["我年三十二，鬢有八九絲。", "非無官次第，其如身早衰。", "今人夸貴富，肉食與妖姬。", "而我俱不樂，貴富亦何爲。", "況逢多士朝，賢俊若布棊。", "班行次第立，朱紫相參差。", "謨猷密勿進，羽檄縱橫馳。", "監察官甚小，發言無所裨。", "小官仍不了，譴奪亦已隨。", "時或不之棄，得不自棄之。", "陶君喜不遇，顧我復何疑。", "潛書周隱士，白雲今有期。"]'),
('67106cbb-0b9c-4d2c-ae3b-2edea7d74627','元和五年予官不了罰俸西歸三月六日至陝府與吳十一兄端公崔二十二院長思愴曩遊因投五十韻','元稹','唐','唐诗','tang','','[]','小年閑愛春，認得春風意。',288,'全唐诗/poet.tang.21000.json','["小年閑愛春，認得春風意。", "未有花草時，先醲曉窗睡。", "霞朝澹雲色，霽景牽詩思。", "漸到柳枝頭，川光始明媚。", "長安車馬客，傾心奉權貴。", "晝夜塵土中，那言早春至。", "此時我獨遊，我遊有倫次。", "閑行曲江岸，便宿慈恩寺。", "扣林引寒龜，疏叢出幽翠。", "凌晨過杏園，曉露凝芳氣。", "初陽好明淨，嫩樹憐低庳。", "排房似綴珠，欲啼紅臉淚。", "新鶯語嬌小，淺水光流利。", "冷飲空腹杯，因成日高醉。", "酒醒聞飯鐘，隨僧受遺施。", "餐罷還復遊，過從上文記。", "行逢二月半，始足遊春騎。", "是時春已老，我遊亦云既。", "藤開九華觀，草結三條隧。", "新筍踴犀株，落梅飜蝶翅。", "名倡繡轂車，公子青絲轡。", "朝士還旬休，豪家得春賜。", "提攜好音樂，翦鏟空田地。", "同占杏花園，喧闐各叢萃。"]'),
('3c740dd3-e671-4258-9806-0a056ec7cf92','寄吳士矩端公五十韻','元稹','唐','唐诗','tang','','[]','昔在鳳翔日，十歲即相識。',288,'全唐诗/poet.tang.21000.json','["昔在鳳翔日，十歲即相識。", "未有好文章，逢人賞顏色。", "可憐何郎面，二十纔冠飾。", "短髮予近梳，羅衫紫蟬翼。", "伯舅各驕縱，仁兄未摧抑。", "事業若杯盤，詩書甚徽纆。", "西州戎馬地，賢豪事雄特。", "百萬時可贏，十千良易借。", "寒食桐陰下，春風柳林側。", "藉草送遠遊，列筵酬博塞。", "萎蕤雲幕翠，燦爛紅茵赩。", "膾縷輕似絲，香醅膩如職。", "將軍頻下城，佳人盡傾國。", "媚語嬌不聞，纖腰輭無力。", "歌辭妙宛轉，舞態能剜刻。", "箏弦玉指調，粉汗紅綃拭。", "予時最年少，專務酒中職。", "未能解生獰，偏矜任狂直。", "曲庇桃根盞，橫講捎雲式。", "亂布鬬分朋，惟新間讒慝。", "恥作最先吐，羞言未朝食。", "醉眼漸紛紛，酒聲頻䬵䬵。", "扣節參差亂，飛觥往來織。", "強起相維持，飜成兩匍匐。"]'),
('ad4f41bb-c368-4717-8c6e-ccf9018d14a2','三月二十四日宿曾峰館夜對桐花寄樂天','元稹','唐','唐诗','tang','','[]','微月照桐花，月微花漠漠。',96,'全唐诗/poet.tang.21000.json','["微月照桐花，月微花漠漠。", "怨澹不勝情，低回拂簾幕。", "葉新陰影細，露重枝條弱。", "夜久春恨多，風清暗香薄。", "是夕遠思君，思君瘦如削。", "但感事睽違，非言官好惡。", "奏書金鑾殿，步屣青龍閣。", "我在山館中，滿地桐花落。"]'),
('80d63100-8c8a-4236-8b5c-d0529a072330','酬樂天書懷見寄','元稹','唐','唐诗','tang','','[]','新昌北門外，與君從此分。',288,'全唐诗/poet.tang.21000.json','["新昌北門外，與君從此分。", "街衢走車馬，塵土不見君。", "君爲分手歸，我行行不息。", "我上秦嶺南，君直樞星北。", "秦嶺高崔嵬，商山好顏色。", "月照山館花，裁詩寄相憶。", "天明作詩罷，草草隨所如。", "憑人寄將去，三月無報書。", "荆州白日晚，城上鼓鼕鼕。", "行逢賀州牧，致書三四封。", "封題樂天字，未坼已霑裳。", "坼書八九讀，淚落千萬行。", "中有酬我詩，句句截我腸。", "仍云得詩夜，夢我魂淒涼。", "終言作書處，上直金鑾東。", "詩書費一夕，萬恨緘其中。", "中宵宮中出，復見宮月斜。", "書罷月亦落，曉燈隨暗花。", "想君書罷時，南望勞所思。", "況我江上立，吟君懷我詩。", "懷我浩無極，江水秋正深。", "清見萬丈底，照我平生心。", "感君求友什，因報壯士吟。", "持謝衆人口，銷盡猶是金。"]'),
('e5849033-e6e2-4536-b5be-a3eebcced359','酬樂天登樂遊園見憶','元稹','唐','唐诗','tang','','[]','昔君樂遊園，悵望天欲曛。',96,'全唐诗/poet.tang.21000.json','["昔君樂遊園，悵望天欲曛。", "今我大江上，快意波飜雲。", "秋空壓澶漫，澒洞無垢氛。", "四顧皆豁達，我眉今日伸。", "長安隘朝市，百道走埃塵。", "軒車隨對列，骨肉非本親。", "誇遊丞相第，偷入常侍門。", "愛君直如髮，勿念江湖人。"]'),
('0b51076e-bad9-40ff-9777-efdd4cbf1577','酬樂天早夏見懷','元稹','唐','唐诗','tang','','[]','庭柚有垂實，燕巢無宿雛。',72,'全唐诗/poet.tang.21000.json','["庭柚有垂實，燕巢無宿雛。", "我亦辭社燕，茫茫焉所如。", "君詩夏方早，我歎秋已徂。", "食物風土異，衾裯時節殊。", "荒草滿田地，近移江上居。", "八日復切九，月明侵半除。"]'),
('8ceb3b00-bc23-488b-b536-40bcd943dff6','酬樂天勸醉','元稹','唐','唐诗','tang','','[]','神麯清濁酒，牡丹深淺花。',156,'全唐诗/poet.tang.21000.json','["神麯清濁酒，牡丹深淺花。", "少年欲相飲，此樂何可涯。", "沈機造神境，不必悟楞伽。", "酡顏返童貌，安用成丹砂。", "劉伶稱酒德，所稱良未多。", "願君聽此曲，我爲盡稱嗟。", "一杯顏色好，十盞膽氣加。", "半酣得自恣，酩酊歸太和。", "共醉真可樂，飛觥撩亂歌。", "獨醉亦有趣，兀然無與他。", "美人醉燈下，左右流橫波。", "王孫醉牀上，顛倒眠綺羅。", "君今勸我醉，勸醉意如何。"]'),
('fc380aec-cd91-4881-b0b8-e411ce754f9c','和樂天初授戶曹喜而言志','元稹','唐','唐诗','tang','','[]','王爵無細大，得請即爲恩。',192,'全唐诗/poet.tang.21000.json','["王爵無細大，得請即爲恩。", "君求戶曹掾，貴以祿奉親。", "聞君得所請，感我欲霑巾。", "今人重軒冕，所重華與紛。", "矜誇仕臺閣，奔走無朝昏。", "君衣不盈篋，君食不滿囷。", "君言養既薄，何以榮我門。", "披誠再三請，天子憐儉貧。", "詞曹直文苑，捧詔榮且忻。", "歸來高堂上，兄弟羅酒尊。", "各稱千萬壽，共飲三四巡。", "我實知君者，千里能具陳。", "感君求祿意，求祿殊衆人。", "上以奉顏色，餘以及親賓。", "棄名不棄實，謀養不謀身。", "可憐白華士，永願凌青雲。"]'),
('33c308b7-ba59-4de1-a9fe-4d23e1fedf9d','和樂天贈吳丹','元稹','唐','唐诗','tang','','[]','不識吳生面，久知吳生道。',194,'全唐诗/poet.tang.21000.json','["不識吳生面，久知吳生道。", "跡雖染世名，心本奉天老。", "雌一守命門，廻九填血腦。", "委氣榮衛和，咽津顏色好。", "傳聞共甲子，衰隤盡枯[槁]。", "獨有冰雪容，纖華奪鮮縞。", "問人何能爾，吳實曠懷抱。", "弁冕徒挂身，身外非所寶。", "伊予固童昧，希真亦云早。", "石壇玉晨尊，晝夜長自埽。", "密印視丹田，遊神夢三島。", "萬過黃庭經，一食青精稻。", "冥搜方朔桃，結念安期棗。", "綠髮幸未改，丹誠自能保。", "行當擺塵纓，吳門事探討。", "君爲先此詞，終期搴瑤草。"]'),
('cb9cb9b7-03ed-497e-a738-76d3308589ee','和樂天秋題曲江','元稹','唐','唐诗','tang','','[]','十載定交契，七年鎮相隨。',96,'全唐诗/poet.tang.21000.json','["十載定交契，七年鎮相隨。", "長安最多處，多是曲江池。", "梅杏春尚小，芰荷秋已衰。", "共愛寥落境，相將偏此時。", "緜緜紅蓼水，颺颺白鷺鶿。", "詩句偶未得，酒杯聊久持。", "今來雲雨曠，舊賞魂夢知。", "況乃江楓夕，和君秋興詩。"]'),
('81dc8eb8-35d5-4c79-ace2-1a4f056c98b9','和樂天別弟後月夜作','元稹','唐','唐诗','tang','','[]','聞君別愛弟，明天照夜寒。',72,'全唐诗/poet.tang.21000.json','["聞君別愛弟，明天照夜寒。", "秋雁拂檐影，曉琴當砌彈。", "悵望天澹澹，因思路漫漫。", "吟爲別弟操，聞者爲辛酸。", "況我兄弟遠，一身形影單。", "江波浩無極，但見時歲闌。"]'),
('4ca21ea8-bd62-40c9-8379-af18e9b70ac6','和樂天秋題牡丹叢','元稹','唐','唐诗','tang','','[]','敝宅豔山卉，別來長歎息。',36,'全唐诗/poet.tang.21000.json','["敝宅豔山卉，別來長歎息。", "吟君晚叢詠，似見摧隤色。", "欲識別後容，勤過晚叢側。"]'),
('f432e98f-b6e0-4e2e-af94-fa92408ce57f','春月','元稹','唐','唐诗','tang','','[]','春月雖至明，終有靄靄光。',240,'全唐诗/poet.tang.21000.json','["春月雖至明，終有靄靄光。", "不似秋冬色，逼人寒帶霜。", "纖粉澹虛壁，輕煙籠半牀。", "分暉間林影，餘照上虹梁。", "病久塵事隔，夜閑清興長。", "擁抱顛倒領，步屣東西廂。", "風柳結柔援，露梅飄暗香。", "雪含櫻綻蘂，珠蹙桃綴房。", "杳杳有餘思，行行安可忘。", "四鄰非舊識，無以話中腸。", "南有居士儼，默坐調心王。", "款關一問訊，爲我披衣裳。", "延我入深竹，暖我於小堂。", "視身琉璃瑩，諭指芭蕉黃。", "復有比丘溢，早傳龍樹方。", "口中祕丹訣，肘後懸青囊。", "錫杖雖獨振，刀圭期共嘗。", "未知仙近遠，已覺神輕翔。", "夜久魂耿耿，月明露蒼蒼。", "悲哉沈眠士，寧見茲夕良。"]'),
('fbf36c89-11f0-44a1-a662-d56cf82538b0','月臨花','元稹','唐','唐诗','tang','','[]','臨風颺颺花，透影朧朧月。',48,'全唐诗/poet.tang.21000.json','["臨風颺颺花，透影朧朧月。", "巫峽隔波雲，姑峰漏霞雪。", "鏡勻嬌面粉，燈泛高籠纈。", "夜久清露多，啼珠墜還結。"]'),
('28352993-bd3d-49af-978a-15c50c95e3a8','紅芍藥','元稹','唐','唐诗','tang','','[]','芍藥綻紅綃，巴籬織青瑣。',120,'全唐诗/poet.tang.21000.json','["芍藥綻紅綃，巴籬織青瑣。", "繁絲蹙金蘂，高燄當爐火。", "翦刻彤雲片，開張赤霞裹。", "煙輕琉璃葉，風亞珊瑚朵。", "受露色低迷，向人嬌婀娜。", "酡顏醉後泣，小女妝成坐。", "豔豔錦不如，夭夭桃未可。", "晴霞畏欲散，晚日愁將墮。", "結植本爲誰，賞心期在我。", "采之諒多思，幽贈何由果。"]'),
('982d9042-2215-4e98-8246-9311c81e6dfd','送王十一南行','元稹','唐','唐诗','tang','','[]','夏水漾天末，晚暘依岸邨。',120,'全唐诗/poet.tang.21000.json','["夏水漾天末，晚暘依岸邨。", "風調烏尾勁，眷戀餘芳尊。", "解袂方瞬息，征帆已翩翻。", "江豚湧高浪，楓樹搖去魂。", "遠戍宗侶泊，暮煙洲渚昏。", "離心詎幾許，驟若移寒溫。", "此別信非久，胡爲坐憂煩。", "我留石難轉，君泛雲無根。", "萬里湖南月，三聲山上猿。", "從茲耿幽夢，夜夜湘與沅。"]'),
('067093bb-db5b-4c50-a358-259a913f1175','三歎 一','元稹','唐','唐诗','tang','','[]','孤劒鋒刀澀，猶能神彩生。',96,'全唐诗/poet.tang.21000.json','["孤劒鋒刀澀，猶能神彩生。", "有時雷雨過，暗吼闐闐聲。", "主人閟靈寶，畏作升天行。", "淬礪當陽鐵，刻爲干鏌名。", "遠求鸊鵜瑩，同用玉匣盛。", "顏色縱相類，利鈍頗相傾。", "雄爲光電烻，雌但深泓澄。", "龍怒有奇變，青蛇終不驚。"]'),
('4115ed4e-e092-4b2e-910d-03ad70742d3b','三歎 二','元稹','唐','唐诗','tang','','[]','仙鳳翠皇死，葳蕤光彩低。',72,'全唐诗/poet.tang.21000.json','["仙鳳翠皇死，葳蕤光彩低。", "非無鴛鸞侶，誓不同樹棲。", "飛馳歲云暮，感念雛在泥。", "顧影不自暖，寄爾蟠桃雞。", "馴養豈無愧，類族安得齊。", "願言成羽翼，奮翅凌丹梯。"]'),
('299b35c1-468e-4c88-8d3e-db70e6499155','三歎 三','元稹','唐','唐诗','tang','','[]','天驥失龍偶，三年常夜嘶。',72,'全唐诗/poet.tang.21000.json','["天驥失龍偶，三年常夜嘶。", "哀緣噴風斷，渴且含霜啼。", "長恐絕遺類，不復躡雲霓。", "非無駉駉者，鶴意不在雞。", "春來筋骨瘦，弔影心亦迷。", "自此渥洼種，應生濁水泥。"]'),
('5d2707ec-0f62-43e3-aa3c-057876efea8e','遣晝','元稹','唐','唐诗','tang','','[]','密竹有清陰，曠懷無塵滓。',120,'全唐诗/poet.tang.21000.json','["密竹有清陰，曠懷無塵滓。", "況乃秋日光，玲瓏曉窗裏。", "旬休聊自適，今辰日高起。", "櫛沐坐前軒，風輕鏡如水。", "開卷恣詠謠，望雲閑徙倚。", "新菊媚鮮妍，短萍憐靃靡。", "埽除田地靜，摘掇園蔬美。", "幽翫愜詩流，空堂稱居士。", "客來傷寂寞，我念遺煩鄙。", "心跡兩相忘，誰能驗行止。"]'),
('daf0257b-55fe-4822-970a-bc3ad25c50d8','冬夜懷李侍御王太祝段丞','元稹','唐','唐诗','tang','','[]','浩露煙壒盡，月光閒有餘。',144,'全唐诗/poet.tang.21000.json','["浩露煙壒盡，月光閒有餘。", "松篁細陰影，重以簾牖疎。", "泛覽星粲粲，輕河悠碧虛。", "纖雲不成葉，脈脈風絲舒。", "丹竈熾東序，燒香羅玉書。", "飄飄魂神舉，若驂鸞鶴輿。", "感念夙昔意，華尚簪與裾。", "簪裾詎幾許，累創吞鉤魚。", "今聞馨香道，一以悟臭帤。", "悟覺誓不惑，永抱胎仙居。", "晝夜欣所適，安知歲云除。", "行行二三友，君懷復何如。"]'),
('b52e2b04-d70b-4f44-9a44-1f889b3e9e43','西齋小松二首 一','元稹','唐','唐诗','tang','','[]','松樹短於我，清風亦已多。',48,'全唐诗/poet.tang.21000.json','["松樹短於我，清風亦已多。", "況乃枝上雪，動搖微月波。", "幽姿得閒地，詎感歲蹉跎。", "但恐廈終構，藉君當奈何。"]'),
('9fa5f524-e2d5-4b63-82e8-91598f53ff42','西齋小松二首 二','元稹','唐','唐诗','tang','','[]','簇簇枝新黃，纖纖攢素指。',48,'全唐诗/poet.tang.21000.json','["簇簇枝新黃，纖纖攢素指。", "柔苙漸依條，短莎還半委。", "清風日夜高，凌雲意何已。", "千歲盤老龍，修鱗自茲始。"]'),
('23c9e117-1272-4f69-9d77-0d784c91ff39','周先生','元稹','唐','唐诗','tang','','[]','寥寥空山岑，冷冷風松林。',48,'全唐诗/poet.tang.21000.json','["寥寥空山岑，冷冷風松林。", "流月垂鱗光，懸泉揚高音。", "希夷周先生，燒香調琴心。", "神力盈三千，誰能還黃金。"]'),
('2bf69f17-7c47-438c-b912-89c33a272dd8','遣春十首 一','元稹','唐','唐诗','tang','','[]','曉月籠雲影，鸎聲餘霧中。',48,'全唐诗/poet.tang.21000.json','["曉月籠雲影，鸎聲餘霧中。", "暗芳飄露氣，輕寒生柳風。", "冉冉一趨府，未爲勞我躬。", "因茲得晨起，但覺情興隆。"]'),
('48534bac-39c2-4d9a-93d4-2dc10e9d17b8','遣春十首 二','元稹','唐','唐诗','tang','','[]','久雨憐霽景，偶來隄上行。',48,'全唐诗/poet.tang.21000.json','["久雨憐霽景，偶來隄上行。", "空濛天色嫩，杳淼江面平。", "百草短長出，衆禽高下鳴。", "春陽各有分，予亦澹無情。"]'),
('f0deb7b5-d369-4127-92c1-f996d20d02e9','遣春十首 三','元稹','唐','唐诗','tang','','[]','鏡皎碧潭水，微波粗成文。',48,'全唐诗/poet.tang.21000.json','["鏡皎碧潭水，微波粗成文。", "煙光垂碧草，瓊脈散纖雲。", "岸柳好陰影，風裾遺垢氛。", "悠然送春目，八荒誰與羣。"]'),
('27f39431-d669-4554-96ac-52badcf9a706','遣春十首 四','元稹','唐','唐诗','tang','','[]','低迷籠樹煙，明淨當霞日。',48,'全唐诗/poet.tang.21000.json','["低迷籠樹煙，明淨當霞日。", "陽燄波春空，平湖漫凝溢。", "雪鷺遠近飛，渚牙淺深出。", "江流復浩蕩，相爲坐紆鬱。"]'),
('b8b6c460-1009-42a0-8a35-ca6e29737887','遣春十首 五','元稹','唐','唐诗','tang','','[]','暄寒深淺春，紅白前後花。',48,'全唐诗/poet.tang.21000.json','["暄寒深淺春，紅白前後花。", "顏色詎相讓，生成良有涯。", "梅芳勿自早，菊秀勿自賒。", "各將一時意，終年無再華。"]'),
('542f7635-1170-48ca-9481-ee32aaf96f5f','遣春十首 六','元稹','唐','唐诗','tang','','[]','高屋童稚少，春來歸燕多。',48,'全唐诗/poet.tang.21000.json','["高屋童稚少，春來歸燕多。", "葺舊良易就，新院亦已羅。", "俯憐雛化卵，仰愧鵬無窠。", "巢棟與巢幕，秋風俱奈何。"]'),
('2bc72a8a-88bf-4e57-89ec-b21e3016b789','遣春十首 七','元稹','唐','唐诗','tang','','[]','撩亂撲樹蜂，摧殘戀房蕊。',48,'全唐诗/poet.tang.21000.json','["撩亂撲樹蜂，摧殘戀房蕊。", "風吹雨又頻，安得繁於綺。", "酒盃沈易過，世事紛何已。", "莫倚顏似花，君看歲如水。"]'),
('97a5ce15-f00d-4082-b5df-053e1438a2e1','遣春十首 八','元稹','唐','唐诗','tang','','[]','繞郭高高冢，半是荆王墓。',48,'全唐诗/poet.tang.21000.json','["繞郭高高冢，半是荆王墓。", "後嗣熾陽臺，前賢甘蓽路。", "善惡徒自分，波流盡東注。", "胡然不飲酒，坐落桐花樹。"]'),
('86f5fa89-0a65-4d53-b596-88aa0f010c41','遣春十首 九','元稹','唐','唐诗','tang','','[]','花陰莎草長，藉莎閑自酌。',48,'全唐诗/poet.tang.21000.json','["花陰莎草長，藉莎閑自酌。", "坐看鸎鬬枝，輕花滿尊杓。", "葛巾竹稍挂，書卷琴上閣。", "沽酒過此生，狂歌眼前樂。"]'),
('21951b1b-02ad-461f-91a7-95b8eed71859','遣春十首 十','元稹','唐','唐诗','tang','','[]','梨葉已成陰，柳條紛起絮。',48,'全唐诗/poet.tang.21000.json','["梨葉已成陰，柳條紛起絮。", "波綠紫屏風，螺紅碧籌筯。", "三杯面上熱，萬事心中去。", "我意風散雲，何勞問行處。"]'),
('edebf922-4b99-4c67-be6d-9132f015f9e6','表夏十首 一','元稹','唐','唐诗','tang','','[]','夏風多暖暖，樹木有繁陰。',48,'全唐诗/poet.tang.21000.json','["夏風多暖暖，樹木有繁陰。", "新筍紫長短，早櫻紅淺深。", "煙花雲幕重，榴豔朝景侵。", "華實各自好，詎云芳意沈。"]'),
('9492ddc6-b920-4416-a8d9-d5c565e50818','表夏十首 二','元稹','唐','唐诗','tang','','[]','初日滿階前，輕風動簾影。',48,'全唐诗/poet.tang.21000.json','["初日滿階前，輕風動簾影。", "旬時得休浣，高臥閱清景。", "僮兒拂巾箱，鵶軋深林井。", "心到物自閑，何勞遠箕頴。"]'),
('534d2e7d-7e23-4185-b14d-295cbfe9b86d','表夏十首 三','元稹','唐','唐诗','tang','','[]','江瘴炎夏早，蒸騰信難度。',48,'全唐诗/poet.tang.21000.json','["江瘴炎夏早，蒸騰信難度。", "今宵好風月，獨此荒庭趣。", "露葉傾暗光，流星委餘素。", "但恐清夜徂，詎悲朝景暮。"]'),
('9a0b1723-d500-42e4-b7d8-1df7cafc7215','表夏十首 四','元稹','唐','唐诗','tang','','[]','孟月夏猶淺，奇雲未成峰。',48,'全唐诗/poet.tang.21000.json','["孟月夏猶淺，奇雲未成峰。", "度霞紅漠漠，壓浪白溶溶。", "玉委有餘潤，飆馳無去蹤。", "何如捧雲雨，噴毒隨蛟龍。"]'),
('a3c7fbc8-ace1-4c74-998a-7b29dd06a7a4','表夏十首 五','元稹','唐','唐诗','tang','','[]','流芳遞炎景，繁英盡寥落。',48,'全唐诗/poet.tang.21000.json','["流芳遞炎景，繁英盡寥落。", "公署香滿庭，晴霞覆闌藥。", "裁紅起高燄，綴綠排新萼。", "憑此遣幽懷，非言念將謔。"]'),
('d1b9749d-83c5-42ba-a6a0-71b5a6d3ba7c','表夏十首 六','元稹','唐','唐诗','tang','','[]','紅絲散芳樹，旋轉光風急。',48,'全唐诗/poet.tang.21000.json','["紅絲散芳樹，旋轉光風急。", "煙泛被籠香，露濃妝面溼。", "佳人不在此，恨望堦前立。", "忽厭夏景長，今春行已及。"]'),
('99854059-ac6f-4fc8-b634-ad48b6ad23b4','表夏十首 七','元稹','唐','唐诗','tang','','[]','百舌漸吞聲，黃鸎正嬌小。',48,'全唐诗/poet.tang.21000.json','["百舌漸吞聲，黃鸎正嬌小。", "雲鴻方警夜，籠雞已鳴曉。", "當時客自適，運去誰能矯。", "莫厭夏蟲多，蜩螗定相擾。"]'),
('322d6de1-e145-4532-bd76-8c4f6f483c88','表夏十首 八','元稹','唐','唐诗','tang','','[]','翩翩簾外燕，戢戢巢內雛。',48,'全唐诗/poet.tang.21000.json','["翩翩簾外燕，戢戢巢內雛。", "啖食筋力盡，毛衣成紫襦。", "朝來各飛去，雄雌梁上呼。", "養子將備老，惡兒那勝無。"]'),
('042c6864-1284-4ace-a521-28245a52d1c3','表夏十首 九','元稹','唐','唐诗','tang','','[]','西山夏雪消，江勢東南瀉。',48,'全唐诗/poet.tang.21000.json','["西山夏雪消，江勢東南瀉。", "風波高若天，灩澦低於馬。", "正被黃牛旋，難期白帝下。", "我在平地行，翻憂濟川者。"]'),
('700b574e-b8a8-41b8-b3c8-bb46cc94913c','表夏十首 十','元稹','唐','唐诗','tang','','[]','靈均死波後，是節常浴蘭。',48,'全唐诗/poet.tang.21000.json','["靈均死波後，是節常浴蘭。", "綵縷碧筠糉，香秔白玉團。", "逝者良自苦，今人反爲歡。", "哀哉徇名士，沒命求所難。"]'),
('658c34e2-5bc3-4f95-8001-3328d6093c38','解秋十首 一','元稹','唐','唐诗','tang','','[]','清晨頮寒水，動搖襟袖輕。',48,'全唐诗/poet.tang.21000.json','["清晨頮寒水，動搖襟袖輕。", "翳翳林上葉，不知秋暗生。", "回悲鏡中髮，華白三四莖。", "豈無滿頭黑，念此衰已萌。"]'),
('b83295ee-8b5b-40d7-9498-ad8bdff50029','解秋十首 二','元稹','唐','唐诗','tang','','[]','微霜纔結露，翔鳩初變鷹。',48,'全唐诗/poet.tang.21000.json','["微霜纔結露，翔鳩初變鷹。", "無乃天地意，使之行小懲。", "鴟鴞誠可惡，蔽日有高鵬。", "捨大以擒細，我心終不能。"]'),
('56c9e941-9f5d-47ff-97b6-7bc47458754e','解秋十首 三','元稹','唐','唐诗','tang','','[]','往歲學仙侶，各在無何鄉。',48,'全唐诗/poet.tang.21000.json','["往歲學仙侶，各在無何鄉。", "同時騖名者，次第鵷鷺行。", "而我兩不遂，三十鬢添霜。", "日暮江上立，蟬鳴楓樹黃。"]'),
('e0f11dcd-63c1-46e3-821f-cfe9145aef48','解秋十首 四','元稹','唐','唐诗','tang','','[]','後伏火猶在，先秋蟬已多。',48,'全唐诗/poet.tang.21000.json','["後伏火猶在，先秋蟬已多。", "雲色日夜白，驕陽能幾何。", "壤隙漏江海，忽微成網羅。", "勿言時不至，但恐歲蹉跎。"]'),
('db2a09c3-7311-42be-84ba-afe3b8063943','解秋十首 五','元稹','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','新月纔到地，輕河如泛雲。',48,'全唐诗/poet.tang.21000.json','["新月纔到地，輕河如泛雲。", "螢飛高下火，樹影參差文。", "露簟有微潤，清香時暗焚。", "夜閑心寂默，洞庭無垢氛。"]'),
('80288410-e8ee-4ccf-a11f-726eb03b1931','解秋十首 六','元稹','唐','唐诗','tang','','[]','霽麗牀前影，飄蕭簾外竹。',48,'全唐诗/poet.tang.21000.json','["霽麗牀前影，飄蕭簾外竹。", "簟涼朝睡重，夢覺茶香熟。", "親烹園內葵，憑買家家麯。", "釀酒幷毓蔬，人來有棊局。"]'),
('d6aec35b-4a12-40ab-ad18-163b207ec4c1','解秋十首 七','元稹','唐','唐诗','tang','','[]','寒竹秋雨重，凌霄晚花落。',48,'全唐诗/poet.tang.21000.json','["寒竹秋雨重，凌霄晚花落。", "低回翠玉梢，散亂梔黃萼。", "顏色有殊異，風霜無好惡。", "年年百草芳，畢意同蕭索。"]'),
('c34f843a-5e27-41d5-a34c-f09e4835a200','解秋十首 八','元稹','唐','唐诗','tang','','[]','春非我獨春，秋非我獨秋。',48,'全唐诗/poet.tang.21000.json','["春非我獨春，秋非我獨秋。", "豈念百草死，但念霜滿頭。", "頭白古所同，胡爲坐煩憂。", "茫茫百年內，處身良未休。"]'),
('d06d15d6-ce1d-41f3-9ed7-bb7b4e6f6522','解秋十首 九','元稹','唐','唐诗','tang','','[]','西風冷衾簟，展轉布華茵。',48,'全唐诗/poet.tang.21000.json','["西風冷衾簟，展轉布華茵。", "來者承玉體，去者流芳塵。", "適意醜爲好，及時疎亦親。", "衰周仲尼出，無乃爲妖人。"]'),
('c0da9dc1-bef7-4da1-9616-47ec4f3af784','解秋十首 十','元稹','唐','唐诗','tang','','[]','漠漠江面燒，微微楓樹煙。',48,'全唐诗/poet.tang.21000.json','["漠漠江面燒，微微楓樹煙。", "今日復今夕，秋懷方浩然。", "況我頭上髮，衰白不待年。", "我懷有時極，此意何由詮。"]'),
('c0c704fa-f371-4c8e-aad8-d950f67d5b40','遣病十首 一','元稹','唐','唐诗','tang','','[]','服藥備江瘴，四年方一癘。',48,'全唐诗/poet.tang.21000.json','["服藥備江瘴，四年方一癘。", "豈是藥無功，伊予久留滯。", "滯留人固薄，瘴久藥難制。", "去日良已甘，歸途奈無際。"]'),
('5b267785-80f9-4bf6-80e1-3abf30689e39','遣病十首 二','元稹','唐','唐诗','tang','','[]','棄置何所任，鄭公憐我病。',48,'全唐诗/poet.tang.21000.json','["棄置何所任，鄭公憐我病。", "三十九萬錢，資予養頑瞑。", "身賤殺何益，恩深報難罄。", "公其萬千年，世有天之鄭。"]'),
('af8adcc6-5616-46be-9fe5-b4528206fb84','遣病十首 三','元稹','唐','唐诗','tang','','[]','憶作孩稚初，健羨成人列。',48,'全唐诗/poet.tang.21000.json','["憶作孩稚初，健羨成人列。", "倦學厭日長，嬉遊念佳節。", "今來漸諱年，頓與前心別。", "白日速如飛，佳晨亦騷屑。"]'),
('b05b33f9-0f28-489e-89a4-8a40742c03ba','遣病十首 四','元稹','唐','唐诗','tang','','[]','昔在痛飲場，憎人病辭醉。',48,'全唐诗/poet.tang.21000.json','["昔在痛飲場，憎人病辭醉。", "病來身怕酒，始悟他人意。", "怕酒豈不閑，悲無少年氣。", "傳語少年兒，杯盤莫廻避。"]'),
('fc7a697d-439d-449e-a294-41406b8c80ff','遣病十首 五','元稹','唐','唐诗','tang','','[]','憶初頭始白，晝夜驚一縷。',48,'全唐诗/poet.tang.21000.json','["憶初頭始白，晝夜驚一縷。", "漸及鬢與鬚，多來不能數。", "壯年等閑過，過壯年已五。", "華髮不再青，勞生竟何補。"]'),
('cd72e49e-112d-43ea-a024-10b2d1c96df5','遣病十首 六','元稹','唐','唐诗','tang','','[]','在家非不病，有病心亦安。',48,'全唐诗/poet.tang.21000.json','["在家非不病，有病心亦安。", "起居甥姪扶，藥餌兄嫂看。", "今病兄遠路，道遙書信難。", "寄言嬌小弟，莫作官家官。"]'),
('beb4132d-1343-46b2-aafe-e1f6beec0d6d','遣病十首 七','元稹','唐','唐诗','tang','','[]','燕巢官舍內，我爾俱爲客。',48,'全唐诗/poet.tang.21000.json','["燕巢官舍內，我爾俱爲客。", "歲晚我獨留，秋深爾安適。", "風高翅羽垂，路遠煙波隔。", "去去玉山岑，人間網羅窄。"]'),
('74efe2b4-7f46-4c15-85db-5728cd45a02e','遣病十首 八','元稹','唐','唐诗','tang','','[]','簷宇夜來曠，暗知秋已生。',48,'全唐诗/poet.tang.21000.json','["簷宇夜來曠，暗知秋已生。", "臥悲衾簟冷，病覺支體輕。", "炎昏豈不勌，時去聊自驚。", "浩歎終一夕，空堂天欲明。"]'),
('3b831e75-e886-4c54-a564-159374d90eb6','遣病十首 九','元稹','唐','唐诗','tang','','[]','秋依靜處多，況乃凌晨趣。',48,'全唐诗/poet.tang.21000.json','["秋依靜處多，況乃凌晨趣。", "深竹蟬晝風，翠茸衫曉露。", "庭莎病看長，林果閑知數。", "何以強健時，公門日勞騖。"]'),
('3f957c76-d693-43a7-8c42-75da65c30eb8','遣病十首 十','元稹','唐','唐诗','tang','','[]','朝結故鄉念，暮作空堂寢。',48,'全唐诗/poet.tang.21000.json','["朝結故鄉念，暮作空堂寢。", "夢別淚亦流，啼痕暗橫枕。", "昔愁憑酒遣，今病安能飲。", "落盡秋槿花，離人病猶甚。"]'),
('0cf6a7cf-ab6c-4576-8a31-5069b66551da','寒','元稹','唐','唐诗','tang','','[]','江瘴節候暖，臘初梅已殘。',48,'全唐诗/poet.tang.21000.json','["江瘴節候暖，臘初梅已殘。", "夜來北風至，喜見今日寒。", "扣冰淺塘水，擁雪深竹闌。", "復此滿尊醁，但嗟誰與歡。"]'),
('a7bd9b32-1516-4511-893b-d78798e943b9','玉泉道中作','元稹','唐','唐诗','tang','','[]','楚俗物候晚，孟冬纔有霜。',96,'全唐诗/poet.tang.21000.json','["楚俗物候晚，孟冬纔有霜。", "早農半華實，夕水含風涼。", "遐想雲外寺，峰巒渺相望。", "松門接官路，泉脈連僧房。", "微露上弦月，暗焚初夜香。", "谷深煙壒淨，山虛鐘磬長。", "念此清境遠，復憂塵事妨。", "行行即前路，勿滯分寸光。"]'),
('409ecfdc-bec5-4cf0-b795-39aa7cd942ea','遣病','元稹','唐','唐诗','tang','','[]','自古誰不死，不復記其名。',240,'全唐诗/poet.tang.21000.json','["自古誰不死，不復記其名。", "今年京城內，死者老少幷。", "獨孤纔四十，仕宦方榮榮。", "李三三十九，登朝有清聲。", "趙昌八十餘，三擁大將旌。", "爲生信異異，之死同冥冥。", "其家哭泣愛，一一無異情。", "其類嗟歎惜，各各無重輕。", "萬齡龜菌等，一死天地平。", "以此方我病，我病何足驚。", "借如今日死，亦足了一生。", "借使到百年，不知何所成。", "況我早師佛，屋宅此身形。", "捨彼復就此，去留何所縈。", "前身爲過跡，來世即前程。", "但念行不息，豈憂無路行。", "蛻骨龍不死，蛻皮蟬自鳴。", "胡爲神蛻體，此道人不明。", "持謝愛朋友，寄之仁弟兄。", "吟此可達觀，世言何足聽。"]'),
('1b4e05e4-bccf-41f3-9138-a264dd24ae63','感夢','元稹','唐','唐诗','tang','','[]','十月初二日，我行蓬州西。',288,'全唐诗/poet.tang.21000.json','["十月初二日，我行蓬州西。", "三十里有館，有館名芳溪。", "荒郵屋舍壞，新雨田地泥。", "我病百日餘，肌體顧若刲。", "氣填暮不食，早早掩竇圭。", "陰寒筋骨病，夜久燈火低。", "忽然寢成夢，宛見顏如珪。", "似歎久離別，嗟嗟復悽悽。", "問我何病痛，又歎何棲棲。", "答云痰滯久，與世復相暌。", "重云痰小疾，良藥固易擠。", "前時奉橘丸，攻疾有神功。", "何不善和療，豈獨頭有風。", "殷勤平生事，款曲無不終。", "悲歡兩相極，以是半日中。", "言罷相與行，行行古成裏。", "同行復一人，不識誰氏子。", "逡巡急吏來，呼喚願且止。", "馳至相君前，再拜復再起。", "啓云吏有奉，奉命傳所旨。", "事有大驚忙，非君不能理。", "答云久就閑，不願見勞使。", "多謝致勤勤，未敢相唯唯。", "我因前獻言，此事愚可料。"]'),
('2f9a6fd7-233e-4fee-ad21-ac6a39c7aff4','和東川李相公慈竹十二韻','元稹','唐','唐诗','tang','','[]','慈竹不外長，密比青瑤華。',144,'全唐诗/poet.tang.21000.json','["慈竹不外長，密比青瑤華。", "矛攢有森束，玉粒無蹉跎。", "纖粉妍膩質，細瓊交翠柯。", "亭亭霄漢近，靄靄雨露多。", "冰碧寒夜聳，簫韶風晝羅。", "煙含朧朧影，月泛鱗鱗波。", "鸞鳳一已顧，燕雀永不過。", "幽姿媚庭實，顥氣爽天涯。", "峻節高轉露，貞筠寒更佳。", "託身仙壇上，靈物神所呵。", "時與天籟合，日聞陽春歌。", "應憐孤生者，摧折成病痾。"]'),
('eaf872cd-1643-493b-9f2b-bc34ecdf57eb','酬東川李相公十六韻','元稹','唐','唐诗','tang','','[]','昔附赤霄羽，葳蕤遊紫垣。',192,'全唐诗/poet.tang.21000.json','["昔附赤霄羽，葳蕤遊紫垣。", "鬬班香案上，奏語玉晨尊。", "戇直撩忌諱，科儀懲傲頑。", "自從真籍除，棄置勿復論。", "前時共遊者，日夕黃金軒。", "請帝下巫覡，八荒求我魂。", "鸞鳳屢鳴顧，燕雀尚籬藩。", "徒令霄漢外，往往塵念存。", "存念豈虛設，併投瓊與璠。", "彈珠古所訝，此用何太敦。", "鄒律寒氣變，鄭琴祥景奔。", "靈芝繞身出，左右光彩繁。", "碾玉無俗色，蘂珠非世言。", "重慙前日句，陋若蕕並蓀。", "臘月巴地雨，瘴江愁浪翻。", "因持駭雞寶，一照濁水昏。"]'),
('89ea3f5f-8721-4d41-b147-952bc0507706','酬獨孤二十六送歸通州','元稹','唐','唐诗','tang','','[]','再拜捧兄贈，拜兄珍重言。',192,'全唐诗/poet.tang.21000.json','["再拜捧兄贈，拜兄珍重言。", "我有平生志，臨別將具論。", "十歲慕倜儻，愛白不愛昏。", "寧愛寒切烈，不愛暘溫暾。", "二十走獵騎，三十遊海門。", "憎兔跳趯趯，惡鵬黑翻翻。", "鼇釣氣方壯，鶻拳心頗尊。", "下觀鬇鬡輩，一掃冀不存。", "名冠壯士籍，功酬明主恩。", "不然合身棄，何況身上痕。", "金石有銷爍，胏腑無寒溫。", "分畫久已定，波濤何足煩。", "嘗希蘇門嘯，詎厭巴樹猿。", "瘴水徒浩浩，浮雲亦軒軒。", "長歌莫長歡，飲斛莫飲樽。", "生爲醉鄉客，死作達士魂。"]'),
('066adddf-9303-4030-a07f-ccf08e2bd81f','酬劉猛見送','元稹','唐','唐诗','tang','','[]','種花有顏色，異色即爲妖。',204,'全唐诗/poet.tang.21000.json','["種花有顏色，異色即爲妖。", "養鳥惡羽翮，剪翮不待高。", "非無剪傷者，物性難自逃。", "百足雖捷捷，商羊亦翹翹。", "伊余狷然質，謬入多士朝。", "任氣有愎戇，容身寡朋曹。", "愚狂偶似直，靜僻非敢驕。", "一爲毫髮忤，十載山川遙。", "爍鐵不在火，割肌不在刀。", "險心露山嶽，流語翻波濤。", "六尺安敢主，方寸自由調。", "神劒土不蝕，異布火不燋。", "雖無二物姿，庶欲効一毫。", "未能深蹙蹙，多謝相勞勞。", "去去我移馬，遲遲君過橋。", "雲勢正橫壑，江流初滿槽。", "持此慰遠道，此之爲舊交。"]'),
('a056ad49-c180-40f0-8657-643e2c531990','酬樂天赴江州路上見寄三首 一','元稹','唐','唐诗','tang','','[]','昔在京城心，今在吳楚末。',108,'全唐诗/poet.tang.21000.json','["昔在京城心，今在吳楚末。", "千山道路險，萬里音塵闊。", "天上參與商，地上胡與越。", "終天升沈異，滿地網羅設。", "心有無眹環，腸有無繩結。", "有結解不開，有環尋不歇。", "山嶽移可盡，江海塞可絕。", "離恨若空虛，窮年思不徹。", "生莫強相同，相同會相別。"]'),
('a02a4b68-3e7e-43d5-b1be-0bfdb4476395','酬樂天赴江州路上見寄三首 二','元稹','唐','唐诗','tang','','[]','襄陽大隄繞，我向隄前住。',72,'全唐诗/poet.tang.21000.json','["襄陽大隄繞，我向隄前住。", "燭隨花豔來，騎送朝雲去。", "萬竿高廟竹，三月徐亭樹。", "我昔憶君時，君今懷我處。", "有身有離別，無地無岐路。", "風塵同古今，人世勞新故。"]'),
('f8b8c3d4-9f0f-4b55-8bb6-f8691c816505','酬樂天赴江州路上見寄三首 三','元稹','唐','唐诗','tang','','[]','人亦有相愛，我爾殊衆人。',72,'全唐诗/poet.tang.21000.json','["人亦有相愛，我爾殊衆人。", "朝朝寧不食，日日願見君。", "一日不得見，愁腸坐氛氳。", "如何遠相失，各作萬里雲。", "雲高風苦多，會合難遽因。", "天上猶有礙，何況地上身。"]'),
('5a6d2252-a05a-4fbb-ae88-890ff87ce04c','郵竹','元稹','唐','唐诗','tang','','[]','庭有蕭蕭竹，門有闐闐騎。',48,'全唐诗/poet.tang.21000.json','["庭有蕭蕭竹，門有闐闐騎。", "囂靜本殊途，因依偶同寄。", "亭亭乍干雲，嫋嫋亦垂地。", "人有異我心，我無異人意。"]'),
('5a844e25-382f-43c0-942b-cd20bd397ee9','落月','元稹','唐','唐诗','tang','','[]','落月沈餘影，陰渠流暗光。',48,'全唐诗/poet.tang.21000.json','["落月沈餘影，陰渠流暗光。", "蚊聲靄窗戶，螢火繞屋梁。", "飛幌翠雲薄，新荷清露香。", "不吟復不寐，竟夕池水傍。"]'),
('ff9ba6ba-1892-40f7-b02c-2ce2e0e2c8ed','高荷','元稹','唐','唐诗','tang','','[]','種藕百餘根，高荷纔四葉。',48,'全唐诗/poet.tang.21000.json','["種藕百餘根，高荷纔四葉。", "颭閃碧雲扇，團圓青玉疊。", "亭亭自擡舉，鼎鼎難藏擪。", "不學著水荃，一生長怗怗。"]'),
('1ca77171-5ad9-4f9a-934e-1ea54f2cc9d3','和裴校書鷺鷥飛','元稹','唐','唐诗','tang','','[]','鷺鷥鷺鷥何遽飛，鵶驚雀噪難久依。',32,'全唐诗/poet.tang.21000.json','["鷺鷥鷺鷥何遽飛，鵶驚雀噪難久依。", "清江見底草堂在，一點白光終不歸。"]'),
('894341d4-2c13-4b88-a016-ebe6aeb0a66a','夜池','元稹','唐','唐诗','tang','','[]','荷葉團圓莖削削，綠萍面上紅衣落。',32,'全唐诗/poet.tang.21000.json','["荷葉團圓莖削削，綠萍面上紅衣落。", "滿池明月思啼螿，高屋無人風張幕。"]'),
('e110c62b-f130-4558-b4af-8282d6a2a5de','酬楊司業十二兄早秋述情見寄','元稹','唐','唐诗','tang','','[]','白髮故人少，相逢意彌遠。',72,'全唐诗/poet.tang.21000.json','["白髮故人少，相逢意彌遠。", "往事共銷沈，前期各衰晚。", "昨來遇彌苦，已復雲離巘。", "秋草古膠庠，寒沙廢宮苑。", "知心豈忘鮑，詠懷難和阮。", "壯志日蕭條，那能競朝幰。"]'),
('cea9c022-0ca5-4f5a-992a-7f7b42826486','代杭人作使君一朝去二首 一','元稹','唐','唐诗','tang','','[]','使君一朝去，遺愛在人口。',36,'全唐诗/poet.tang.21000.json','["使君一朝去，遺愛在人口。", "惠化境內春，才名天下首。", "爲問龔黃輩，兼能作詩否。"]'),
('c9d26c42-e29a-45f7-af74-1925d1f1f22a','代杭人作使君一朝去二首 二','元稹','唐','唐诗','tang','','[]','使君一朝去，斷腸如剉檗。',36,'全唐诗/poet.tang.21000.json','["使君一朝去，斷腸如剉檗。", "無復見冰壺，唯應鏤金石。", "自此一州人，生男盡名白。"]'),
('e779dbae-0771-4cea-9af3-67d0d761e562','長慶曆','元稹','唐','唐诗','tang','','[]','年曆復年曆，卷盡悲且惜。',48,'全唐诗/poet.tang.21000.json','["年曆復年曆，卷盡悲且惜。", "曆日何足悲，但悲年運易。", "年年豈無歎，此歎何唧唧。", "所歎別此年，永無長慶曆。"]'),
('675edd27-789d-417e-aaf1-27d7b405bec5','順宗至德大聖大安孝皇帝挽歌詞三首 一','元稹','唐','唐诗','tang','','[]','不改延洪祚，因成揖讓朝。',48,'全唐诗/poet.tang.21000.json','["不改延洪祚，因成揖讓朝。", "謳歌同戴啓，遏密共思堯。", "雨露施恩廣，梯航會葬遙。", "號弓那獨切，曾感昔年招。"]'),
('ed566302-ccbe-44fc-b92d-df28a414c402','順宗至德大聖大安孝皇帝挽歌詞三首 二','元稹','唐','唐诗','tang','','[]','前春文祖廟，大舜嗣堯登。',48,'全唐诗/poet.tang.21000.json','["前春文祖廟，大舜嗣堯登。", "及此踰年感，還因是月崩。", "壽緣追孝促，業在繼明興。", "儉詔同今古，山川繞灞陵。"]'),
('55813a3e-3b1d-4f2a-97b8-663a092a5cc6','順宗至德大聖大安孝皇帝挽歌詞三首 三','元稹','唐','唐诗','tang','','[]','七月悲風起，淒涼萬國人。',48,'全唐诗/poet.tang.21000.json','["七月悲風起，淒涼萬國人。", "羽儀經巷內，輼𨍇轉城闉。", "暝色依陵早，秋聲入輅新。", "自嗟同草木，不識永貞春。"]'),
('6fcfdc6b-b8d6-4df3-a68e-4ce6954620d6','憲宗章武孝皇帝挽歌詞三首 一','元稹','唐','唐诗','tang','','[]','國付重離後，身隨十聖仙。',48,'全唐诗/poet.tang.21000.json','["國付重離後，身隨十聖仙。", "北辰移帝座，西日到虞泉。", "方丈言虛設，華胥事眇然。", "觸鱗曾在宥，偏哭墮髯前。"]'),
('a4007237-d828-4152-9ec1-d74a689981ba','憲宗章武孝皇帝挽歌詞三首 二','元稹','唐','唐诗','tang','','[]','天寶遺餘事，元和盛聖功。',48,'全唐诗/poet.tang.21000.json','["天寶遺餘事，元和盛聖功。", "二凶梟帳下，三叛斬都中。", "始服沙陁虜，方吞邏逤戎。", "狼星如要射，猶有鼎湖弓。"]'),
('eeeff4e4-de73-4bea-9c57-c1bf522ecb93','憲宗章武孝皇帝挽歌詞三首 三','元稹','唐','唐诗','tang','','[]','月落禁垣西，星攢曉仗齊。',48,'全唐诗/poet.tang.21000.json','["月落禁垣西，星攢曉仗齊。", "風傳宮漏苦，雲拂羽儀低。", "路隘車千兩，橋危馬萬蹄。", "共嗟封石撿，不爲報功泥。"]'),
('2bf33164-0d8b-4739-9e34-005e781ee3e0','恭王故太妃挽歌詞二首 一','元稹','唐','唐诗','tang','','[]','燕姞貽天夢，梁王盡孝思。',48,'全唐诗/poet.tang.21000.json','["燕姞貽天夢，梁王盡孝思。", "雖從魏詔葬，得用漢藩儀。", "曙月殘光斂，寒簫度曲遲。", "平生奉恩地，哀挽欲何之。"]'),
('8b6bb06d-6988-4aff-af45-ad7a0f59341c','恭王故太妃挽歌詞二首 二','元稹','唐','唐诗','tang','','[]','文衛羅新壙，仙娥掩暝山。',48,'全唐诗/poet.tang.21000.json','["文衛羅新壙，仙娥掩暝山。", "雪雲埋隴合，簫鼓望城還。", "寒樹風難靜，霜郊夜更閑。", "哀榮深孝嗣，儀表在河間。"]'),
('3b23777c-6576-4919-8704-4ed7aa64936b','哭呂衡州六首 一','元稹','唐','唐诗','tang','','[]','氣敵三人傑，交深一紙書。',48,'全唐诗/poet.tang.21000.json','["氣敵三人傑，交深一紙書。", "我投冰瑩眼，君報水憐魚。", "髀股惟夸瘦，膏肓豈暇除。", "傷心死諸葛，憂道不憂餘。"]'),
('a27011ee-2e78-4bcf-a41f-125975716b57','哭呂衡州六首 二','元稹','唐','唐诗','tang','','[]','望有經綸釣，虔收宰相刀。',48,'全唐诗/poet.tang.21000.json','["望有經綸釣，虔收宰相刀。", "江文駕風遠，雲貌接天高。", "國待球琳器，家藏虎豹韜。", "盡將千載寶，埋入五原蒿。"]'),
('4b40ffb4-d390-4d54-a701-87cc76906bcf','哭呂衡州六首 三','元稹','唐','唐诗','tang','','[]','白馬雙旌隊，青山八陣圖。',48,'全唐诗/poet.tang.21000.json','["白馬雙旌隊，青山八陣圖。", "請纓期繫虜，枕草誓捐軀。", "勢激三千壯，年應四十無。", "遙聞不瞑目，非是不憐吳。"]'),
('83f874a6-f01c-41f5-be65-4b7bcf652188','哭呂衡州六首 四','元稹','唐','唐诗','tang','','[]','鵰鶚生難敵，沉檀死更香。',48,'全唐诗/poet.tang.21000.json','["鵰鶚生難敵，沉檀死更香。", "兒童喧巷市，羸老哭碑堂。", "鴈起沙汀闇，雲連海氣黃。", "祝融峰上月，幾照北人喪。"]'),
('4f440666-83e7-4027-b5b2-f70f542df04c','哭呂衡州六首 五','元稹','唐','唐诗','tang','','[]','廻鴈峰前鴈，春廻盡却廻。',48,'全唐诗/poet.tang.21000.json','["廻鴈峰前鴈，春廻盡却廻。", "聯行四人去，同葬一人來。", "鐃吹臨江返，城池隔霧開。", "滿船深夜哭，風棹楚猿哀。"]'),
('66f683e8-8fa8-498a-bd56-4e8059f0504c','哭呂衡州六首 六','元稹','唐','唐诗','tang','','[]','杜預春秋癖，揚雄著述精。',48,'全唐诗/poet.tang.21000.json','["杜預春秋癖，揚雄著述精。", "在時兼不語，終古定歸名。", "耒水波文細，湘江竹葉輕。", "平生思風月，潛寐若爲情。"]'),
('f06deb49-67a0-4e05-bbde-b9b2b2fe3f76','僧如展及韋載同遊碧澗寺各賦詩予落句云他生莫忘靈山座滿壁人名後會稀展共吟他生之句因話釋氏緣會所以莫不悽然久之不十日而展公長逝驚悼返覆則他生豈有兆耶其間展公仍賦黃字五十韻飛札相示予方屬和未畢自此不復撰成徒以四韻爲識','元稹','唐','唐诗','tang','','[]','重吟前日他生句，豈料踰旬便隔生。',64,'全唐诗/poet.tang.21000.json','["重吟前日他生句，豈料踰旬便隔生。", "會擬一來身塔下，無因共繞寺廊竹。", "紫毫飛札看猶濕，黃字新詩和未成。", "縱使得如羊叔子，不聞兼記舊交情。"]'),
('7aaacf65-f482-4535-aec2-9c90b03fddc5','公安縣遠安寺水亭見展公題壁漂然淚流因書四韻','元稹','唐','唐诗','tang','','[]','碧澗去年會，與師三兩人。',48,'全唐诗/poet.tang.21000.json','["碧澗去年會，與師三兩人。", "今來見題壁，師已是前身。", "芰葉迎僧夏，楊花度俗春。", "空將數行淚，灑徧塔中塵。"]'),
('aecb2ee2-c4e2-400e-a841-b76053a48e11','寒食日毛空路示姪晦及從簡','元稹','唐','唐诗','tang','','[]','我昔孩提從我兄，我今衰白爾初成。',32,'全唐诗/poet.tang.21000.json','["我昔孩提從我兄，我今衰白爾初成。", "分明寄取原頭路，百世長須此路行。"]'),
('83ef62e6-6e12-4c94-abdd-ed38dc822865','別孫村老人','元稹','唐','唐诗','tang','','[]','年年漸覺老人稀，欲別孫翁淚滿衣。',32,'全唐诗/poet.tang.21000.json','["年年漸覺老人稀，欲別孫翁淚滿衣。", "未死不知何處去，此身終向此原歸。"]'),
('0fb05c83-4978-40d1-bb36-5ca1a0629256','和樂天劉家花','元稹','唐','唐诗','tang','','[]','閑坊靜曲同消日，淚草傷花不爲春。',32,'全唐诗/poet.tang.21000.json','["閑坊靜曲同消日，淚草傷花不爲春。", "徧問舊交零落盡，十人纔有兩三人。"]'),
('a3c60b89-0636-4b9b-bdaf-09c45824b38b','褒城驛二首 一','元稹','唐','唐诗','tang','','[]','容州詩句在褒城，幾度經過眼暫明。',32,'全唐诗/poet.tang.21000.json','["容州詩句在褒城，幾度經過眼暫明。", "今日重看滿衫淚，可憐名字已前生。"]'),
('48d3a16d-6c47-4795-afe0-60269a5c432e','褒城驛二首 二','元稹','唐','唐诗','tang','','[]','憶昔萬株梨映竹，遇逢黃令醉殘春。',32,'全唐诗/poet.tang.21000.json','["憶昔萬株梨映竹，遇逢黃令醉殘春。", "梨枯竹盡黃令死，今日再來衰病身。"]'),
('0bf2c95c-5bfa-4b1b-b178-f4bd1532a1f6','和樂天夢亡友劉太白同遊二首 一','元稹','唐','唐诗','tang','','[]','君詩昨日到通州。',32,'全唐诗/poet.tang.21000.json','["君詩昨日到通州。", "萬里知君一夢劉，閑坐思量小來事。", "秪應元是夢中遊。"]'),
('4791faf7-6918-49aa-924c-1878951eb8be','和樂天夢亡友劉太白同遊二首 二','元稹','唐','唐诗','tang','','[]','老來東郡復西州，行處生塵爲喪劉。',32,'全唐诗/poet.tang.21000.json','["老來東郡復西州，行處生塵爲喪劉。", "縱使劉君魂魄在，也應至死不同遊。"]'),
('fc616470-cbb8-4276-b930-9567fa206e64','酬樂天見憶兼傷仲遠','元稹','唐','唐诗','tang','','[]','死別重泉閟，生離萬里賒。',72,'全唐诗/poet.tang.21000.json','["死別重泉閟，生離萬里賒。", "瘴侵新病骨，夢到故人家。", "遙淚陳根草，閑收落地花。", "庾公樓悵望，巴子國生涯。", "河任天然曲，江隨峽勢斜。", "與君皆直戇，須分老泥沙。"]'),
('62628a33-df75-4e06-a6c6-f80faa92c977','與樂天同葬杓直','元稹','唐','唐诗','tang','','[]','元伯來相葬，山濤誓撫孤。',24,'全唐诗/poet.tang.21000.json','["元伯來相葬，山濤誓撫孤。", "不知他日事，兼得似君無。"]'),
('035adec3-38c3-4760-9464-6c2cb34f9f34','夜閑','元稹','唐','唐诗','tang','','[]','感極都無夢，魂銷轉易驚。',48,'全唐诗/poet.tang.21000.json','["感極都無夢，魂銷轉易驚。", "風簾半鉤落，秋月滿牀明。", "悵望臨階坐，沈吟遶樹行。", "孤琴在幽匣，時迸斷弦聲。"]'),
('06432b35-8b0d-4e26-a239-4b326ecffbb0','感小株夜合','元稹','唐','唐诗','tang','','[]','纖幹未盈把，高條纔過眉。',48,'全唐诗/poet.tang.21000.json','["纖幹未盈把，高條纔過眉。", "不禁風苦動，偏受露先萎。", "不分秋同盡，深嗟小便衰。", "傷心落殘葉，猶識合昏期。"]'),
('4b1c634b-15ac-4c6f-8d16-6ce955841f68','醉醒','元稹','唐','唐诗','tang','','[]','積善坊中前度飲，謝家諸婢笑扶行。',32,'全唐诗/poet.tang.21000.json','["積善坊中前度飲，謝家諸婢笑扶行。", "今宵還似當時醉，半夜覺來聞哭聲。"]'),
('7dcd7968-f1c5-4f2e-a770-11f77a135df1','追昔遊','元稹','唐','唐诗','tang','','[]','謝傅堂前音樂和，狗兒吹笛膽娘歌。',64,'全唐诗/poet.tang.21000.json','["謝傅堂前音樂和，狗兒吹笛膽娘歌。", "花園欲盛千場飲，水閣初成百度過。", "醉摘櫻桃投小玉，嬾梳叢鬢舞曹婆。", "再來門館唯相弔，風落秋池紅葉多。"]'),
('bcc300ce-c53a-4a2a-9073-bdb619ee91f5','空屋題','元稹','唐','唐诗','tang','','[]','朝從空屋裏，騎馬入空臺。',48,'全唐诗/poet.tang.21000.json','["朝從空屋裏，騎馬入空臺。", "盡日推閒事，還歸空屋來。", "月明穿暗隙，燈燼落殘灰。", "更想咸陽道，魂車昨夜回。"]'),
('3121ade4-3a76-4604-8160-2bd100756280','初寒夜寄盧子蒙','元稹','唐','唐诗','tang','','[]','月是陰秋鏡，寒爲寂寞資。',48,'全唐诗/poet.tang.21000.json','["月是陰秋鏡，寒爲寂寞資。", "輕寒酒醒後，斜月枕前時。", "倚壁思閑事，回燈檢舊詩。", "聞君亦同病，終夜遠相悲。"]'),
('6c11f704-767c-4152-af8b-f3c10b1449d1','城外回謝子蒙見諭','元稹','唐','唐诗','tang','','[]','十里撫柩別，一身騎馬回。',48,'全唐诗/poet.tang.21000.json','["十里撫柩別，一身騎馬回。", "寒煙半堂影，燼火滿庭灰。", "稚女憑人問，病夫空自哀。", "潘安寄新詠，仍是夜深來。"]'),
('ab8091c8-ab65-457e-a707-b1bbdfdd5db5','諭子蒙','元稹','唐','唐诗','tang','','[]','撫稚君休感，無兒我不傷。',48,'全唐诗/poet.tang.21000.json','["撫稚君休感，無兒我不傷。", "片雲離岫遠，雙燕念巢忙。", "大壑誰非水，華星各自光。", "但令長有酒，何必謝家莊。"]'),
('8b57e03d-6d1f-4a4a-ba34-1f58e2551ca1','遣悲懷三首 一','元稹','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u5f8b\u8bd7", "\u60bc\u4ea1"]','謝公最小偏憐女，嫁與黔婁百事乖。',64,'全唐诗/poet.tang.21000.json','["謝公最小偏憐女，嫁與黔婁百事乖。", "顧我無衣搜畫篋，泥他沽酒拔金釵。", "野蔬充膳甘長藿，落葉添薪仰古槐。", "今日俸錢過十萬，與君營奠復營齋。"]'),
('ea3f91f0-487e-4df7-826a-3692ef82e64d','遣悲懷三首 二','元稹','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u8ffd\u5fc6", "\u60bc\u4ea1", "\u4e03\u8a00\u5f8b\u8bd7"]','昔日戲言身後意，今朝皆到眼前來。',64,'全唐诗/poet.tang.21000.json','["昔日戲言身後意，今朝皆到眼前來。", "衣裳已施行看盡，針線猶存未忍開。", "尚想舊情憐婢僕，也曾因夢送錢財。", "誠知此恨人人有，貧賤夫妻百事哀。"]'),
('82f57261-b608-4ee9-8d88-7fde20c49a7a','遣悲懷三首 三','元稹','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u5f8b\u8bd7", "\u60bc\u4ea1"]','閑坐悲君亦自悲，百年都是幾多時。',64,'全唐诗/poet.tang.21000.json','["閑坐悲君亦自悲，百年都是幾多時。", "鄧攸無子尋知命，潘岳悼亡猶費詞。", "同穴窅冥何所望，他生緣會更難期。", "唯將終夜長開眼，報荅平生未展眉。"]'),
('04ab26f8-1756-4e66-bd67-de1c077e141c','旅眠','元稹','唐','唐诗','tang','','[]','內外都無隔，帷屏不復張。',24,'全唐诗/poet.tang.21000.json','["內外都無隔，帷屏不復張。", "夜眠兼客坐，同在火爐牀。"]'),
('832aa93e-e827-423c-870b-810d2395e847','除夜','元稹','唐','唐诗','tang','','[]','憶昔歲除夜，見君花燭前。',48,'全唐诗/poet.tang.21000.json','["憶昔歲除夜，見君花燭前。", "今宵祝文上，重疊敘新年。", "閑處低聲哭，空堂背月眠。", "傷心小兒女，撩亂火堆邊。"]'),
('658158db-7d51-4ec4-8cf5-0c28ae6ad4b5','感夢','元稹','唐','唐诗','tang','','[]','行吟坐歎知何極，影絕魂銷動隔年。',32,'全唐诗/poet.tang.21000.json','["行吟坐歎知何極，影絕魂銷動隔年。", "今夜商山館中夢，分明同在後堂前。"]'),
('0fd97a39-0da0-408b-ac9c-5ffd7e16e796','合衣寢','元稹','唐','唐诗','tang','','[]','良夕背燈坐，方成合衣寢。',24,'全唐诗/poet.tang.21000.json','["良夕背燈坐，方成合衣寢。", "酒醉夜未闌，幾回顛倒枕。"]'),
('358a8bed-f849-414a-8de0-47844f396294','竹簟','元稹','唐','唐诗','tang','','[]','竹簟襯重茵，未忍都令卷。',24,'全唐诗/poet.tang.21000.json','["竹簟襯重茵，未忍都令卷。", "憶昨初來日，看君自施展。"]'),
('bdcc3308-ee5d-40a6-a7ab-4c61f50c6add','聽庾及之彈烏夜啼引','元稹','唐','唐诗','tang','','[]','君彈烏夜啼，我傳樂府解古題。',174,'全唐诗/poet.tang.21000.json','["君彈烏夜啼，我傳樂府解古題。", "良人在獄妻在閨，官家欲赦烏報妻。", "烏前再拜淚如雨，烏作哀聲妻暗語。", "後人寫出烏啼引，吳調哀弦聲楚楚。", "四五年前作拾遺，諫書不密丞相知。", "謫官詔下吏驅遣，身作囚拘妻在遠。", "歸來相見淚如珠，唯說閑宵長拜烏。", "君來到舍是烏力，粧點烏盤邀女巫。", "今君爲我千萬彈，烏啼啄啄淚瀾瀾。", "感君此曲有深意，昨日烏啼桐葉墜。", "當時爲我賽烏人，死葬咸陽原上地。"]'),
('578e682b-2c71-4949-bc64-daa901dc2549','夢井','元稹','唐','唐诗','tang','','[]','夢上高高原，原上有深井。',240,'全唐诗/poet.tang.21000.json','["夢上高高原，原上有深井。", "登高意枯渴，願見深泉冷。", "裴回遶井顧，自照泉中影。", "沈浮落井瓶，井上無懸綆。", "念此瓶欲沈，荒忙爲求請。", "遍入原上村，村空犬仍猛。", "還來遶井哭，哭聲通復哽。", "哽噎夢忽驚，覺來房舍靜。", "燈焰碧朧朧，淚光疑冏冏。", "鍾聲夜方半，坐臥心難整。", "忽憶咸陽原，荒田萬餘頃。", "土厚壙亦深，埋魂在深埂。", "埂深安可越，魂通有時逞。", "今宵泉下人，化作瓶相憬。", "感此涕汍瀾，汍瀾涕霑領。", "所傷覺夢間，便覺死生境。", "豈無同穴期，生期諒綿永。", "又恐前後魂，安能兩知省。", "尋環意無極，坐見天將昞。", "吟此夢井詩，春朝好光景。"]'),
('2982b48c-527e-4f8a-adbc-4479085c2d93','江陵三夢 一','元稹','唐','唐诗','tang','','[]','平生每相夢，不省兩相知。',288,'全唐诗/poet.tang.21000.json','["平生每相夢，不省兩相知。", "況乃幽明隔，夢魂徒爾爲。", "情知夢無益，非夢見何期。", "今夕亦何夕，夢君相見時。", "依稀舊粧服，晻淡昔容儀。", "不道間生死，但言將別離。", "分張碎針線，襵疊故幈幃。", "撫稚再三囑，淚珠千萬垂。", "囑云唯此女，自歎總無兒。", "尚念嬌且騃，未禁寒與飢。", "君復不憘事，奉身猶脫遺。", "況有官縛束，安能長顧私。", "他人生間別，婢僕多謾欺。", "君在或有託，出門當付誰。", "言罷泣幽噎，我亦涕淋漓。", "驚悲忽然寤，坐臥若狂癡。", "月影半床黑，蟲聲幽草移。", "心魂生次第，覺夢久自疑。", "寂默深想像，淚下如流澌。", "百年永已訣，一夢何太悲。", "悲君所嬌女，棄置不我隨。", "長安遠於日，山川雲間之。", "縱我生羽翼，網羅生縶維。", "今宵淚零落，半爲生別滋。"]'),
('2217c01b-cc6c-4c0a-afd1-61ba7ee33870','江陵三夢 二','元稹','唐','唐诗','tang','','[]','古原三丈穴，深葬一枝瓊。',48,'全唐诗/poet.tang.21000.json','["古原三丈穴，深葬一枝瓊。", "崩剝山門壞，煙綿墳草生。", "久依荒隴坐，却望遠村行。", "驚覺滿床月，風波江上聲。"]'),
('d248f583-59ea-4085-8d07-ca902f456bcb','江陵三夢 三','元稹','唐','唐诗','tang','','[]','君骨久爲土，我心長似灰。',48,'全唐诗/poet.tang.21000.json','["君骨久爲土，我心長似灰。", "百年何處盡，三夜夢中來。", "逝水良已矣，行雲安在哉？", "坐看朝日出，衆鳥雙裴回。"]'),
('d5832c35-3c94-470f-9a79-3e11476c1248','張舊蚊幬','元稹','唐','唐诗','tang','','[]','踰年間生死，千里曠南北。',192,'全唐诗/poet.tang.21000.json','["踰年間生死，千里曠南北。", "家居無見期，況乃異鄉國。", "破盡裁縫衣，忘收遺翰墨。", "獨有纈紗幬，憑人遠攜得。", "施張合歡榻，展卷雙鴛翼。", "已矣長空虛，依然舊顏色。", "裴回將就寢，徙倚情何極。", "昔透香田田，今無魂惻惻。", "隙穿斜月照，燈背空床黑。", "達理強開懷，夢啼還過臆。", "平生貧寡歡，夭枉勞苦憶。", "我亦距幾時，胡爲自摧逼。", "燭蛾焰中舞，蠒蠶叢上織。", "燋爛各自求，他人顧何力。", "多離因苟合，惡影當務息。", "往事勿復言，將來幸前識。"]'),
('0ceccf70-4da6-4c11-90cb-fd49af6bec31','獨夜傷懷贈呈張侍御','元稹','唐','唐诗','tang','','[]','燼火孤星滅，殘燈寸焰明。',48,'全唐诗/poet.tang.21000.json','["燼火孤星滅，殘燈寸焰明。", "竹風吹面冷，簷雪墜階聲。", "寡鶴連天呌，寒雛徹夜驚。", "秪應張侍御，潛會我心情。"]'),
('b7d820dd-b106-4c8f-9eec-c04bbb8c4347','六年春遣懷八首 一','元稹','唐','唐诗','tang','','[]','傷禽我是籠中鶴，沈劒君爲泉下龍。',32,'全唐诗/poet.tang.21000.json','["傷禽我是籠中鶴，沈劒君爲泉下龍。", "重纊猶存孤枕在，春衫無復舊裁縫。"]'),
('6391003a-2248-48db-88a4-e7a6e2781eab','六年春遣懷八首 二','元稹','唐','唐诗','tang','','[]','檢得舊書三四紙，高低闊狹粗成行。',32,'全唐诗/poet.tang.21000.json','["檢得舊書三四紙，高低闊狹粗成行。", "自言併食尋高事，唯念山深驛路長。"]'),
('72d2e362-2a47-4fb7-9fe2-54514118febb','六年春遣懷八首 三','元稹','唐','唐诗','tang','','[]','公無渡河音響絕，已隔前春復去秋。',32,'全唐诗/poet.tang.21000.json','["公無渡河音響絕，已隔前春復去秋。", "今日閑窗拂塵土，殘弦猶迸鈿箜篌。"]'),
('257d4e4d-4a82-475d-a094-996ae3df5d4d','六年春遣懷八首 四','元稹','唐','唐诗','tang','','[]','婢僕曬君餘服用，嬌癡稚女遶床行。',32,'全唐诗/poet.tang.21000.json','["婢僕曬君餘服用，嬌癡稚女遶床行。", "玉梳鈿朵香膠解，盡日風吹玳瑁箏。"]'),
('ea9d0862-3c66-4ae5-a004-8fbb4a75d7f8','六年春遣懷八首 五','元稹','唐','唐诗','tang','','[]','伴客銷愁長日飲，偶然乘興便醺醺。',32,'全唐诗/poet.tang.21000.json','["伴客銷愁長日飲，偶然乘興便醺醺。", "怪來醒後傍人泣，醉裏時時錯問君。"]'),
('6fa8a162-3426-446f-a7f7-3ca6a3ecb6c4','六年春遣懷八首 六','元稹','唐','唐诗','tang','','[]','我隨楚澤波中梗，君作咸陽泉下泥。',32,'全唐诗/poet.tang.21000.json','["我隨楚澤波中梗，君作咸陽泉下泥。", "百事無心值寒食，身將稚女帳前啼。"]'),
('4e77ad85-2bda-4d61-a72c-daa3fc5a1edc','六年春遣懷八首 七','元稹','唐','唐诗','tang','','[]','童稚癡狂撩亂走，繡毬花仗滿堂前。',32,'全唐诗/poet.tang.21000.json','["童稚癡狂撩亂走，繡毬花仗滿堂前。", "病身一到繐帷下，還向臨階背日眠。"]'),
('4ed476c3-dff5-4908-9590-a4f36b26e69e','六年春遣懷八首 八','元稹','唐','唐诗','tang','','[]','小於潘岳頭先白，學取莊周淚莫多。',32,'全唐诗/poet.tang.21000.json','["小於潘岳頭先白，學取莊周淚莫多。", "止竟悲君須自省，川流前後各風波。"]'),
('5e2e750e-0af2-46d9-b5a9-1ce7d03ace46','荅友封見贈','元稹','唐','唐诗','tang','','[]','荀令香銷潘簟空，悼亡詩滿舊屏風。',32,'全唐诗/poet.tang.21000.json','["荀令香銷潘簟空，悼亡詩滿舊屏風。", "扶床小女君先識，應爲些些似外翁。"]'),
('4d449b13-aabf-46be-80a0-dd34a128f2a5','夢成之','元稹','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','燭暗船風獨夢驚，夢君頻問向南行。',32,'全唐诗/poet.tang.21000.json','["燭暗船風獨夢驚，夢君頻問向南行。", "覺來不語到明坐，一夜洞庭湖水聲。"]'),
('94428446-19f1-418f-8775-14e5409f6e0e','哭小女降真','元稹','唐','唐诗','tang','','[]','雨點輕漚風復驚，偶來何事去何情。',32,'全唐诗/poet.tang.21000.json','["雨點輕漚風復驚，偶來何事去何情。", "浮生未到無生地，暫到人間又一生。"]'),
('5926ca12-e01f-4fc7-a484-554e39ba7a65','哭女樊','元稹','唐','唐诗','tang','','[]','秋天淨綠月分明，何事巴猿不賸鳴。',32,'全唐诗/poet.tang.21000.json','["秋天淨綠月分明，何事巴猿不賸鳴。", "應是一聲腸斷去，不容啼到第三聲。"]'),
('5b5624fc-d2df-4ead-ad76-3a91a6f3ebaa','哭女樊四十韻','元稹','唐','唐诗','tang','','[]','逝者何由見，中人未達情。',288,'全唐诗/poet.tang.21000.json','["逝者何由見，中人未達情。", "馬無生角望，猿有斷腸鳴。", "去伴投遐徼，來隨夢險程。", "四年巴養育，萬里硤回縈。", "病是他鄉染，魂應遠處驚。", "山魈邪亂逼，沙虱毒潛嬰。", "母約看寧辨，余慵療不精。", "欲尋方次第，俄值疾充盈。", "燈火徒相守，香花秪浪擎。", "蓮初開月梵，蕣已落朝榮。", "魄散雲將盡，形全玉尚瑩。", "空垂兩行血，深送一枝瓊。", "祕祝休巫覡，安眠放使令。", "舊衣和篋施，殘藥滿甌傾。", "乳媼閑於社，醫僧婗似酲。", "憫渠身覺賸，訝佛力難爭。", "騎竹癡猶子，牽車小外甥。", "等長迷過影，遙戲誤啼聲。", "涴紙傷餘畫，扶床念試行。", "獨留呵面鏡，誰弄倚牆箏。", "憶昨工言語，憐初妙長成。", "撩風妬鸚舌，凌露觸蘭英。", "翠鳳輿真女，紅蕖捧化生。", "秪憂嫌五濁，終恐向三清。"]'),
('7f619c79-94aa-41a1-889a-cee7d82a5d3c','哭子十首 一','元稹','唐','唐诗','tang','','[]','維鵜受刺因吾過，得馬生災念爾冤。',32,'全唐诗/poet.tang.21000.json','["維鵜受刺因吾過，得馬生災念爾冤。", "獨在中庭倚閑樹，亂蟬嘶噪欲黃昏。"]'),
('31750525-f643-4697-98ad-827486571e82','哭子十首 二','元稹','唐','唐诗','tang','','[]','纔能辨別東西位，未解分明管帶身。',32,'全唐诗/poet.tang.21000.json','["纔能辨別東西位，未解分明管帶身。", "自食自眠猶未得，九重泉路託何人。"]'),
('b188da7e-b837-4794-a18b-b98c67062f6e','哭子十首 三','元稹','唐','唐诗','tang','','[]','爾母溺情連夜哭，我身因事有時悲。',32,'全唐诗/poet.tang.21000.json','["爾母溺情連夜哭，我身因事有時悲。", "鍾聲欲絕東方動，便是尋常上學時。"]'),
('5bfd871a-01ea-44d3-8e11-7d4c84398803','哭子十首 四','元稹','唐','唐诗','tang','','[]','蓮花上品生真界，兜率天中離世途。',32,'全唐诗/poet.tang.21000.json','["蓮花上品生真界，兜率天中離世途。", "彼此業緣多障礙，不知還得見兒無。"]'),
('c9c46414-a0d8-4da8-901d-d30dba0f63ac','哭子十首 五','元稹','唐','唐诗','tang','','[]','節量棃栗愁生疾，教示詩書望早成。',32,'全唐诗/poet.tang.21000.json','["節量棃栗愁生疾，教示詩書望早成。", "鞭扑校多憐校少，又緣遺恨哭三聲。"]'),
('fb30a518-8a79-46f6-b9d1-3f1a2f318d32','哭子十首 六','元稹','唐','唐诗','tang','','[]','深嗟爾更無兄弟，自歎予應絕子孫。',32,'全唐诗/poet.tang.21000.json','["深嗟爾更無兄弟，自歎予應絕子孫。", "寂寞講堂基址在，何人車馬入高門。"]'),
('b57ac5cd-1244-47f3-b0e6-4f26f7498c93','哭子十首 七','元稹','唐','唐诗','tang','','[]','往年鬢已同潘岳，垂老年教作鄧攸。',32,'全唐诗/poet.tang.21000.json','["往年鬢已同潘岳，垂老年教作鄧攸。", "煩惱數中除一事，自茲無復子孫憂。"]'),
('9edfa7fc-e23e-48c1-84ed-fab50e202dd0','哭子十首 八','元稹','唐','唐诗','tang','','[]','長年苦境知何限，豈得因兒獨喪明。',32,'全唐诗/poet.tang.21000.json','["長年苦境知何限，豈得因兒獨喪明。", "消遣又來緣爾母，夜深和淚有經聲。"]'),
('04414b63-3fc3-4a2f-8440-9b08a320c768','哭子十首 九','元稹','唐','唐诗','tang','','[]','烏生八子今無七，猿呌三聲月正孤。',32,'全唐诗/poet.tang.21000.json','["烏生八子今無七，猿呌三聲月正孤。", "寂寞空堂天欲曙，拂簾雙燕引新雛。"]'),
('0271325b-c2a6-48d5-bc32-0254b4789280','哭子十首 十','元稹','唐','唐诗','tang','','["\u957f\u6c5f"]','頻頻子落長江水，夜夜巢邊舊處棲。',32,'全唐诗/poet.tang.21000.json','["頻頻子落長江水，夜夜巢邊舊處棲。", "若是愁腸終不斷，一年添得一聲啼。"]'),
('bdf8de4b-9cc2-45ce-95ea-8aa15434766a','感逝','元稹','唐','唐诗','tang','','[]','頭白夫妻分無子，誰令蘭夢感衰翁。',64,'全唐诗/poet.tang.21000.json','["頭白夫妻分無子，誰令蘭夢感衰翁。", "三聲啼婦臥床上，一寸斷腸埋土中。", "蜩甲暗枯秋葉墜，燕雛新去夜巢空。", "情知此恨人皆有，應與暮年心不同。"]'),
('87897b1f-84f8-44e3-a590-d75f479afa53','妻滿月日相唁','元稹','唐','唐诗','tang','','[]','十月辛勤一月悲，今朝相見淚淋漓。',32,'全唐诗/poet.tang.21000.json','["十月辛勤一月悲，今朝相見淚淋漓。", "狂風落盡莫惆悵，猶勝因花壓折枝。"]'),
('045b57ab-f8b0-4230-b0cd-18ae35d8c577','代曲江老人百韻','元稹','唐','唐诗','tang','','["\u6cf0\u5c71"]','何事花前泣，曾逢舊日春。',288,'全唐诗/poet.tang.21000.json','["何事花前泣，曾逢舊日春。", "先皇初在鎬，賤子正遊秦。", "撥亂干戈後，經文禮樂辰。", "徽章懸象魏，貔虎畫騏驎。", "光武休言戰，唐堯念睦姻。", "琳瑯鋪柱礎，葛藟茂河漘。", "尚齒惇耆艾，搜材拔積薪。", "裴王持藻鏡，姚宋斡陶鈞。", "內史稱張敞，蒼生借寇恂。", "名卿唯講德，命士恥憂貧。", "杞梓無遺用，蒭蕘不忘詢。", "懸金收逸驥，鼓瑟薦嘉賓。", "羽翼皆隨鳳，圭璋肯雜珉。", "班行容濟濟，文質道彬彬。", "百度依皇極，千門闢紫宸。", "措刑非苟簡，稽古蹈因循。", "書謬偏求伏，詩亡遠聽申。", "雄推三虎賈，羣擢八龍荀。", "海外恩方洽，寰中教不泯。", "儒林精閫奧，流品重清淳。", "天淨三光麗，時和四序均。", "卑官休力役，蠲賦免艱辛。", "蠻貊同車軌，鄉原盡里仁。", "帝途高蕩蕩，風俗厚誾誾。"]'),
('b06b95c9-6fe7-4d85-bf88-b0a6751037cb','開元觀閑居酬吳士矩侍御三十韻','元稹','唐','唐诗','tang','','[]','靜習狂心盡，幽居道氣添。',288,'全唐诗/poet.tang.21000.json','["靜習狂心盡，幽居道氣添。", "神編啓黃簡，祕籙捧朱籤。", "爛熳煙霞駐，優游歲序淹。", "登壇擁旄節，趨殿禮胡髯。", "醮起彤庭燭，香開白玉匳。", "結盟金劒重，斬魅寶刀銛。", "禹步星綱動，焚符竈鬼詹。", "冥搜呼直使，章奏役飛廉。", "仙籍聊憑檢，浮名復爲占。", "赤誠祈皓鶴，綠髮代青縑。", "虛室常懷素，玄關屢引枮。", "貂蟬徒自寵，鷗鷺不相嫌。", "始悟身爲患，唯欣祿未恬。", "龜龍戀淮海，雞犬傍閭閻。", "松笠新偏翠，山峰遠更尖。", "簫聲吟茂竹，虹影逗虛簷。", "初日先通牖，輕颸每透簾。", "露盤朝滴滴，鉤月夜纖纖。", "已得餐霞味，應嗤食蓼甜。", "工琴閑度晝，耽酒醉銷炎。", "几案隨宜設，詩書逐便拈。", "灌園多抱甕，刈藿乍腰鐮。", "野鳥終難縶，鷦鷯本易厭。", "風高雲遠逝，波駭鯉深潛。"]'),
('75abd818-1160-4e48-b49f-bbaf0627fd8f','病減逢春期白二十二辛大不至十韻','元稹','唐','唐诗','tang','','[]','病與窮陰退，春從血氣生。',120,'全唐诗/poet.tang.21000.json','["病與窮陰退，春從血氣生。", "寒膚漸舒展，陽脈乍虛盈。", "就日臨堦坐，扶牀履地行。", "問人知面瘦，祝鳥願身輕。", "風暖牽詩興，時新變賣聲。", "飢饞看藥忌，閑悶點書名。", "舊雪依深竹，微和動早萌。", "推遷悲往事，疎數辨交情。", "琴待嵇中散，杯思阮步兵。", "世間除却病，何者不營營。"]'),
('cfdc251a-0522-4ea7-acde-620e456a4a9e','黃明府詩','元稹','唐','唐诗','tang','','[]','少年曾痛飲，黃令苦飛觥。',120,'全唐诗/poet.tang.21000.json','["少年曾痛飲，黃令苦飛觥。", "席上當時走，馬前今日迎。", "依稀迷姓氏，積漸識平生。", "故友身皆遠，他鄉眼暫明。", "便邀連榻坐，兼共榜船行。", "酒思臨風亂，霜稜埽地平。", "不堪深淺酌，貪愴古今情。", "邐迤七盤路，坡陁數丈城。", "花疑褒女笑，棧想武侯征。", "一種埋幽石，老閑千載名。"]'),
('63c586ff-dfa2-4c4e-88fe-4f017c9b52bb','酬翰林白學士代書一百韻','元稹','唐','唐诗','tang','','[]','昔歲俱充賦，同年遇有司。',288,'全唐诗/poet.tang.21000.json','["昔歲俱充賦，同年遇有司。", "八人稱迥拔，兩郡濫相知。", "逸驥初翻步，鞲鷹暫脫羈。", "遠途憂地窄，高視覺天卑。", "並入紅蘭署，偏親白玉規。", "近朱憐冉冉，伐木願偲偲。", "魚魯非難識，鉛黃自嬾持。", "心輕馬融帳，謀奪子房帷。", "秀發幽巖電，清澄隘岸陂。", "九霄排直上，萬里整前期。", "勇贈棲鸞句，慙當古井詩。", "多聞全受益，擇善頗相師。", "脫俗殊常調，潛工大有爲。", "還醇憑酎酒，運智託圍棊。", "情會招車胤，閑行覓戴逵。", "僧餐月燈閣，醵宴劫灰池。", "勝概爭先到，篇章競出奇。", "輸贏論破的，點竄肯容絲。", "山岫當街翠，牆花拂面枝。", "鶯聲愛嬌小，燕翼翫逶迤。", "轡爲逢車緩，鞭緣趂伴施。", "密攜長上樂，偷宿靜坊姬。", "僻性慵朝起，新晴助晚嬉。", "相歡常滿目，別處鮮開眉。"]'),
('d9a797ae-9623-412f-8b66-4d18a7e5be7f','紀懷贈李六戶曹崔二十功曹五十韻','元稹','唐','唐诗','tang','','[]','昔冠諸生首，初因三道徵。',288,'全唐诗/poet.tang.21000.json','["昔冠諸生首，初因三道徵。", "公卿碧墀會，名姓白麻稱。", "日月光遙射，煙霄志漸弘。", "榮班聯錦繡，諫紙賜牋藤。", "便欲呈肝膽，何言犯股肱。", "椎埋衝斗劒，消碎瑩壺冰。", "赤縣纔分務，青驄已迥乘。", "因騎度海鶻，擬殺蔽天鵬。", "縛虎聲空壯，連鼇力未勝。", "風翻波竟蹙，山壓勢逾崩。", "僇辱徒相困，蒼黃性不能。", "酣歌離峴頂，負氣入江陵。", "華表當蟾魄，高樓挂玉繩。", "角聲悲掉蕩，城影暗稜層。", "軍幕威容盛，官曹禮數兢。", "心雖出雲鶴，身尚觸籠鷹。", "竦足良甘分，排衙苦未曾。", "通名參將校，抵掌見親朋。", "喣沫求涓滴，滄波怯斗升。", "荒居鄰鬼魅，羸馬步殑㱥。", "白草堂簷短，黃梅雨氣蒸。", "霑黏經汗席，颭閃盡油燈。", "夜怯餐膚蚋，朝煩拂面蠅。", "過從愁厭賤，專靜畏猜仍。"]'),
('e81c1e7b-dec6-413c-a12f-0e1cac054b72','答姨兄胡靈之見寄五十韻','元稹','唐','唐诗','tang','','[]','憶昔鳳翔城，齠年是事榮。',288,'全唐诗/poet.tang.21000.json','["憶昔鳳翔城，齠年是事榮。", "理家煩伯舅，相宅盡吾兄。", "詩律蒙親授，朋遊忝自迎。", "題頭筠管縵，教射角弓騂。", "矮馬駞鬉䪜，犛牛獸面纓。", "對談依赳赳，送客步盈盈。", "米椀諸賢讓，蠡杯大戶傾。", "一船席外語，三榼拍心精。", "傳盞加分數，橫波擲目成。", "華奴歌淅淅，媚子舞卿卿。", "鬬設狂爲好，誰憂飲敗名。", "屠過隱朱亥，樓夢古秦嬴。", "環坐唯便草，投盤暫廢觥。", "春郊纔爛熳，夕鼓已砰轟。", "荏苒移灰琯，喧闐勌塞兵。", "糟漿聞漸足，書劒訝無成。", "抵璧慙虛棄，彈珠覺用輕。", "遂籠雲際鶴，來狎谷中鶯。", "學問攻方苦，篇章興太清。", "囊疎螢易透，錐鈍股多坑。", "筆陣戈矛合，文房棟桷撐。", "豆萁才敏儁，羽獵正崢嶸。", "岐下尋時別，京師觸處行。", "醉眠街北廟，閑繞宅南營。"]'),
('cf031530-a0f2-489c-908b-74ca603d96e8','酬許五康佐','元稹','唐','唐诗','tang','','[]','奮迅君何晚，羈離我詎儔。',120,'全唐诗/poet.tang.21000.json','["奮迅君何晚，羈離我詎儔。", "鶴籠閑警露，鷹縛悶牽韝。", "蓬閣深沈省，荆門遠慢州。", "課書同吏職，旅宦各鄉愁。", "白日傷心過，滄江滿眼流。", "嘶風悲代馬，喘月伴吳牛。", "枯涸方窮轍，生涯不繫舟。", "猿啼三峽雨，蟬報兩京秋。", "珠玉慙新贈，芝蘭忝舊游。", "他年問狂客，須向老農求。"]'),
('9d8ddb6a-0a57-4b7b-93ad-96a081b6295f','送崔侍御之嶺南二十韻','元稹','唐','唐诗','tang','','[]','漢法戎施幕，秦官郡置監。',240,'全唐诗/poet.tang.21000.json','["漢法戎施幕，秦官郡置監。", "蕭何歸舊印，鮑永授新銜。", "幣聘雖盈篋，泥章未破緘。", "蛛懸絲繚繞，鵲報語詀諵。", "再礪神羊角，重開憲簡函。", "鞶纓驄赳赳，緌珮繡縿縿。", "逸翮憐鴻翥，離心覺刃劖。", "聯游虧片玉，洞照失明鑒。", "遙想車登嶺，那無淚滿衫。", "茅蒸連蟒氣，衣漬度梅黬。", "象鬬緣谿竹，猿鳴帶雨杉。", "颶風狂浩浩，韶石峻嶄嶄。", "宿浦宜深泊，祈瀧在至諴。", "瘴江乘早度，毒草莫親芟。", "試蠱看銀黑，排腥貴食鹹。", "菌須蟲已蠹，菓重鳥先鵮。", "冰瑩懷貪水，霜清顧痛巖。", "珠璣當盡擲，薏苡詎能讒。", "荆俗欺王粲，吾生問季咸。", "遠書多不達，勤爲枉攕攕。"]'),
('9253a6d3-3d63-4a08-917f-497aadb0333d','酬段丞與諸棊流會宿弊居見贈二十四韻','元稹','唐','唐诗','tang','','[]','鳴局寧虛日，閑窗任廢時。',288,'全唐诗/poet.tang.21000.json','["鳴局寧虛日，閑窗任廢時。", "琴書甘盡棄，園井詎能窺。", "運石疑填海，爭籌憶坐帷。", "赤心方苦鬬，紅燭已先施。", "蛇勢縈山合，鴻聯度嶺遲。", "堂堂排直陣，袞袞逼羸師。", "懸劫偏深猛，回征特險巇。", "旁攻百道進，死戰萬般爲。", "異日玄黃隊，今宵黑白棊。", "斫營看迥點，對壘重相持。", "善敗雖稱怯，驕盈最易欺。", "狼牙當必碎，虎口禍難移。", "乘勝同三捷，扶顛望一詞。", "希因送目便，敢恃指縱奇。", "退引防邊策，雄吟斬將詩。", "眠牀都浪置，通夕共忘疲。", "曉雉風傳角，寒藂雪壓枝。", "繁星收玉版，殘月耀冰池。", "僧請聞鐘粥，賓催下藥巵。", "獸炎餘炭在，蠟淚短光衰。", "俛仰嗟陳跡，殷勤卜後期。", "公私牽去住，車馬各支離。", "分作終身癖，兼從是事隳。", "此中無限興，唯怕俗人知。"]'),
('b5d59d9d-e52a-4c05-b850-47fb66b39263','酬竇校書二十韻','元稹','唐','唐诗','tang','','[]','鷗鷺元相得，杯觴每共傳。',240,'全唐诗/poet.tang.21000.json','["鷗鷺元相得，杯觴每共傳。", "芳遊春爛熳，晴望月團圓。", "調笑風流劇，論文屬對全。", "賞花珠並綴，看雪璧常連。", "竹寺荒唯好，松齋小更憐。", "潛投孟公轄，狂乞莫愁錢。", "塵土拋書卷，槍籌弄酒權。", "令誇齊箭道，力鬬抹弓弦。", "但喜添樽滿，誰憂乏桂然。", "漸輕身外役，渾證飲中禪。", "及我辭雲陛，逢君仕圃田。", "音徽千里斷，魂夢兩情偏。", "足聽猿啼雨，深藏馬腹鞭。", "官醪半清濁，夷饌雜腥膻。", "顧影無依倚，甘心守靜專。", "那知暮江上，俱會落英前。", "欵曲生平在，悲涼歲序遷。", "鶴方同北渚，鴻又過南天。", "麗句慙虛擲，沈機嬾強牽。", "粗酬珍重意，工拙定相懸。"]'),
('ee2a018b-e708-404c-81e5-ae6d1a0cee91','泛江翫月十二韻','元稹','唐','唐诗','tang','','[]','楚塞分形勢，羊公壓大邦。',144,'全唐诗/poet.tang.21000.json','["楚塞分形勢，羊公壓大邦。", "因依多士子，參畫盡敦厖。", "岳璧閑相對，荀龍自有雙。", "共將船載酒，同泛月臨江。", "遠樹懸金鏡，深潭倒玉幢。", "委波添淨練，洞照滅凝釭。", "闐咽沙頭市，𤫩瓏竹岸窗。", "巴童唱巫峽，海客話神瀧。", "已困連飛盞，猶催未倒缸。", "飲荒情爛熳，風棹樂崢摐。", "勝事他年憶，愁心此夜降。", "知君皆逸韻，須爲應莛撞。"]'),
('799d09c7-b7db-4e45-a9ea-1500216d6d46','痁臥聞幕中諸公徵樂會飲因有戲呈三十韻','元稹','唐','唐诗','tang','','[]','濩落因寒甚，沈陰與病偕。',288,'全唐诗/poet.tang.21000.json','["濩落因寒甚，沈陰與病偕。", "藥囊堆小案，書卷塞空齋。", "脹腹看成鼓，羸形漸比柴。", "道情憂易適，溫瘴氣難排。", "治尰扶輕杖，開門立靜街。", "耳鳴疑暮角，眼暗助昏霾。", "野竹連荒草，平陂接斷崖。", "坐隅甘對鵩，當路恐遭豺。", "蛇蠱迷弓影，鵰翎落箭靫。", "晚籬喧鬬雀，殘菊半枯荄。", "悵望悲回鴈，依遲傍古槐。", "一生長苦節，三省詎行怪。", "奔北翻成勇，司南却是咼。", "穹蒼真漠漠，風雨漫喈喈。", "彼美猶谿女，其誰占館娃。", "誠知通有日，太極浩無涯。", "布卦求无妄，祈天願孔皆。", "藏衰謀計拙，地僻往還乖。", "況羨蓮花侶，方欣綺席諧。", "鈿車迎妓樂，銀翰屈朋儕。", "白紵顰歌黛，同蹄墜舞釵。", "纖身霞出海，豔臉月臨淮。", "籌箸隨宜放，投盤止罰啀。", "紅娘留醉打，觥使及醒差。"]'),
('545657de-d6a7-4051-91e3-a539862a6df2','酬友封話舊敘懷十二韻','元稹','唐','唐诗','tang','','[]','風波千里別，書信二年稀。',144,'全唐诗/poet.tang.21000.json','["風波千里別，書信二年稀。", "乍見悲兼喜，猶驚是與非。", "身名判作夢，盃盞莫相違。", "草館同牀宿，沙頭待月歸。", "春深鄉路遠，老去宦情微。", "魏闕何由到，荆州且共依。", "人欺翻省事，官冷易藏威。", "但擬馴鷗鳥，無因用弩機。", "開張圖卷軸，顛倒醉衫衣。", "蓴菜銀絲嫩，鱸魚雪片肥。", "憐君詩似湧，贈我筆如飛。", "會遣諸伶唱，篇篇入禁闈。"]'),
('ba8ed091-2d31-4f42-8416-d2deed04c071','送王協律游杭越十韻','元稹','唐','唐诗','tang','','[]','去去莫悽悽，餘杭接會稽。',120,'全唐诗/poet.tang.21000.json','["去去莫悽悽，餘杭接會稽。", "松門天竺寺，花洞若耶溪。", "浣渚逢新豔，蘭亭識舊題。", "山經秦帝望，壘辨越王棲。", "江樹春常早，城樓月易低。", "鏡呈湖面出，雲疊海潮齊。", "章甫官人戴，蓴絲姹女提。", "長干迎客鬧，小市隔煙迷。", "紙亂紅藍壓，甌凝碧玉泥。", "荆南無抵物，來日爲儂攜。"]'),
('3567f8d0-9a5e-4412-8b21-49d6c1f1f305','送東川馬逢侍御使回十韻','元稹','唐','唐诗','tang','','[]','風水荆門闊，文章蜀地豪。',120,'全唐诗/poet.tang.21000.json','["風水荆門闊，文章蜀地豪。", "眼青賓禮重，眉白衆情高。", "思勇曾吞筆，投虛慣用刀。", "詞鋒倚天劒，學海駕雲濤。", "南郡傳紗帳，東方讓錦袍。", "旋吟新樂府，便續古離騷。", "雪岸猶封草，春江欲滿槽。", "餞筵君置醴，隨俗我餔糟。", "莫歎巴三峽，休驚鬢二毛。", "流年等頭過，人世各勞勞。"]'),
('c76f3ccd-1927-4788-a6bb-c5f58d000c39','酬盧祕書','元稹','唐','唐诗','tang','','[]','偶有衝天氣，都無處世才。',240,'全唐诗/poet.tang.21000.json','["偶有衝天氣，都無處世才。", "未容榮路穩，先蹋禍機開。", "分久沉荆掾，慙經廁柏臺。", "理推愁易惑，鄉思病難裁。", "夜伴吳牛喘，春驚朔鴈回。", "北人腸斷送，西日眼穿頹。", "唯望魂歸去，那知詔下來。", "涸魚千丈水，殭燕一聲雷。", "幽匣提清鏡，衰顏拂故埃。", "夢雲期紫閣，厭雨別黃梅。", "親戚迎時到，班行見處陪。", "文工猶畏忌，朝士絕嫌猜。", "新識蓬山傑，深交翰苑材。", "連投珠作貫，獨和玉成堆。", "劇敵徒相軋，羸師亦自媒。", "磨礱刮骨刃，翻擲委心灰。", "恐被神明哭，憂爲造化災。", "私調破葉箭，定飲搴旗杯。", "金寶潛砂礫，芝蘭似草萊。", "憑君毫髮鑒，莫遣翳莓苔。"]'),
('8c895dac-d461-45d2-8613-940494bc98e4','見人詠韓舍人新律詩因有戲贈','元稹','唐','唐诗','tang','','[]','喜聞韓古調，兼愛近詩篇。',120,'全唐诗/poet.tang.21000.json','["喜聞韓古調，兼愛近詩篇。", "玉磬聲聲徹，金鈴箇箇圓。", "高疎明月下，細膩早春前。", "花態繁於綺，閨情軟似綿。", "輕新便妓唱，凝妙入僧禪。", "欲得人人伏，能教面面全。", "延之苦拘檢，摩詰好因緣。", "七字排居敬，千詞敵樂天。", "殷勤閑太祝，好去老通川。", "莫漫裁章句，須饒紫禁仙。"]'),
('e04a8844-2663-48cb-b8de-5989fbf5845b','奉和權相公行次臨闕驛逢僕射相公歸朝俄頃分途因以奉贈詩十四韻','元稹','唐','唐诗','tang','','[]','帝下赤霄符，搜求造化爐。',168,'全唐诗/poet.tang.21000.json','["帝下赤霄符，搜求造化爐。", "中台歸內座，太一直南都。", "黃霸乘軺入，王尊叱馭趨。", "萬人東道送，六纛北風驅。", "棧閣纔傾蓋，關門已合繻。", "貫魚行邐迤，交馬語踟躕。", "去速熊羆兆，來馳虎豹夫。", "昔憐三易地，今訝兩分途。", "別路環山雪，離章運寸珠。", "鋒鋩斷犀兕，波浪沒蓬壺。", "區宇聲雖動，淮河孽末誅。", "將軍遙策畫，師氏密訏謨。", "漢上壇仍築，褒西陣再圖。", "公方先二虜，何暇進愚儒。"]'),
('dc110d69-e883-45b4-b69b-080c6d7bd941','酬樂天東南行詩一百韻','元稹','唐','唐诗','tang','','[]','我病方吟越，君行已過湖。',288,'全唐诗/poet.tang.21000.json','["我病方吟越，君行已過湖。", "去應緣直道，哭不爲窮途。", "亞竹寒驚牖，空堂夜向隅。", "暗魂思背燭，危夢怯乘桴。", "坐痛筋骸憯，旁嗟物候殊。", "雨蒸蟲沸渭，浪湧怪睢盱。", "索綆飄蚊蚋，蓬麻甃舳艫。", "短簷苫稻草，微俸封漁租。", "泥浦喧撈蛤，荒郊險鬬貙。", "鯨吞近溟漲，猿鬧接黔巫。", "芒屩泅牛婦，丫頭蕩槳夫。", "酢醅荷裹賣，醨酒水淋沽。", "舞態翻鸜鵒，歌詞咽鷓鴣。", "夷音啼似笑，蠻語謎相呼。", "江郭船添店，山城木豎郛。", "吠聲沙市犬，爭食墓林烏。", "獷俗誠堪憚，妖神甚可虞。", "欲令仁漸及，已被瘧潛圖。", "膳減思調鼎，行稀恐蠹樞。", "雜蓴多剖鱔，和黍半蒸菰。", "綠糉新菱實，金丸小木奴。", "芋羹真蹔淡，䶉炙漫塗蘇。", "炰鼈那勝羜，烹鯄只似鱸。", "楚風輕似蜀，巴地濕如吳。"]'),
('7c5775e2-be12-40ae-8382-ce87f9c2037c','和樂天送客遊嶺南二十韻','元稹','唐','唐诗','tang','','[]','我自離鄉久，君那度嶺頻。',240,'全唐诗/poet.tang.21000.json','["我自離鄉久，君那度嶺頻。", "一杯魂慘澹，萬里路艱辛。", "江館連沙市，瀧船泊水濱。", "騎田廻北顧，銅柱指南鄰。", "大壑浮三島，周天過五均。", "波心湧樓閣，規外布星辰。", "狒狒穿筒格，猩猩置屐馴。", "貢兼蛟女絹，俗重語兒巾。", "舶主腰藏寶，黃家砦起塵。", "歌鍾排象背，炊爨上魚身。", "電白雷山接，旗紅賊艦新。", "島夷徐市種，廟覡趙佗神。", "鳶跕方知瘴，蛇蘇不待春。", "曙潮雲斬斬，夜海火燐燐。", "冠冕中華客，梯航異域臣。", "果然皮勝錦，吉了舌如人。", "風黖秋茅葉，煙埋曉月輪。", "定應玄髮變，焉用翠毛珍。", "句漏沙須買，貪泉貨莫親。", "能傳稚川術，何患隱之貧。"]'),
('6326d175-7980-4cbc-9237-62120d12a482','獻滎陽公詩五十韻','元稹','唐','唐诗','tang','','[]','鄭驛騎翩翩，丘門子弟賢。',288,'全唐诗/poet.tang.21000.json','["鄭驛騎翩翩，丘門子弟賢。", "文翁開學日，正禮騁途年。", "駿骨黃金買，英髦絳帳延。", "趨風皆蹀足，侍坐各差肩。", "解榻招徐穉，登樓引仲宣。", "鳳攢題字扇，魚落講經筵。", "盛氣河包濟，貞姿嶽柱天。", "臯夔當五百，鄒魯重三千。", "科斗翻騰取，關雎教授先。", "篆垂朝露滴，詩綴夜珠聯。", "逸禮多心匠，焚書舊口傳。", "陳遵修尺牘，阮瑀讓飛牋。", "中的顏初啓，抽毫踵未旋。", "森羅萬木合，屬對百花全。", "詞海跳波湧，文星拂坐懸。", "戴馮遙避席，祖逖後施鞭。", "西蜀凌雲賦，東陽詠月篇。", "勁芟鼇足斷，精貫蝨心穿。", "浩汗神彌王，鷂颺興欲仙。", "冰壺通皓雪，綺樹眇晴煙。", "驅駕雷霆走，鋪陳錦繡鮮。", "情機登穾奧，流韻溢山川。", "墨客膺潛服，談賓膝誤前。", "張鱗定摧敗，折角反矜憐。"]'),
('e5d6b2c8-8c40-41bd-bc26-89b792f8b659','酬樂天江樓夜吟稹詩因成三十韻','元稹','唐','唐诗','tang','','[]','忽見君新句，君吟我舊篇。',288,'全唐诗/poet.tang.21000.json','["忽見君新句，君吟我舊篇。", "見當巴徼外，吟在楚江前。", "思鄙寧通律，聲清遂扣玄。", "三都時覺重，一顧世稱妍。", "排韻曾遙荅，分題幾共聯。", "昔憑銀翰寫，今賴玉音宣。", "布鼓隨椎響，坯泥仰匠圓。", "鈴因風斷續，珠與調牽緜。", "阮籍驚長嘯，商陵怨別弦。", "猿羞啼月峽，鶴讓警秋天。", "志士潛興感，高僧暫廢禪。", "興飄滄海動，氣合碧雲連。", "點綴工微者，吹噓勢特然。", "休文徒倚檻，彥伯浪回船。", "伎樂當筵唱，兒童滿巷傳。", "改張思婦錦，騰躍賈人牋。", "魏拙虛教出，曹風敢望痊。", "定遭才子笑，恐賺學生癲。", "裁什情何厚，飛書信不專。", "隼猜鴻蓄縮，虎橫犬迍邅。", "水墨看雖久，瓊瑤喜尚全。", "纔從魚裏得，便向市頭懸。", "夜置堂東序，朝鋪座右邊。", "手尋韋欲絕，淚滴紙渾穿。"]'),
('dddafe62-5195-43d1-ae5d-8b1ac66eb1ca','酬樂天待漏入閤見贈','元稹','唐','唐诗','tang','','[]','未勘銀臺契，先排浴殿關。',110,'全唐诗/poet.tang.21000.json','["未勘銀臺契，先排浴殿關。", "沃心因特召，[承]旨絕常班。", "颭閃才人袖，嘔鵶軟舉鐶。", "宮花低作帳，雲從積成山。", "密視樞機草，偷瞻咫尺顏。", "恩垂天語近，對久漏聲閑。", "丹陛曾同立，金鑾恨獨攀。", "筆無鴻業潤，袍愧紫文殷。", "河水通天上，瀛州接世間。"]'),
('d7890db1-28cc-4cc4-b81a-90b6f9d68568','酬樂天早春閑遊西湖頗多野趣恨不得與微之同賞因思在越官重事殷鏡湖之遊或恐未暇因成十八韻見寄樂天前篇到時適會予亦宴鏡湖南亭因述目前所睹以成酬荅末章亦示暇誠則勢使之然亦欲粗爲恬養之贈耳','元稹','唐','唐诗','tang','','["\u897f\u6e56"]','雁思欲回賓，風聲乍變新。',216,'全唐诗/poet.tang.21000.json','["雁思欲回賓，風聲乍變新。", "各攜紅粉伎，俱伴紫垣人。", "水面波疑縠，山腰虹似巾。", "柳條黃大帶，茭葑綠文茵。", "雪盡纔通屐，汀寒未有蘋。", "向陽偏曬羽，依岸小游鱗。", "浦嶼崎嶇到，林園次第巡。", "墨池憐嗜學，丹井羨登真。", "雅歎游方盛，聊非意所親。", "白頭辭北闕，滄海是東鄰。", "問俗煩江界，蒐畋想渭津。", "故交音訊少，歸夢往來頻。", "獨喜同門舊，皆爲列郡臣。", "三刀連地軸，一葦礙車輪。", "尚阻青天霧，空瞻白玉塵。", "龍因雕字識，犬爲送書馴。", "勝事無窮境，流年有限身。", "嬾將閑氣力，爭鬬野塘春。"]'),
('6c14a7b2-fa69-4730-b1c2-849eda7012d9','江邊四十韻','元稹','唐','唐诗','tang','','[]','官借江邊宅，天生地勢坳。',288,'全唐诗/poet.tang.21000.json','["官借江邊宅，天生地勢坳。", "敧危饒壞構，迢遞接長郊。", "怪鵩頻棲息，跳蛙頗混殽。", "總無籬繳繞，尤怕虎咆哮。", "停潦魚招獺，空倉鼠敵貓。", "土虛煩穴蟻，柱朽畏藏蛟。", "蛇虺吞簷雀，豺狼逐野麃。", "犬驚狂浩浩，雞亂響嘐嘐。", "濩落貧甘守，荒涼穢盡包。", "斷簾飛熠燿，當戶網蠨蛸。", "曲突翻成沼，行廊却代庖。", "橋橫老顛枿，馬病裛芻茭。", "一一牀頭點，連連砌下泡。", "辱泥疑在絳，避雨想經崤。", "相顧憂爲鼈，誰能復繫匏。", "誓心來利往，卜食過安爻。", "何計逃昏墊，移文報舊交。", "棟梁存伐木，苫蓋愧分茅。", "金琯排黃荻，琅玕褭翠梢。", "花塼水面鬬，鴛瓦玉聲敲。", "方礎荆山採，修掾郢匠鉋。", "隱錐雷震蟄，破竹箭鳴骹。", "正寢初停午，頻眠欲轉胞。", "囷圓收薄祿，廚敝備嘉肴。"]'),
('c99e55a4-ea4a-49ea-b3ca-980c39777cdf','春六十韻','元稹','唐','唐诗','tang','','[]','節應寒灰下，春生返照中。',288,'全唐诗/poet.tang.21000.json','["節應寒灰下，春生返照中。", "未能消積雪，已漸少回風。", "迎氣邦經重，齋誠帝念隆。", "龍驤紫宸北，天壓翠壇東。", "仙仗搖佳彩，榮光荅聖衷。", "便從威仰座，隨入大羅宮。", "先到璇淵底，偷穿玳瑁櫳。", "館娃朝鏡晚，太液曉冰融。", "撩摘芳情徧，搜求好處終。", "九霄渾可可，萬姓尚忡忡。", "晝漏頻加箭，宵暉欲半弓。", "驅令三殿出，乞與百蠻同。", "直自方壺島，斜臨絕漠戎。", "南巡曖珠樹，西轉麗崆峒。", "度嶺梅甘坻，潛泉脈暗洪。", "悠悠鋪塞草，冉冉著江楓。", "蠶役投筐妾，耘催荷蓧翁。", "既蒸難發地，仍送嬾歸鴻。", "約略環區宇，殷勤綺鎬酆。", "華山青黛撲，渭水碧沙蒙。", "宿露清餘靄，晴煙塞迥空。", "燕巢纔點綴，鶯舌最惺愡。", "膩粉梨園白，臙脂桃徑紅。", "鬱金垂嫩柳，罯畫委高籠。"]'),
('019b3965-59ae-46a8-8b7a-96f1cb9ab59c','月三十韻','元稹','唐','唐诗','tang','','[]','蓂葉標新朔，霜豪引細輝。',288,'全唐诗/poet.tang.21000.json','["蓂葉標新朔，霜豪引細輝。", "白眉驚半隱，虹勢訝全微。", "涼魄潭空洞，虛弓雁畏威。", "上弦何汲汲，佳色轉依依。", "綺幕殘燈斂，妝樓破鏡飛。", "玲瓏穿竹樹，岑寂思幈幃。", "坐愛規將合，行看望已幾。", "絳河冰鑑朗，黃道玉輪巍。", "迥照偏瓊砌，餘光借粉闈。", "泛池相皎潔，壓桂共芳菲。", "的的當歌扇，娟娟透舞衣。", "殷勤入懷什，懇款墮雲圻。", "素液傳烘盞，鳴琴薦碧徽。", "椒房深肅肅，蘭路靄霏霏。", "翡翠通簾影，琉璃瑩殿扉。", "西園筵玳瑁，東壁射蛜蝛。", "老將占天陣，幽人釣石磯。", "荷鋤元亮息，回櫂子猷歸。", "迢遞同千里，孤高淨九圍。", "從星作風雨，配日麗旌旗。", "麟鬬寧徒設，蠅聲豈浪譏。", "司存委卿士，新拜出郊畿。", "今古雖云極，虧盈不易違。", "珠胎方夜滿，清露忍朝晞。"]'),
('a8847586-067b-4b68-a2fc-740b860e11c1','飲致用神麴酒三十韻','元稹','唐','唐诗','tang','','[]','七月調神麴，三春釀綠醽。',288,'全唐诗/poet.tang.21000.json','["七月調神麴，三春釀綠醽。", "雕鐫荆玉盞，烘透內丘缾。", "試滴盤心露，疑添案上螢。", "滿尊凝止水，祝地落繁星。", "翻陋瓊漿濁，唯聞石髓馨。", "冰壺通角簟，金鏡徹雲屏。", "雪暎煙光薄，霜涵霽色泠。", "蚌珠懸皎皛，桂魄倒瀴溟。", "晝灑蟬將飲，宵揮鶴誤聆。", "琉璃驚太白，鍾乳訝微青。", "詎敢辭濡首，幷憐可鑒形。", "行當遣俗累，便得造禪扃。", "何憚說千日，甘從過百齡。", "但令長泛蟻，無復恨漂萍。", "膽壯還增氣，機忘反自冥。", "甕眠思畢卓，糟籍憶劉伶。", "髣髴中聖日，希夷夾大庭。", "眼前須底物，座右任他銘。", "刮骨都無痛，如泥未擬停。", "殘觴猶漠漠，華燭已熒熒。", "真性臨時見，狂歌半睡聽。", "喧闐爭意氣，調笑學娉婷。", "酩酊焉知極，羇離忽暫寧。", "雞聲催欲曙，蟾影照初醒。"]'),
('d1734c10-cff7-42c7-8763-0b04378a3864','感石榴二十韻','元稹','唐','唐诗','tang','','[]','何年安石國，萬里貢榴花。',240,'全唐诗/poet.tang.21000.json','["何年安石國，萬里貢榴花。", "迢遞河源道，因依漢使槎。", "酸辛犯蔥嶺，顦顇涉龍沙。", "初到摽珍木，多來比亂麻。", "深拋故園裏，少種貴人家。", "唯我荆州見，憐君胡地賒。", "從教當路長，兼恣入檐斜。", "綠葉裁煙翠，紅英動日華。", "新簾帬透影，疎牖燭籠紗。", "委作金爐燄，飄成玉砌瑕。", "乍驚珠綴密，終誤繡幃奢。", "琥珀烘梳碎，燕支嬾頰塗。", "風翻一樹火，電轉五雲車。", "絳帳迎宵日，芙蕖綻早牙。", "淺深俱隱映，前後各分葩。", "宿露低蓮臉，朝光借綺霞。", "暗虹徒繳繞，濯錦莫周遮。", "俗態能嫌舊，芳姿尚可嘉。", "非專愛顏色，同恨阻幽遐。", "滿眼思鄉淚，相嗟亦自嗟。"]'),
('1fb84b33-da4d-4bb9-bb7d-9bfeab08608b','度門寺','元稹','唐','唐诗','tang','','[]','北祖三禪地，西山萬樹松。',240,'全唐诗/poet.tang.21000.json','["北祖三禪地，西山萬樹松。", "門臨溪一帶，橋映竹千重。", "翦鑿基階正，包藏景氣濃。", "諸巖分院宇，雙嶺抱垣墉。", "舍利開層墖，香爐占小峰。", "道場居士置，經藏大師封。", "太子知栽植，神王守要衝。", "由旬排講座，丈六寫真容。", "佛語迦陵說，僧行猛虎從。", "修羅擡日拒，樓至拔霜鋒。", "畫井垂枯朽，穿池救噞喁。", "蕉非難敗壞，槿喻暫丰茸。", "寶界留遺事，金棺滅去蹤。", "鉢傳烘瑪瑙，石長翠芙蓉。", "影帳紗全落，繩牀土半壅。", "荒林迷醉象，危壁亞盤龍。", "行色憐初月，歸程待曉鐘。", "心源雖了了，塵世苦憧憧。", "宿蔭高聲懺，齋糧幷力舂。", "他生再來此，還願總相逢。"]'),
('b0e26451-3be1-460a-9f1d-e17607290640','大雲寺二十韻','元稹','唐','唐诗','tang','','[]','地勝宜臺殿，山晴離垢氛。',240,'全唐诗/poet.tang.21000.json','["地勝宜臺殿，山晴離垢氛。", "現身千佛國，護世四王軍。", "碧耀高樓瓦，赬飛半壁文。", "鶴林縈古道，雁墖沒歸雲。", "幡影中天颺，鐘聲下界聞。", "攀蘿極峰頂，游目到江濆。", "馴鴿閑依綴，調猿靜守羣。", "虎行風捷獵，龍睡氣氛氳。", "穫稻禪衣卷，燒畬劫火焚。", "新英蜂采掇，荒草象耕耘。", "鉢付靈童洗，香教善女熏。", "果枝低罯罯，花雨澤雰雰。", "示化維摩疾，降魔力士勳。", "聽經神變見，說偈鳥紛紜。", "上境光猶在，深谿暗不分。", "竹籠煙欲暝，松帶日餘曛。", "真諦成知別，迷心尚有云。", "多生沈五蘊，宿習樂三墳。", "諭鹿車雖設，如蠶緒正棼。", "且將平等義，還奉聖明君。"]'),
('e7c83743-6442-49fb-b288-203753683560','和友封題開善寺十韻','元稹','唐','唐诗','tang','','[]','梁王開佛廟，雲構歲時遙。',120,'全唐诗/poet.tang.21000.json','["梁王開佛廟，雲構歲時遙。", "珠綴飛閑鴿，紅泥落碎椒。", "燈籠青燄短，香印白灰銷。", "古匣收遺施，行廊畫本朝。", "藏經霑雨爛，魔女捧花嬌。", "亞樹牽藤閣，橫查壓石橋。", "竹荒新筍細，池淺小魚跳。", "匠正琉璃瓦，僧鋤芍藥苗。", "旋蒸茶嫩葉，偏把柳長條。", "便欲忘歸路，方知隱易招。"]'),
('9126df60-fdbd-4366-a7de-737c8008ab7d','牡丹二首 一','元稹','唐','唐诗','tang','','[]','簇蘂風頻壞，裁紅雨更新。',24,'全唐诗/poet.tang.21000.json','["簇蘂風頻壞，裁紅雨更新。", "眼看吹落地，便別一年春。"]'),
('c57e3942-d51e-4d6c-af57-0993269f0ed8','牡丹二首 二','元稹','唐','唐诗','tang','','[]','繁綠陰全合，衰紅展漸難。',24,'全唐诗/poet.tang.21000.json','["繁綠陰全合，衰紅展漸難。", "風光一擡舉，猶得暫時看。"]'),
('ec33550f-5cd0-433f-ab85-a86a288eeeab','象人','元稹','唐','唐诗','tang','','[]','被色空成象，觀空色異真。',24,'全唐诗/poet.tang.21000.json','["被色空成象，觀空色異真。", "自悲人是假，那復假爲人。"]'),
('d6b9f2e8-6fd8-4b1c-9492-b6c5cd780ada','與楊十二巨源盧十九經濟同遊大安亭各賦二物各爲五韻探得松石','元稹','唐','唐诗','tang','','[]','片石與孤松，曾經物外逢。',60,'全唐诗/poet.tang.21000.json','["片石與孤松，曾經物外逢。", "月臨棲鶴影，雲抱老人峰。", "蜀客君當問，秦官我舊封。", "積膏當琥珀，新劫長芙蓉。", "待補蒼蒼去，樛柯早變龍。"]'),
('98cf143d-0917-47aa-8a24-ce3db79ce765','賦得春雪映早梅','元稹','唐','唐诗','tang','','[]','飛舞先春雪，因依上番梅。',72,'全唐诗/poet.tang.21000.json','["飛舞先春雪，因依上番梅。", "一枝方漸秀，六出已同開。", "積素光逾密，真花節暗催。", "摶風飄不散，見晛忽偏摧。", "郢曲琴空奏，羌音笛自哀。", "今朝兩成詠，翻挾昔人才。"]'),
('012cfe29-e025-4b76-97ad-b096c3c25975','賦得玉巵無當','元稹','唐','唐诗','tang','','[]','共惜連城寶，翻成無當巵。',72,'全唐诗/poet.tang.21000.json','["共惜連城寶，翻成無當巵。", "詎慙君子貴，深訝巧工隳。", "泛蟻功全小，如虹色不移。", "可憐殊礫石，何計辨糟醨。", "江海誠難滿，盤筵莫忘施。", "縱乖斟酌意，猶得對光儀。"]'),
('dac18257-d38e-4150-a334-fd228d6a3bd3','賦得數蓂','元稹','唐','唐诗','tang','','[]','將課司天曆，先觀近砌蓂。',72,'全唐诗/poet.tang.21000.json','["將課司天曆，先觀近砌蓂。", "一旬開應月，五日數從星。", "桂滿叢初合，蟾虧影漸零。", "辨時長有素，數閏或餘青。", "墜葉推前事，新芽察未形。", "堯年始今歲，方欲瑞千齡。"]'),
('dd96aa7d-7490-44c0-8c76-f9499f44b62a','賦得九月盡','元稹','唐','唐诗','tang','','[]','霜降三旬後，蓂餘一葉秋。',48,'全唐诗/poet.tang.21000.json','["霜降三旬後，蓂餘一葉秋。", "玄陰迎落日，涼魄盡殘釣。", "半夜灰移琯，明朝帝御裘。", "潘安過今夕，休詠賦中愁。"]'),
('89ef0c6f-d36b-4825-9659-120c77e2bec5','賦得雨後花','元稹','唐','唐诗','tang','','[]','紅芳憐靜色，深與雨相宜。',48,'全唐诗/poet.tang.21000.json','["紅芳憐靜色，深與雨相宜。", "餘滴下纖蘂，殘珠墮細枝。", "浣花江上思，啼粉鏡中窺。", "念此低回久，風光幸一吹。"]'),
('4c609eb2-61d7-4af4-9233-bfe611c6edfa','早歸','元稹','唐','唐诗','tang','','[]','春靜曉風微，凌晨帶酒歸。',48,'全唐诗/poet.tang.21000.json','["春靜曉風微，凌晨帶酒歸。", "遠山籠宿霧，高樹影朝暉。", "飲馬魚驚水，穿花露滴衣。", "嬌鶯似相惱，含囀傍人飛。"]'),
('798fd01e-5640-491a-b856-20f3f58be019','晚秋','元稹','唐','唐诗','tang','','[]','竹露滴寒聲，離人曉思驚。',48,'全唐诗/poet.tang.21000.json','["竹露滴寒聲，離人曉思驚。", "酒醒秋簟冷，風急夏衣輕。", "寢倦解幽夢，慮閑添遠情。", "誰憐獨欹枕，斜月透窗明。"]'),
('dad4f0cb-e7a1-4cde-877e-a181b7c8b7d7','送林復夢赴韋令辟','元稹','唐','唐诗','tang','','[]','蜀路危於劒，憐君自坦途。',48,'全唐诗/poet.tang.21000.json','["蜀路危於劒，憐君自坦途。", "幾回曾啖炙，千里遠銜珠。", "野性便荒飲，時風忌酒徒。", "相門多禮讓，前後莫相踰。"]'),
('c9599c93-9d2d-4ca0-9ff3-1ee8df809789','憶楊十二','元稹','唐','唐诗','tang','','[]','楊子愛言詩，春天好詠時。',48,'全唐诗/poet.tang.21000.json','["楊子愛言詩，春天好詠時。", "戀花從馬滯，聯句放杯遲。", "日映含煙竹，風牽臥柳絲。", "南山更多興，須作白雲期。"]'),
('9a095532-df23-4c16-b7d7-02dd9fc3e563','夜合','元稹','唐','唐诗','tang','','[]','綺樹滿朝陽，融融有露光。',48,'全唐诗/poet.tang.21000.json','["綺樹滿朝陽，融融有露光。", "雨多疑濯錦，風散似分妝。", "葉密煙蒙火，枝低繡拂牆。", "更憐當暑見，留詠日偏長。"]'),
('f19beb4c-5135-4a1c-8534-3945c8430474','新竹','元稹','唐','唐诗','tang','','[]','新篁纔解籜，寒色已青蔥。',48,'全唐诗/poet.tang.21000.json','["新篁纔解籜，寒色已青蔥。", "冉冉偏凝粉，蕭蕭漸引風。", "扶疎多透日，寥落未成叢。", "惟有團團節，堅貞大小同。"]'),
('b7eac3f3-b918-4887-885d-d49e71f8764a','秋相望','元稹','唐','唐诗','tang','','[]','檐月驚殘夢，浮涼滿夏衾。',48,'全唐诗/poet.tang.21000.json','["檐月驚殘夢，浮涼滿夏衾。", "蠨蛸低戶網，螢火度牆陰。", "爐暗燈光短，牀空帳影深。", "此時相望久，高樹憶橫岑。"]'),
('dac5ab62-cc19-4f32-9667-4ed0077ee6c3','春病','元稹','唐','唐诗','tang','','[]','病來閑臥久，因見靜時心。',48,'全唐诗/poet.tang.21000.json','["病來閑臥久，因見靜時心。", "殘月曉窗迥，落花幽院深。", "望山移坐榻，行藥步牆陰。", "車馬門前度，遙聞哀苦吟。"]'),
('30c10188-d6da-4384-a219-25b8bf00bff8','山竹枝','元稹','唐','唐诗','tang','','[]','深院虎溪竹，遠公身自栽。',48,'全唐诗/poet.tang.21000.json','["深院虎溪竹，遠公身自栽。", "多慙折君節，扶我出山來。", "貴宅安危步，難將混俗材。", "還投輞川水，從作老龍回。"]'),
('3d086a93-0b1d-4a07-a994-6e76198a17d6','悟禪三首寄胡果 一','元稹','唐','唐诗','tang','','[]','近聞胡隱士，潛認得心王。',48,'全唐诗/poet.tang.21000.json','["近聞胡隱士，潛認得心王。", "不恨百年促，翻悲萬劫長。", "有修終有限，無事亦無殃。", "慎莫通方便，應機不頓忘。"]');
